//! JavaScriptCore-shaped C API subset, implemented in pure Zig.
//!
//! These `export fn` symbols mirror Apple's `<JavaScriptCore/JSValueRef.h>` and
//! `<JSObjectRef.h>` names closely enough for embedders that only use the
//! implemented public subset to try this library in place of
//! `JavaScriptCore.framework` (e.g. `~/Code/Home/lang`'s
//! `packages/runtime/src/jsc/extern_fns.zig`). Pre-stabilization API cleanup
//! should prefer clear zig-js contracts over preserving inert compatibility
//! parameters.
//!
//! Internally a `JSValueRef` is a pointer to a `Boxed` value living in the
//! Context arena; a `JSStringRef` is a reference-counted `JsString`.
//!
//! ## Threading rules
//!
//! Every handle is affine to its context group and creator thread. Values may be
//! exchanged by distinct global contexts in the same `JSContextGroupRef`; APIs
//! reject handles from another group. Cross-thread use is still
//! undefined behavior (the arena, object graph, and microtask queue are
//! unsynchronized by design); debug builds panic on it.
//! The supported multithreading pattern is one context per thread, sharing
//! only `SharedArrayBuffer` storage — see docs/threads/bindings.md and
//! https://github.com/zig-utils/zig-js/issues/1 for the worker/agent roadmap.
//! The `JSWorker*` surface (below) spawns such per-thread contexts and moves
//! values between them as structured-clone bytes.
//! `JSStringRef`s are immutable and retain/release is atomic, so references may
//! be created, retained, and released on any thread.

const std = @import("std");
const builtin = @import("builtin");
const regex_mod = @import("regex");
const ast = @import("ast.zig");
const gc_mod = @import("gc.zig");
const value = @import("value.zig");
const ContextMod = @import("context.zig");
const agent = @import("agent.zig");
const interp = @import("interpreter.zig");
const builtins = @import("builtins.zig");
const promise = @import("promise.zig");
const structured_clone = @import("structured_clone.zig");
const jit = @import("jit.zig");
const vm = @import("vm.zig");
const strcell = @import("strcell.zig");
const text_codec = @import("text_codec.zig");
const private_encoded_value = @import("private_abi/encoded_value.zig");
const private_jstype = @import("private_abi/jstype.zig");
const WorkerMod = @import("worker.zig");
const JsString = @import("jsstring.zig").JsString;

const Context = ContextMod.Context;
const Value = value.Value;
const Object = value.Object;
const EncodedValue = private_encoded_value.EncodedValue;
const PrivatePromiseWrapCallback = *const fn (*anyopaque, JSContextRef) callconv(.c) EncodedValue;
const PrivateMicrotaskCallback = *const fn (?*anyopaque) callconv(.c) void;
const PrivateForEachPropertyCallback = *const fn (
    JSContextRef,
    ?*anyopaque,
    *PrivateZigString,
    EncodedValue,
    bool,
    bool,
) callconv(.c) void;

const PrivateCommonAbortReason = enum(u8) {
    none = 0,
    timeout = 1,
    user_abort = 2,
    connection_closed = 3,
    _,
};

/// Bun/Home pass `bun.String` by value across the private ABI. On 64-bit
/// targets this is the 24-byte `BunString` C layout from
/// `headers-handwritten.h`: one byte of tag, natural padding, then a 16-byte
/// union large enough for `ZigString { ptr, len }`.
const PrivateBunStringTag = enum(u8) {
    dead = 0,
    wtf_string_impl = 1,
    zig_string = 2,
    static_zig_string = 3,
    empty = 4,
};

const PrivateZigString = extern struct {
    tagged_ptr: usize = 0,
    len: usize = 0,
};

const PrivateZigStringView = struct {
    result: PrivateZigString,
    storage: union(enum) {
        latin1: []u8,
        utf16: []u16,
    },
};

const PrivateBunStringImpl = extern union {
    zig_string: PrivateZigString,
    wtf_string_impl: ?*PrivateWTFStringImpl,
};

const PrivateBunString = extern struct {
    tag: PrivateBunStringTag,
    value: PrivateBunStringImpl,

    fn dead() PrivateBunString {
        return .{ .tag = .dead, .value = .{ .zig_string = .{} } };
    }

    fn empty() PrivateBunString {
        return .{ .tag = .empty, .value = .{ .zig_string = .{} } };
    }
};

/// Pinned Home/Bun `SerializedScriptValue.External` return layout. The byte
/// view borrows the opaque handle and remains valid until its matching free.
const PrivateSerializedScriptExternal = extern struct {
    bytes: ?[*]const u8 = null,
    size: usize = 0,
    handle: ?*anyopaque = null,
};

const PrivateSerializedScriptOwned = struct {
    bytes: []u8,
    allocator: std.mem.Allocator,
};

/// Pure-Zig storage for the pinned 24-byte/8-byte WTF::StringBuilder boundary.
/// The consumer owns these bytes. Keeping the UTF-16 buffer pointer, length,
/// and tagged capacity inline makes construction allocation-free just like the
/// C++ object. The upper half of `metadata` rejects stale/uninitialized bytes;
/// the low 31 bits hold capacity and bit 31 records sticky overflow.
const PrivateStringBuilder = extern struct {
    units: ?[*]u16 = null,
    length: usize = 0,
    metadata: usize = 0,
};

/// The pinned Home/Bun `SystemError` by-value layout. `errno` leads, the six
/// 24-byte BunString fields follow in declaration order, and `fd` sits between
/// `hostname` and `dest`; `fd == minInt(c_int)` records "no file descriptor".
/// Both `SystemError__*` bridges consume a borrowed pointer without touching
/// field ownership: the consumer refs/derefs the BunStrings itself.
const PrivateSystemError = extern struct {
    errno: c_int = 0,
    code: PrivateBunString = PrivateBunString.empty(),
    message: PrivateBunString,
    path: PrivateBunString = PrivateBunString.empty(),
    syscall: PrivateBunString = PrivateBunString.empty(),
    hostname: PrivateBunString = PrivateBunString.empty(),
    fd: c_int = std.math.minInt(c_int),
    dest: PrivateBunString = PrivateBunString.empty(),
};

const PrivateJSStringIterator = extern struct {
    data: ?*anyopaque,
    stop: u8,
    append8: ?*const fn (*PrivateJSStringIterator, [*]const u8, u32) callconv(.c) void,
    append16: ?*const fn (*PrivateJSStringIterator, [*]const u16, u32) callconv(.c) void,
    write8: ?*const fn (*PrivateJSStringIterator, [*]const u8, u32, u32) callconv(.c) void,
    write16: ?*const fn (*PrivateJSStringIterator, [*]const u16, u32, u32) callconv(.c) void,
};

/// JSC host functions receive a pointer to the first register of the pinned
/// CallFrame layout and return one JSC64 EncodedJSValue word. Home declares the
/// function type itself and passes `*const JSHostFn`; spelling it this way keeps
/// the pointer ABI identical while letting us reject a null implementation at
/// the external boundary.
const PrivateJSHostFn = fn (JSContextRef, *PrivateCallFrame) callconv(.c) EncodedValue;
const PrivateCallFrame = opaque {};

const PrivateZigStackFrameCode = enum(u8) {
    none = 0,
    eval = 1,
    module = 2,
    function = 3,
    global = 4,
    wasm = 5,
    constructor = 6,
    _,
};

const PrivateZigStackFramePosition = extern struct {
    line: c_int,
    column: c_int,
    line_start_byte: c_int,
};

const PrivateZigStackFrame = extern struct {
    function_name: PrivateBunString,
    source_url: PrivateBunString,
    position: PrivateZigStackFramePosition,
    code_type: PrivateZigStackFrameCode,
    is_async: bool,
    remapped: bool = false,
    jsc_stack_frame_index: i32 = -1,
};

const PrivateZigStackTrace = extern struct {
    source_lines_ptr: [*c]PrivateBunString,
    source_lines_numbers: [*c]i32,
    source_lines_len: u8,
    source_lines_to_collect: u8,
    frames_ptr: [*c]PrivateZigStackFrame,
    frames_len: u8,
    frames_cap: u8,
    referenced_source_provider: ?*anyopaque = null,
};

const PrivateJSErrorCode = enum(u8) {
    error_ = 0,
    eval_error = 1,
    range_error = 2,
    reference_error = 3,
    syntax_error = 4,
    type_error = 5,
    uri_error = 6,
    aggregate_error = 7,
    out_of_memory_error = 8,
    bundler_error = 252,
    stack_overflow = 253,
    user_error = 254,
    _,
};

const PrivateJSRuntimeType = enum(u16) {
    nothing = 0x0,
    function = 0x1,
    undefined = 0x2,
    null = 0x4,
    boolean = 0x8,
    any_int = 0x10,
    number = 0x20,
    string = 0x40,
    object = 0x80,
    symbol = 0x100,
    bigint = 0x200,
    _,
};

/// Exact current Home/Bun by-value exception record. `browser_url` was added
/// after WebKit's handwritten C header and is part of both pinned Zig consumers.
const PrivateZigException = extern struct {
    type: PrivateJSErrorCode = .user_error,
    runtime_type: PrivateJSRuntimeType = .nothing,
    errno: c_int = 0,
    syscall: PrivateBunString = .empty(),
    system_code: PrivateBunString = .empty(),
    path: PrivateBunString = .empty(),
    name: PrivateBunString = .empty(),
    message: PrivateBunString = .empty(),
    stack: PrivateZigStackTrace = .{
        .source_lines_ptr = null,
        .source_lines_numbers = null,
        .source_lines_len = 0,
        .source_lines_to_collect = 0,
        .frames_ptr = null,
        .frames_len = 0,
        .frames_cap = 0,
    },
    exception: ?*anyopaque = null,
    remapped: bool = false,
    fd: i32 = -1,
    browser_url: PrivateBunString = .empty(),
};

const PrivateImplementationVisibility = enum(u8) {
    public = 0,
    private = 1,
    private_recursive = 2,
    _,
};

const PrivateIntrinsic = enum(u8) {
    none = 0,
    _,
};

const PrivateHostFunctionRecord = struct {
    const Kind = enum { zig_host, ffi };

    context: *Context,
    implementation: *const PrivateJSHostFn,
    constructor: ?*const PrivateJSHostFn,
    name: []const u8,
    implementation_visibility: PrivateImplementationVisibility,
    intrinsic: PrivateIntrinsic,
    kind: Kind = .zig_host,
    data_ptr: std.atomic.Value(?*anyopaque) = .init(null),
    symbol_from_dynamic_library: ?*anyopaque = null,
};

const PrivateActiveCallFrame = struct {
    frame: *const PrivateCallFrame,
    context: *Context,
    caller_location: ?interp.DebugStatementLocation,
    caller_function_name: []const u8,
};

threadlocal var private_active_call_frame: ?*const PrivateActiveCallFrame = null;
threadlocal var private_call_frame_description: [512]u8 = @splat(0);

const private_string_builder_magic: usize = 0x5a4a_5342_0000_0000; // "ZJSB"
const private_string_builder_overflow: usize = 0x8000_0000;
const private_string_builder_capacity_mask: usize = 0x7fff_ffff;
const private_string_builder_max_length: usize = std.math.maxInt(i32);

const PrivateRegularExpression = struct {
    magic: u64 = private_regular_expression_magic,
    compiled: ?regex_mod.Regex = null,
    last_match_length: i32 = -1,
    sticky: bool = false,
};

const private_regular_expression_magic: u64 = 0x5a4a_5352_4547_4558; // "ZJSREGEX"

/// Prefix-compatible with WTF::StringImpl's pinned 64-bit data layout. The
/// trailing fields are private allocator metadata and are never exposed to the
/// consumer. BigInt decimal output is ASCII, so every instance is an 8-bit
/// StringImpl and `m_length` is also the owned byte allocation length.
const PrivateWTFStringImpl = extern struct {
    m_ref_count: u32,
    m_length: u32,
    m_ptr: [*]const u8,
    m_hash_and_flags: u32,
    private_magic: u32,
};

const private_wtf_ref_increment: u32 = 2;
const private_wtf_flag_8_bit_buffer: u32 = 1 << 2;
const private_wtf_magic: u32 = 0x5a4a_5354; // "ZJST"

comptime {
    if (@sizeOf(PrivateZigString) != 16 or @alignOf(PrivateZigString) != 8)
        @compileError("private ZigString must retain its pinned 16-byte/8-byte ABI");
    if (@sizeOf(PrivateBunString) != 24 or @alignOf(PrivateBunString) != 8 or
        @offsetOf(PrivateBunString, "value") != 8)
        @compileError("private BunString must retain its pinned 24-byte/8-byte ABI");
    if (@sizeOf(PrivateSerializedScriptExternal) != 24 or
        @alignOf(PrivateSerializedScriptExternal) != 8 or
        @offsetOf(PrivateSerializedScriptExternal, "size") != 8 or
        @offsetOf(PrivateSerializedScriptExternal, "handle") != 16)
        @compileError("private serialized-script slice must retain its pinned 24-byte/8-byte ABI");
    if (@sizeOf(PrivateSystemError) != 160 or @alignOf(PrivateSystemError) != 8 or
        @offsetOf(PrivateSystemError, "code") != 8 or @offsetOf(PrivateSystemError, "message") != 32 or
        @offsetOf(PrivateSystemError, "path") != 56 or @offsetOf(PrivateSystemError, "syscall") != 80 or
        @offsetOf(PrivateSystemError, "hostname") != 104 or @offsetOf(PrivateSystemError, "fd") != 128 or
        @offsetOf(PrivateSystemError, "dest") != 136)
        @compileError("private SystemError layout drifted from the pinned ABI");
    if (@sizeOf(PrivateStringBuilder) != 24 or @alignOf(PrivateStringBuilder) != 8)
        @compileError("private StringBuilder must retain its pinned 24-byte/8-byte ABI");
    if (@sizeOf(PrivateJSStringIterator) != 48 or @alignOf(PrivateJSStringIterator) != 8 or
        @offsetOf(PrivateJSStringIterator, "stop") != 8 or @offsetOf(PrivateJSStringIterator, "append8") != 16)
        @compileError("private JSString iterator layout drifted from the pinned ABI");
    if (@sizeOf(*const PrivateJSHostFn) != 8 or @alignOf(*const PrivateJSHostFn) != 8)
        @compileError("private JSHostFn pointer must retain the pinned 64-bit ABI");
    if (@sizeOf(PrivateZigStackFramePosition) != 12 or @alignOf(PrivateZigStackFramePosition) != 4 or
        @sizeOf(PrivateZigStackFrame) != 72 or @alignOf(PrivateZigStackFrame) != 8 or
        @offsetOf(PrivateZigStackFrame, "source_url") != 24 or
        @offsetOf(PrivateZigStackFrame, "position") != 48 or
        @offsetOf(PrivateZigStackFrame, "jsc_stack_frame_index") != 64)
        @compileError("private ZigStackFrame layout drifted from the pinned ABI");
    if (@sizeOf(PrivateZigStackTrace) != 48 or @alignOf(PrivateZigStackTrace) != 8 or
        @offsetOf(PrivateZigStackTrace, "frames_ptr") != 24 or
        @offsetOf(PrivateZigStackTrace, "referenced_source_provider") != 40)
        @compileError("private ZigStackTrace layout drifted from the pinned ABI");
    if (@sizeOf(PrivateZigException) != 216 or @alignOf(PrivateZigException) != 8 or
        @offsetOf(PrivateZigException, "errno") != 4 or
        @offsetOf(PrivateZigException, "syscall") != 8 or
        @offsetOf(PrivateZigException, "stack") != 128 or
        @offsetOf(PrivateZigException, "exception") != 176 or
        @offsetOf(PrivateZigException, "fd") != 188 or
        @offsetOf(PrivateZigException, "browser_url") != 192)
        @compileError("private ZigException layout drifted from the pinned Home/Bun ABI");
    if (@offsetOf(PrivateWTFStringImpl, "m_ref_count") != 0 or
        @offsetOf(PrivateWTFStringImpl, "m_length") != 4 or
        @offsetOf(PrivateWTFStringImpl, "m_ptr") != 8 or
        @offsetOf(PrivateWTFStringImpl, "m_hash_and_flags") != 16)
        @compileError("private WTFStringImpl prefix drifted from the pinned ABI");
}

/// Global allocator for C-API-created contexts and strings. `page_allocator`
/// needs no libc and is always available; a tuned allocator can replace it.
const gpa = std.heap.page_allocator;
const private_string_allocator = std.heap.c_allocator;
const private_remote_inspection_default = switch (builtin.os.tag) {
    .driverkit, .ios, .maccatalyst, .macos, .tvos, .visionos, .watchos => false,
    else => true,
};

const PrivateRemoteInspectorProcessState = struct {
    auto_start_enabled: std.atomic.Value(bool) = .init(true),
    started: std.atomic.Value(bool) = .init(false),
    log_to_system_console: std.atomic.Value(bool) = .init(false),
    inspection_enabled_by_default: std.atomic.Value(bool) = .init(private_remote_inspection_default),
};

var private_remote_inspector_process: PrivateRemoteInspectorProcessState = .{};
var next_private_script_execution_context_id: std.atomic.Value(u32) = .init(1);
var private_serialized_script_lock: std.atomic.Mutex = .unlocked;
var private_serialized_script_handles: std.AutoHashMapUnmanaged(usize, PrivateSerializedScriptOwned) = .empty;
var private_serialized_script_next_handle: usize = 1;

fn lockPrivateSerializedScripts() void {
    var spins: usize = 0;
    while (!private_serialized_script_lock.tryLock()) : (spins += 1) {
        if ((spins & 0xff) == 0) std.Thread.yield() catch {} else std.atomic.spinLoopHint();
    }
}

fn registerPrivateSerializedScript(owned: PrivateSerializedScriptOwned) error{OutOfMemory}!*anyopaque {
    lockPrivateSerializedScripts();
    defer private_serialized_script_lock.unlock();
    const token = private_serialized_script_next_handle;
    private_serialized_script_next_handle = std.math.add(usize, token, 1) catch
        return error.OutOfMemory;
    try private_serialized_script_handles.putNoClobber(gpa, token, owned);
    return @ptrFromInt(token);
}

fn takePrivateSerializedScript(raw: ?*anyopaque) ?PrivateSerializedScriptOwned {
    const token = @intFromPtr(raw orelse return null);
    lockPrivateSerializedScripts();
    defer private_serialized_script_lock.unlock();
    const removed = private_serialized_script_handles.fetchRemove(token) orelse return null;
    return removed.value;
}

fn privateScriptExecutionContextIdentifier(context: *Context) u32 {
    const existing = context.c_api_script_execution_context_id.load(.acquire);
    if (existing != 0) return existing;
    var current = next_private_script_execution_context_id.load(.monotonic);
    while (true) {
        if (current == 0 or current == std.math.maxInt(u32)) return 0;
        if (next_private_script_execution_context_id.cmpxchgWeak(current, current + 1, .acq_rel, .monotonic)) |observed| {
            current = observed;
            continue;
        }
        break;
    }
    if (context.c_api_script_execution_context_id.cmpxchgStrong(0, current, .release, .acquire)) |winner|
        return winner;
    return current;
}

/// Boxed interpreter value handed across the C boundary as a `JSValueRef`.
/// Handles are realm-affine: APIs that receive a `JSContextRef` reject boxes
/// created by another context instead of silently mixing arenas/object graphs.
const Boxed = struct {
    /// Keep `value` first: the GC root scanner treats a protected `*Boxed` as
    /// a `*Value` when tracing C-API handles.
    value: Value,
    owner: *Context,
    private_kind: enum(u8) { value, exception } = .value,
    exception_encoded: EncodedValue = .empty,
};

const PrivateContiguousVector = struct {
    array: *Object,
    source_address: usize,
    encoded: []EncodedValue,
};

const ReachabilityCell = struct {
    pointer: *anyopaque,
    kind: gc_mod.CellKind,
};

const ReachabilityVisitor = struct {
    allocator: std.mem.Allocator,
    seen: std.AutoHashMapUnmanaged(usize, void) = .empty,
    queue: std.ArrayListUnmanaged(ReachabilityCell) = .empty,
    objects: std.ArrayListUnmanaged(*Object) = .empty,

    fn deinit(self: *ReachabilityVisitor) void {
        self.seen.deinit(self.allocator);
        self.queue.deinit(self.allocator);
        self.objects.deinit(self.allocator);
    }

    pub fn concurrent(_: *ReachabilityVisitor) bool {
        return false;
    }
    pub fn markWeak(_: *ReachabilityVisitor, _: *?*anyopaque) void {}
    pub fn markWeakAtomic(_: *ReachabilityVisitor, _: *std.atomic.Value(?*anyopaque)) void {}
    pub fn deferToFinish(_: *ReachabilityVisitor, _: *anyopaque) void {}
    pub fn isManaged(_: *ReachabilityVisitor, cell: ?*anyopaque) bool {
        return cell != null;
    }
    pub fn markConservativeWord(_: *ReachabilityVisitor, _: usize) void {}
    pub fn markConservativeWords(_: *ReachabilityVisitor, _: [*]const usize, _: usize) void {}

    pub fn isMarked(self: *ReachabilityVisitor, cell: ?*anyopaque) bool {
        return if (cell) |pointer| self.seen.contains(@intFromPtr(pointer)) else false;
    }

    pub fn mark(self: *ReachabilityVisitor, maybe_cell: anytype) void {
        const cell = switch (@typeInfo(@TypeOf(maybe_cell))) {
            .optional => maybe_cell orelse return,
            .pointer => maybe_cell,
            else => @compileError("reachability mark expects a cell pointer"),
        };
        const Pointer = @TypeOf(cell);
        const kind: gc_mod.CellKind = if (Pointer == *Object)
            .object
        else if (Pointer == *strcell.StringCell)
            .string
        else if (Pointer == *interp.Environment)
            .environment
        else if (Pointer == *interp.Function)
            .function
        else if (Pointer == *interp.Interpreter.BoundFn)
            .bound_fn
        else if (Pointer == *promise.Promise)
            .promise
        else if (Pointer == *vm.Generator)
            .generator
        else if (Pointer == *value.IterHelper)
            .iter_helper
        else if (Pointer == *interp.ModuleNs)
            .module_ns
        else
            @compileError("unclassified reachability cell " ++ @typeName(Pointer));
        const pointer: *anyopaque = @ptrCast(cell);
        const result = self.seen.getOrPut(self.allocator, @intFromPtr(pointer)) catch return;
        if (result.found_existing) return;
        self.queue.append(self.allocator, .{ .pointer = pointer, .kind = kind }) catch return;
        if (kind == .object)
            self.objects.append(self.allocator, @ptrCast(@alignCast(pointer))) catch return;
    }

    fn drain(self: *ReachabilityVisitor) void {
        var index: usize = 0;
        while (index < self.queue.items.len) : (index += 1) {
            const cell = self.queue.items[index];
            switch (cell.kind) {
                .function => {
                    const function: *interp.Function = @ptrCast(@alignCast(cell.pointer));
                    self.mark(function.closure);
                    self.mark(function.realm_global);
                    gc_mod.traceFunction(function, self);
                },
                .environment => {
                    const environment: *interp.Environment = @ptrCast(@alignCast(cell.pointer));
                    self.mark(environment.parent);
                    var aliases = environment.aliases.valueIterator();
                    while (aliases.next()) |alias| self.mark(alias.env);
                    gc_mod.traceEnv(environment, self);
                },
                else => gc_mod.Binding.trace(cell.pointer, cell.kind, self),
            }
        }
    }

    fn finishEphemerons(self: *ReachabilityVisitor) void {
        while (true) {
            const before = self.queue.items.len;
            for (self.objects.items) |object| gc_mod.traceObjectEphemeron(object, self);
            self.drain();
            if (self.queue.items.len == before) return;
        }
    }
};

/// One public JavaScriptCore VM lifetime. The hidden primary Context owns the
/// shared arena/JIT runtime; every exposed global context is a distinct realm on
/// that runtime and retains this record until its own final release.
const CContextGroup = struct {
    ref_count: std.atomic.Value(usize) = .init(1),
    owner_thread: std.Thread.Id,
    primary: *Context,
    contexts: std.ArrayListUnmanaged(*Context) = .empty,
    /// Private EncodedJSValue boundaries expose the engine cell address, so
    /// publishing the same object twice must return the same encoded handle.
    /// Keep one canonical Boxed cell per VM-owned object across sibling realms.
    private_object_boxes: std.AutoHashMapUnmanaged(*Object, *Boxed) = .empty,
    /// Stable encoded snapshots returned by the private JSArray iterator fast
    /// path. There is no consumer release hook, so vectors live with the VM;
    /// each pointer remains independently revalidatable until group teardown.
    private_contiguous_vectors: std.AutoHashMapUnmanaged(usize, *PrivateContiguousVector) = .empty,
    /// JSC returns VM small strings for these pure diagnostic projections.
    /// Preserve that raw EncodedJSValue stability across repeated calls.
    no_side_effect_strings: [6]?*Boxed = @splat(null),
    /// VM-owned atom strings. Equal `ZigString__toAtomicValue` inputs share
    /// one immutable backing cell inside this context group, never across VMs.
    atom_strings: strcell.InternTable,
    /// JavaScriptCore's `jsTypeStringForValue` returns one of the VM's immortal
    /// small strings. Keep the eight possible private JSString handles stable
    /// across sibling realms for the same VM, without sharing them across VMs.
    typeof_strings: [8]?*Boxed = @splat(null),
    /// Stable borrowed Latin-1/UTF-16 views returned to private ABI consumers.
    /// Keys and backing buffers are group-owned so sibling realms share them.
    zig_string_views: std.StringHashMapUnmanaged(PrivateZigStringView) = .empty,
    collection_epoch: u64 = 0,
    /// JavaScriptCore stores the active exception on the VM, not the realm.
    /// Preserve a distinct cell so sibling globals observe the same identity.
    pending_exception: ?*Boxed = null,
    termination_exception: ?*Boxed = null,
    termination_requested: std.atomic.Value(bool) = .init(false),
    execution_forbidden: std.atomic.Value(bool) = .init(false),
    reported_extra_memory: std.atomic.Value(usize) = .init(0),
    async_gc_requested: std.atomic.Value(bool) = .init(false),
    /// `JSC::VM::apiLock()`: recursive mutual exclusion among the native
    /// API-lock holders of this VM — JSLock is recursive for its owner thread,
    /// so same-thread nesting must not deadlock while foreign threads block.
    api_lock: std.atomic.Mutex = .unlocked,
    api_lock_owner: std.atomic.Value(u64) = .init(0),
    api_lock_depth: usize = 0,
    /// `JSC::Watchdog` equivalent: monotonic-nanosecond execution deadline.
    /// Zero means no time limit (`Watchdog::noTimeLimit`); `watchdog_fired_ns`
    /// records the deadline the host watchdog last terminated on so a single
    /// arming fires at most once, while re-arming still fires again.
    execution_deadline_ns: std.atomic.Value(u64) = .init(0),
    watchdog_fired_ns: std.atomic.Value(u64) = .init(0),
    watchdog_stop: std.atomic.Value(bool) = .init(false),
    watchdog_thread: ?std.Thread = null,
    /// `JSC::VMTraps::NeedWatchdogCheck` trap bit: set by
    /// `JSC__VM__notifyNeedWatchdogCheck`, consumed (cleared + deadline
    /// re-check) at the running interpreter's next step checkpoint. Every
    /// context of this group points its `watchdog_check_flag` here.
    need_watchdog_check: std.atomic.Value(bool) = .init(false),

    fn retain(self: *CContextGroup) bool {
        var current = self.ref_count.load(.monotonic);
        while (true) {
            if (current == 0 or current == std.math.maxInt(usize)) return false;
            if (self.ref_count.cmpxchgWeak(current, current + 1, .monotonic, .monotonic)) |observed| {
                current = observed;
                continue;
            }
            return true;
        }
    }

    fn release(self: *CContextGroup) bool {
        var current = self.ref_count.load(.acquire);
        while (true) {
            if (current == 0) return false;
            const next = current - 1;
            if (self.ref_count.cmpxchgWeak(current, next, .acq_rel, .acquire)) |observed| {
                current = observed;
                continue;
            }
            return next == 0;
        }
    }

    fn destroy(self: *CContextGroup) void {
        // Stop and join the host watchdog before any realm state it can touch
        // (`primary.requestTermination`) is torn down; its nap bound keeps the
        // join latency below ~1ms.
        if (self.watchdog_thread) |thread| {
            self.watchdog_stop.store(true, .release);
            thread.join();
            self.watchdog_thread = null;
        }
        var index = self.contexts.items.len;
        while (index > 0) {
            index -= 1;
            self.contexts.items[index].destroySharedArenaRealm();
        }
        self.contexts.deinit(gpa);
        self.private_object_boxes.deinit(gpa);
        var vectors = self.private_contiguous_vectors.valueIterator();
        while (vectors.next()) |record| {
            gpa.free(record.*.encoded);
            gpa.destroy(record.*);
        }
        self.private_contiguous_vectors.deinit(gpa);
        self.primary.c_api_group = null;
        self.primary.destroy();
        self.atom_strings.deinit();
        var views = self.zig_string_views.iterator();
        while (views.next()) |entry| {
            gpa.free(entry.key_ptr.*);
            switch (entry.value_ptr.storage) {
                .latin1 => |bytes| gpa.free(bytes),
                .utf16 => |units| gpa.free(units),
            }
        }
        self.zig_string_views.deinit(gpa);
        gpa.destroy(self);
    }
};

/// Bun's `Strong.Impl` reads the first machine word directly as an
/// EncodedJSValue, so keep the encoded slot at offset zero. The paired internal
/// value is what zig-js traces; cell encodings point at arena-stable `Boxed`
/// handles and therefore remain valid until the VM dies.
const PrivateStrongRef = struct {
    encoded: EncodedValue,
    root: Context.PrivateStrongRoot,
    group: *CContextGroup,
    alive: bool = true,
};

const PrivateWeakRefType = enum(u32) {
    none = 0,
    fetch_response = 1,
    postgresql_query_client = 2,
    _,
};

const PrivateWeakRef = struct {
    root: Context.PrivateWeakRoot,
    group: *CContextGroup,
    ref_type: PrivateWeakRefType,
    callback_context: ?*anyopaque,
    alive: bool = true,
};

const PrivateAbortListener = struct {
    context: ?*anyopaque,
    callback: *const fn (?*anyopaque, EncodedValue) callconv(.c) void,
};

/// One native wrapper per genuine JavaScript AbortSignal. The JS object owns
/// this record through a deferred C-API owner finalizer; native refs and
/// pending activity add one precise root only while they are non-zero.
const PrivateAbortSignal = struct {
    native: *value.AbortSignalNativeState,
    context: *Context,
    group: *CContextGroup,
    object: *Object,
    root: Context.PrivateStrongRoot,
    listeners: std.ArrayListUnmanaged(PrivateAbortListener) = .empty,
    external_refs: u32 = 0,
    pending_activity: u32 = 0,
    operation_depth: u32 = 0,
    common_reason: PrivateCommonAbortReason = .none,
    rooted: bool = false,
    alive: bool = true,
};

const PrivateMarkedArgumentBuffer = struct {
    magic: u64 = private_marked_argument_buffer_magic,
    values: std.ArrayListUnmanaged(EncodedValue) = .empty,
    roots: std.ArrayListUnmanaged(*Context.PrivateStrongRoot) = .empty,
    group: ?*CContextGroup = null,
};

/// Native owner for the pinned Home/Bun `JSPropertyIterator` boundary. JSC's
/// iterator owns a `PropertyNameArray` and a strong VM reference; mirror both:
/// keys are copied out of the evaluation arena, while borrowed BunString views
/// live in (and therefore share the lifetime of) the retained context group.
const PrivateJSPropertyIteratorEntry = struct {
    key: []u8,
    name: PrivateBunString,
    utf16_length: usize,
};

const PrivateJSPropertyIterator = struct {
    magic: u64 = private_js_property_iterator_magic,
    group: *CContextGroup,
    entries: []PrivateJSPropertyIteratorEntry,
};

const private_js_property_iterator_magic: u64 = 0x5a4a_5350_524f_5049; // "ZJSPROPI"

const private_marked_argument_buffer_magic: u64 = 0x5a4a_534d_4142_5546; // "ZJSMABUF"
const PrivateMarkedArgumentCallback = *const fn (?*anyopaque, ?*anyopaque) callconv(.c) void;

fn privateDefaultFetchResponseFinalize(_: ?*anyopaque) callconv(.c) void {}

comptime {
    @export(&privateDefaultFetchResponseFinalize, .{
        .name = "Bun__FetchResponse_finalize",
        .linkage = .weak,
    });
}

extern fn Bun__FetchResponse_finalize(?*anyopaque) callconv(.c) void;

comptime {
    if (@offsetOf(PrivateStrongRef, "encoded") != 0 or @sizeOf(EncodedValue) != @sizeOf(i64))
        @compileError("private StrongRef must expose one EncodedJSValue at offset zero");
}

