const CClass = struct {
    ref_count: std.atomic.Value(usize) = .init(1),
    definition: JSClassDefinition,
    class_name: ?[:0]u8 = null,
    static_values: []JSStaticValue = &.{},
    static_functions: []JSStaticFunction = &.{},
    parent: ?*CClass = null,
};

const PropertyNameAccumulator = struct {
    names: std.ArrayListUnmanaged(*JsString) = .empty,
    seen: std.StringHashMapUnmanaged(void) = .empty,
    failed: bool = false,

    fn addBytes(self: *PropertyNameAccumulator, bytes: []const u8) void {
        if (self.failed or self.seen.contains(bytes)) return;
        const string = JsString.create(gpa, bytes) catch {
            self.failed = true;
            return;
        };
        self.seen.put(gpa, string.bytes, {}) catch {
            string.release();
            self.failed = true;
            return;
        };
        self.names.append(gpa, string) catch {
            _ = self.seen.remove(string.bytes);
            string.release();
            self.failed = true;
        };
    }

    fn deinit(self: *PropertyNameAccumulator) void {
        for (self.names.items) |name| name.release();
        self.names.deinit(gpa);
        self.seen.deinit(gpa);
        self.* = .{};
    }
};

const PropertyNameArray = struct {
    ref_count: std.atomic.Value(usize) = .init(1),
    names: []*JsString,
};

fn propertyNameArrayFrom(ref: JSPropertyNameArrayRef) ?*PropertyNameArray {
    return @ptrCast(@alignCast(ref orelse return null));
}

fn destroyPropertyNameArray(array: *PropertyNameArray) void {
    for (array.names) |name| name.release();
    gpa.free(array.names);
    gpa.destroy(array);
}

fn classFrom(ref: JSClassRef) ?*CClass {
    return @ptrCast(@alignCast(ref orelse return null));
}

fn retainClass(class: *CClass) bool {
    var current = class.ref_count.load(.acquire);
    while (true) {
        if (current == std.math.maxInt(usize)) return false;
        if (class.ref_count.cmpxchgWeak(current, current + 1, .acq_rel, .acquire)) |actual| {
            current = actual;
        } else return true;
    }
}

fn destroyClass(class: *CClass) void {
    for (class.static_values) |entry| if (entry.name) |name| gpa.free(std.mem.span(name));
    for (class.static_functions) |entry| if (entry.name) |name| gpa.free(std.mem.span(name));
    if (class.static_values.len > 0) gpa.free(class.static_values);
    if (class.static_functions.len > 0) gpa.free(class.static_functions);
    if (class.class_name) |name| gpa.free(name);
    if (class.parent) |parent| releaseClass(parent);
    gpa.destroy(class);
}

fn releaseClass(class: *CClass) void {
    var current = class.ref_count.load(.acquire);
    while (true) {
        std.debug.assert(current > 0);
        if (class.ref_count.cmpxchgWeak(current, current - 1, .acq_rel, .acquire)) |actual| {
            current = actual;
        } else {
            if (current == 1) destroyClass(class);
            return;
        }
    }
}

fn dupeCString(bytes: []const u8) ![:0]u8 {
    const out = try gpa.allocSentinel(u8, bytes.len, 0);
    @memcpy(out, bytes);
    return out;
}

fn copyStaticValues(source: [*c]const JSStaticValue) ![]JSStaticValue {
    if (source == null) return &.{};
    var count: usize = 0;
    while (source[count].name != null) : (count += 1) {}
    if (count == 0) return &.{};
    const out = try gpa.alloc(JSStaticValue, count + 1);
    errdefer gpa.free(out);
    var copied: usize = 0;
    errdefer for (out[0..copied]) |entry| if (entry.name) |name| gpa.free(std.mem.span(name));
    while (copied < count) : (copied += 1) {
        out[copied] = source[copied];
        const owned = try dupeCString(std.mem.span(source[copied].name.?));
        out[copied].name = owned.ptr;
    }
    out[count] = .{};
    return out;
}

fn copyStaticFunctions(source: [*c]const JSStaticFunction) ![]JSStaticFunction {
    if (source == null) return &.{};
    var count: usize = 0;
    while (source[count].name != null) : (count += 1) {}
    if (count == 0) return &.{};
    const out = try gpa.alloc(JSStaticFunction, count + 1);
    errdefer gpa.free(out);
    var copied: usize = 0;
    errdefer for (out[0..copied]) |entry| if (entry.name) |name| gpa.free(std.mem.span(name));
    while (copied < count) : (copied += 1) {
        out[copied] = source[copied];
        const owned = try dupeCString(std.mem.span(source[copied].name.?));
        out[copied].name = owned.ptr;
    }
    out[count] = .{};
    return out;
}

fn finishClassObject(owner: *value.CApiObjectOwner) void {
    const class = classFrom(owner.class_ref).?;
    if (owner.object_ref) |object_ref| {
        var current: ?*CClass = class;
        while (current) |item| : (current = item.parent) {
            if (item.definition.finalize) |finalize| finalize(object_ref);
        }
    }
    releaseClass(class);
}

fn initializeClassObject(ctx: JSContextRef, object_ref: JSObjectRef, class: *CClass) void {
    if (class.parent) |parent| initializeClassObject(ctx, object_ref, parent);
    if (class.definition.initialize) |initialize| initialize(ctx, object_ref);
}

fn attachClassToExistingObject(ctx: JSContextRef, c: *Context, obj: *Object, class: *CClass, data: ?*anyopaque) bool {
    const gc_saved = gc_mod.setActiveHeap(c.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(c.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = c.interpreter();
    c.pushActiveInterpreter(&machine) catch return false;
    defer c.popActiveInterpreter(&machine);

    if ((class.definition.attributes & kJSClassAttributeNoAutomaticPrototype) != 0) {
        installStaticFunctionChain(c, &machine, obj, class) catch return false;
    } else {
        const prototype = ensureClassPrototype(c, &machine, class) catch return false;
        obj.setProtoAtomic(prototype);
    }
    if (!retainClass(class)) return false;
    const owner = c.createCApiObjectOwner(@ptrCast(class), finishClassObject) catch {
        releaseClass(class);
        return false;
    };
    obj.private_data = data;
    obj.private_data_tag = .host;
    obj.setCApiObjectClass(c.arena(), owner, &c_api_class_hooks) catch {
        owner.finishOnce();
        return false;
    };
    const object_ref = box(c, Value.obj(obj)) orelse {
        owner.finishOnce();
        return false;
    };
    owner.object_ref = object_ref;
    const protected = valueProtect(ctx, object_ref);
    defer {
        if (protected) _ = valueUnprotect(ctx, object_ref);
    }
    initializeClassObject(ctx, object_ref, class);
    return true;
}

fn finishClassPrototype(owner: *value.CApiClassPrototypeOwner) void {
    releaseClass(classFrom(owner.class_ref).?);
}

const CApiConstructorData = struct {
    context: *Context,
    class: ?*CClass,
    callback: JSObjectCallAsConstructorCallback,
    constructor_ref: JSObjectRef = null,
};

fn finishCApiConstructor(owner: *value.CApiObjectOwner) void {
    const data: *CApiConstructorData = @ptrCast(@alignCast(owner.payload.?));
    if (data.class) |class| releaseClass(class);
}

fn cApiConstructorData(object: *const Object) ?*CApiConstructorData {
    const owner = object.cApiObjectOwner() orelse return null;
    return @ptrCast(@alignCast(owner.payload orelse return null));
}

fn cApiConstructorIsConstructor(object: *const Object) bool {
    return cApiConstructorData(object) != null;
}

fn cApiConstructorConstruct(
    raw_machine: *anyopaque,
    object: *Object,
    args: []const Value,
) value.HostError!Value {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const data = cApiConstructorData(object) orelse {
        machine.exception = Value.str("TypeError: constructor metadata is missing");
        return error.Throw;
    };
    if (data.callback) |callback| {
        const js_args = try machine.arena.alloc(JSValueRef, args.len);
        for (args, js_args) |arg, *slot| slot.* = box(data.context, arg) orelse return error.OutOfMemory;
        var exception: JSValueRef = null;
        const result = callback(
            @ptrCast(data.context),
            data.constructor_ref,
            js_args.len,
            js_args.ptr,
            &exception,
        );
        try applyCallbackException(machine, data.context, exception);
        const result_ref = result orelse {
            machine.exception = Value.str("TypeError: constructor callback returned null without exception");
            return error.Throw;
        };
        const result_value = valueFromContext(data.context, result_ref) orelse {
            machine.exception = Value.str("TypeError: constructor callback returned an invalid object");
            return error.Throw;
        };
        if (!result_value.isObject() or result_value.asObj().is_symbol or result_value.asObj().is_bigint) {
            machine.exception = Value.str("TypeError: constructor callback returned a non-object");
            return error.Throw;
        }
        return result_value;
    }
    const class_ref: JSClassRef = if (data.class) |class| @ptrCast(class) else null;
    const result_ref = JSObjectMake(@ptrCast(data.context), class_ref, null) orelse {
        machine.exception = Value.str("OutOfMemory");
        return error.OutOfMemory;
    };
    return valueFromContext(data.context, result_ref).?;
}

const c_api_constructor_hooks: value.HostClassHooks = .{
    .is_constructor = cApiConstructorIsConstructor,
    .construct = cApiConstructorConstruct,
};

const ClassCallbackTarget = struct {
    context: *Context,
    object_ref: JSObjectRef,
    class: *CClass,
};

fn classCallbackTarget(machine: *interp.Interpreter, object: *Object) value.HostError!ClassCallbackTarget {
    const owner = object.cApiObjectOwner() orelse {
        machine.exception = Value.str("TypeError: class callback missing instance owner");
        return error.Throw;
    };
    const object_ref = owner.object_ref orelse {
        machine.exception = Value.str("TypeError: class callback missing object handle");
        return error.Throw;
    };
    const boxed = boxedFrom(object_ref) orelse {
        machine.exception = Value.str("TypeError: class callback has invalid object handle");
        return error.Throw;
    };
    return .{
        .context = boxed.owner,
        .object_ref = object_ref,
        .class = classFrom(owner.class_ref).?,
    };
}

fn callbackPropertyName(key: []const u8) value.HostError!JSStringRef {
    const string = JsString.create(gpa, key) catch return error.OutOfMemory;
    return @ptrCast(string);
}

fn applyCallbackException(
    machine: *interp.Interpreter,
    context: *Context,
    exception: JSValueRef,
) value.HostError!void {
    if (exception == null) return;
    machine.exception = valueFromContext(context, exception) orelse
        Value.str("TypeError: class callback set an invalid exception");
    return error.Throw;
}

fn callHasPropertyCallback(
    target: ClassCallbackTarget,
    key: []const u8,
    callback: *const fn (JSContextRef, JSObjectRef, JSStringRef) callconv(.c) bool,
) value.HostError!bool {
    const property_name = try callbackPropertyName(key);
    defer JSStringRelease(property_name);
    return callback(@ptrCast(target.context), target.object_ref, property_name);
}

fn callGetPropertyCallback(
    machine: *interp.Interpreter,
    target: ClassCallbackTarget,
    key: []const u8,
    callback: *const fn (JSContextRef, JSObjectRef, JSStringRef, ExceptionRef) callconv(.c) JSValueRef,
) value.HostError!?Value {
    const property_name = try callbackPropertyName(key);
    defer JSStringRelease(property_name);
    var exception: JSValueRef = null;
    const result = callback(@ptrCast(target.context), target.object_ref, property_name, &exception);
    try applyCallbackException(machine, target.context, exception);
    const result_ref = result orelse return null;
    return valueFromContext(target.context, result_ref) orelse {
        machine.exception = Value.str("TypeError: class getter returned an invalid value");
        return error.Throw;
    };
}

fn callSetPropertyCallback(
    machine: *interp.Interpreter,
    target: ClassCallbackTarget,
    key: []const u8,
    new_value: Value,
    callback: *const fn (JSContextRef, JSObjectRef, JSStringRef, JSValueRef, ExceptionRef) callconv(.c) bool,
) value.HostError!bool {
    const property_name = try callbackPropertyName(key);
    defer JSStringRelease(property_name);
    var exception: JSValueRef = null;
    const value_ref = box(target.context, new_value) orelse return error.OutOfMemory;
    const handled = callback(
        @ptrCast(target.context),
        target.object_ref,
        property_name,
        value_ref,
        &exception,
    );
    try applyCallbackException(machine, target.context, exception);
    return handled;
}

fn classGet(
    raw_machine: *anyopaque,
    object: *Object,
    key: []const u8,
) value.HostError!value.HostClassGetResult {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        if (item.definition.has_property) |has| {
            if (try callHasPropertyCallback(target, key, has)) {
                if (item.definition.get_property) |get| {
                    if (try callGetPropertyCallback(machine, target, key, get)) |result|
                        return .{ .value = result };
                }
            }
        } else if (item.definition.get_property) |get| {
            if (try callGetPropertyCallback(machine, target, key, get)) |result|
                return .{ .value = result };
        }
        for (item.static_values) |entry| {
            const name = entry.name orelse continue;
            if (!std.mem.eql(u8, std.mem.span(name), key)) continue;
            const getter = entry.get_property orelse return .unhandled;
            if (try callGetPropertyCallback(machine, target, key, getter)) |result|
                return .{ .value = result };
        }
    }
    return .unhandled;
}

fn classSet(
    raw_machine: *anyopaque,
    object: *Object,
    key: []const u8,
    new_value: Value,
) value.HostError!value.HostClassSetResult {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        var has_static_value = false;
        for (item.static_values) |entry| {
            const name = entry.name orelse continue;
            if (std.mem.eql(u8, std.mem.span(name), key)) {
                has_static_value = true;
                break;
            }
        }
        if (!has_static_value) {
            if (item.definition.has_property) |has|
                _ = try callHasPropertyCallback(target, key, has);
        }
        if (item.definition.set_property) |set| {
            if (try callSetPropertyCallback(machine, target, key, new_value, set))
                return .{ .accepted = true };
        }
        for (item.static_values) |entry| {
            const name = entry.name orelse continue;
            if (!std.mem.eql(u8, std.mem.span(name), key)) continue;
            const setter = entry.set_property orelse return if ((entry.attributes & kJSPropertyAttributeReadOnly) != 0)
                .{ .accepted = false }
            else
                .unhandled;
            const handled = try callSetPropertyCallback(machine, target, key, new_value, setter);
            return if (handled) .{ .accepted = true } else .declined;
        }
    }
    return .unhandled;
}

fn classHas(
    raw_machine: *anyopaque,
    object: *Object,
    key: []const u8,
) value.HostError!bool {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        if (item.definition.has_property) |has| {
            if (try callHasPropertyCallback(target, key, has)) return true;
        } else if (item.definition.get_property) |get| {
            if (try callGetPropertyCallback(machine, target, key, get) != null) return true;
        }
        for (item.static_values) |entry| {
            const name = entry.name orelse continue;
            if (!std.mem.eql(u8, std.mem.span(name), key)) continue;
            const getter = entry.get_property orelse continue;
            if (try callGetPropertyCallback(machine, target, key, getter) != null) return true;
        }
    }
    return false;
}

fn classDelete(
    raw_machine: *anyopaque,
    object: *Object,
    key: []const u8,
) value.HostError!value.HostClassDeleteResult {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        if (item.definition.delete_property) |callback| {
            const property_name = try callbackPropertyName(key);
            defer JSStringRelease(property_name);
            var exception: JSValueRef = null;
            const handled = callback(
                @ptrCast(target.context),
                target.object_ref,
                property_name,
                &exception,
            );
            try applyCallbackException(machine, target.context, exception);
            if (handled) return .{ .accepted = true };
        }
        for (item.static_values) |entry| {
            const name = entry.name orelse continue;
            if (!std.mem.eql(u8, std.mem.span(name), key)) continue;
            return .{ .accepted = (entry.attributes & kJSPropertyAttributeDontDelete) == 0 };
        }
    }
    return .unhandled;
}

fn staticValueAttributes(
    raw_machine: *anyopaque,
    object: *Object,
    key: []const u8,
) value.HostError!?value.PropAttr {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    var has_name_callback = false;
    while (class) |item| : (class = item.parent) {
        has_name_callback = has_name_callback or item.definition.get_property_names != null;
        for (item.static_values) |entry| {
            const name = entry.name orelse continue;
            if (std.mem.eql(u8, std.mem.span(name), key)) return propAttrFromC(entry.attributes);
        }
    }
    if (has_name_callback) return .{ .writable = false, .enumerable = true, .configurable = true };
    return null;
}

fn classOwnKeys(
    raw_machine: *anyopaque,
    object: *Object,
) value.HostError![]const []const u8 {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var accumulator: PropertyNameAccumulator = .{};
    defer accumulator.deinit();
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        if (item.definition.get_property_names) |callback| {
            callback(@ptrCast(target.context), target.object_ref, @ptrCast(&accumulator));
            if (accumulator.failed) return error.OutOfMemory;
        }
        for (item.static_values) |entry| {
            const name_ptr = entry.name orelse continue;
            accumulator.addBytes(std.mem.span(name_ptr));
            if (accumulator.failed) return error.OutOfMemory;
        }
    }
    const result = try machine.arena.alloc([]const u8, accumulator.names.items.len);
    for (accumulator.names.items, result) |name, *slot|
        slot.* = try machine.arena.dupe(u8, name.bytes);
    return result;
}

fn classForObject(object: *const Object) ?*CClass {
    const owner = object.cApiObjectOwner() orelse return null;
    return classFrom(owner.class_ref);
}

fn classIsCallable(object: *const Object) bool {
    var class: ?*CClass = classForObject(object);
    while (class) |item| : (class = item.parent)
        if (item.definition.call_as_function != null) return true;
    return false;
}

fn classIsConstructor(object: *const Object) bool {
    var class: ?*CClass = classForObject(object);
    while (class) |item| : (class = item.parent)
        if (item.definition.call_as_constructor != null) return true;
    return false;
}

fn classCall(
    raw_machine: *anyopaque,
    object: *Object,
    this_value: Value,
    args: []const Value,
) value.HostError!Value {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        const callback = item.definition.call_as_function orelse continue;
        const js_args = try machine.arena.alloc(JSValueRef, args.len);
        for (args, js_args) |arg, *slot| slot.* = box(target.context, arg) orelse return error.OutOfMemory;
        const this_ref = if (this_value.isObject() and !this_value.asObj().is_symbol and !this_value.asObj().is_bigint)
            box(target.context, this_value)
        else
            box(target.context, Value.obj(target.context.global_object));
        if (this_ref == null) return error.OutOfMemory;
        var exception: JSValueRef = null;
        const result = callback(
            @ptrCast(target.context),
            target.object_ref,
            this_ref,
            js_args.len,
            js_args.ptr,
            &exception,
        );
        try applyCallbackException(machine, target.context, exception);
        const result_ref = result orelse {
            machine.exception = Value.str("TypeError: class call callback returned null without exception");
            return error.Throw;
        };
        return valueFromContext(target.context, result_ref) orelse {
            machine.exception = Value.str("TypeError: class call callback returned an invalid value");
            return error.Throw;
        };
    }
    machine.exception = Value.str("TypeError: class object is not callable");
    return error.Throw;
}

fn classConstruct(
    raw_machine: *anyopaque,
    object: *Object,
    args: []const Value,
) value.HostError!Value {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        const callback = item.definition.call_as_constructor orelse continue;
        const js_args = try machine.arena.alloc(JSValueRef, args.len);
        for (args, js_args) |arg, *slot| slot.* = box(target.context, arg) orelse return error.OutOfMemory;
        var exception: JSValueRef = null;
        const result = callback(
            @ptrCast(target.context),
            target.object_ref,
            js_args.len,
            js_args.ptr,
            &exception,
        );
        try applyCallbackException(machine, target.context, exception);
        const result_ref = result orelse {
            machine.exception = Value.str("TypeError: class constructor callback returned null without exception");
            return error.Throw;
        };
        const result_value = valueFromContext(target.context, result_ref) orelse {
            machine.exception = Value.str("TypeError: class constructor callback returned an invalid object");
            return error.Throw;
        };
        if (!result_value.isObject() or result_value.asObj().is_symbol or result_value.asObj().is_bigint) {
            machine.exception = Value.str("TypeError: class constructor callback returned a non-object");
            return error.Throw;
        }
        return result_value;
    }
    machine.exception = Value.str("TypeError: class object is not a constructor");
    return error.Throw;
}

fn classHasInstance(
    raw_machine: *anyopaque,
    object: *Object,
    candidate: Value,
) value.HostError!bool {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        const callback = item.definition.has_instance orelse continue;
        var exception: JSValueRef = null;
        const candidate_ref = box(target.context, candidate) orelse return error.OutOfMemory;
        const result = callback(
            @ptrCast(target.context),
            target.object_ref,
            candidate_ref,
            &exception,
        );
        try applyCallbackException(machine, target.context, exception);
        return result;
    }
    return false;
}

fn classConvert(
    raw_machine: *anyopaque,
    object: *Object,
    hint: value.HostClassConvertHint,
) value.HostError!Value {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(raw_machine));
    const target = try classCallbackTarget(machine, object);
    var class: ?*CClass = target.class;
    while (class) |item| : (class = item.parent) {
        const callback = item.definition.convert_to_type orelse continue;
        var exception: JSValueRef = null;
        const result = callback(
            @ptrCast(target.context),
            target.object_ref,
            if (hint == .string) .string else .number,
            &exception,
        );
        try applyCallbackException(machine, target.context, exception);
        const result_ref = result orelse {
            machine.exception = Value.str("TypeError: class conversion callback returned null without exception");
            return error.Throw;
        };
        return valueFromContext(target.context, result_ref) orelse {
            machine.exception = Value.str("TypeError: class conversion callback returned an invalid value");
            return error.Throw;
        };
    }
    machine.exception = Value.str("TypeError: class object has no conversion callback");
    return error.Throw;
}

const c_api_class_hooks: value.HostClassHooks = .{
    .get = classGet,
    .set = classSet,
    .has = classHas,
    .delete = classDelete,
    .attributes = staticValueAttributes,
    .own_keys = classOwnKeys,
    .is_callable = classIsCallable,
    .is_constructor = classIsConstructor,
    .call = classCall,
    .construct = classConstruct,
    .has_instance = classHasInstance,
    .convert = classConvert,
};

// ---- internal helpers --------------------------------------------------

fn ctxRawFrom(ref: JSContextRef) ?*Context {
    return @ptrCast(@alignCast(ref orelse return null));
}

fn ctxFrom(ref: JSContextRef) ?*Context {
    const c = ctxRawFrom(ref) orelse return null;
    if (c.c_api_group != null and c.c_api_ref_count.load(.acquire) == 0) return null;
    // Single funnel for every C-API entry point: enforce context thread
    // affinity in debug builds (see "Threading rules" above).
    c.assertOwnerThread();
    return c;
}

fn ctxForHandleInspection(ref: JSContextRef) ?*Context {
    const c = ctxRawFrom(ref) orelse return null;
    if (c.c_api_group != null and c.c_api_ref_count.load(.acquire) == 0) return null;
    if (comptime builtin.mode == .Debug) {
        if (!c.isOwnerThread()) std.debug.panic(
            "Context is single-thread-affine: used from thread {d}, owned by thread {d} (docs/threads/bindings.md)",
            .{ std.Thread.getCurrentId(), c.owner_thread },
        );
    }
    return c;
}

fn ctxForEvaluation(ref: JSContextRef) ?*Context {
    const c = ctxRawFrom(ref) orelse return null;
    if (c.c_api_group != null and c.c_api_ref_count.load(.acquire) == 0) return null;
    if (comptime builtin.mode == .Debug) {
        // Serialized threaded contexts acquire the GIL inside
        // `Context.evaluateWithThis`, then assert that ownership there. For
        // non-threaded and true-parallel C contexts, preserve the documented
        // C-handle affinity before touching the unsynchronized host boundary.
        if (c.gil == null or c.parallel_js) {
            if (!c.isOwnerThread()) std.debug.panic(
                "Context is single-thread-affine: used from thread {d}, owned by thread {d} (docs/threads/bindings.md)",
                .{ std.Thread.getCurrentId(), c.owner_thread },
            );
        }
    }
    return c;
}

fn ctxForLifecycle(ref: JSContextRef) ?*Context {
    const c = ctxRawFrom(ref) orelse return null;
    if (c.c_api_group != null and c.c_api_ref_count.load(.acquire) == 0) return null;
    if (comptime builtin.mode == .Debug) {
        // Retain/release are host lifecycle operations, not VM execution. They
        // must preserve context thread-affinity without requiring the serialized
        // GIL to already be held.
        if (!c.isOwnerThread()) std.debug.panic(
            "Context is single-thread-affine: used from thread {d}, owned by thread {d} (docs/threads/bindings.md)",
            .{ std.Thread.getCurrentId(), c.owner_thread },
        );
    }
    return c;
}

fn box(ctx: *Context, v: Value) JSValueRef {
    const b = ctx.arena().create(Boxed) catch return null;
    b.* = .{ .value = v, .owner = ctx };
    return @ptrCast(b);
}

fn privateExceptionBox(ctx: *Context, thrown: Value, encoded: EncodedValue) ?*Boxed {
    const boxed = ctx.arena().create(Boxed) catch return null;
    boxed.* = .{
        .value = thrown,
        .owner = ctx,
        .private_kind = .exception,
        .exception_encoded = encoded,
    };
    return boxed;
}

fn boxedFrom(ref: JSValueRef) ?*Boxed {
    return @ptrCast(@alignCast(ref orelse return null));
}

fn privateBoxedFrom(encoded: EncodedValue) ?*Boxed {
    const address = encoded.asCellAddress() catch return null;
    const boxed: *Boxed = @ptrFromInt(address);
    const opaque_group = boxed.owner.c_api_group orelse return null;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (boxed.owner != group.primary and boxed.owner.c_api_ref_count.load(.acquire) == 0) return null;
    boxed.owner.assertOwnerThread();
    return boxed;
}

fn privateIsExceptionCell(encoded: EncodedValue) bool {
    const boxed = privateBoxedFrom(encoded) orelse return false;
    return boxed.private_kind == .exception;
}

fn privateEncodedFromRef(ref: JSValueRef) EncodedValue {
    const pointer = ref orelse return .empty;
    return EncodedValue.fromCellAddress(@intFromPtr(pointer)) catch .empty;
}

fn privateEncodedFromValue(context: *Context, internal: Value) EncodedValue {
    return switch (internal.kind()) {
        .undefined => .undefined,
        .null => .null,
        .boolean => if (internal.asBool()) .true else .false,
        .number => number: {
            const value_ = internal.asNum();
            if (std.math.isFinite(value_) and @trunc(value_) == value_ and
                value_ >= @as(f64, @floatFromInt(std.math.minInt(i32))) and
                value_ <= @as(f64, @floatFromInt(std.math.maxInt(i32))) and
                !(value_ == 0 and std.math.signbit(value_)))
            {
                break :number EncodedValue.fromInt32(@intFromFloat(value_));
            }
            break :number EncodedValue.fromDouble(value_);
        },
        .string => privateEncodedFromRef(box(context, internal)),
        .object => object: {
            const opaque_group = context.c_api_group orelse
                break :object privateEncodedFromRef(box(context, internal));
            const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
            const object_ptr = internal.asObj();
            if (group.private_object_boxes.get(object_ptr)) |existing|
                break :object privateEncodedFromRef(@ptrCast(existing));
            const created: *Boxed = @ptrCast(@alignCast(box(context, internal) orelse break :object .empty));
            group.private_object_boxes.put(gpa, object_ptr, created) catch break :object .empty;
            break :object privateEncodedFromRef(@ptrCast(created));
        },
    };
}

fn privateRefFromEncoded(global: JSContextRef, encoded: EncodedValue) JSValueRef {
    const context = ctxForHandleInspection(global) orelse return null;
    const internal = privateValueFrom(global, encoded) orelse return null;
    if (encoded.asCellAddress()) |_| {
        const boxed = privateBoxedFrom(encoded) orelse return null;
        return @ptrCast(boxed);
    } else |_| {}
    return box(context, internal);
}

fn privateValueFrom(global: JSContextRef, encoded: EncodedValue) ?Value {
    const context = ctxForHandleInspection(global) orelse return null;
    return encoded.toInternalPrimitive(Value) catch |err| switch (err) {
        error.CellRequiresHandle => {
            const boxed = privateBoxedFrom(encoded) orelse return null;
            if (boxed.private_kind != .value) return null;
            if (boxed.owner != context) {
                const group = context.c_api_group orelse return null;
                if (boxed.owner.c_api_group != group) return null;
            }
            return boxed.value;
        },
        else => null,
    };
}

fn privateSetPendingValue(context: *Context, thrown: Value) void {
    const opaque_group = context.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return;
    const encoded = privateEncodedFromValue(context, thrown);
    if (encoded == .empty) return;
    group.pending_exception = privateExceptionBox(context, thrown, encoded);
    if (group.pending_exception != null)
        group.primary.private_pending_exception_root = thrown;
}

fn privateSetPendingAbrupt(context: *Context, machine: *interp.Interpreter, err: anyerror) void {
    const thrown = if (err == error.Throw)
        machine.exception
    else
        context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory");
    privateSetPendingValue(context, thrown);
}

fn privateEncodeResult(context: *Context, machine: *interp.Interpreter, result: Value) EncodedValue {
    const encoded = privateEncodedFromValue(context, result);
    if (encoded == .empty)
        privateSetPendingAbrupt(context, machine, error.OutOfMemory);
    return encoded;
}

/// Capture Bun/Home's realm-local async-context slot around a callback without
/// making the wrapper itself callable. JSC recognizes this private brand only
/// at its explicit call boundary; keeping that distinction prevents ordinary
/// JavaScript `Function` checks from accepting the frame.
export fn AsyncContextFrame__withAsyncContextIfNeeded(
    global: JSContextRef,
    callback_encoded: EncodedValue,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const callback = privateValueFrom(global, callback_encoded) orelse return .empty;
    if (context.private_async_context.isUndefined()) return callback_encoded;
    if (callback.isObject() and callback.asObj().asyncContextFrame() != null) return callback_encoded;
    if (!callback.isObject() or !callback.asObj().isCallableObject()) return .empty;

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const frame_value = machine.newObject() catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const frame = frame_value.asObj();
    frame.proto = null;
    frame.setAsyncContextFrame(context.arena(), callback, context.private_async_context) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, frame_value);
}

export fn Bun__JSValue__isAsyncContextFrame(encoded: EncodedValue) callconv(.c) bool {
    const boxed = privateBoxedFrom(encoded) orelse return false;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return false;
    return boxed.value.asObj().asyncContextFrame() != null;
}

fn privateCallWithAsyncContext(
    context: *Context,
    machine: *interp.Interpreter,
    callable: Value,
    this_value: Value,
    arguments: []const Value,
) interp.EvalError!Value {
    var target = callable;
    const frame = if (callable.isObject()) callable.asObj().asyncContextFrame() else null;
    const previous = context.private_async_context;
    var async_root_mark: ?usize = null;
    if (frame) |captured| {
        async_root_mark = try machine.pushTempRoot(previous);
        target = captured.callback;
        context.private_async_context = captured.context;
        gc_mod.barrierValue(captured.context);
    }
    defer if (frame != null) {
        context.private_async_context = previous;
        gc_mod.barrierValue(previous);
        machine.restoreTempRoots(async_root_mark.?);
    };
    return machine.callValueWithThis(target, arguments, this_value);
}

export fn Bun__JSValue__call(
    global: JSContextRef,
    callable_encoded: EncodedValue,
    this_encoded: EncodedValue,
    argument_count: usize,
    argument_encodings: [*]const EncodedValue,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const callable = privateValueFrom(global, callable_encoded) orelse return .empty;
    const this_value = if (this_encoded == .empty)
        Value.obj(context.global_object)
    else
        privateValueFrom(global, this_encoded) orelse return .empty;
    const arguments = context.arena().alloc(Value, argument_count) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    for (argument_encodings[0..argument_count], arguments) |encoded, *argument| {
        argument.* = privateValueFrom(global, encoded) orelse return .empty;
    }
    const result = privateCallWithAsyncContext(context, &machine, callable, this_value, arguments) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

/// Invoke a Home/Bun `JSHostFn` using JavaScriptCore's 64-bit CallFrame register
/// layout. The consumer's opaque `CallFrame` methods index these words directly:
/// 0 caller, 1 return PC, 2 code block, 3 callee, 4 argc including `this`, 5
/// receiver/new.target, then the ordinary arguments.
fn privateJSHostFunctionNative(
    opaque_machine: *anyopaque,
    this_value: Value,
    args: []const Value,
) value.HostError!Value {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(opaque_machine));
    const function = machine.active_native orelse
        return machine.throwError("TypeError", "Zig host function is missing its callee");
    const record: *const PrivateHostFunctionRecord = @ptrCast(@alignCast(function.private_data orelse
        return machine.throwError("TypeError", "Zig host function is missing its implementation")));
    const constructing = !machine.new_target.isUndefined();
    const callback = if (constructing)
        record.constructor orelse return machine.throwError("TypeError", "Zig host function is not a constructor")
    else
        record.implementation;

    const register_count = std.math.add(usize, args.len, 6) catch
        return machine.throwError("RangeError", "Too many host function arguments");
    if (args.len >= std.math.maxInt(i32))
        return machine.throwError("RangeError", "Too many host function arguments");
    const registers = try machine.arena.alloc(EncodedValue, register_count);
    @memset(registers, .empty);
    registers[3] = privateEncodedFromValue(record.context, Value.obj(function));
    registers[4] = EncodedValue.fromInt32(@intCast(args.len + 1));
    registers[5] = privateEncodedFromValue(
        record.context,
        if (constructing) machine.new_target else this_value,
    );
    if (registers[3] == .empty or registers[5] == .empty) return error.OutOfMemory;
    for (args, registers[6..]) |arg, *slot| {
        slot.* = privateEncodedFromValue(record.context, arg);
        if (slot.* == .empty) return error.OutOfMemory;
    }

    const frame: *PrivateCallFrame = @ptrCast(@alignCast(registers.ptr));
    const caller_frame = machine.stack_trace_call_frame;
    const active = PrivateActiveCallFrame{
        .frame = frame,
        .context = record.context,
        .caller_location = machine.debug_current_location orelse if (caller_frame) |caller| caller.location else null,
        .caller_function_name = if (caller_frame) |caller| caller.function_name else "",
    };
    const previous_active = private_active_call_frame;
    private_active_call_frame = &active;
    defer private_active_call_frame = previous_active;

    const result = callback(
        @ptrCast(record.context),
        frame,
    );
    if (privateTakePendingExceptionValue(record.context)) |thrown| {
        machine.exception = thrown;
        return error.Throw;
    }
    if (result == .empty)
        return machine.throwError("TypeError", "Zig host function returned an empty value without an exception");
    const internal = privateValueFrom(@ptrCast(record.context), result) orelse
        return machine.throwError("TypeError", "Zig host function returned an invalid or foreign value");
    if (constructing and !internal.isObject())
        return machine.throwError("TypeError", "Zig host constructor must return an object");
    return internal;
}

fn privateHostFunctionRecord(encoded: EncodedValue) ?*PrivateHostFunctionRecord {
    const boxed = privateBoxedFrom(encoded) orelse return null;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return null;
    const object = boxed.value.asObj();
    const native = object.native orelse return null;
    if (@intFromPtr(native) != @intFromPtr(&privateJSHostFunctionNative)) return null;
    return @ptrCast(@alignCast(object.private_data orelse return null));
}

fn privateFFIFunctionRecord(encoded: EncodedValue) ?*PrivateHostFunctionRecord {
    const record = privateHostFunctionRecord(encoded) orelse return null;
    return if (record.kind == .ffi) record else null;
}

fn privateActiveCallFrame(frame: ?*const PrivateCallFrame) ?*const PrivateActiveCallFrame {
    const active = private_active_call_frame orelse return null;
    if (frame == null or active.frame != frame.?) return null;
    return active;
}

export fn Bun__CallFrame__getCallerSrcLoc(
    frame: ?*const PrivateCallFrame,
    global: JSContextRef,
    out_source_url: ?*PrivateBunString,
    out_line: ?*c_uint,
    out_column: ?*c_uint,
) callconv(.c) void {
    const source_url = out_source_url orelse return;
    const line = out_line orelse return;
    const column = out_column orelse return;
    source_url.* = .empty();
    line.* = 0;
    column.* = 0;

    const active = privateActiveCallFrame(frame) orelse return;
    const selected = ctxForHandleInspection(global) orelse return;
    if (selected.c_api_group != active.context.c_api_group) return;
    const location = active.caller_location orelse return;
    source_url.* = privateOwnedWTF8String(location.source_url) catch return;
    line.* = std.math.cast(c_uint, location.location.line) orelse 0;
    column.* = std.math.cast(c_uint, location.location.column) orelse 0;
}

export fn Bun__CallFrame__isFromBunMain(
    frame: ?*const PrivateCallFrame,
    vm_ref: ?*const anyopaque,
) callconv(.c) bool {
    const active = privateActiveCallFrame(frame) orelse return false;
    if (vm_ref == null or @intFromPtr(vm_ref.?) != @intFromPtr(active.context.c_api_group orelse return false)) return false;
    const location = active.caller_location orelse return false;
    return std.mem.eql(u8, location.source_url, "builtin://bun/main");
}

export fn Bun__CallFrame__describeFrame(frame: ?*const PrivateCallFrame) callconv(.c) [*:0]const u8 {
    const active = privateActiveCallFrame(frame) orelse return "invalid CallFrame";
    const location = active.caller_location;
    const function_name = if (active.caller_function_name.len > 0) active.caller_function_name else "<global>";
    const rendered = if (location) |source|
        std.fmt.bufPrint(
            private_call_frame_description[0 .. private_call_frame_description.len - 1],
            "{s} at {s}:{d}:{d}",
            .{ function_name, source.source_url, source.location.line, source.location.column },
        ) catch return "CallFrame description overflow"
    else
        std.fmt.bufPrint(private_call_frame_description[0 .. private_call_frame_description.len - 1], "{s} at <native>", .{function_name}) catch
            return "CallFrame description overflow";
    private_call_frame_description[rendered.len] = 0;
    return @ptrCast(private_call_frame_description[0..].ptr);
}

/// Create the pinned private-JSC host-function object. Visibility and intrinsic
/// are execution-tier hints in JSC; zig-js stores their exact ABI values for
/// future tiers while preserving the observable call/construct semantics now.
export fn JSFunction__createFromZig(
    global: JSContextRef,
    fn_name: PrivateBunString,
    implementation: ?*const PrivateJSHostFn,
    arg_count: u32,
    implementation_visibility: PrivateImplementationVisibility,
    intrinsic: PrivateIntrinsic,
    constructor: ?*const PrivateJSHostFn,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const implementation_fn = implementation orelse {
        const abrupt = machine.throwError("TypeError", "JSFunction implementation must not be null");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .empty;
    };
    const name_value = privateBunStringValue(context, &fn_name, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const name = name_value.asStr();
    const name_copy = context.arena().dupe(u8, name) catch {
        privateSetPendingAbrupt(context, &machine, error.OutOfMemory);
        return .empty;
    };
    const record = context.arena().create(PrivateHostFunctionRecord) catch {
        privateSetPendingAbrupt(context, &machine, error.OutOfMemory);
        return .empty;
    };
    record.* = .{
        .context = context,
        .implementation = implementation_fn,
        .constructor = constructor,
        .name = name_copy,
        .implementation_visibility = implementation_visibility,
        .intrinsic = intrinsic,
    };
    const object = gc_mod.allocObject(context.gc, context.arena()) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    object.* = .{
        .native = privateJSHostFunctionNative,
        // JSC installs `callHostFunctionAsConstructor` when no explicit
        // constructor is supplied. It still has a construct entry, which throws.
        .native_ctor = true,
        .proto = machine.functionProto(),
        .private_data = @ptrCast(record),
    };
    const function_attr: value.PropAttr = .{
        .writable = false,
        .enumerable = false,
        .configurable = true,
    };
    object.setOwn(context.arena(), context.root_shape, "length", Value.num(@floatFromInt(arg_count))) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    object.setAttr(context.arena(), "length", function_attr) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    object.setOwn(context.arena(), context.root_shape, "name", Value.strAlloc(context.arena(), name_copy) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    }) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    object.setAttr(context.arena(), "name", function_attr) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, Value.obj(object));
}

fn privateFFIFunctionName(symbol_name: ?*const PrivateZigString) PrivateBunString {
    const name = symbol_name orelse return .empty();
    return .{ .tag = .zig_string, .value = .{ .zig_string = name.* } };
}

fn privateCreateFFIFunction(
    global: JSContextRef,
    symbol_name: ?*const PrivateZigString,
    arg_count: u32,
    function: ?*const PrivateJSHostFn,
    data: ?*anyopaque,
    add_ptr_field: bool,
    symbol_from_dynamic_library: ?*anyopaque,
) EncodedValue {
    const callback = function orelse return JSFunction__createFromZig(
        global,
        privateFFIFunctionName(symbol_name),
        null,
        arg_count,
        .public,
        .none,
        null,
    );
    const encoded = JSFunction__createFromZig(
        global,
        privateFFIFunctionName(symbol_name),
        callback,
        arg_count,
        .public,
        .none,
        callback,
    );
    if (encoded == .empty) return .empty;

    const record = privateHostFunctionRecord(encoded) orelse return .empty;
    record.kind = .ffi;
    record.data_ptr.store(data, .release);
    record.symbol_from_dynamic_library = symbol_from_dynamic_library;
    if (!add_ptr_field) return encoded;

    const boxed = privateBoxedFrom(encoded) orelse return .empty;
    const context = boxed.owner;
    const object = boxed.value.asObj();
    const pointer_bits: u64 = @intFromPtr(callback);
    object.setOwn(context.arena(), context.root_shape, "ptr", Value.num(@bitCast(pointer_bits))) catch {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return .empty;
    };
    object.setAttr(context.arena(), "ptr", .{
        .writable = false,
        .enumerable = true,
        .configurable = true,
    }) catch {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return .empty;
    };
    return encoded;
}

export fn Bun__CreateFFIFunctionValue(
    global: JSContextRef,
    symbol_name: ?*const PrivateZigString,
    arg_count: u32,
    function: ?*const PrivateJSHostFn,
    add_ptr_field: bool,
    input_function_ptr: ?*anyopaque,
) callconv(.c) EncodedValue {
    return privateCreateFFIFunction(
        global,
        symbol_name,
        arg_count,
        function,
        null,
        add_ptr_field,
        input_function_ptr,
    );
}

export fn Bun__CreateFFIFunctionWithDataValue(
    global: JSContextRef,
    symbol_name: ?*const PrivateZigString,
    arg_count: u32,
    function: ?*const PrivateJSHostFn,
    data: ?*anyopaque,
) callconv(.c) EncodedValue {
    return privateCreateFFIFunction(global, symbol_name, arg_count, function, data, false, null);
}

export fn Bun__FFIFunction_getDataPtr(encoded: EncodedValue) callconv(.c) ?*anyopaque {
    const record = privateFFIFunctionRecord(encoded) orelse return null;
    return record.data_ptr.load(.acquire);
}

export fn Bun__FFIFunction_setDataPtr(encoded: EncodedValue, data: ?*anyopaque) callconv(.c) void {
    const record = privateFFIFunctionRecord(encoded) orelse return;
    record.data_ptr.store(data, .release);
}

fn privateBigIntModuloU64(object: *Object) u64 {
    if (object.bigIntText()) |text| {
        const negative = text.len > 0 and text[0] == '-';
        var result: u64 = 0;
        for (text[@intFromBool(negative)..]) |digit| {
            if (digit < '0' or digit > '9') return 0;
            result = result *% 10 +% (digit - '0');
        }
        return if (negative) 0 -% result else result;
    }
    return @truncate(@as(u128, @bitCast(object.bigIntValue())));
}

fn privateBoxFromCell(cell: ?*anyopaque) ?*Boxed {
    const pointer = cell orelse return null;
    const encoded = EncodedValue.fromCellAddress(@intFromPtr(pointer)) catch return null;
    return privateBoxedFrom(encoded);
}

fn privateBigIntBoxFromCell(cell: ?*anyopaque) ?*Boxed {
    const boxed = privateBoxFromCell(cell) orelse return null;
    if (boxed.private_kind != .value) return null;
    if (!boxed.value.isObject() or !boxed.value.asObj().is_bigint) return null;
    return boxed;
}

fn privatePromiseCellFromEncoded(encoded: EncodedValue) ?*anyopaque {
    const boxed = privateBoxedFrom(encoded) orelse return null;
    if (boxed.private_kind != .value or promise.promiseOf(boxed.value) == null) return null;
    return @ptrCast(boxed);
}

fn privatePromiseFromCell(global: JSContextRef, cell: ?*anyopaque) ?*promise.Promise {
    const context = ctxForHandleInspection(global) orelse return null;
    const boxed = privateBoxFromCell(cell) orelse return null;
    if (boxed.private_kind != .value) return null;
    if (boxed.owner != context) {
        const group = context.c_api_group orelse return null;
        if (boxed.owner.c_api_group != group) return null;
    }
    return promise.promiseOf(boxed.value);
}

const PrivateMapOperation = enum { create, get, has, remove, clear, set, size };

const PrivateMapResult = struct {
    encoded: EncodedValue = .empty,
    boolean: bool = false,
    size: usize = 0,
};

fn privateMapCellFromEncoded(encoded: EncodedValue) ?*anyopaque {
    const boxed = privateBoxedFrom(encoded) orelse return null;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return null;
    const object = boxed.value.asObj();
    if (!object.is_map or object.is_weak) return null;
    return @ptrCast(boxed);
}

fn privateMapObjectFromCell(global: JSContextRef, cell: ?*anyopaque) ?*Object {
    const context = ctxForHandleInspection(global) orelse return null;
    const boxed = privateBoxFromCell(cell) orelse return null;
    if (boxed.private_kind != .value) return null;
    if (boxed.owner != context) {
        const group = context.c_api_group orelse return null;
        if (boxed.owner.c_api_group != group) return null;
    }
    if (!boxed.value.isObject()) return null;
    const object = boxed.value.asObj();
    if (!object.is_map or object.is_weak) return null;
    return object;
}

fn privateApplyNativeMap(
    global: JSContextRef,
    cell: ?*anyopaque,
    operation: PrivateMapOperation,
    encoded_key: EncodedValue,
    encoded_value: EncodedValue,
) PrivateMapResult {
    const context = ctxForEvaluation(global) orelse return .{};
    const opaque_group = context.c_api_group orelse return .{};
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .{};
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .{};
    };
    defer context.popActiveInterpreter(&machine);

    if (operation == .create) {
        const created = machine.createNativeMap() catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .{};
        };
        return .{ .encoded = privateEncodeResult(context, &machine, created) };
    }

    const map = privateMapObjectFromCell(global, cell) orelse {
        const err = machine.throwError("TypeError", "JSMap receiver is not a native Map in this VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .{};
    };
    const needs_key = operation == .get or operation == .has or operation == .remove or operation == .set;
    const key = if (needs_key) privateValueFrom(global, encoded_key) orelse {
        const err = machine.throwError("TypeError", "JSMap key belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .{};
    } else Value.undef();
    const stored_value = if (operation == .set) privateValueFrom(global, encoded_value) orelse {
        const err = machine.throwError("TypeError", "JSMap value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .{};
    } else Value.undef();

    return switch (operation) {
        .create => unreachable,
        .get => result: {
            const found = machine.nativeMapGet(map, key) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                break :result .{};
            };
            break :result .{ .encoded = privateEncodeResult(context, &machine, found) };
        },
        .has => result: {
            const found = machine.nativeMapHas(map, key) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                break :result .{};
            };
            break :result .{ .boolean = found };
        },
        .remove => result: {
            const removed = machine.nativeMapRemove(map, key) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                break :result .{};
            };
            break :result .{ .boolean = removed };
        },
        .clear => result: {
            machine.nativeMapClear(map) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                break :result .{};
            };
            break :result .{};
        },
        .set => result: {
            machine.nativeMapSet(map, key, stored_value) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                break :result .{};
            };
            break :result .{};
        },
        .size => .{ .size = machine.nativeMapSize(map) },
    };
}

fn privateTakePendingExceptionValue(context: *Context) ?Value {
    const opaque_group = context.c_api_group orelse return null;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    const exception = group.pending_exception orelse return null;
    group.pending_exception = null;
    group.primary.private_pending_exception_root = null;
    return exception.value;
}

fn privateEncodeNativePromise(
    context: *Context,
    machine: *interp.Interpreter,
    state: ?promise.State,
    stored_value: Value,
) EncodedValue {
    const object = if (state) |settled_state|
        promise.newSettledPromise(machine, settled_state, stored_value)
    else
        promise.newPromise(machine);
    const result = object catch |err| {
        privateSetPendingAbrupt(context, machine, err);
        return .empty;
    };
    return privateEncodeResult(context, machine, Value.obj(result));
}

fn privateCreateNativePromise(
    global: JSContextRef,
    state: ?promise.State,
    encoded_value: EncodedValue,
) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const stored_value = if (state != null) value_: {
        const internal = privateValueFrom(global, encoded_value) orelse {
            const err = machine.throwError("TypeError", "Promise value belongs to another VM");
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
        break :value_ internal;
    } else Value.undef();
    return privateEncodeNativePromise(context, &machine, state, stored_value);
}

fn privateCommonAbortReasonToJS(
    global: JSContextRef,
    reason: PrivateCommonAbortReason,
) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const contract = switch (reason) {
        .none => return .undefined,
        .timeout => .{ "TimeoutError", "The operation timed out." },
        .user_abort => .{ "AbortError", "The operation was aborted." },
        .connection_closed => .{ "AbortError", "The connection was closed." },
        else => @panic("invalid CommonAbortReason"),
    };
    const result = machine.makeDOMException(contract[0], contract[1]) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

fn privateBigIntObjectFrom(global: JSContextRef, encoded: EncodedValue) ?*Object {
    const internal = privateValueFrom(global, encoded) orelse return null;
    if (!internal.isObject() or !internal.asObj().is_bigint) return null;
    return internal.asObj();
}

fn privateStringBoxFromCell(cell: ?*anyopaque) ?*Boxed {
    const boxed = privateBoxFromCell(cell) orelse return null;
    if (boxed.private_kind != .value) return null;
    if (!boxed.value.isString()) return null;
    return boxed;
}

fn privateOrderResult(order: std.math.Order) i8 {
    return switch (order) {
        .lt => -1,
        .eq => 0,
        .gt => 1,
    };
}

fn privateBigIntComparisonResult(order: std.math.Order) u8 {
    return switch (order) {
        .eq => 0,
        .gt => 2,
        .lt => 3,
    };
}

fn privateObjectJSType(object: *Object) private_jstype.Kind {
    if (object.is_symbol) return .Symbol;
    if (object.is_bigint) return .HeapBigInt;
    if (object.getterSetterCellData()) |cell|
        return if (cell.isCustom()) .CustomGetterSetter else .GetterSetter;
    if (object.behavior.is_error) return .ErrorInstance;
    if (object.arrayBuffer() != null) return .ArrayBuffer;
    if (object.typedArray()) |typed_array| return switch (typed_array.kind) {
        .i8 => .Int8Array,
        .u8 => .Uint8Array,
        .u8c => .Uint8ClampedArray,
        .i16 => .Int16Array,
        .u16 => .Uint16Array,
        .i32 => .Int32Array,
        .u32 => .Uint32Array,
        .f16 => .Float16Array,
        .f32 => .Float32Array,
        .f64 => .Float64Array,
        .i64 => .BigInt64Array,
        .u64 => .BigUint64Array,
    };
    if (object.dataView() != null) return .DataView;
    if (object.moduleNs() != null) return .ModuleNamespaceObject;
    if (object.behavior.is_shadow_realm) return .ShadowRealm;
    if (object.behavior.is_regex) return .RegExpObject;
    if (object.behavior.is_date) return .JSDate;
    if (object.proxy_revoked or object.proxyTarget() != null) return .ProxyObject;
    if (object.generator() != null) return .Generator;
    if (object.iteratorHelper() != null) return .IteratorHelper;
    if (object.promiseData() != null) return .JSPromise;
    if (object.is_map) return if (object.is_weak) .WeakMap else .Map;
    if (object.is_set) return if (object.is_weak) .WeakSet else .Set;
    if (object.is_arguments) return .DirectArguments;
    if (object.is_array) return .Array;
    if (object.boxedPrimitive()) |primitive| return switch (primitive.kind()) {
        .boolean => .BooleanObject,
        .number => .NumberObject,
        .string => .StringObject,
        else => .FinalObject,
    };
    if (object.jsFunction() != null) return .JSFunction;
    if (object.isCallableObject()) return .InternalFunction;
    return .FinalObject;
}

fn privateJSType(encoded: EncodedValue) u8 {
    const boxed = privateBoxedFrom(encoded) orelse return 0;
    if (boxed.private_kind == .exception) return 0; // JSC::CellType
    const kind: private_jstype.Kind = switch (boxed.value.kind()) {
        .string => .String,
        .object => privateObjectJSType(boxed.value.asObj()),
        else => return 0,
    };
    return private_jstype.selectedTag(kind);
}

/// First revision-pinned Home private-ABI slice. These symbols consume JSC64
/// words, not zig-js's internal NaN-box representation.
export fn JSC__JSValue__eqlCell(encoded: EncodedValue, cell: ?*anyopaque) callconv(.c) bool {
    const address = encoded.asCellAddress() catch return false;
    return cell != null and address == @intFromPtr(cell.?);
}

fn privateGetterSetterCellFromBox(cell: ?*anyopaque, custom: bool) ?value.GetterSetterCellData {
    const boxed = privateBoxFromCell(cell) orelse return null;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return null;
    const data = boxed.value.asObj().getterSetterCellData() orelse return null;
    return if (data.isCustom() == custom) data else null;
}

export fn JSC__JSValue__isGetterSetter(encoded: EncodedValue) callconv(.c) bool {
    const boxed = privateBoxedFrom(encoded) orelse return false;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return false;
    const data = boxed.value.asObj().getterSetterCellData() orelse return false;
    return !data.isCustom();
}

export fn JSC__JSValue__isCustomGetterSetter(encoded: EncodedValue) callconv(.c) bool {
    const boxed = privateBoxedFrom(encoded) orelse return false;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return false;
    const data = boxed.value.asObj().getterSetterCellData() orelse return false;
    return data.isCustom();
}

export fn JSC__GetterSetter__isGetterNull(cell: ?*anyopaque) callconv(.c) bool {
    const data = privateGetterSetterCellFromBox(cell, false) orelse return true;
    return data.getterValue() == null;
}

export fn JSC__GetterSetter__isSetterNull(cell: ?*anyopaque) callconv(.c) bool {
    const data = privateGetterSetterCellFromBox(cell, false) orelse return true;
    return data.setterValue() == null;
}

export fn JSC__CustomGetterSetter__isGetterNull(cell: ?*anyopaque) callconv(.c) bool {
    const data = privateGetterSetterCellFromBox(cell, true) orelse return true;
    return data.customGetter() == null;
}

export fn JSC__CustomGetterSetter__isSetterNull(cell: ?*anyopaque) callconv(.c) bool {
    const data = privateGetterSetterCellFromBox(cell, true) orelse return true;
    return data.customSetter() == null;
}

export fn JSC__JSValue__eqlValue(left: EncodedValue, right: EncodedValue) callconv(.c) bool {
    return left.rawBits() == right.rawBits();
}

export fn JSC__JSValue__toInt32(encoded: EncodedValue) callconv(.c) i32 {
    return if (encoded.isInt32()) encoded.asInt32() else 0;
}

export fn JSC__JSValue__toBoolean(encoded: EncodedValue) callconv(.c) bool {
    const decoded = encoded.toInternalPrimitive(Value) catch |conversion_error| switch (conversion_error) {
        error.CellRequiresHandle => {
            const boxed = privateBoxedFrom(encoded) orelse return false;
            if (boxed.private_kind == .exception) return true;
            // Bun's pinned shim uses pureToBoolean() and deliberately counts
            // masquerades-as-undefined objects as true at this boundary.
            if (boxed.value.isObject() and boxed.value.asObj().behavior.is_htmldda) return true;
            return boxed.value.toBoolean();
        },
        else => return false,
    };
    return decoded.toBoolean();
}

export fn JSC__JSValue__fromInt64NoTruncate(global: JSContextRef, number: i64) callconv(.c) EncodedValue {
    return privateEncodedFromRef(JSBigIntCreateWithInt64(global, number, null));
}

export fn JSC__JSValue__fromUInt64NoTruncate(global: JSContextRef, number: u64) callconv(.c) EncodedValue {
    return privateEncodedFromRef(JSBigIntCreateWithUInt64(global, number, null));
}

export fn JSC__JSValue__asBigIntCompare(
    encoded: EncodedValue,
    global: JSContextRef,
    other_encoded: EncodedValue,
) callconv(.c) u8 {
    const context = ctxForHandleInspection(global) orelse return 4;
    const lhs = privateBigIntObjectFrom(global, encoded) orelse return 4;
    const other = privateValueFrom(global, other_encoded) orelse return 4;
    const order = switch (other.kind()) {
        .number => number: {
            const rhs = other.asNum();
            if (std.math.isNan(rhs)) return 1;
            break :number interp.orderBigIntObjectAgainstDouble(context.arena(), lhs, rhs) catch return 4;
        },
        .object => object: {
            const rhs = other.asObj();
            if (!rhs.is_bigint) return 4;
            break :object interp.orderBigIntObjects(context.arena(), lhs, rhs) catch return 4;
        },
        else => return 4,
    };
    return privateBigIntComparisonResult(order);
}

export fn JSC__JSValue__bigIntSum(
    global: JSContextRef,
    left: EncodedValue,
    right: EncodedValue,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const lhs = privateBigIntObjectFrom(global, left) orelse return .empty;
    const rhs = privateBigIntObjectFrom(global, right) orelse return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch return .empty;
    defer context.popActiveInterpreter(&machine);
    const result = interp.addBigIntObjects(&machine, lhs, rhs) catch return .empty;
    return privateEncodedFromValue(context, result);
}

export fn JSC__JSValue__fromTimevalNoTruncate(
    global: JSContextRef,
    nsec: i64,
    sec: i64,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch return .empty;
    defer context.popActiveInterpreter(&machine);
    const result = interp.makeTimevalBigInt(&machine, nsec, sec) catch return .empty;
    return privateEncodedFromValue(context, result);
}

export fn JSC__JSValue__toUInt64NoTruncate(encoded: EncodedValue) callconv(.c) u64 {
    if (encoded.isInt32()) return @bitCast(@as(i64, encoded.asInt32()));
    if (encoded.isDouble()) {
        const number = encoded.asDouble();
        const int52_limit: f64 = @floatFromInt(@as(u64, 1) << 51);
        if (!std.math.isFinite(number) or @trunc(number) != number or
            number < 0 or number >= int52_limit)
            return 0;
        return @intFromFloat(number);
    }
    const boxed = privateBoxedFrom(encoded) orelse return 0;
    if (boxed.private_kind != .value) return 0;
    if (!boxed.value.isObject() or !boxed.value.asObj().is_bigint) return 0;
    return privateBigIntModuloU64(boxed.value.asObj());
}

export fn JSVALUE_TO_UINT64_SLOW(encoded: EncodedValue) callconv(.c) u64 {
    return JSC__JSValue__toUInt64NoTruncate(encoded);
}

export fn JSVALUE_TO_INT64_SLOW(encoded: EncodedValue) callconv(.c) i64 {
    if (encoded.isInt32()) return encoded.asInt32();
    if (encoded.isDouble()) {
        const number = encoded.asDouble();
        const minimum: f64 = @floatFromInt(std.math.minInt(i64));
        const maximum_exclusive: f64 = 9223372036854775808.0;
        if (!std.math.isFinite(number) or @trunc(number) != number or
            number < minimum or number >= maximum_exclusive)
            return 0;
        return @intFromFloat(number);
    }
    const boxed = privateBoxedFrom(encoded) orelse return 0;
    if (boxed.private_kind != .value or !boxed.value.isObject() or
        !boxed.value.asObj().is_bigint)
        return 0;
    return @bitCast(privateBigIntModuloU64(boxed.value.asObj()));
}

export fn Bun__JSC__operationMathPow(base: f64, exponent: f64) callconv(.c) f64 {
    return builtins.operationMathPow(base, exponent);
}

export fn Bun__JSValue__toNumber(encoded: EncodedValue, global: JSContextRef) callconv(.c) f64 {
    const context = ctxForEvaluation(global) orelse return std.math.nan(f64);
    const opaque_group = context.c_api_group orelse return std.math.nan(f64);
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return std.math.nan(f64);
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return std.math.nan(f64);
    };
    defer context.popActiveInterpreter(&machine);
    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "Value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return std.math.nan(f64);
    };
    return machine.toNumberV(internal) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return std.math.nan(f64);
    };
}

export fn JSC__JSValue__isInstanceOf(
    encoded: EncodedValue,
    global: JSContextRef,
    constructor_encoded: EncodedValue,
) callconv(.c) bool {
    const context = ctxForEvaluation(global) orelse return false;
    const opaque_group = context.c_api_group orelse return false;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return false;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    defer context.popActiveInterpreter(&machine);
    const candidate = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "Value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    const constructor = privateValueFrom(global, constructor_encoded) orelse {
        const err = machine.throwError("TypeError", "Constructor belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    if (!constructor.isObject() or constructor.asObj().is_symbol or constructor.asObj().is_bigint)
        return false;
    const object = constructor.asObj();
    const custom_has_instance = if (object.hostClassHooks()) |hooks| hooks.has_instance != null else false;
    if (!object.isCallableObject() and !custom_has_instance) return false;
    return machine.instanceOf(candidate, constructor) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
}

export fn JSC__JSValue__isIterable(encoded: EncodedValue, global: JSContextRef) callconv(.c) bool {
    const context = ctxForEvaluation(global) orelse return false;
    const opaque_group = context.c_api_group orelse return false;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return false;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    defer context.popActiveInterpreter(&machine);
    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "Value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    return machine.hasIteratorMethod(internal) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
}

export fn JSC__JSValue__stringIncludes(
    encoded: EncodedValue,
    global: JSContextRef,
    other_encoded: EncodedValue,
) callconv(.c) bool {
    const context = ctxForEvaluation(global) orelse return false;
    const opaque_group = context.c_api_group orelse return false;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return false;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    defer context.popActiveInterpreter(&machine);
    const value_to_search = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "Value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    const search_value = privateValueFrom(global, other_encoded) orelse {
        const err = machine.throwError("TypeError", "Search value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    const haystack = machine.toStringV(value_to_search) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    const needle = machine.toStringV(search_value) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    return interp.Interpreter.stringIncludesUtf16(haystack, needle);
}

export fn JSC__JSValue__isClass(encoded: EncodedValue, global: JSContextRef) callconv(.c) bool {
    const internal = privateValueFrom(global, encoded) orelse return false;
    if (!internal.isObject() or internal.asObj().is_symbol or internal.asObj().is_bigint) return false;
    const object = internal.asObj();
    if (object.jsFunction()) |erased| {
        const function: *interp.Function = @ptrCast(@alignCast(erased));
        return function.is_class_constructor;
    }
    if (object.boundFunction() != null) return false;
    return interp.isConstructorValue(internal);
}

export fn JSC__JSValue__isAggregateError(encoded: EncodedValue, global: JSContextRef) callconv(.c) bool {
    const internal = privateValueFrom(global, encoded) orelse return false;
    if (!internal.isObject()) return false;
    const object = internal.asObj();
    return object.behavior.is_error and std.mem.eql(u8, object.errorName(), "AggregateError");
}

export fn JSC__JSValue__isStrictEqual(
    left: EncodedValue,
    right: EncodedValue,
    global: JSContextRef,
) callconv(.c) bool {
    if (privateIsExceptionCell(left) or privateIsExceptionCell(right))
        return left.rawBits() == right.rawBits();
    const lhs = privateValueFrom(global, left) orelse return false;
    const rhs = privateValueFrom(global, right) orelse return false;
    return value.strictEquals(lhs, rhs);
}

export fn JSC__JSValue__isSameValue(
    left: EncodedValue,
    right: EncodedValue,
    global: JSContextRef,
) callconv(.c) bool {
    if (privateIsExceptionCell(left) or privateIsExceptionCell(right))
        return left.rawBits() == right.rawBits();
    const lhs = privateValueFrom(global, left) orelse return false;
    const rhs = privateValueFrom(global, right) orelse return false;
    return value.sameValue(lhs, rhs);
}

export fn JSC__JSValue__jsType(encoded: EncodedValue) callconv(.c) u8 {
    return privateJSType(encoded);
}

export fn JSC__JSCell__getType(cell: ?*anyopaque) callconv(.c) u8 {
    const pointer = cell orelse return 0;
    const encoded = EncodedValue.fromCellAddress(@intFromPtr(pointer)) catch return 0;
    return privateJSType(encoded);
}

export fn JSC__JSBigInt__fromJS(encoded: EncodedValue) callconv(.c) ?*anyopaque {
    const boxed = privateBoxedFrom(encoded) orelse return null;
    if (boxed.private_kind != .value) return null;
    if (!boxed.value.isObject() or !boxed.value.asObj().is_bigint) return null;
    return @ptrCast(boxed);
}

export fn JSC__JSBigInt__orderDouble(cell: ?*anyopaque, number: f64) callconv(.c) i8 {
    const boxed = privateBigIntBoxFromCell(cell) orelse return 0;
    const order = interp.orderBigIntObjectAgainstDouble(
        boxed.owner.arena(),
        boxed.value.asObj(),
        number,
    ) catch return 0;
    return privateOrderResult(order);
}

export fn JSC__JSBigInt__orderInt64(cell: ?*anyopaque, number: i64) callconv(.c) i8 {
    const boxed = privateBigIntBoxFromCell(cell) orelse return 0;
    const order = interp.orderBigIntObjectAgainstInteger(
        boxed.owner.arena(),
        boxed.value.asObj(),
        number,
    ) catch return 0;
    return privateOrderResult(order);
}

export fn JSC__JSBigInt__orderUint64(cell: ?*anyopaque, number: u64) callconv(.c) i8 {
    const boxed = privateBigIntBoxFromCell(cell) orelse return 0;
    const order = interp.orderBigIntObjectAgainstInteger(
        boxed.owner.arena(),
        boxed.value.asObj(),
        number,
    ) catch return 0;
    return privateOrderResult(order);
}

export fn JSC__JSBigInt__toInt64(cell: ?*anyopaque) callconv(.c) i64 {
    const boxed = privateBigIntBoxFromCell(cell) orelse return 0;
    return @bitCast(privateBigIntModuloU64(boxed.value.asObj()));
}

fn privateDestroyWTFStringImpl(impl: *PrivateWTFStringImpl) void {
    if (impl.private_magic != private_wtf_magic) return;
    const byte_length: usize = if (impl.m_hash_and_flags & private_wtf_flag_8_bit_buffer != 0)
        impl.m_length
    else
        @as(usize, impl.m_length) * @sizeOf(u16);
    const bytes = @constCast(impl.m_ptr[0..byte_length]);
    impl.private_magic = 0;
    private_string_allocator.free(bytes);
    private_string_allocator.destroy(impl);
}

export fn Bun__WTFStringImpl__ref(impl: ?*PrivateWTFStringImpl) callconv(.c) void {
    const string = impl orelse return;
    if (string.private_magic != private_wtf_magic) return;
    _ = @atomicRmw(u32, &string.m_ref_count, .Add, private_wtf_ref_increment, .monotonic);
}

export fn Bun__WTFStringImpl__deref(impl: ?*PrivateWTFStringImpl) callconv(.c) void {
    const string = impl orelse return;
    if (string.private_magic != private_wtf_magic) return;
    const previous = @atomicRmw(u32, &string.m_ref_count, .Sub, private_wtf_ref_increment, .acq_rel);
    if (previous == private_wtf_ref_increment) privateDestroyWTFStringImpl(string);
}

/// Rust-side Bun strings use an inline atomic decrement and call this cold
/// destroy path only after they brought the count to zero themselves.
export fn Bun__WTFStringImpl__destroy(impl: ?*PrivateWTFStringImpl) callconv(.c) void {
    const string = impl orelse return;
    if (@atomicLoad(u32, &string.m_ref_count, .acquire) != 0) return;
    privateDestroyWTFStringImpl(string);
}

fn privateOwnedLatin1String(bytes: []const u8) error{OutOfMemory}!PrivateBunString {
    if (bytes.len == 0) return PrivateBunString.empty();
    const owned = try private_string_allocator.dupe(u8, bytes);
    errdefer private_string_allocator.free(owned);
    const impl = try private_string_allocator.create(PrivateWTFStringImpl);
    impl.* = .{
        .m_ref_count = private_wtf_ref_increment,
        .m_length = @intCast(owned.len),
        .m_ptr = owned.ptr,
        .m_hash_and_flags = private_wtf_flag_8_bit_buffer,
        .private_magic = private_wtf_magic,
    };
    return .{ .tag = .wtf_string_impl, .value = .{ .wtf_string_impl = impl } };
}

fn privateOwnedWTF8String(bytes: []const u8) PrivateBunStringError!PrivateBunString {
    if (bytes.len == 0) return PrivateBunString.empty();
    const units = try privateWTF8ToUTF16(private_string_allocator, bytes);
    if (interp.Interpreter.jsStringIs8Bit(bytes)) {
        const latin1 = private_string_allocator.alloc(u8, units.len) catch {
            private_string_allocator.free(units);
            return error.OutOfMemory;
        };
        defer private_string_allocator.free(latin1);
        for (units, latin1) |unit, *byte| byte.* = @intCast(unit);
        private_string_allocator.free(units);
        return privateOwnedLatin1String(latin1);
    }

    const byte_length = std.math.mul(usize, units.len, @sizeOf(u16)) catch {
        private_string_allocator.free(units);
        return error.OutOfMemory;
    };
    const owned = private_string_allocator.alloc(u8, byte_length) catch {
        private_string_allocator.free(units);
        return error.OutOfMemory;
    };
    @memcpy(owned, std.mem.sliceAsBytes(units));
    private_string_allocator.free(units);
    const impl = private_string_allocator.create(PrivateWTFStringImpl) catch {
        private_string_allocator.free(owned);
        return error.OutOfMemory;
    };
    impl.* = .{
        .m_ref_count = private_wtf_ref_increment,
        .m_length = @intCast(byte_length / @sizeOf(u16)),
        .m_ptr = owned.ptr,
        .m_hash_and_flags = 0,
        .private_magic = private_wtf_magic,
    };
    return .{ .tag = .wtf_string_impl, .value = .{ .wtf_string_impl = impl } };
}

const PrivateBunStringError = error{ OutOfMemory, StringTooLong, InvalidString };

export fn Bun__createTextCodec(
    encoding_name: [*c]const u8,
    encoding_name_len: usize,
) callconv(.c) ?*text_codec.Codec {
    if (encoding_name_len > 0 and encoding_name == null) return null;
    const label = if (encoding_name_len == 0) &.{} else encoding_name[0..encoding_name_len];
    const encoding = text_codec.canonicalEncoding(label) orelse return null;
    const codec = private_string_allocator.create(text_codec.Codec) catch return null;
    codec.* = text_codec.Codec.init(encoding);
    return codec;
}

export fn Bun__decodeWithTextCodec(
    codec: ?*text_codec.Codec,
    data: [*c]const u8,
    length: usize,
    flush: bool,
    stop_on_error: bool,
    out_saw_error: ?*bool,
) callconv(.c) PrivateBunString {
    const saw_error = out_saw_error orelse return PrivateBunString.empty();
    saw_error.* = false;
    const decoder = codec orelse return PrivateBunString.empty();
    if (length > 0 and data == null) return PrivateBunString.empty();
    const input = if (length == 0) &.{} else data[0..length];
    const decoded = decoder.decode(private_string_allocator, input, flush, stop_on_error) catch
        return PrivateBunString.dead();
    defer decoded.deinit(private_string_allocator);
    saw_error.* = decoded.saw_error;
    return privateOwnedWTF8String(decoded.bytes) catch PrivateBunString.dead();
}

export fn Bun__deleteTextCodec(codec: ?*text_codec.Codec) callconv(.c) void {
    const decoder = codec orelse return;
    decoder.deinit();
    private_string_allocator.destroy(decoder);
}

/// None of the codecs in the pinned fallback registry overrides WebKit's
/// default no-op `TextCodec::stripByteOrderMark` implementation.
export fn Bun__stripBOMFromTextCodec(codec: ?*text_codec.Codec) callconv(.c) void {
    _ = codec;
}

export fn Bun__isEncodingSupported(
    encoding_name: [*c]const u8,
    encoding_name_len: usize,
) callconv(.c) bool {
    if (encoding_name_len > 0 and encoding_name == null) return false;
    const label = if (encoding_name_len == 0) &.{} else encoding_name[0..encoding_name_len];
    return text_codec.canonicalEncoding(label) != null;
}

export fn Bun__getCanonicalEncodingName(
    encoding_name: [*c]const u8,
    encoding_name_len: usize,
    out_len: ?*usize,
) callconv(.c) ?[*]const u8 {
    const length = out_len orelse return null;
    length.* = 0;
    if (encoding_name_len > 0 and encoding_name == null) return null;
    const label = if (encoding_name_len == 0) &.{} else encoding_name[0..encoding_name_len];
    const encoding = text_codec.canonicalEncoding(label) orelse return null;
    const canonical = encoding.canonicalName();
    length.* = canonical.len;
    return canonical.ptr;
}

fn privateLatin1ToWTF8(allocator: std.mem.Allocator, bytes: []const u8) error{OutOfMemory}![]u8 {
    const capacity = std.math.mul(usize, bytes.len, 2) catch return error.OutOfMemory;
    const out = try allocator.alloc(u8, capacity);
    var used: usize = 0;
    for (bytes) |byte| {
        if (byte < 0x80) {
            out[used] = byte;
            used += 1;
        } else {
            out[used] = 0xc0 | (byte >> 6);
            out[used + 1] = 0x80 | (byte & 0x3f);
            used += 2;
        }
    }
    return allocator.realloc(out, used) catch out[0..used];
}

fn privateAppendWTF8CodeUnit(out: []u8, used: *usize, unit: u16) void {
    if (unit < 0x80) {
        out[used.*] = @intCast(unit);
        used.* += 1;
    } else if (unit < 0x800) {
        out[used.*] = 0xc0 | @as(u8, @intCast(unit >> 6));
        out[used.* + 1] = 0x80 | @as(u8, @intCast(unit & 0x3f));
        used.* += 2;
    } else {
        out[used.*] = 0xe0 | @as(u8, @intCast(unit >> 12));
        out[used.* + 1] = 0x80 | @as(u8, @intCast((unit >> 6) & 0x3f));
        out[used.* + 2] = 0x80 | @as(u8, @intCast(unit & 0x3f));
        used.* += 3;
    }
}

fn privateUTF16ToWTF8(allocator: std.mem.Allocator, units: []align(1) const u16) error{OutOfMemory}![]u8 {
    const capacity = std.math.mul(usize, units.len, 3) catch return error.OutOfMemory;
    const out = try allocator.alloc(u8, capacity);
    var input: usize = 0;
    var used: usize = 0;
    while (input < units.len) : (input += 1) {
        const first = units[input];
        if (first >= 0xd800 and first <= 0xdbff and input + 1 < units.len and
            units[input + 1] >= 0xdc00 and units[input + 1] <= 0xdfff)
        {
            const codepoint: u21 = @intCast(0x10000 +
                ((@as(u32, first) - 0xd800) << 10) +
                (@as(u32, units[input + 1]) - 0xdc00));
            out[used] = 0xf0 | @as(u8, @intCast(codepoint >> 18));
            out[used + 1] = 0x80 | @as(u8, @intCast((codepoint >> 12) & 0x3f));
            out[used + 2] = 0x80 | @as(u8, @intCast((codepoint >> 6) & 0x3f));
            out[used + 3] = 0x80 | @as(u8, @intCast(codepoint & 0x3f));
            used += 4;
            input += 1;
        } else {
            privateAppendWTF8CodeUnit(out, &used, first);
        }
    }
    return allocator.realloc(out, used) catch out[0..used];
}

fn privateUTF8PrefixAsWTF8(
    allocator: std.mem.Allocator,
    bytes: []const u8,
    max_utf16_units: ?usize,
) PrivateBunStringError![]u8 {
    if (max_utf16_units == null) return allocator.dupe(u8, bytes);
    const limit = max_utf16_units.?;
    const capacity = std.math.add(usize, bytes.len, 3) catch return error.OutOfMemory;
    const out = try allocator.alloc(u8, capacity);
    var input: usize = 0;
    var used: usize = 0;
    var units: usize = 0;
    while (input < bytes.len and units < limit) {
        const sequence_len = std.unicode.utf8ByteSequenceLength(bytes[input]) catch return error.InvalidString;
        if (input + sequence_len > bytes.len) return error.InvalidString;
        const codepoint = std.unicode.utf8Decode(bytes[input .. input + sequence_len]) catch return error.InvalidString;
        if (codepoint > 0xffff) {
            const remaining = limit - units;
            if (remaining == 1) {
                const high: u16 = @intCast(0xd800 + ((codepoint - 0x10000) >> 10));
                privateAppendWTF8CodeUnit(out, &used, high);
                units += 1;
                break;
            }
            units += 2;
        } else {
            units += 1;
        }
        @memcpy(out[used .. used + sequence_len], bytes[input .. input + sequence_len]);
        used += sequence_len;
        input += sequence_len;
    }
    return allocator.realloc(out, used) catch out[0..used];
}

fn privateBunStringValue(
    context: *Context,
    string: *const PrivateBunString,
    max_utf16_units: ?usize,
) PrivateBunStringError!Value {
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);

    if (string.tag == .empty) return Value.staticStr("");
    if (string.tag == .dead) return error.StringTooLong;

    const allocator = if (context.gc != null) context.gpa else context.arena();
    const bytes = switch (string.tag) {
        .wtf_string_impl => blk: {
            const impl = string.value.wtf_string_impl orelse return error.InvalidString;
            if (impl.m_length == 0) return Value.staticStr("");
            const length: usize = if (max_utf16_units) |limit| @min(limit, impl.m_length) else impl.m_length;
            if (impl.m_hash_and_flags & private_wtf_flag_8_bit_buffer != 0)
                break :blk try privateLatin1ToWTF8(allocator, impl.m_ptr[0..length]);
            const units: [*]align(1) const u16 = @ptrCast(impl.m_ptr);
            break :blk try privateUTF16ToWTF8(allocator, units[0..length]);
        },
        .zig_string, .static_zig_string => blk: {
            const zig_string = string.value.zig_string;
            if (zig_string.len == 0) return Value.staticStr("");
            const untagged = zig_string.tagged_ptr & ((@as(usize, 1) << 53) - 1);
            if (untagged == 0) return error.InvalidString;
            if (zig_string.tagged_ptr & (@as(usize, 1) << 63) != 0) {
                const length = if (max_utf16_units) |limit| @min(limit, zig_string.len) else zig_string.len;
                const units: [*]align(1) const u16 = @ptrFromInt(untagged);
                break :blk try privateUTF16ToWTF8(allocator, units[0..length]);
            }
            const source: [*]const u8 = @ptrFromInt(untagged);
            if (zig_string.tagged_ptr & (@as(usize, 1) << 61) != 0)
                break :blk try privateUTF8PrefixAsWTF8(allocator, source[0..zig_string.len], max_utf16_units);
            const length = if (max_utf16_units) |limit| @min(limit, zig_string.len) else zig_string.len;
            break :blk try privateLatin1ToWTF8(allocator, source[0..length]);
        },
        else => return error.InvalidString,
    };
    return Value.strOwned(allocator, bytes);
}

fn privatePublishBunStringError(context: *Context, err: PrivateBunStringError) void {
    if (err == error.OutOfMemory) {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return;
    }
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |push_err| {
        privateSetPendingAbrupt(context, &machine, push_err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    const abrupt = switch (err) {
        error.StringTooLong => machine.throwError("RangeError", "Cannot create a string longer than the runtime limit"),
        error.InvalidString => machine.throwError("TypeError", "Invalid BunString representation"),
        error.OutOfMemory => unreachable,
    };
    privateSetPendingAbrupt(context, &machine, abrupt);
}

fn privateBunStringToEncoded(
    global: JSContextRef,
    string: *const PrivateBunString,
    max_utf16_units: ?usize,
) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const result = privateBunStringValue(context, string, max_utf16_units) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const encoded = privateEncodedFromValue(context, result);
    if (encoded == .empty) privatePublishBunStringError(context, error.OutOfMemory);
    return encoded;
}

export fn BunString__toJS(global: JSContextRef, string: *const PrivateBunString) callconv(.c) EncodedValue {
    return privateBunStringToEncoded(global, string, null);
}

export fn BunString__toJSWithLength(
    global: JSContextRef,
    string: *const PrivateBunString,
    max_utf16_units: usize,
) callconv(.c) EncodedValue {
    return privateBunStringToEncoded(global, string, max_utf16_units);
}

export fn BunString__transferToJS(string: *PrivateBunString, global: JSContextRef) callconv(.c) EncodedValue {
    const original_tag = string.tag;
    const result = privateBunStringToEncoded(global, string, null);
    if (result == .empty) return .empty;
    if (original_tag == .empty) return result;
    if (original_tag == .wtf_string_impl) Bun__WTFStringImpl__deref(string.value.wtf_string_impl);
    string.* = PrivateBunString.dead();
    return result;
}

export fn BunString__createArray(
    global: JSContextRef,
    strings: [*c]const PrivateBunString,
    len: usize,
) callconv(.c) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null or (strings == null and len != 0)) return .empty;
    if (len == 0) return JSArray__constructEmptyArray(global, 0);
    const encoded = context.arena().alloc(EncodedValue, len) catch {
        privatePublishBunStringError(context, error.OutOfMemory);
        return .empty;
    };
    for (strings[0..len], encoded) |*string, *slot| {
        slot.* = privateBunStringToEncoded(global, string, null);
        if (slot.* == .empty) return .empty;
    }
    return JSArray__constructArray(global, encoded.ptr, encoded.len);
}

fn privateZigStringValue(context: *Context, string: *const PrivateZigString) PrivateBunStringError!Value {
    const bun_string = PrivateBunString{
        .tag = .zig_string,
        .value = .{ .zig_string = string.* },
    };
    return privateBunStringValue(context, &bun_string, null);
}

fn privateZigStringToCopiedValue(
    string: *const PrivateZigString,
    global: JSContextRef,
) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const result = privateZigStringValue(context, string) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const encoded = privateEncodedFromValue(context, result);
    if (encoded == .empty) privatePublishBunStringError(context, error.OutOfMemory);
    return encoded;
}

export fn ZigString__toValueGC(
    string: *const PrivateZigString,
    global: JSContextRef,
) callconv(.c) EncodedValue {
    return privateZigStringToCopiedValue(string, global);
}

fn privateExternalZigString(
    string: *const PrivateZigString,
    global: JSContextRef,
    callback_context: ?*anyopaque,
    callback: strcell.ExternalStringDeallocator,
) EncodedValue {
    const address = string.tagged_ptr & ((@as(usize, 1) << 53) - 1);
    const pointer: ?*anyopaque = if (address == 0) null else @ptrFromInt(address);
    const context = ctxForHandleInspection(global) orelse {
        callback(callback_context, pointer, string.len);
        return .empty;
    };
    const opaque_group = context.c_api_group orelse {
        callback(callback_context, pointer, string.len);
        return .empty;
    };
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) {
        callback(callback_context, pointer, string.len);
        return .empty;
    }

    const owner = context.createExternalStringOwner(pointer, string.len, callback_context, callback) catch {
        callback(callback_context, pointer, string.len);
        privatePublishBunStringError(context, error.OutOfMemory);
        return .empty;
    };
    var attached = false;
    defer {
        if (!attached) _ = owner.release();
    }

    if (string.len > std.math.maxInt(u32)) {
        privatePublishBunStringError(context, error.StringTooLong);
        return .empty;
    }
    if (string.len != 0 and address == 0) {
        privatePublishBunStringError(context, error.InvalidString);
        return .empty;
    }

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    const allocator = if (context.gc != null) context.gpa else context.arena();
    const bytes = if (string.len == 0)
        allocator.alloc(u8, 0) catch {
            privatePublishBunStringError(context, error.OutOfMemory);
            return .empty;
        }
    else if (string.tagged_ptr & (@as(usize, 1) << 63) != 0) blk: {
        const units: [*]align(1) const u16 = @ptrFromInt(address);
        break :blk privateUTF16ToWTF8(allocator, units[0..string.len]) catch {
            privatePublishBunStringError(context, error.OutOfMemory);
            return .empty;
        };
    } else blk: {
        // The pinned JSC bridge treats every non-UTF16 external ZigString as
        // Latin-1; the UTF-8 tag is intentionally not consulted here.
        const source: [*]const u8 = @ptrFromInt(address);
        break :blk privateLatin1ToWTF8(allocator, source[0..string.len]) catch {
            privatePublishBunStringError(context, error.OutOfMemory);
            return .empty;
        };
    };
    const result = Value.strOwned(allocator, bytes) catch {
        privatePublishBunStringError(context, error.OutOfMemory);
        return .empty;
    };
    const cell = @constCast(result.asStringCell());
    cell.setExternalOwner(owner);
    attached = true;

    const encoded = privateEncodedFromValue(context, result);
    if (encoded == .empty) {
        cell.setExternalOwner(null);
        attached = false;
        privatePublishBunStringError(context, error.OutOfMemory);
    }
    return encoded;
}

export fn ZigString__external(
    string: *const PrivateZigString,
    global: JSContextRef,
    callback_context: ?*anyopaque,
    callback: strcell.ExternalStringDeallocator,
) callconv(.c) EncodedValue {
    return privateExternalZigString(string, global, callback_context, callback);
}

export fn ZigString__toExternalValueWithCallback(
    string: *const PrivateZigString,
    global: JSContextRef,
    callback: strcell.ExternalStringDeallocator,
) callconv(.c) EncodedValue {
    return privateExternalZigString(string, global, null, callback);
}

var private_external_u16_release_count: if (builtin.is_test) std.atomic.Value(usize) else void = if (builtin.is_test) .init(0) else {};

fn privateFallbackZigStringFreeGlobal(pointer: [*]const u8, _: usize) callconv(.c) void {
    if (builtin.is_test) _ = private_external_u16_release_count.fetchAdd(1, .monotonic);
    std.c.free(@constCast(pointer));
}

comptime {
    // Home/Bun provide a strong ZigString__freeGlobal backed by their default
    // allocator. Standalone consumers get the same ownership shape through a
    // weak libc fallback, which a real embedder definition overrides at link.
    @export(&privateFallbackZigStringFreeGlobal, .{
        .name = "ZigString__freeGlobal",
        .linkage = .weak,
    });
}

extern fn ZigString__freeGlobal(pointer: [*]const u8, len: usize) callconv(.c) void;

fn privateReleaseExternalU16(_: ?*anyopaque, pointer: ?*anyopaque, len: usize) callconv(.c) void {
    const bytes: [*]const u8 = @ptrCast(pointer orelse return);
    ZigString__freeGlobal(bytes, len);
}

export fn ZigString__toExternalU16(
    pointer: [*]const u16,
    len: usize,
    global: JSContextRef,
) callconv(.c) EncodedValue {
    // Match the pinned JSC bridge: the shared VM empty string owns no external
    // allocation and therefore installs no finalizer for the zero-length case.
    if (len == 0) {
        const context = ctxForHandleInspection(global) orelse return .empty;
        return privateEncodedFromValue(context, Value.staticStr(""));
    }
    const string = PrivateZigString{
        .tagged_ptr = @intFromPtr(pointer) | (@as(usize, 1) << 63),
        .len = len,
    };
    return privateExternalZigString(&string, global, null, privateReleaseExternalU16);
}

export fn ZigString__to16BitValue(
    string: *const PrivateZigString,
    global: JSContextRef,
) callconv(.c) EncodedValue {
    if (string.len == 0) {
        const empty: PrivateZigString = .{};
        return privateZigStringToCopiedValue(&empty, global);
    }
    const address = string.tagged_ptr & ((@as(usize, 1) << 53) - 1);
    if (address == 0) {
        const context = ctxForHandleInspection(global) orelse return .empty;
        privatePublishBunStringError(context, error.InvalidString);
        return .empty;
    }
    const raw: [*]const u8 = @ptrFromInt(address);
    if (!std.unicode.utf8ValidateSlice(raw[0..string.len])) {
        const context = ctxForHandleInspection(global) orelse return .empty;
        privatePublishBunStringError(context, error.InvalidString);
        return .empty;
    }
    const utf8 = PrivateZigString{
        .tagged_ptr = address | (@as(usize, 1) << 61),
        .len = string.len,
    };
    return privateZigStringToCopiedValue(&utf8, global);
}

export fn ZigString__toAtomicValue(
    string: *const PrivateZigString,
    global: JSContextRef,
) callconv(.c) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const copied = privateZigStringValue(context, string) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const cell = group.atom_strings.intern(copied.asStr()) catch {
        privatePublishBunStringError(context, error.OutOfMemory);
        return .empty;
    };
    const encoded = privateEncodedFromValue(context, Value.strCell(cell));
    if (encoded == .empty) privatePublishBunStringError(context, error.OutOfMemory);
    return encoded;
}

export fn JSC__JSValue__createRopeString(
    left_encoded: EncodedValue,
    right_encoded: EncodedValue,
    global: JSContextRef,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const left = privateValueFrom(global, left_encoded) orelse {
        const err = machine.throwError("TypeError", "Rope string value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const left_string = machine.toStringV(left) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const right = privateValueFrom(global, right_encoded) orelse {
        const err = machine.throwError("TypeError", "Rope string value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const right_string = machine.toStringV(right) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const joined = std.mem.concat(context.arena(), u8, &.{ left_string, right_string }) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const result = Value.strOwned(context.arena(), joined) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

fn privateWTF8SurrogateAt(bytes: []const u8, index: usize) ?u16 {
    if (index + 2 >= bytes.len or bytes[index] != 0xed or
        bytes[index + 1] < 0xa0 or bytes[index + 1] > 0xbf or
        bytes[index + 2] & 0xc0 != 0x80)
        return null;
    return @intCast((@as(u21, bytes[index] & 0x0f) << 12) |
        (@as(u21, bytes[index + 1] & 0x3f) << 6) |
        @as(u21, bytes[index + 2] & 0x3f));
}

fn privateWTF8ToUTF16(allocator: std.mem.Allocator, bytes: []const u8) PrivateBunStringError![]u16 {
    const units = try allocator.alloc(u16, interp.Interpreter.utf16LenOfString(bytes));
    errdefer allocator.free(units);
    var input: usize = 0;
    var output: usize = 0;
    while (input < bytes.len) {
        if (privateWTF8SurrogateAt(bytes, input)) |surrogate| {
            units[output] = surrogate;
            input += 3;
            output += 1;
            continue;
        }
        const sequence_len = std.unicode.utf8ByteSequenceLength(bytes[input]) catch return error.InvalidString;
        if (input + sequence_len > bytes.len) return error.InvalidString;
        const codepoint = std.unicode.utf8Decode(bytes[input .. input + sequence_len]) catch return error.InvalidString;
        if (codepoint <= 0xffff) {
            units[output] = @intCast(codepoint);
            output += 1;
        } else {
            const pair = codepoint - 0x10000;
            units[output] = @intCast(0xd800 + (pair >> 10));
            units[output + 1] = @intCast(0xdc00 + (pair & 0x3ff));
            output += 2;
        }
        input += sequence_len;
    }
    std.debug.assert(output == units.len);
    return units;
}

fn privateStringBuilderFromOpaque(raw: ?*anyopaque) ?*PrivateStringBuilder {
    const pointer = raw orelse return null;
    if (@intFromPtr(pointer) % @alignOf(PrivateStringBuilder) != 0) return null;
    const builder: *PrivateStringBuilder = @ptrCast(@alignCast(pointer));
    if (builder.metadata & ~private_string_builder_capacity_mask & ~private_string_builder_overflow !=
        private_string_builder_magic)
        return null;
    const capacity = builder.metadata & private_string_builder_capacity_mask;
    if (builder.length > capacity or (capacity == 0) != (builder.units == null)) return null;
    return builder;
}

fn privateStringBuilderCapacity(builder: *const PrivateStringBuilder) usize {
    return builder.metadata & private_string_builder_capacity_mask;
}

fn privateStringBuilderHasOverflowed(builder: *const PrivateStringBuilder) bool {
    return builder.metadata & private_string_builder_overflow != 0;
}

fn privateStringBuilderDidOverflow(builder: *PrivateStringBuilder) void {
    builder.metadata |= private_string_builder_overflow;
}

fn privateStringBuilderReserve(builder: *PrivateStringBuilder, required: usize) bool {
    if (privateStringBuilderHasOverflowed(builder)) return false;
    if (required > private_string_builder_max_length) {
        privateStringBuilderDidOverflow(builder);
        return false;
    }
    const old_capacity = privateStringBuilderCapacity(builder);
    if (required <= old_capacity) return true;
    const doubled = std.math.mul(usize, old_capacity, 2) catch private_string_builder_max_length;
    const new_capacity = @min(
        private_string_builder_max_length,
        @max(required, @max(@as(usize, 16), doubled)),
    );
    const resized = if (builder.units) |units|
        private_string_allocator.realloc(units[0..old_capacity], new_capacity)
    else
        private_string_allocator.alloc(u16, new_capacity);
    const allocation = resized catch {
        privateStringBuilderDidOverflow(builder);
        return false;
    };
    builder.units = allocation.ptr;
    builder.metadata = private_string_builder_magic |
        (builder.metadata & private_string_builder_overflow) |
        new_capacity;
    return true;
}

fn privateStringBuilderReserveAdditional(builder: *PrivateStringBuilder, additional: usize) bool {
    const required = std.math.add(usize, builder.length, additional) catch {
        privateStringBuilderDidOverflow(builder);
        return false;
    };
    return privateStringBuilderReserve(builder, required);
}

fn privateStringBuilderAppendUnits(builder: *PrivateStringBuilder, units: []align(1) const u16) void {
    if (units.len == 0 or !privateStringBuilderReserveAdditional(builder, units.len)) return;
    const end = builder.length + units.len;
    @memcpy(builder.units.?[builder.length..end], units);
    builder.length = end;
}

fn privateStringBuilderAppendLatin1Slice(builder: *PrivateStringBuilder, bytes: []const u8) void {
    if (bytes.len == 0 or !privateStringBuilderReserveAdditional(builder, bytes.len)) return;
    const start = builder.length;
    for (bytes, builder.units.?[start .. start + bytes.len]) |byte, *unit| unit.* = byte;
    builder.length += bytes.len;
}

/// Bun's tagged UTF-8 path uses `fromUTF8ReplacingInvalidSequences`. Decode to
/// UTF-16 while consuming one byte for every malformed lead/sequence, matching
/// the replacement behavior used elsewhere by this runtime's TextDecoder.
fn privateStringBuilderUTF8ReplacingInvalid(allocator: std.mem.Allocator, bytes: []const u8) error{OutOfMemory}![]u16 {
    const units = try allocator.alloc(u16, bytes.len);
    errdefer allocator.free(units);
    var input: usize = 0;
    var output: usize = 0;
    while (input < bytes.len) {
        const sequence_len = std.unicode.utf8ByteSequenceLength(bytes[input]) catch {
            units[output] = 0xfffd;
            output += 1;
            input += 1;
            continue;
        };
        if (input + sequence_len > bytes.len) {
            units[output] = 0xfffd;
            output += 1;
            input += 1;
            continue;
        }
        const codepoint = std.unicode.utf8Decode(bytes[input .. input + sequence_len]) catch {
            units[output] = 0xfffd;
            output += 1;
            input += 1;
            continue;
        };
        if (codepoint <= 0xffff) {
            units[output] = @intCast(codepoint);
            output += 1;
        } else {
            const pair = codepoint - 0x10000;
            units[output] = @intCast(0xd800 + (pair >> 10));
            units[output + 1] = @intCast(0xdc00 + (pair & 0x3ff));
            output += 2;
        }
        input += sequence_len;
    }
    return allocator.realloc(units, output) catch units[0..output];
}

fn privateStringBuilderBunStringUnits(
    allocator: std.mem.Allocator,
    string: *const PrivateBunString,
) PrivateBunStringError![]u16 {
    switch (string.tag) {
        .dead, .empty => return allocator.alloc(u16, 0),
        .wtf_string_impl => {
            const impl = string.value.wtf_string_impl orelse return allocator.alloc(u16, 0);
            const length: usize = impl.m_length;
            if (length > private_string_builder_max_length) return error.StringTooLong;
            const units = try allocator.alloc(u16, length);
            if (impl.m_hash_and_flags & private_wtf_flag_8_bit_buffer != 0) {
                for (impl.m_ptr[0..length], units) |byte, *unit| unit.* = byte;
            } else {
                const source: [*]align(1) const u16 = @ptrCast(impl.m_ptr);
                @memcpy(units, source[0..length]);
            }
            return units;
        },
        .zig_string, .static_zig_string => {
            const zig_string = string.value.zig_string;
            if (zig_string.len == 0) return allocator.alloc(u16, 0);
            const address = zig_string.tagged_ptr & ((@as(usize, 1) << 53) - 1);
            if (address == 0) return allocator.alloc(u16, 0);
            if (zig_string.len > private_string_builder_max_length) return error.StringTooLong;
            if (zig_string.tagged_ptr & (@as(usize, 1) << 63) != 0) {
                const source: [*]align(1) const u16 = @ptrFromInt(address);
                const units = try allocator.alloc(u16, zig_string.len);
                @memcpy(units, source[0..zig_string.len]);
                return units;
            }
            const source: [*]const u8 = @ptrFromInt(address);
            if (zig_string.tagged_ptr & (@as(usize, 1) << 61) != 0)
                return privateStringBuilderUTF8ReplacingInvalid(allocator, source[0..zig_string.len]);
            const units = try allocator.alloc(u16, zig_string.len);
            for (source[0..zig_string.len], units) |byte, *unit| unit.* = byte;
            return units;
        },
    }
}

/// Yarr operates on UTF-16 code units. Encoding every unit independently as
/// WTF-8 (including each half of a valid surrogate pair) lets zig-regex retain
/// non-Unicode JavaScript matching semantics; its Unicode mode deliberately
/// combines adjacent surrogate encodings into one ECMAScript code point.
fn privateRegularExpressionWTF8(
    allocator: std.mem.Allocator,
    units: []align(1) const u16,
) error{OutOfMemory}![]u8 {
    const capacity = std.math.mul(usize, units.len, 3) catch return error.OutOfMemory;
    const out = try allocator.alloc(u8, capacity);
    var used: usize = 0;
    for (units) |unit| privateAppendWTF8CodeUnit(out, &used, unit);
    return allocator.realloc(out, used) catch out[0..used];
}

fn privateRegularExpressionByteOffset(units: []const u16, unit_offset: usize) usize {
    var result: usize = 0;
    for (units[0..@min(unit_offset, units.len)]) |unit| {
        result += if (unit < 0x80) 1 else if (unit < 0x800) 2 else 3;
    }
    return result;
}

fn privateRegularExpressionUnitOffset(bytes: []const u8, byte_offset: usize) usize {
    var input: usize = 0;
    var units: usize = 0;
    const end = @min(byte_offset, bytes.len);
    while (input < end) : (units += 1) {
        const decoded = regex_mod.unicode.decodeUtf8Lenient(bytes[input..]) orelse {
            input += 1;
            continue;
        };
        input += decoded.len;
    }
    return units;
}

const PrivateRegularExpressionInput = struct {
    units: []u16,
    bytes: []u8,

    fn deinit(self: PrivateRegularExpressionInput) void {
        private_string_allocator.free(self.bytes);
        private_string_allocator.free(self.units);
    }
};

fn privateRegularExpressionInput(
    string: *const PrivateBunString,
) PrivateBunStringError!?PrivateRegularExpressionInput {
    // BunString::toWTFString(ZeroCopy) yields a null WTF::String for Dead,
    // Empty, and all zero-length ZigStrings. RegularExpression::match rejects
    // null strings before executing even a zero-width pattern.
    if (string.tag == .dead or string.tag == .empty) return null;
    switch (string.tag) {
        .wtf_string_impl => if (string.value.wtf_string_impl == null) return null,
        .zig_string, .static_zig_string => if (string.value.zig_string.len == 0) return null,
        else => unreachable,
    }

    const units = try privateStringBuilderBunStringUnits(private_string_allocator, string);
    errdefer private_string_allocator.free(units);
    if (units.len == 0) return null;
    const bytes = try privateRegularExpressionWTF8(private_string_allocator, units);
    return .{ .units = units, .bytes = bytes };
}

fn privateRegularExpressionFromOpaque(raw: ?*anyopaque) ?*PrivateRegularExpression {
    const pointer = raw orelse return null;
    if (@intFromPtr(pointer) % @alignOf(PrivateRegularExpression) != 0) return null;
    const expression: *PrivateRegularExpression = @ptrCast(@alignCast(pointer));
    if (expression.magic != private_regular_expression_magic) return null;
    return expression;
}

const PrivateRegularExpressionMatch = struct {
    position: usize,
    length: usize,
};

fn privateRegularExpressionFind(
    expression: *PrivateRegularExpression,
    input: *const PrivateRegularExpressionInput,
    start_units: usize,
) ?PrivateRegularExpressionMatch {
    const compiled = if (expression.compiled) |*compiled_regex| compiled_regex else return null;
    if (start_units > input.units.len) return null;
    const start_byte = privateRegularExpressionByteOffset(input.units, start_units);
    var found = (compiled.findFrom(input.bytes, start_byte) catch return null) orelse return null;
    defer found.deinit(private_string_allocator);
    if (expression.sticky and found.start != start_byte) return null;
    const position = privateRegularExpressionUnitOffset(input.bytes, found.start);
    const end = privateRegularExpressionUnitOffset(input.bytes, found.end);
    return .{ .position = position, .length = end - position };
}

export fn Yarr__RegularExpression__init(
    pattern: PrivateBunString,
    raw_flags: u16,
) callconv(.c) ?*anyopaque {
    const expression = private_string_allocator.create(PrivateRegularExpression) catch return null;
    expression.* = .{ .sticky = raw_flags & (@as(u16, 1) << 7) != 0 };

    const units = privateStringBuilderBunStringUnits(private_string_allocator, &pattern) catch |err| {
        if (err == error.OutOfMemory) {
            private_string_allocator.destroy(expression);
            return null;
        }
        return expression;
    };
    defer private_string_allocator.free(units);
    const bytes = privateRegularExpressionWTF8(private_string_allocator, units) catch {
        private_string_allocator.destroy(expression);
        return null;
    };
    defer private_string_allocator.free(bytes);

    const unicode_sets = raw_flags & (@as(u16, 1) << 6) != 0;
    expression.compiled = regex_mod.Regex.compileWithFlags(private_string_allocator, bytes, .{
        .case_insensitive = raw_flags & (@as(u16, 1) << 2) != 0,
        .multiline = raw_flags & (@as(u16, 1) << 3) != 0,
        .dot_all = raw_flags & (@as(u16, 1) << 4) != 0,
        .unicode = raw_flags & (@as(u16, 1) << 5) != 0 or unicode_sets,
        .unicode_sets = unicode_sets,
        .ecmascript = true,
    }) catch |err| {
        if (err == error.OutOfMemory) {
            private_string_allocator.destroy(expression);
            return null;
        }
        return expression;
    };
    return expression;
}

export fn Yarr__RegularExpression__deinit(raw: ?*anyopaque) callconv(.c) void {
    const expression = privateRegularExpressionFromOpaque(raw) orelse return;
    if (expression.compiled) |*compiled| compiled.deinit();
    expression.magic = 0;
    private_string_allocator.destroy(expression);
}

export fn Yarr__RegularExpression__isValid(raw: ?*anyopaque) callconv(.c) bool {
    const expression = privateRegularExpressionFromOpaque(raw) orelse return false;
    return expression.compiled != null;
}

export fn Yarr__RegularExpression__matchedLength(raw: ?*anyopaque) callconv(.c) i32 {
    const expression = privateRegularExpressionFromOpaque(raw) orelse return -1;
    return expression.last_match_length;
}

export fn Yarr__RegularExpression__matches(
    raw: ?*anyopaque,
    string: PrivateBunString,
) callconv(.c) i32 {
    const expression = privateRegularExpressionFromOpaque(raw) orelse return -1;
    expression.last_match_length = -1;
    const input = (privateRegularExpressionInput(&string) catch return -1) orelse return -1;
    defer input.deinit();
    const found = privateRegularExpressionFind(expression, &input, 0) orelse return -1;
    expression.last_match_length = @intCast(found.length);
    return @intCast(found.position);
}

/// The pinned Zig declaration accidentally omits `string`; Bun's C++ and Rust
/// bindings expose this real two-argument executable ABI.
export fn Yarr__RegularExpression__searchRev(
    raw: ?*anyopaque,
    string: PrivateBunString,
) callconv(.c) i32 {
    const expression = privateRegularExpressionFromOpaque(raw) orelse return -1;
    expression.last_match_length = -1;
    const input = (privateRegularExpressionInput(&string) catch return -1) orelse return -1;
    defer input.deinit();

    var start: usize = 0;
    var last: ?PrivateRegularExpressionMatch = null;
    while (privateRegularExpressionFind(expression, &input, start)) |found| {
        if (last == null or found.position + found.length > last.?.position + last.?.length)
            last = found;
        start = found.position + 1;
    }
    const result = last orelse return -1;
    expression.last_match_length = @intCast(result.length);
    return @intCast(result.position);
}

export fn WTF__parseDouble(bytes: [*]const u8, length: usize, counted: *usize) callconv(.c) f64 {
    counted.* = 0;
    const input = bytes[0..length];
    var index: usize = 0;
    if (index < input.len and (input[index] == '+' or input[index] == '-')) index += 1;

    var saw_digit = false;
    while (index < input.len and std.ascii.isDigit(input[index])) : (index += 1) saw_digit = true;
    if (index < input.len and input[index] == '.') {
        index += 1;
        while (index < input.len and std.ascii.isDigit(input[index])) : (index += 1) saw_digit = true;
    }
    if (!saw_digit) return 0;

    if (index < input.len and (input[index] == 'e' or input[index] == 'E')) {
        var exponent_end = index + 1;
        if (exponent_end < input.len and (input[exponent_end] == '+' or input[exponent_end] == '-'))
            exponent_end += 1;
        const exponent_start = exponent_end;
        while (exponent_end < input.len and std.ascii.isDigit(input[exponent_end])) : (exponent_end += 1) {}
        if (exponent_end != exponent_start) index = exponent_end;
    }

    const result = std.fmt.parseFloat(f64, input[0..index]) catch return 0;
    counted.* = index;
    return result;
}

fn privateES5DateInteger(input: []const u8, index: *usize, minimum: i64, maximum: i64) ?i64 {
    while (index.* < input.len and switch (input[index.*]) {
        ' ', '\t', '\n', '\r', 0x0b, 0x0c => true,
        else => false,
    }) index.* += 1;
    if (index.* < input.len and input[index.*] == '+') index.* += 1;
    var negative = false;
    if (index.* < input.len and input[index.*] == '-') {
        negative = true;
        index.* += 1;
    }
    const digit_start = index.*;
    var magnitude: i128 = 0;
    while (index.* < input.len and std.ascii.isDigit(input[index.*])) : (index.* += 1) {
        const digit: i128 = input[index.*] - '0';
        const limit = @as(i128, std.math.maxInt(i64)) + 1;
        if (magnitude > @divTrunc(limit - digit, 10)) return null;
        magnitude = magnitude * 10 + digit;
    }
    if (index.* == digit_start) return null;
    const signed = if (negative) -magnitude else magnitude;
    if (signed <= minimum or signed >= maximum) return null;
    return @intCast(signed);
}

fn privateES5LeapYear(year: i64) bool {
    return @mod(year, 4) == 0 and (@mod(year, 100) != 0 or @mod(year, 400) == 0);
}

fn privateES5DaysFromCivil(year_input: i64, month: i64, day: i64) i64 {
    const year = year_input - @as(i64, if (month <= 2) 1 else 0);
    const era = @divTrunc(if (year >= 0) year else year - 399, 400);
    const year_of_era = year - era * 400;
    const shifted_month = if (month > 2) month - 3 else month + 9;
    const day_of_year = @divFloor(153 * shifted_month + 2, 5) + day - 1;
    const day_of_era = year_of_era * 365 + @divFloor(year_of_era, 4) -
        @divFloor(year_of_era, 100) + day_of_year;
    return era * 146097 + day_of_era - 719468;
}

fn privateParseES5Date(input: []const u8) f64 {
    const nan = std.math.nan(f64);
    var index: usize = 0;
    const negative_year = input.len != 0 and input[0] == '-';
    const year = privateES5DateInteger(input, &index, std.math.minInt(i32), std.math.maxInt(i32)) orelse return nan;
    if (year == 0 and negative_year) return nan;

    var month: i64 = 1;
    var day: i64 = 1;
    var single_digit = false;
    if (index < input.len and input[index] == '-') {
        index += 1;
        if (index >= input.len or !std.ascii.isDigit(input[index])) return nan;
        const start = index;
        month = privateES5DateInteger(input, &index, std.math.minInt(i64), std.math.maxInt(i64)) orelse return nan;
        const digits = index - start;
        if (digits == 1) single_digit = true else if (digits != 2) return nan;
        if (index < input.len and input[index] == '-') {
            index += 1;
            if (index >= input.len or !std.ascii.isDigit(input[index])) return nan;
            const day_start = index;
            day = privateES5DateInteger(input, &index, std.math.minInt(i64), std.math.maxInt(i64)) orelse return nan;
            const day_digits = index - day_start;
            if (day_digits == 1) single_digit = true else if (day_digits != 2) return nan;
        }
    }

    var hours: i64 = 0;
    var minutes: i64 = 0;
    var seconds: i64 = 0;
    var milliseconds: f64 = 0;
    var timezone_seconds: i64 = 0;
    if (index < input.len and (input[index] == 'T' or input[index] == 't' or input[index] == ' ')) {
        const has_t = input[index] == 'T' or input[index] == 't';
        index += 1;
        if (single_digit and has_t) return nan;
        if (index >= input.len or !std.ascii.isDigit(input[index])) return nan;

        var start = index;
        hours = privateES5DateInteger(input, &index, std.math.minInt(i64), std.math.maxInt(i64)) orelse return nan;
        if (index >= input.len or input[index] != ':' or (has_t and index - start != 2)) return nan;
        index += 1;
        if (index >= input.len or !std.ascii.isDigit(input[index])) return nan;
        start = index;
        minutes = privateES5DateInteger(input, &index, std.math.minInt(i64), std.math.maxInt(i64)) orelse return nan;
        if (has_t and index - start != 2) return nan;

        if (index < input.len and input[index] == ':') {
            index += 1;
            if (index >= input.len or !std.ascii.isDigit(input[index])) return nan;
            start = index;
            seconds = privateES5DateInteger(input, &index, std.math.minInt(i64), std.math.maxInt(i64)) orelse return nan;
            if (has_t and index - start != 2) return nan;
            if (index < input.len and input[index] == '.') {
                index += 1;
                if (index >= input.len or !std.ascii.isDigit(input[index])) return nan;
                const fraction_start = index;
                const fraction = privateES5DateInteger(input, &index, std.math.minInt(i64), std.math.maxInt(i64)) orelse return nan;
                const fraction_digits: i32 = @intCast(index - fraction_start);
                milliseconds = @as(f64, @floatFromInt(fraction)) * std.math.pow(f64, 10, @as(f64, @floatFromInt(3 - fraction_digits)));
            }
        }

        if (index < input.len and input[index] == 'Z') {
            index += 1;
        } else if (index < input.len and (input[index] == '+' or input[index] == '-')) {
            const timezone_negative = input[index] == '-';
            index += 1;
            if (index >= input.len or !std.ascii.isDigit(input[index])) return nan;
            const timezone_start = index;
            const timezone = privateES5DateInteger(input, &index, std.math.minInt(i64), std.math.maxInt(i64)) orelse return nan;
            const timezone_digits = index - timezone_start;
            var timezone_hours: i64 = undefined;
            var timezone_minutes: i64 = 0;
            if (index < input.len and input[index] == ':') {
                if (has_t and timezone_digits != 2) return nan;
                timezone_hours = timezone;
                index += 1;
                if (index >= input.len or !std.ascii.isDigit(input[index])) return nan;
                const minute_start = index;
                timezone_minutes = privateES5DateInteger(input, &index, std.math.minInt(i64), std.math.maxInt(i64)) orelse return nan;
                if (has_t and index - minute_start != 2) return nan;
            } else if (!has_t and timezone_digits == 2) {
                timezone_hours = timezone;
            } else if (timezone_digits == 4) {
                timezone_hours = @divTrunc(timezone, 100);
                timezone_minutes = @mod(timezone, 100);
            } else return nan;
            if (timezone_hours > 23 or timezone_minutes < 0 or timezone_minutes > 59) return nan;
            timezone_seconds = 60 * (timezone_minutes + 60 * timezone_hours);
            if (timezone_negative) timezone_seconds = -timezone_seconds;
        }
    }

    if (index != input.len) return nan;
    const days_per_month = [_]i64{ 31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31 };
    if (month < 1 or month > 12) return nan;
    if (day < 1 or day > days_per_month[@intCast(month - 1)]) return nan;
    if (month == 2 and day > 28 and !privateES5LeapYear(year)) return nan;
    if (hours < 0 or hours > 24 or minutes < 0 or minutes > 59 or seconds < 0 or seconds >= 61) return nan;
    if (hours == 24 and (minutes != 0 or seconds != 0)) return nan;
    if (seconds == 60) milliseconds = 0;

    const day_value: f64 = @floatFromInt(privateES5DaysFromCivil(year, month, day));
    return day_value * 86_400_000.0 + @as(f64, @floatFromInt(hours)) * 3_600_000.0 +
        @as(f64, @floatFromInt(minutes)) * 60_000.0 + @as(f64, @floatFromInt(seconds)) * 1_000.0 +
        milliseconds - @as(f64, @floatFromInt(timezone_seconds)) * 1_000.0;
}

export fn WTF__parseES5Date(bytes: [*]const u8, length: usize) callconv(.c) f64 {
    return privateParseES5Date(bytes[0..length]);
}

export fn WTF__numberOfProcessorCores() callconv(.c) c_int {
    const count = std.Thread.getCpuCount() catch 1;
    return @intCast(@max(1, @min(count, @as(usize, std.math.maxInt(c_int)))));
}

/// zig-js does not use WTF FastMalloc and retains no per-thread FastMalloc
/// cache, so the release request is already satisfied when it reaches us.
export fn WTF__releaseFastMallocFreeMemoryForThisThread() callconv(.c) void {}

export fn Bun__writeHTTPDate(buffer: *[32]u8, length: usize, timestamp_ms: u64) callconv(.c) c_int {
    if (timestamp_ms == 0) return 0;
    const seconds = timestamp_ms / 1000;
    const max_epoch_seconds: u64 = @intCast(privateES5DaysFromCivil(std.math.maxInt(std.time.epoch.Year), 12, 31) *
        std.time.epoch.secs_per_day + (std.time.epoch.secs_per_day - 1));
    if (seconds > max_epoch_seconds) return -1;
    const epoch_seconds = std.time.epoch.EpochSeconds{ .secs = seconds };
    const year_day = epoch_seconds.getEpochDay().calculateYearDay();
    const month_day = year_day.calculateMonthDay();
    const day_seconds = epoch_seconds.getDaySeconds();
    const weekday_names = [_][]const u8{ "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" };
    const month_names = [_][]const u8{ "Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec" };
    const weekday: usize = @intCast(@mod(epoch_seconds.getEpochDay().day + 4, 7));
    var rendered_storage: [31]u8 = undefined;
    const rendered = std.fmt.bufPrint(&rendered_storage, "{s}, {d:0>2} {s} {d:0>4} {d:0>2}:{d:0>2}:{d:0>2} GMT", .{
        weekday_names[weekday],
        month_day.day_index + 1,
        month_names[@intFromEnum(month_day.month) - 1],
        @as(u32, year_day.year) % 9999,
        day_seconds.getHoursIntoDay(),
        day_seconds.getMinutesIntoHour(),
        day_seconds.getSecondsIntoMinute(),
    }) catch return -1;
    const writable = @min(length, buffer.len);
    if (writable != 0) {
        const copied = @min(rendered.len, writable - 1);
        @memcpy(buffer[0..copied], rendered[0..copied]);
        buffer[copied] = 0;
    }
    return @intCast(rendered.len);
}

fn privateStringBuilderAppendBunString(builder: *PrivateStringBuilder, string: *const PrivateBunString) void {
    const units = privateStringBuilderBunStringUnits(private_string_allocator, string) catch {
        privateStringBuilderDidOverflow(builder);
        return;
    };
    defer private_string_allocator.free(units);
    privateStringBuilderAppendUnits(builder, units);
}

fn privateStringBuilderHexDigit(nibble: u16) u16 {
    return if (nibble < 10) '0' + nibble else 'a' + (nibble - 10);
}

fn privateStringBuilderAppendQuoted(builder: *PrivateStringBuilder, string: *const PrivateBunString) void {
    const units = privateStringBuilderBunStringUnits(private_string_allocator, string) catch {
        privateStringBuilderDidOverflow(builder);
        return;
    };
    defer private_string_allocator.free(units);

    const worst_content = std.math.mul(usize, units.len, 6) catch {
        privateStringBuilderDidOverflow(builder);
        return;
    };
    const worst_total = std.math.add(usize, worst_content, 2) catch {
        privateStringBuilderDidOverflow(builder);
        return;
    };
    if (!privateStringBuilderReserveAdditional(builder, worst_total)) return;

    var output = builder.length;
    const destination = builder.units.?;
    destination[output] = '"';
    output += 1;
    var index: usize = 0;
    while (index < units.len) : (index += 1) {
        const unit = units[index];
        const short_escape: ?u16 = switch (unit) {
            '"' => '"',
            '\\' => '\\',
            0x08 => 'b',
            0x09 => 't',
            0x0a => 'n',
            0x0c => 'f',
            0x0d => 'r',
            else => null,
        };
        if (short_escape) |escaped| {
            destination[output] = '\\';
            destination[output + 1] = escaped;
            output += 2;
            continue;
        }
        if (unit < 0x20) {
            destination[output] = '\\';
            destination[output + 1] = 'u';
            destination[output + 2] = '0';
            destination[output + 3] = '0';
            destination[output + 4] = privateStringBuilderHexDigit(unit >> 4);
            destination[output + 5] = privateStringBuilderHexDigit(unit & 0xf);
            output += 6;
            continue;
        }
        if (unit >= 0xd800 and unit <= 0xdfff) {
            const valid_pair = unit <= 0xdbff and index + 1 < units.len and
                units[index + 1] >= 0xdc00 and units[index + 1] <= 0xdfff;
            if (valid_pair) {
                destination[output] = unit;
                destination[output + 1] = units[index + 1];
                output += 2;
                index += 1;
                continue;
            }
            destination[output] = '\\';
            destination[output + 1] = 'u';
            destination[output + 2] = privateStringBuilderHexDigit((unit >> 12) & 0xf);
            destination[output + 3] = privateStringBuilderHexDigit((unit >> 8) & 0xf);
            destination[output + 4] = privateStringBuilderHexDigit((unit >> 4) & 0xf);
            destination[output + 5] = privateStringBuilderHexDigit(unit & 0xf);
            output += 6;
            continue;
        }
        destination[output] = unit;
        output += 1;
    }
    destination[output] = '"';
    output += 1;
    builder.length = output;
}

export fn StringBuilder__init(raw: ?*anyopaque) callconv(.c) void {
    const pointer = raw orelse return;
    if (@intFromPtr(pointer) % @alignOf(PrivateStringBuilder) != 0) return;
    const builder: *PrivateStringBuilder = @ptrCast(@alignCast(pointer));
    builder.* = .{ .metadata = private_string_builder_magic };
}

export fn StringBuilder__deinit(raw: ?*anyopaque) callconv(.c) void {
    const builder = privateStringBuilderFromOpaque(raw) orelse return;
    if (builder.units) |units| private_string_allocator.free(units[0..privateStringBuilderCapacity(builder)]);
    builder.* = .{};
}

export fn StringBuilder__ensureUnusedCapacity(raw: ?*anyopaque, additional: usize) callconv(.c) void {
    const builder = privateStringBuilderFromOpaque(raw) orelse return;
    _ = privateStringBuilderReserveAdditional(builder, additional);
}

export fn StringBuilder__appendLatin1(raw: ?*anyopaque, characters: [*c]const u8, len: usize) callconv(.c) void {
    const builder = privateStringBuilderFromOpaque(raw) orelse return;
    if (characters == null and len != 0) return privateStringBuilderDidOverflow(builder);
    privateStringBuilderAppendLatin1Slice(builder, characters[0..len]);
}

export fn StringBuilder__appendUtf16(raw: ?*anyopaque, characters: [*c]const u16, len: usize) callconv(.c) void {
    const builder = privateStringBuilderFromOpaque(raw) orelse return;
    if (characters == null and len != 0) return privateStringBuilderDidOverflow(builder);
    privateStringBuilderAppendUnits(builder, characters[0..len]);
}

