export fn StringBuilder__toString(raw: ?*anyopaque, global: JSContextRef) callconv(.c) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const builder = privateStringBuilderFromOpaque(raw) orelse return .empty;
    if (privateStringBuilderHasOverflowed(builder)) {
        privatePublishBunStringError(context, error.OutOfMemory);
        return .empty;
    }
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    const units: []const u16 = if (builder.units) |pointer| pointer[0..builder.length] else &.{};
    const allocator = if (context.gc != null) context.gpa else context.arena();
    const bytes = privateUTF16ToWTF8(allocator, units) catch {
        privatePublishBunStringError(context, error.OutOfMemory);
        return .empty;
    };
    const result = Value.strOwned(allocator, bytes) catch {
        privatePublishBunStringError(context, error.OutOfMemory);
        return .empty;
    };
    const encoded = privateEncodedFromValue(context, result);
    if (encoded == .empty) privatePublishBunStringError(context, error.OutOfMemory);
    return encoded;
}

fn privateInternZigStringView(
    views: *std.StringHashMapUnmanaged(PrivateZigStringView),
    bytes: []const u8,
) PrivateBunStringError!PrivateZigString {
    if (bytes.len == 0) return .{ .tagged_ptr = @intFromPtr("".ptr), .len = 0 };
    if (views.get(bytes)) |view| return view.result;

    const units = try privateWTF8ToUTF16(gpa, bytes);
    var owns_units = true;
    errdefer if (owns_units) gpa.free(units);
    const view: PrivateZigStringView = if (interp.Interpreter.jsStringIs8Bit(bytes)) latin1: {
        const latin1_bytes = try gpa.alloc(u8, units.len);
        errdefer gpa.free(latin1_bytes);
        for (units, latin1_bytes) |unit, *byte| byte.* = @intCast(unit);
        gpa.free(units);
        owns_units = false;
        break :latin1 .{
            .result = .{ .tagged_ptr = @intFromPtr(latin1_bytes.ptr), .len = latin1_bytes.len },
            .storage = .{ .latin1 = latin1_bytes },
        };
    } else .{
        .result = .{ .tagged_ptr = @intFromPtr(units.ptr) | (@as(usize, 1) << 63), .len = units.len },
        .storage = .{ .utf16 = units },
    };
    owns_units = false;
    errdefer switch (view.storage) {
        .latin1 => |storage| gpa.free(storage),
        .utf16 => |storage| gpa.free(storage),
    };
    const key = try gpa.dupe(u8, bytes);
    errdefer gpa.free(key);
    try views.put(gpa, key, view);
    return view.result;
}

fn privateBorrowedZigStringView(
    group: *CContextGroup,
    bytes: []const u8,
) PrivateBunStringError!PrivateZigString {
    return privateInternZigStringView(&group.zig_string_views, bytes);
}

/// Process-global borrowed-view store for the context-free `WebCore__DOMURL__*`
/// getters: Bun's ZigString views borrow the DOMURL's own WTF strings, so the
/// bytes must outlive the call without a free hook. Same latin1/UTF-16
/// conversion as the group-level store, mutex-guarded because it is not
/// thread-affine.
var private_global_zig_string_views: std.StringHashMapUnmanaged(PrivateZigStringView) = .empty;
var private_global_zig_string_views_mutex: std.atomic.Mutex = .unlocked;

fn privateGlobalZigStringView(bytes: []const u8) PrivateBunStringError!PrivateZigString {
    while (!private_global_zig_string_views_mutex.tryLock()) {}
    defer private_global_zig_string_views_mutex.unlock();
    return privateInternZigStringView(&private_global_zig_string_views, bytes);
}

export fn JSC__JSString__toZigString(
    cell: ?*anyopaque,
    global: JSContextRef,
    output: *PrivateZigString,
) callconv(.c) void {
    output.* = .{};
    const context = ctxForHandleInspection(global) orelse return;
    const opaque_group = context.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return;
    const boxed = privateStringBoxFromCell(cell) orelse return;
    if (boxed.owner.c_api_group != context.c_api_group) return;
    output.* = privateBorrowedZigStringView(group, boxed.value.asStr()) catch |err| {
        privatePublishBunStringError(context, err);
        return;
    };
}

export fn JSC__JSString__iterator(
    cell: ?*anyopaque,
    global: JSContextRef,
    raw_iterator: ?*anyopaque,
) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const opaque_group = context.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return;
    const raw = raw_iterator orelse return;
    if (@intFromPtr(raw) % @alignOf(PrivateJSStringIterator) != 0) return;
    const iterator: *PrivateJSStringIterator = @ptrCast(@alignCast(raw));
    if (iterator.stop != 0) return;
    const boxed = privateStringBoxFromCell(cell) orelse return;
    if (boxed.owner.c_api_group != context.c_api_group) return;
    const view = privateBorrowedZigStringView(group, boxed.value.asStr()) catch |err| {
        privatePublishBunStringError(context, err);
        return;
    };
    const address = view.tagged_ptr & ((@as(usize, 1) << 53) - 1);
    if (address == 0 or view.len > std.math.maxInt(u32)) return;
    if (view.tagged_ptr & (@as(usize, 1) << 63) != 0) {
        const callback = iterator.append16 orelse return;
        callback(iterator, @ptrFromInt(address), @intCast(view.len));
    } else {
        const callback = iterator.append8 orelse return;
        callback(iterator, @ptrFromInt(address), @intCast(view.len));
    }
}

export fn JSC__JSValue__toZigString(
    encoded: EncodedValue,
    output: *PrivateZigString,
    global: JSContextRef,
) callconv(.c) void {
    output.* = .{};
    const context = ctxForEvaluation(global) orelse return;
    const opaque_group = context.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return;

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "String value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const bytes = machine.toStringV(internal) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    output.* = privateBorrowedZigStringView(group, bytes) catch |err| {
        privatePublishBunStringError(context, err);
        return;
    };
}

fn privateZigStringErrorInstance(
    string: *const PrivateZigString,
    global: JSContextRef,
    comptime error_name: []const u8,
) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;

    const bun_string = PrivateBunString{
        .tag = .zig_string,
        .value = .{ .zig_string = string.* },
    };
    const message_value = privateBunStringValue(context, &bun_string, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const result = machine.makeError(error_name, message_value.asStr()) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

export fn ZigString__toErrorInstance(string: *const PrivateZigString, global: JSContextRef) callconv(.c) EncodedValue {
    return privateZigStringErrorInstance(string, global, "Error");
}

export fn ZigString__toTypeErrorInstance(string: *const PrivateZigString, global: JSContextRef) callconv(.c) EncodedValue {
    return privateZigStringErrorInstance(string, global, "TypeError");
}

export fn ZigString__toRangeErrorInstance(string: *const PrivateZigString, global: JSContextRef) callconv(.c) EncodedValue {
    return privateZigStringErrorInstance(string, global, "RangeError");
}

export fn ZigString__toSyntaxErrorInstance(string: *const PrivateZigString, global: JSContextRef) callconv(.c) EncodedValue {
    return privateZigStringErrorInstance(string, global, "SyntaxError");
}

/// Bun's pinned JSON bridge returns a parse exception as an ordinary value and
/// clears the transient VM throw. This differs deliberately from both
/// `JSON.parse` and the public `JSValueMakeFromJSONString` failure contracts.
export fn ZigString__toJSONObject(
    string: *const PrivateZigString,
    global: JSContextRef,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    if (string.len > std.math.maxInt(u32)) {
        const too_long = machine.makeError("Error", "Cannot parse a JSON string longer than 2^32-1 characters") catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
        privateSetErrorCodeWithAttributes(&machine, too_long, "ERR_STRING_TOO_LONG", true) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
        return privateEncodeResult(context, &machine, too_long);
    }
    const input = privateZigStringValue(context, string) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const parsed = builtins.jsonParse(&machine, Value.undef(), &.{input}) catch |err| {
        const thrown = if (err == error.Throw)
            machine.exception
        else
            machine.makeError("OutOfMemoryError", "Out of memory") catch {
                privateSetPendingAbrupt(context, &machine, err);
                return .empty;
            };
        machine.exception = Value.undef();
        return privateEncodeResult(context, &machine, thrown);
    };
    return privateEncodeResult(context, &machine, parsed);
}

fn privateZigStringErrorWithCode(
    message: *const PrivateZigString,
    code: *const PrivateZigString,
    global: JSContextRef,
    comptime error_name: []const u8,
    comptime code_writable: bool,
) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const message_value = privateZigStringValue(context, message) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const code_value = privateZigStringValue(context, code) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const result = machine.makeError(error_name, message_value.asStr()) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    privateSetErrorCodeWithAttributes(&machine, result, code_value.asStr(), code_writable) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

export fn JSC__JSValue__createTypeError(
    message: *const PrivateZigString,
