/// JSC's `PropertyAttribute::DontDelete | 0`: writable and enumerable, but not
/// configurable. The pinned SystemError bridge stamps every system field with
/// exactly these attributes.
const private_dont_delete_attr: value.PropAttr = .{
    .writable = true,
    .enumerable = true,
    .configurable = false,
};

/// Install one optional SystemError string field as a DontDelete own data
/// property. A `.empty` tag installs nothing; a conversion failure clears and
/// skips the field, matching the pinned `scope.clearException()` fall-through.
fn privateSystemErrorInstallField(
    context: *Context,
    machine: *interp.Interpreter,
    object: *Object,
    comptime name: []const u8,
    string: *const PrivateBunString,
) error{OutOfMemory}!void {
    if (string.tag == .empty) return;
    const field = privateBunStringValue(context, string, null) catch return;
    try object.setOwn(machine.arena, machine.root_shape, name, field);
    try object.setAttr(machine.arena, name, private_dont_delete_attr);
}

fn privateSystemErrorNumber(
    machine: *interp.Interpreter,
    object: *Object,
    comptime name: []const u8,
    number: c_int,
) error{OutOfMemory}!void {
    try object.setOwn(machine.arena, machine.root_shape, name, Value.num(@floatFromInt(number)));
    try object.setAttr(machine.arena, name, private_dont_delete_attr);
}

/// Install one already-materialized SystemError value as a DontDelete own data
/// property. The info-object bridge converts each BunString once (an `.empty`
/// tag becomes the empty string) and reuses that exact value on both the error
/// and its `info` object, so installation is unconditional.
fn privateSystemErrorInstallValue(
    machine: *interp.Interpreter,
    object: *Object,
    comptime name: []const u8,
    field: Value,
) error{OutOfMemory}!void {
    try object.setOwn(machine.arena, machine.root_shape, name, field);
    try object.setAttr(machine.arena, name, private_dont_delete_attr);
}

/// The pinned Bun `SystemError__toErrorInstance` bridge: an ordinary `Error`
/// carrying the exact message plus the populated system fields, in pinned
/// insertion order (`code`, `path`, `dest`, `fd`, `syscall`, `hostname`,
/// `errno`). Field reads never run user code, and an already-pending VM
/// exception is preserved untouched.
export fn SystemError__toErrorInstance(this: ?*const PrivateSystemError, global: JSContextRef) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null or this == null) return .empty;
    const system_error = this.?;
    const message_value = privateBunStringValue(context, &system_error.message, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const result = machine.makeError("Error", message_value.asStr()) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const object = result.asObj();
    // JSC materializes an own `message` property even for the empty string;
    // makeError only installs one for non-empty messages.
    if (message_value.asStr().len == 0) {
        object.setOwn(machine.arena, machine.root_shape, "message", Value.staticStr("")) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
        object.setAttr(machine.arena, "message", .{
            .writable = true,
            .enumerable = false,
            .configurable = true,
        }) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
    }
    inline for (.{ "code", "path", "dest" }) |name| {
        privateSystemErrorInstallField(context, &machine, object, name, &@field(system_error, name)) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
    }
    if (system_error.fd >= 0) {
        privateSystemErrorNumber(&machine, object, "fd", system_error.fd) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
    }
    inline for (.{ "syscall", "hostname" }) |name| {
        privateSystemErrorInstallField(context, &machine, object, name, &@field(system_error, name)) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
    }
    privateSystemErrorNumber(&machine, object, "errno", system_error.errno) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

/// The pinned Bun `SystemError__toErrorInstanceWithInfoObject` bridge: the
/// `node:os` `ERR_SYSTEM_ERROR` shape. The error is named `SystemError` with a
/// non-enumerable `code`, the composed summary message, and a plain `info`
/// object carrying `code`/`syscall`/`message`/`errno`; `syscall` and `errno`
/// also land on the error itself. All system fields are DontDelete.
export fn SystemError__toErrorInstanceWithInfoObject(this: ?*const PrivateSystemError, global: JSContextRef) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null or this == null) return .empty;
    const system_error = this.?;
    const code_value = privateBunStringValue(context, &system_error.code, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const syscall_value = privateBunStringValue(context, &system_error.syscall, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const message_value = privateBunStringValue(context, &system_error.message, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const summary = std.fmt.allocPrint(
        context.arena(),
        "A system error occurred: {s} returned {s} ({s})",
        .{ syscall_value.asStr(), code_value.asStr(), message_value.asStr() },
    ) catch {
        privatePublishBunStringError(context, error.OutOfMemory);
        return .empty;
    };

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const result = machine.makeError("Error", summary) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const object = result.asObj();
    const dont_enum_attr: value.PropAttr = .{
        .writable = true,
        .enumerable = false,
        .configurable = true,
    };
    object.setOwn(machine.arena, machine.root_shape, "name", Value.staticStr("SystemError")) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    object.setAttr(machine.arena, "name", dont_enum_attr) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    object.setOwn(machine.arena, machine.root_shape, "code", Value.staticStr("ERR_SYSTEM_ERROR")) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    object.setAttr(machine.arena, "code", dont_enum_attr) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const info = machine.newObject() catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const info_object = info.asObj();
    privateSystemErrorInstallValue(&machine, info_object, "code", code_value) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    // The pinned bridge installs `info.code` before exposing `info`, so the
    // error's own order is name, code, info, syscall, errno.
    object.setOwn(machine.arena, machine.root_shape, "info", info) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    object.setAttr(machine.arena, "info", private_dont_delete_attr) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    privateSystemErrorInstallValue(&machine, object, "syscall", syscall_value) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    privateSystemErrorInstallValue(&machine, info_object, "syscall", syscall_value) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    privateSystemErrorInstallValue(&machine, info_object, "message", message_value) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    privateSystemErrorNumber(&machine, info_object, "errno", system_error.errno) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    privateSystemErrorNumber(&machine, object, "errno", system_error.errno) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

fn privateMakeAggregateError(
    machine: *interp.Interpreter,
    errors: Value,
    message: []const u8,
    cause: Value,
) !Value {
    const result = try machine.makeError("AggregateError", message);
    const object = result.asObj();
    try object.setOwn(machine.arena, machine.root_shape, "errors", errors);
    try object.setAttr(machine.arena, "errors", .{
        .writable = true,
        .enumerable = false,
        .configurable = true,
    });
    if (!cause.isUndefined()) {
        try object.setOwn(machine.arena, machine.root_shape, "cause", cause);
        try object.setAttr(machine.arena, "cause", .{
            .writable = true,
            .enumerable = false,
            .configurable = true,
        });
    }
    return result;
}

export fn JSC__JSGlobalObject__createAggregateError(
    global: JSContextRef,
    errors: [*c]const EncodedValue,
    errors_count: usize,
    message: *const PrivateZigString,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;

    const message_value = privateZigStringValue(context, message) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    if (errors_count > std.math.maxInt(u32) or (errors == null and errors_count != 0)) {
        const err = machine.throwError("RangeError", "Invalid AggregateError length");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    }
    const values: []Value = if (errors_count == 0) &.{} else context.arena().alloc(Value, errors_count) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    if (errors_count > 0) {
        for (errors[0..errors_count], values) |encoded, *slot| {
            slot.* = privateValueFrom(global, encoded) orelse {
                const err = machine.throwError("TypeError", "AggregateError value belongs to another VM");
                privateSetPendingAbrupt(context, &machine, err);
                return .empty;
            };
        }
    }
    const array = machine.newArray() catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    for (values) |item| array.asObj().appendElement(context.arena(), item) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const result = privateMakeAggregateError(&machine, array, message_value.asStr(), Value.undef()) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

export fn JSC__JSGlobalObject__createAggregateErrorWithArray(
    global: JSContextRef,
    errors_encoded: EncodedValue,
    message: PrivateBunString,
    cause_encoded: EncodedValue,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;

    const message_value = privateBunStringValue(context, &message, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const errors_value = privateValueFrom(global, errors_encoded) orelse {
        const err = machine.throwError("TypeError", "AggregateError array belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    if (!errors_value.isObject() or !errors_value.asObj().is_array) {
        const err = machine.throwError("TypeError", "AggregateError errors must be an array");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    }
    const cause = privateValueFrom(global, cause_encoded) orelse {
        const err = machine.throwError("TypeError", "AggregateError cause belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const result = privateMakeAggregateError(&machine, errors_value, message_value.asStr(), cause) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

export fn JSC__JSValue__getErrorsProperty(encoded: EncodedValue, global: JSContextRef) callconv(.c) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const internal = privateValueFrom(global, encoded) orelse return .empty;
    if (!internal.isObject()) return .undefined;
    return privateEncodedFromValue(context, internal.asObj().getOwn("errors") orelse Value.undef());
}

fn privatePropertyBoundaryGroup(context: *Context) ?*CContextGroup {
    const erased_group = context.c_api_group orelse return null;
    return @ptrCast(@alignCast(erased_group));
}

fn privateZigStringPropertyKey(context: *Context, key: *const PrivateZigString) ?[]const u8 {
    const string = privateZigStringValue(context, key) catch |err| {
        privatePublishBunStringError(context, err);
        return null;
    };
    return string.asStr();
}

fn privateBunStringPropertyKey(context: *Context, key: *const PrivateBunString) ?[]const u8 {
    const string = privateBunStringValue(context, key, null) catch |err| {
        privatePublishBunStringError(context, err);
        return null;
    };
    return string.asStr();
}

fn privateLatin1PropertyKey(context: *Context, bytes: [*]const u8, len: u32) ?[]const u8 {
    if (len == 0) return "";
    return privateLatin1ToWTF8(context.arena(), bytes[0..len]) catch {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return null;
    };
}

fn privatePublishPropertyTypeError(context: *Context, message: []const u8) void {
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    privateSetPendingAbrupt(context, &machine, machine.throwError("TypeError", message));
}

fn privatePutDirectData(machine: *interp.Interpreter, object: *Object, property: []const u8, stored: Value) !void {
    switch (try object.deleteAccessorOwn(machine.arena, property)) {
        .blocked => return machine.throwError("TypeError", "Cannot replace non-configurable property"),
        .absent, .removed_continue, .deleted => {},
    }
    try machine.setProp(object, property, stored);
    try object.setAttr(machine.arena, property, .{});
}

fn privateGetBeforeObjectPrototype(
    machine: *interp.Interpreter,
    target: *Object,
    key: []const u8,
) !?Value {
    const receiver = Value.obj(target);
    const cutoff = machine.objectProto();
    var current: ?*Object = target;
    while (current) |object| {
        // JSC's Proxy getOwnPropertySlot with a Get slot resolves through the
        // proxy's ordinary [[Get]] path.  Treat even `undefined` as a produced
        // slot, and let a missing trap forward through the target normally.
        if (object.proxyHandler() != null or object.proxy_revoked)
            return try machine.getProperty(Value.obj(object), key);
        if (try machine.getOwnPropertyValue(object, key, receiver)) |result| return result;
        const next = machine.effectiveProto(object);
        if (next != null and next.? == cutoff) return null;
        current = next;
    }
    return null;
}

export fn JSC__JSValue__createObject2(
    global: JSContextRef,
    key1: *const PrivateZigString,
    key2: *const PrivateZigString,
    value1_encoded: EncodedValue,
    value2_encoded: EncodedValue,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const first_key = privateZigStringPropertyKey(context, key1) orelse return .empty;
    const second_key = privateZigStringPropertyKey(context, key2) orelse return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const first_value = privateValueFrom(global, value1_encoded) orelse {
        const err = machine.throwError("TypeError", "Property value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const second_value = privateValueFrom(global, value2_encoded) orelse {
        const err = machine.throwError("TypeError", "Property value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const result = machine.newObject() catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    // The pinned C++ boundary intentionally defines key 2 first.  For duplicate
    // keys that preserves key 2's insertion position while key 1 wins the value.
    machine.setProp(result.asObj(), second_key, second_value) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    machine.setProp(result.asObj(), first_key, first_value) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

fn privateRecordString(context: *Context, string: *const PrivateZigString) ?Value {
    return privateZigStringValue(context, string) catch |err| {
        privatePublishBunStringError(context, err);
        return null;
    };
}

export fn JSC__JSValue__putRecord(
    target_encoded: EncodedValue,
    global: JSContextRef,
    key: ?*const PrivateZigString,
    values: [*c]const PrivateZigString,
    values_len: usize,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const key_string = key orelse {
        privatePublishBunStringError(context, error.InvalidString);
        return;
    };
    if (values == null and values_len != 0) {
        privatePublishBunStringError(context, error.InvalidString);
        return;
    }
    if (values_len > std.math.maxInt(u32)) {
        privatePublishBunStringError(context, error.StringTooLong);
        return;
    }
    const values_ptr: [*]const PrivateZigString = if (values_len == 0)
        undefined
    else
        @ptrFromInt(@intFromPtr(values));
    const property = privateZigStringPropertyKey(context, key_string) orelse return;
    const target = privateValueFrom(global, target_encoded) orelse {
        privatePublishBunStringError(context, error.InvalidString);
        return;
    };
    if (!target.isObject() or target.asObj().is_symbol or target.asObj().is_bigint) {
        privatePublishBunStringError(context, error.InvalidString);
        return;
    }

    // The pinned boundary converts every native string before allocating the
    // many-value array.  Besides matching JSC's abrupt-completion point, this
    // keeps a failed call from publishing a partially initialized aggregate.
    var stored = Value.undef();
    if (values_len == 1) {
        stored = privateRecordString(context, &values_ptr[0]) orelse return;
    } else {
        const converted = context.arena().alloc(Value, values_len) catch {
            privatePublishBunStringError(context, error.OutOfMemory);
            return;
        };
        for (values_ptr[0..values_len], converted) |*string, *slot|
            slot.* = privateRecordString(context, string) orelse return;

        const gc_saved = gc_mod.setActiveHeap(context.gc);
        defer _ = gc_mod.setActiveHeap(gc_saved);
        const sa_saved = strcell.setActiveArena(context.arena());
        defer _ = strcell.setActiveArena(sa_saved);
        var array_machine = context.interpreter();
        context.pushActiveInterpreter(&array_machine) catch |err| {
            privateSetPendingAbrupt(context, &array_machine, err);
            return;
        };
        defer context.popActiveInterpreter(&array_machine);
        const array = array_machine.newArrayWithLength(values_len) catch |err| {
            privateSetPendingAbrupt(context, &array_machine, err);
            return;
        };
        for (converted, 0..) |item, index|
            array_machine.putArrayDirectIndex(array.asObj(), @intCast(index), item) catch |err| {
                privateSetPendingAbrupt(context, &array_machine, err);
                return;
            };
        stored = array;
    }

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    // defineOwnProperty(..., { writable, enumerable, configurable: true }) plus
    // putDirect: replace a configurable own accessor and never run a prototype
    // setter.  Default PropAttr is the exact all-true descriptor.
    switch (target.asObj().deleteAccessorOwn(machine.arena, property) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    }) {
        .blocked => {
            const err = machine.throwError("TypeError", "Cannot redefine non-configurable property");
            privateSetPendingAbrupt(context, &machine, err);
            return;
        },
        else => {},
    }
    machine.setProp(target.asObj(), property, stored) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    target.asObj().setAttr(machine.arena, property, .{}) catch |err|
        privateSetPendingAbrupt(context, &machine, err);
}

export fn JSC__JSValue__fromEntries(
    global: JSContextRef,
    keys: [*c]const PrivateZigString,
    values: [*c]const PrivateZigString,
    count: usize,
    clone: bool,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    if (count != 0 and (keys == null or values == null)) {
        privatePublishBunStringError(context, error.InvalidString);
        return .empty;
    }
    if (count > std.math.maxInt(u32)) {
        privatePublishBunStringError(context, error.StringTooLong);
        return .empty;
    }
    const keys_ptr: [*]const PrivateZigString = if (count == 0)
        undefined
    else
        @ptrFromInt(@intFromPtr(keys));
    const values_ptr: [*]const PrivateZigString = if (count == 0)
        undefined
    else
        @ptrFromInt(@intFromPtr(values));
    // Both pinned branches intern/copy the final Identifier. `clone` only
    // changes whether the temporary native WTF::String borrows or copies its
    // input before interning; all observable result strings are independent of
    // the caller's buffers in either branch. Our WTF-8 decoding already copies
    // that temporary, so no second semantic branch is required.
    _ = clone;

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const result = machine.newObject() catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    for (0..count) |index| {
        const property = privateZigStringPropertyKey(context, &keys_ptr[index]) orelse return .empty;
        const stored = privateRecordString(context, &values_ptr[index]) orelse return .empty;
        machine.setProp(result.asObj(), property, stored) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
    }
    return privateEncodeResult(context, &machine, result);
}

