    cell: ?*anyopaque,
) callconv(.c) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const boxed = privateBoxFromCell(cell) orelse return .empty;
    if (boxed.private_kind != .value or boxed.owner.c_api_group != context.c_api_group or
        !boxed.value.isObject() or boxed.value.asObj().is_symbol or boxed.value.asObj().is_bigint)
        return .empty;
    var current: ?*Object = boxed.value.asObj();
    while (current) |object| {
        // VMInquiry is intentionally pure: an opaque Proxy, accessor, or custom
        // host slot is not inspected and cannot execute user code.
        if (object.proxyHandler() != null or object.proxy_revoked) return .empty;
        if (object.getAccessor("code") != null) return .empty;
        if (object.getOwn("code")) |result| return privateEncodedFromValue(context, result);
        if (object.hostClassHooks() != null) return .empty;
        current = object.protoAtomic();
    }
    return .empty;
}

fn privatePropertyIteratorKeys(
    machine: *interp.Interpreter,
    start: *Object,
    own_properties_only: bool,
    only_non_index_properties: bool,
) interp.EvalError![]const []const u8 {
    var result: std.ArrayListUnmanaged([]const u8) = .empty;
    var seen: std.StringHashMapUnmanaged(void) = .empty;
    var current: ?*Object = start;
    var prototype_count: usize = 0;

    while (current) |object| {
        // JSC's PropertyNameArrayBuilder de-duplicates names that were actually
        // added. A non-enumerable own name therefore does not hide an enumerable
        // name on a prototype for this private API (unlike language `for-in`).
        for (try builtins.ownEnumerablePropertyKeys(machine, object, true)) |key| {
            if (value.isPrivateKey(key)) continue;
            if (value.isSymbolKey(key) and !value.isRealSymbolKey(key)) continue;
            if (own_properties_only and only_non_index_properties and value.canonicalIndex(key) != null) continue;
            if (seen.contains(key)) continue;
            try seen.put(machine.arena, key, {});
            try result.append(machine.arena, key);
        }
        if (own_properties_only) break;

        prototype_count += 1;
        if (prototype_count > 10_000)
            return machine.throwError("RangeError", "Maximum prototype chain depth exceeded");
        const prototype = try machine.getPrototypeOfObject(object);
        if (prototype.isNull()) break;
        if (!prototype.isObject() or prototype.asObj().is_symbol or prototype.asObj().is_bigint)
            return machine.throwError("TypeError", "Object prototype is neither an object nor null");
        current = prototype.asObj();
    }
    return result.items;
}

fn privateCreatePropertyIteratorRecord(
    group: *CContextGroup,
    machine: *interp.Interpreter,
    keys: []const []const u8,
) !*PrivateJSPropertyIterator {
    if (!group.retain()) return error.OutOfMemory;
    errdefer _ = group.release();

    const entries = try gpa.alloc(PrivateJSPropertyIteratorEntry, keys.len);
    var initialized: usize = 0;
    errdefer {
        for (entries[0..initialized]) |entry| gpa.free(entry.key);
        gpa.free(entries);
    }
    for (keys, entries) |key, *entry| {
        const owned_key = try gpa.dupe(u8, key);
        errdefer gpa.free(owned_key);
        const name_bytes = if (value.isRealSymbolKey(key)) symbol: {
            const symbol_value = try machine.keyToValue(key);
            if (!symbol_value.isObject() or !symbol_value.asObj().is_symbol)
                return machine.throwError("TypeError", "Property iterator could not recover a Symbol key");
            break :symbol symbol_value.asObj().symbolDescription() orelse "";
        } else key;
        const view = try privateBorrowedZigStringView(group, name_bytes);
        entry.* = .{
            .key = owned_key,
            .name = .{ .tag = .zig_string, .value = .{ .zig_string = view } },
            .utf16_length = view.len,
        };
        initialized += 1;
    }
    const iterator = try gpa.create(PrivateJSPropertyIterator);
    iterator.* = .{ .group = group, .entries = entries };
    return iterator;
}

fn privateDestroyPropertyIterator(iterator: *PrivateJSPropertyIterator) void {
    const group = iterator.group;
    iterator.magic = 0;
    for (iterator.entries) |entry| gpa.free(entry.key);
    gpa.free(iterator.entries);
    gpa.destroy(iterator);
    if (group.release()) group.destroy();
}

fn privatePropertyIteratorObject(
    group: *CContextGroup,
    cell: ?*anyopaque,
) ?*Object {
    const boxed = privateBoxFromCell(cell) orelse return null;
    if (boxed.private_kind != .value or boxed.owner.c_api_group != @as(?*anyopaque, @ptrCast(group))) return null;
    if (!boxed.value.isObject() or boxed.value.asObj().is_symbol or boxed.value.asObj().is_bigint) return null;
    return boxed.value.asObj();
}

/// Pure PropertySlot::VMInquiry analogue. Ordinary data slots may be found on
/// direct prototypes, but an accessor or any opaque/exotic object taints the
/// inquiry and stops it without invoking JS, Proxy traps, or host callbacks.
fn privatePropertyIteratorVMInquiry(object: *Object, key: []const u8) ?Value {
    if (value.canonicalIndex(key) != null) return null;
    var current: ?*Object = object;
    var depth: usize = 0;
    while (current) |candidate| {
        depth += 1;
        if (depth > 10_000) return null;
        if (candidate.proxyHandler() != null or candidate.proxy_revoked or candidate.moduleNs() != null) return null;
        if (candidate.getAccessor(key) != null) return null;
        if (candidate.getOwn(key)) |found| return found;

        // Pure virtual own data properties represented outside the shape.
        if (std.mem.eql(u8, key, "length")) {
            if (candidate.boxedPrimitive()) |primitive|
                if (primitive.isString()) return Value.num(@floatFromInt(interp.Interpreter.utf16LenOfString(primitive.asStr())));
            if (candidate.is_array and !candidate.is_arguments)
                return Value.num(@floatFromInt(candidate.arrayLength()));
        }

        // Integer-indexed exotics do not continue to their prototype for any
        // canonical numeric string, including "-0", negatives, fractions, and
        // out-of-bounds values that are not ordinary array indices.
        if (candidate.typedArray() != null and interp.canonicalNumericIndexString(key) != null) return null;

        if (candidate.hostClassHooks() != null) return null;
        current = candidate.protoAtomic();
    }
    return null;
}

export fn Bun__JSPropertyIterator__create(
    global: JSContextRef,
    encoded_value: EncodedValue,
    count: *usize,
    own_properties_only: bool,
    only_non_index_properties: bool,
) callconv(.c) ?*PrivateJSPropertyIterator {
    count.* = 0;
    const context = ctxForEvaluation(global) orelse return null;
    const group = privatePropertyBoundaryGroup(context) orelse return null;
    if (group.pending_exception != null) return null;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return null;
    };
    defer context.popActiveInterpreter(&machine);

    const target = privateValueFrom(global, encoded_value) orelse {
        const abrupt = machine.throwError("TypeError", "Property iterator target belongs to another VM");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return null;
    };
    if (!target.isObject() or target.asObj().is_symbol or target.asObj().is_bigint) {
        const abrupt = machine.throwError("TypeError", "Property iterator target is not an object");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return null;
    }
    const keys = privatePropertyIteratorKeys(
        &machine,
        target.asObj(),
        own_properties_only,
        only_non_index_properties,
    ) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return null;
    };
    if (keys.len == 0) return null;
    const iterator = privateCreatePropertyIteratorRecord(group, &machine, keys) catch |err| {
        switch (err) {
            error.StringTooLong, error.InvalidString => privatePublishBunStringError(context, @errorCast(err)),
            else => privateSetPendingAbrupt(context, &machine, err),
        }
        return null;
    };
    count.* = iterator.entries.len;
    return iterator;
}

export fn Bun__JSPropertyIterator__deinit(iterator: ?*PrivateJSPropertyIterator) callconv(.c) void {
    const value_ = iterator orelse return;
    if (value_.magic != private_js_property_iterator_magic) return;
    privateDestroyPropertyIterator(value_);
}

export fn Bun__JSPropertyIterator__getLongestPropertyName(
    iterator: ?*PrivateJSPropertyIterator,
    global: JSContextRef,
    object_cell: ?*anyopaque,
) callconv(.c) usize {
    const value_ = iterator orelse return 0;
    if (value_.magic != private_js_property_iterator_magic) return 0;
    const context = ctxForHandleInspection(global) orelse return 0;
    if (context.c_api_group != @as(?*anyopaque, @ptrCast(value_.group))) return 0;
    if (privatePropertyIteratorObject(value_.group, object_cell) == null) return 0;
    var longest: usize = 0;
    for (value_.entries) |entry| longest = @max(longest, entry.utf16_length);
    return longest;
}

export fn Bun__JSPropertyIterator__getName(
    iterator: ?*PrivateJSPropertyIterator,
    property_name: *PrivateBunString,
    index: usize,
) callconv(.c) void {
    property_name.* = PrivateBunString.dead();
    const value_ = iterator orelse return;
    if (value_.magic != private_js_property_iterator_magic or index >= value_.entries.len) return;
    property_name.* = value_.entries[index].name;
}

fn privatePropertyIteratorGet(
    iterator: ?*PrivateJSPropertyIterator,
    global: JSContextRef,
    object_cell: ?*anyopaque,
    property_name: *PrivateBunString,
    index: usize,
    observable: bool,
) EncodedValue {
    property_name.* = PrivateBunString.dead();
    const value_ = iterator orelse return .empty;
    if (value_.magic != private_js_property_iterator_magic or index >= value_.entries.len) return .empty;
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group != value_.group or group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const object = privatePropertyIteratorObject(group, object_cell) orelse {
        const abrupt = machine.throwError("TypeError", "Property iterator object belongs to another VM");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .empty;
    };
    const entry = value_.entries[index];
    const result = if (observable)
        machine.getPropertyIfExists(Value.obj(object), entry.key) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        }
    else
        privatePropertyIteratorVMInquiry(object, entry.key);
    const found = result orelse return .empty;
    const encoded = privateEncodeResult(context, &machine, found);
    if (encoded == .empty) return .empty;
    property_name.* = entry.name;
    return encoded;
}

export fn Bun__JSPropertyIterator__getNameAndValue(
    iterator: ?*PrivateJSPropertyIterator,
    global: JSContextRef,
    object_cell: ?*anyopaque,
    property_name: *PrivateBunString,
    index: usize,
) callconv(.c) EncodedValue {
    return privatePropertyIteratorGet(iterator, global, object_cell, property_name, index, true);
}

export fn Bun__JSPropertyIterator__getNameAndValueNonObservable(
    iterator: ?*PrivateJSPropertyIterator,
    global: JSContextRef,
    object_cell: ?*anyopaque,
    property_name: *PrivateBunString,
    index: usize,
) callconv(.c) EncodedValue {
    return privatePropertyIteratorGet(iterator, global, object_cell, property_name, index, false);
}

export fn JSC__JSValue__symbolFor(
    global: JSContextRef,
    key: *const PrivateZigString,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const property = privateZigStringPropertyKey(context, key) orelse return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const result = interp.symbolForKey(&machine, property) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

export fn JSC__JSValue__getSymbolDescription(
    symbol_encoded: EncodedValue,
    global: JSContextRef,
    output: *PrivateZigString,
) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const symbol = privateValueFrom(global, symbol_encoded) orelse return;
    if (!symbol.isObject() or !symbol.asObj().is_symbol) return;
    const description = symbol.asObj().symbolDescription() orelse "";
    output.* = privateBorrowedZigStringView(group, description) catch |err| {
        privatePublishBunStringError(context, err);
        return;
    };
}

export fn JSC__JSValue__symbolKeyFor(
    symbol_encoded: EncodedValue,
    global: JSContextRef,
    output: *PrivateZigString,
) callconv(.c) bool {
    const context = ctxForHandleInspection(global) orelse return false;
    const group = privatePropertyBoundaryGroup(context) orelse return false;
    if (group.pending_exception != null) return false;
    const symbol = privateValueFrom(global, symbol_encoded) orelse return false;
    if (!symbol.isObject() or !symbol.asObj().is_symbol) return false;
    const registry_key = symbol.asObj().getOwn("\x00forKey") orelse return false;
    if (!registry_key.isString()) return false;
    output.* = privateBorrowedZigStringView(group, registry_key.asStr()) catch |err| {
        privatePublishBunStringError(context, err);
        return false;
    };
    return true;
}

const PrivateCustomAccessor = struct {
    data: value.GetterSetterCellData,
    enumerable: bool,
};

fn privateCustomAccessor(object: *Object, key: []const u8) ?PrivateCustomAccessor {
    // Own ordinary data/accessor properties win before embedding class hooks.
    if (object.getOwn(key) != null or object.getAccessor(key) != null) return null;
    var class = classForObject(object);
    while (class) |item| : (class = item.parent) {
        for (item.static_values) |entry| {
            const name = entry.name orelse continue;
            if (!std.mem.eql(u8, std.mem.span(name), key)) continue;
            return .{
                .data = .native(
                    if (entry.get_property) |callback| @ptrCast(callback) else null,
                    if (entry.set_property) |callback| @ptrCast(callback) else null,
                ),
                .enumerable = (entry.attributes & kJSPropertyAttributeDontEnum) == 0,
            };
        }
        if (item.definition.get_property != null or item.definition.set_property != null) {
            return .{
                .data = .native(
                    if (item.definition.get_property) |callback| @ptrCast(callback) else null,
                    if (item.definition.set_property) |callback| @ptrCast(callback) else null,
                ),
                .enumerable = true,
            };
        }
    }
    return null;
}

fn privateCreateGetterSetterCell(
    machine: *interp.Interpreter,
    data: value.GetterSetterCellData,
) std.mem.Allocator.Error!*Object {
    const object = try gc_mod.allocObj(machine.arena);
    object.setGetterSetterCellData(data);
    return object;
}

fn privateCustomGetterSetterCell(
    machine: *interp.Interpreter,
    owner: *Object,
    key: []const u8,
    data: value.GetterSetterCellData,
) std.mem.Allocator.Error!*Object {
    if (owner.customAccessorDescriptorCell(key)) |existing| return existing;
    const candidate = try privateCreateGetterSetterCell(machine, data);
    return owner.installCustomAccessorDescriptorCell(key, candidate);
}

fn privateOrdinaryGetterSetterCell(
    machine: *interp.Interpreter,
    owner: *Object,
    key: []const u8,
    initial: value.Accessor,
) std.mem.Allocator.Error!?*Object {
    var accessor = initial;
    var attempts: u8 = 0;
    while (attempts < 3) : (attempts += 1) {
        if (accessor.descriptor_cell) |existing| return existing;
        const candidate = try privateCreateGetterSetterCell(machine, .ordinary(accessor.get, accessor.set));
        if (owner.installAccessorDescriptorCell(key, accessor.get, accessor.set, candidate)) |canonical|
            return canonical;
        accessor = owner.getAccessor(key) orelse return null;
    }
    return null;
}

fn privateTraversalKeyBytes(machine: *interp.Interpreter, key: []const u8) []const u8 {
    if (!value.isRealSymbolKey(key)) return key;
    const symbol = machine.keyToValue(key) catch return "";
    if (!symbol.isObject() or !symbol.asObj().is_symbol) return "";
    return symbol.asObj().symbolDescription() orelse "";
}

/// Traverse the starting value's own, non-index properties using JSC's private
/// PropertySlot contract. Ordinary accessors are returned as internal
/// GetterSetter cells and never invoked; embedding callbacks are represented by
/// CustomGetterSetter cells. Property-read exceptions are deliberately cleared
/// to match the pinned upstream helper, while exceptions published by the host
/// callback stop traversal immediately.
export fn JSC__JSValue__forEachPropertyNonIndexed(
    encoded: EncodedValue,
    global: JSContextRef,
    callback_context: ?*anyopaque,
    callback: ?PrivateForEachPropertyCallback,
) callconv(.c) void {
    const visit = callback orelse return;
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const target = privateValueFrom(global, encoded) orelse return;
    if (!target.isObject() or target.asObj().is_symbol or target.asObj().is_bigint or
        target.asObj().getterSetterCellData() != null) return;

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    const target_address: ?usize = encoded.asCellAddress() catch null;
    const target_ref: JSValueRef = if (target_address) |address| @ptrFromInt(address) else null;
    const target_protected = target_ref != null and valueProtect(global, target_ref);
    if (context.gc != null and !target_protected) {
        privateSetPendingAbrupt(context, &machine, error.OutOfMemory);
        return;
    }
    defer {
        if (target_protected) _ = valueUnprotect(global, target_ref);
    }

    const keys = machine.objectOwnKeysList(target.asObj()) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    var seen: std.StringHashMapUnmanaged(void) = .empty;
    const to_string_tag = interp.objectToStringTagKey(&machine);
    for (keys) |key| {
        if (value.canonicalIndex(key) != null or value.isPrivateKey(key)) continue;
        if (value.isSymbolKey(key) and !value.isRealSymbolKey(key)) continue;
        if (std.mem.eql(u8, key, "length") or std.mem.eql(u8, key, "constructor")) continue;
        if (seen.contains(key)) continue;
        seen.put(machine.arena, key, {}) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return;
        };

        var enumerable = true;
        var result = Value.undef();
        if (target.asObj().getAccessor(key)) |accessor| {
            enumerable = target.asObj().getAttr(key).enumerable;
            const cell = privateOrdinaryGetterSetterCell(&machine, target.asObj(), key, accessor) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                return;
            } orelse continue;
            result = Value.obj(cell);
        } else if (privateCustomAccessor(target.asObj(), key)) |custom| {
            enumerable = custom.enumerable;
            const cell = privateCustomGetterSetterCell(&machine, target.asObj(), key, custom.data) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                return;
            };
            result = Value.obj(cell);
        } else if (target.asObj().proxyHandler() != null or target.asObj().proxy_revoked) proxy: {
            const descriptor = builtins.objectGetOwnPropertyDescriptor(
                @ptrCast(&machine),
                Value.undef(),
                &.{ target, machine.keyToValue(key) catch |err| {
                    privateSetPendingAbrupt(context, &machine, err);
                    return;
                } },
            ) catch {
                machine.exception = Value.undef();
                result = Value.undef();
                break :proxy;
            };
            if (!descriptor.isObject()) continue;
            const descriptor_object = descriptor.asObj();
            enumerable = if (descriptor_object.getOwn("enumerable")) |flag| flag.toBoolean() else false;
            const getter = descriptor_object.getOwn("get");
            const setter = descriptor_object.getOwn("set");
            if (getter != null or setter != null) {
                const cell = privateCreateGetterSetterCell(&machine, .ordinary(getter, setter)) catch |err| {
                    privateSetPendingAbrupt(context, &machine, err);
                    return;
                };
                result = Value.obj(cell);
            } else {
                result = machine.getProperty(target, key) catch {
                    machine.exception = Value.undef();
                    break :proxy;
                };
            }
        } else {
            enumerable = target.asObj().getAttr(key).enumerable;
            result = machine.getProperty(target, key) catch value_error: {
                machine.exception = Value.undef();
                break :value_error Value.undef();
            };
        }

        if (!enumerable and (std.mem.eql(u8, key, "__proto__") or
            std.mem.eql(u8, key, "__esModule") or
            (to_string_tag != null and std.mem.eql(u8, key, to_string_tag.?)))) continue;

        const result_encoded = privateEncodeResult(context, &machine, result);
        if (result_encoded == .empty) return;
        const result_address: ?usize = result_encoded.asCellAddress() catch null;
        const result_ref: JSValueRef = if (result_address) |address| @ptrFromInt(address) else null;
        const result_protected = result_ref != null and valueProtect(global, result_ref);
        if (context.gc != null and result_ref != null and !result_protected) {
            privateSetPendingAbrupt(context, &machine, error.OutOfMemory);
            return;
        }
        defer {
            if (result_protected) _ = valueUnprotect(global, result_ref);
        }

        var zig_key = privateBorrowedZigStringView(group, privateTraversalKeyBytes(&machine, key)) catch |err| {
            privatePublishBunStringError(context, err);
            return;
        };
        visit(global, callback_context, &zig_key, result_encoded, value.isRealSymbolKey(key), false);
        if (group.pending_exception != null) return;
    }
}

const PrivateDOMExceptionDescription = struct {
    name: []const u8,
    message: []const u8,
};

const private_dom_exception_descriptions = [_]PrivateDOMExceptionDescription{
    .{ .name = "IndexSizeError", .message = "The index is not in the allowed range." },
    .{ .name = "HierarchyRequestError", .message = "The operation would yield an incorrect node tree." },
    .{ .name = "WrongDocumentError", .message = "The object is in the wrong document." },
    .{ .name = "InvalidCharacterError", .message = "The string contains invalid characters." },
    .{ .name = "NoModificationAllowedError", .message = "The object can not be modified." },
    .{ .name = "NotFoundError", .message = "The object can not be found here." },
    .{ .name = "NotSupportedError", .message = "The operation is not supported." },
    .{ .name = "InUseAttributeError", .message = "The attribute is in use." },
    .{ .name = "InvalidStateError", .message = "The object is in an invalid state." },
    .{ .name = "SyntaxError", .message = "The string did not match the expected pattern." },
    .{ .name = "InvalidModificationError", .message = " The object can not be modified in this way." },
    .{ .name = "NamespaceError", .message = "The operation is not allowed by Namespaces in XML." },
    .{ .name = "InvalidAccessError", .message = "The object does not support the operation or argument." },
    .{ .name = "TypeMismatchError", .message = "The type of an object was incompatible with the expected type of the parameter associated to the object." },
    .{ .name = "SecurityError", .message = "The operation is insecure." },
    .{ .name = "NetworkError", .message = " A network error occurred." },
    .{ .name = "AbortError", .message = "The operation was aborted." },
    .{ .name = "URLMismatchError", .message = "The given URL does not match another URL." },
    .{ .name = "QuotaExceededError", .message = "The quota has been exceeded." },
    .{ .name = "TimeoutError", .message = "The operation timed out." },
    .{ .name = "InvalidNodeTypeError", .message = "The supplied node is incorrect or has an incorrect ancestor for this operation." },
    .{ .name = "DataCloneError", .message = "The object can not be cloned." },
    .{ .name = "EncodingError", .message = "The encoding operation (either encoded or decoding) failed." },
    .{ .name = "NotReadableError", .message = "The I/O read operation failed." },
    .{ .name = "UnknownError", .message = "The operation failed for an unknown transient reason (e.g. out of memory)." },
    .{ .name = "ConstraintError", .message = "A mutation operation in a transaction failed because a constraint was not satisfied." },
    .{ .name = "DataError", .message = "Provided data is inadequate." },
    .{ .name = "TransactionInactiveError", .message = "A request was placed against a transaction which is currently not active, or which is finished." },
    .{ .name = "ReadOnlyError", .message = "The mutating operation was attempted in a \"readonly\" transaction." },
    .{ .name = "VersionError", .message = "An attempt was made to open a database using a lower version than the existing version." },
    .{ .name = "OperationError", .message = "The operation failed for an operation-specific reason." },
    .{ .name = "NotAllowedError", .message = "The request is not allowed by the user agent or the platform in the current context, possibly because the user denied permission." },
};

fn privateSetErrorCodeWithAttributes(
    machine: *interp.Interpreter,
    result: Value,
    code: []const u8,
    writable: bool,
) !void {
    if (code.len == 0 or !result.isObject()) return;
    try result.asObj().setOwn(machine.arena, machine.root_shape, "code", try Value.strAlloc(machine.arena, code));
    try result.asObj().setAttr(machine.arena, "code", .{
        .writable = writable,
        .enumerable = true,
        .configurable = true,
    });
}

fn privateSetErrorCode(machine: *interp.Interpreter, result: Value, code: []const u8) !void {
    return privateSetErrorCodeWithAttributes(machine, result, code, true);
}

export fn ZigString__toDOMExceptionInstance(
    string: *const PrivateZigString,
    global: JSContextRef,
    code: u8,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const bun_string = PrivateBunString{ .tag = .zig_string, .value = .{ .zig_string = string.* } };
    const message_value = privateBunStringValue(context, &bun_string, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const supplied_message = message_value.asStr();

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const result: Value = blk: {
        if (code < private_dom_exception_descriptions.len and code != 9) {
            const description = private_dom_exception_descriptions[code];
            break :blk machine.makeDOMException(
                description.name,
                if (supplied_message.len > 0) supplied_message else description.message,
            ) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                return .empty;
            };
        }
        const error_contract: struct { name: []const u8, fallback: []const u8, node_code: []const u8 } = switch (code) {
            9, 34 => .{ .name = "SyntaxError", .fallback = "", .node_code = "" },
            32 => .{ .name = "RangeError", .fallback = "Bad value", .node_code = "" },
            33 => .{ .name = "TypeError", .fallback = "", .node_code = "" },
            35 => .{ .name = "RangeError", .fallback = "Maximum call stack size exceeded", .node_code = "" },
            36 => .{ .name = "Error", .fallback = "Out of memory", .node_code = "" },
            37 => break :blk Value.undef(),
            38 => .{ .name = "TypeError", .fallback = "Expected this to be of a different type", .node_code = "ERR_INVALID_THIS" },
            39 => .{ .name = "TypeError", .fallback = "Invalid URL", .node_code = "ERR_INVALID_URL" },
            40 => .{ .name = "Error", .fallback = "Crypto operation failed", .node_code = "ERR_CRYPTO_OPERATION_FAILED" },
            else => break :blk machine.makeDOMException("", supplied_message) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                return .empty;
            },
        };
        const error_value = machine.makeError(
            error_contract.name,
            if (supplied_message.len > 0) supplied_message else error_contract.fallback,
        ) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
        privateSetErrorCode(&machine, error_value, error_contract.node_code) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
        break :blk error_value;
    };
    return privateEncodeResult(context, &machine, result);
}

export fn JSC__JSBigInt__toString(
    cell: ?*anyopaque,
    global: JSContextRef,
) callconv(.c) PrivateBunString {
    const context = ctxForHandleInspection(global) orelse return PrivateBunString.dead();
    const opaque_group = context.c_api_group orelse return PrivateBunString.dead();
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return PrivateBunString.dead();

    const boxed = privateBigIntBoxFromCell(cell) orelse return PrivateBunString.dead();
    if (boxed.owner.c_api_group != context.c_api_group) return PrivateBunString.dead();
    const object = boxed.value.asObj();

    var stack: [42]u8 = undefined;
    const decimal = object.bigIntText() orelse std.fmt.bufPrint(&stack, "{d}", .{object.bigIntValue()}) catch {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return PrivateBunString.dead();
    };
    return privateOwnedLatin1String(decimal) catch {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return PrivateBunString.dead();
    };
}

export fn JSC__JSValue__asString(encoded: EncodedValue) callconv(.c) ?*anyopaque {
    const boxed = privateBoxedFrom(encoded) orelse return null;
    if (boxed.private_kind != .value) return null;
    if (!boxed.value.isString()) return null;
    return @ptrCast(boxed);
}

fn privateTypeofStringIndex(bytes: []const u8) usize {
    return if (std.mem.eql(u8, bytes, "undefined")) 0 else if (std.mem.eql(u8, bytes, "boolean")) 1 else if (std.mem.eql(u8, bytes, "number")) 2 else if (std.mem.eql(u8, bytes, "string")) 3 else if (std.mem.eql(u8, bytes, "symbol")) 4 else if (std.mem.eql(u8, bytes, "bigint")) 5 else if (std.mem.eql(u8, bytes, "function")) 6 else 7;
}

fn privateTypeofStringValue(index: usize) Value {
    return switch (index) {
        0 => Value.str("undefined"),
        1 => Value.str("boolean"),
        2 => Value.str("number"),
        3 => Value.str("string"),
        4 => Value.str("symbol"),
        5 => Value.str("bigint"),
        6 => Value.str("function"),
        else => Value.str("object"),
    };
}

export fn JSC__jsTypeStringForValue(
    global: JSContextRef,
    encoded: EncodedValue,
) callconv(.c) ?*anyopaque {
    const context = ctxForHandleInspection(global) orelse return null;
    const opaque_group = context.c_api_group orelse return null;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    const internal = privateValueFrom(global, encoded) orelse return null;
    const bytes = internal.typeOf();
    const index = privateTypeofStringIndex(bytes);
    const slot = &group.typeof_strings[index];
    if (slot.*) |boxed| return @ptrCast(boxed);

    const handle = box(group.primary, privateTypeofStringValue(index)) orelse return null;
    const boxed: *Boxed = @ptrCast(@alignCast(handle));
    slot.* = boxed;
    return @ptrCast(boxed);
}

export fn JSC__JSFunction__getSourceCode(
    encoded: EncodedValue,
    output: *PrivateZigString,
) callconv(.c) bool {
    const boxed = privateBoxedFrom(encoded) orelse return false;
    if (boxed.private_kind != .value) return false;
    const function = interp.Interpreter.funcOf(boxed.value) orelse return false;
    if (function.source.len == 0) return false;
    const opaque_group = boxed.owner.c_api_group orelse return false;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    const view = privateBorrowedZigStringView(group, function.source) catch return false;
    output.* = view;
    return true;
}

export fn JSC__JSFunction__optimizeSoon(encoded: EncodedValue) callconv(.c) void {
    const boxed = privateBoxedFrom(encoded) orelse return;
    if (boxed.private_kind != .value) return;
    const function = interp.Interpreter.funcOf(boxed.value) orelse return;
    const chunk = function.chunk orelse return;
    if (chunk.tier.loadState() != .cold) return;
    // `observeEntry` increments before checking its threshold. A saturated
    // pre-threshold count therefore makes the next invocation claim compilation
    // while leaving this scheduling request itself allocation- and codegen-free.
    chunk.tier.entries.store(std.math.maxInt(u32) - 1, .release);
}

export fn JSC__JSValue__getLengthIfPropertyExistsInternal(
    encoded: EncodedValue,
    global: JSContextRef,
) callconv(.c) f64 {
    const context = ctxForEvaluation(global) orelse return 0;
    const opaque_group = context.c_api_group orelse return 0;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return 0;
    const internal = privateValueFrom(global, encoded) orelse return 0;
    if (internal.isString()) return @floatFromInt(interp.Interpreter.utf16LenOfString(internal.asStr()));
    if (!internal.isObject()) return 0;

    const object = internal.asObj();
    if (object.is_array and !object.is_arguments) return @floatFromInt(object.arrayLength());
    if (object.typedArray()) |typed| return @floatFromInt(typed.currentLength() orelse 0);
    if (object.arrayBuffer()) |buffer| return @floatFromInt(if (buffer.isDetached()) 0 else buffer.bytes().len);

    var machine = context.interpreter();
    if (object.is_map) {
        return @floatFromInt(if (object.is_weak) object.weakEntryCount() else machine.nativeMapSize(object));
    }
    if (object.is_set and !object.is_weak) return @floatFromInt(machine.nativeSetSize(object));
    if (object.is_symbol or object.is_bigint) return std.math.inf(f64);

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 0;
    };
    defer context.popActiveInterpreter(&machine);
    const length = machine.getPropertyIfExists(internal, "length") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 0;
    } orelse return std.math.inf(f64);
    return machine.toNumberV(length) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 0;
    };
}

fn privatePathSeparator(unit: u16) bool {
    return unit == '[' or unit == ']' or unit == '.';
}

fn privateGetPathProperty(machine: *interp.Interpreter, current: Value, property: []const u8) !?Value {
    const object = try machine.toObject(current);
    return machine.getPropertyIfExists(Value.obj(object), property);
}

fn privateTraverseStringPath(
    machine: *interp.Interpreter,
    allocator: std.mem.Allocator,
    initial: Value,
    path: []const u8,
) !?Value {
    const units = try privateWTF8ToUTF16(allocator, path);
    if (units.len == 0) return privateGetPathProperty(machine, initial, "");

    // This deliberately mirrors Bun's permissive Jest path parser. Brackets,
    // dots, and their combinations are separators rather than validated
    // syntax. Dots at either edge (and consecutive dots) request an empty key.
    var current = initial;
    var i: usize = 0;
    var j: usize = 0;
    if (units[0] == '.')
        current = (try privateGetPathProperty(machine, current, "")) orelse return null;

    while (i < units.len) {
        var current_unit = units[i];
        while (privatePathSeparator(current_unit)) {
            i += 1;
            if (i == units.len) {
                if (current_unit == '.')
                    return privateGetPathProperty(machine, current, "");
                if (j == 0) return null;
                return current;
            }

            const previous = current_unit;
            current_unit = units[i];
            if (previous == '.' and current_unit == '.') {
                current = (try privateGetPathProperty(machine, current, "")) orelse return null;
                continue;
            }
        }

        j = i;
        while (j < units.len and !privatePathSeparator(units[j])) : (j += 1) {}
        const property = try privateUTF16ToWTF8(allocator, units[i..j]);
        current = (try privateGetPathProperty(machine, current, property)) orelse return null;
        i = j;
    }
    return current;
}

fn privateToLength(machine: *interp.Interpreter, value_: Value) !usize {
    const number = try machine.toNumberV(value_);
    if (std.math.isNan(number) or number <= 0) return 0;
    return @intFromFloat(@min(@trunc(number), 9007199254740991.0));
}

fn privateTraverseArrayPath(
    machine: *interp.Interpreter,
    initial: Value,
    path: *Object,
) !?Value {
    // JSC's forEachInArrayLike reads length once with ToLength, then performs
    // ordinary indexed Get for every entry. A hole is therefore `undefined`
    // unless the prototype supplies it, which fails the string/number check.
    const length = try privateToLength(machine, try machine.getProperty(Value.obj(path), "length"));
    var current = initial;
    var index: usize = 0;
    while (index < length) : (index += 1) {
        const index_key = try std.fmt.allocPrint(machine.arena, "{d}", .{index});
        const item = try machine.getProperty(Value.obj(path), index_key);
        if (!item.isString() and !item.isNumber()) return null;
        const property = try machine.toStringV(item);
        current = (try privateGetPathProperty(machine, current, property)) orelse return null;
    }
    return current;
}

export fn JSC__JSValue__getIfPropertyExistsFromPath(
    target_encoded: EncodedValue,
    global: JSContextRef,
    path_encoded: EncodedValue,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const target = privateValueFrom(global, target_encoded) orelse {
        const err = machine.throwError("TypeError", "Property-path target belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const path = privateValueFrom(global, path_encoded) orelse {
        const err = machine.throwError("TypeError", "Property path belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };

    const result: ?Value = if (path.isString())
        privateTraverseStringPath(&machine, context.arena(), target, path.asStr()) catch |err| {
            if (err == error.InvalidString) {
                const abrupt = machine.throwError("TypeError", "Invalid property path string");
                privateSetPendingAbrupt(context, &machine, abrupt);
            } else {
                privateSetPendingAbrupt(context, &machine, err);
            }
            return .empty;
        }
    else if (path.isObject() and !path.asObj().is_symbol and !path.asObj().is_bigint and
        (interp.objectToStringIsArray(&machine, path.asObj()) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        }))
        privateTraverseArrayPath(&machine, target, path.asObj()) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        }
    else
        null;
    return privateEncodeResult(context, &machine, result orelse return .empty);
}

fn privateTypedArrayClassInfoName(kind: value.TAKind) [:0]const u8 {
    return switch (kind) {
        .i8 => "Int8Array",
        .u8 => "Uint8Array",
        .u8c => "Uint8ClampedArray",
        .i16 => "Int16Array",
        .u16 => "Uint16Array",
        .i32 => "Int32Array",
        .u32 => "Uint32Array",
        .f16 => "Float16Array",
        .f32 => "Float32Array",
        .f64 => "Float64Array",
        .i64 => "BigInt64Array",
        .u64 => "BigUint64Array",
    };
}

fn privateCApiClassName(object: *Object) ?[:0]const u8 {
    const owner = object.cApiObjectOwner() orelse return null;
    const class = classFrom(owner.class_ref) orelse return null;
    return class.class_name;
}

fn privateStaticClassInfoName(internal: Value) ?[:0]const u8 {
    if (internal.isString()) return "String";
    if (!internal.isObject()) return null;
    const object = internal.asObj();
    if (object.is_symbol) return "Symbol";
    if (object.is_bigint) return "BigInt";
    if (privateCApiClassName(object)) |name| return name;
    if (object.is_array and !object.is_arguments) return "Array";
    if (object.is_arguments) return "Arguments";
    if (object.typedArray()) |typed| return privateTypedArrayClassInfoName(typed.kind);
    if (object.dataView() != null) return "DataView";
    if (object.arrayBuffer()) |buffer| return if (buffer.is_shared) "SharedArrayBuffer" else "ArrayBuffer";
    if (object.is_map) return if (object.is_weak) "WeakMap" else "Map";
    if (object.is_set) return if (object.is_weak) "WeakSet" else "Set";
    if (object.behavior.is_date) return "Date";
    if (object.behavior.is_regex) return "RegExp";
    if (object.behavior.is_error) return "Error";
    if (promise.promiseOf(internal) != null) return "Promise";
    if (object.generator() != null) return "Generator";
    if (object.moduleNs() != null) return "Module";
    if (object.isCallableObject()) return "Function";
    return "Object";
}

fn privateDirectDataProperty(object: *Object, property: []const u8) ?Value {
    if (object.proxyHandler() != null or object.proxy_revoked) return null;
    if (object.getAccessor(property) != null) return null;
    return object.getOwn(property);
}

fn privateDirectDataPropertyInChain(object: *Object, property: []const u8) ?Value {
    var current: ?*Object = object;
    var guard: usize = 0;
    while (current) |candidate| : (current = candidate.protoAtomic()) {
        guard += 1;
        if (guard > 10_000) return null;
        if (candidate.proxyHandler() != null or candidate.proxy_revoked) return null;
        if (candidate.getAccessor(property) != null) return null;
        if (candidate.getOwn(property)) |found| return found;
    }
    return null;
}

fn privateCalculatedDisplayName(object: *Object) []const u8 {
    const callable = object.jsFunction() != null or object.native != null or object.hostCallback() != null or
        object.errorCtor() != null;
    if (!callable) return "";
    if (privateDirectDataProperty(object, "displayName")) |display_name|
        if (display_name.isString()) return display_name.asStr();
    if (interp.Interpreter.funcOf(Value.obj(object))) |function| return function.name;
    if (privateDirectDataProperty(object, "name")) |name|
        if (name.isString()) return name.asStr();
    return "";
}

fn privateCalculatedClassName(machine: *interp.Interpreter, object: *Object, raw_name: []const u8) []const u8 {
    var constructor_name: ?[]const u8 = null;
    if (privateDirectDataProperty(object, "constructor")) |constructor|
        if (constructor.isObject()) {
            const name = privateCalculatedDisplayName(constructor.asObj());
            if (name.len > 0) constructor_name = name;
        };

    if (constructor_name == null) {
        if (object.protoAtomic()) |prototype| {
            if (privateDirectDataPropertyInChain(prototype, "constructor")) |constructor|
                if (constructor.isObject()) {
                    const name = privateCalculatedDisplayName(constructor.asObj());
                    if (name.len > 0) constructor_name = name;
                };
        }
    }

    if (constructor_name == null or std.mem.eql(u8, constructor_name.?, "Object")) {
        if (interp.objectToStringTagKey(machine)) |tag_key| {
            if (privateDirectDataPropertyInChain(object, tag_key)) |tag|
                if (tag.isString()) return tag.asStr();
        }
        if (raw_name.len > 0) return raw_name;
        if (constructor_name == null) return "Object";
    }
    return constructor_name.?;
}

fn privateWriteBorrowedName(context: *Context, bytes: []const u8, output: *PrivateZigString) bool {
    const opaque_group = context.c_api_group orelse return false;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    output.* = privateBorrowedZigStringView(group, bytes) catch |err| {
        privatePublishBunStringError(context, err);
        return false;
    };
    return true;
}

fn privateNameProperty(
    context: *Context,
    machine: *interp.Interpreter,
    object: *Object,
    output: *PrivateZigString,
) bool {
    if (interp.objectToStringTagKey(machine)) |tag_key| {
        const tag = machine.getPropertyIfExists(Value.obj(object), tag_key) catch |err| {
            privateSetPendingAbrupt(context, machine, err);
            return false;
        };
        if (tag) |candidate| {
            if (candidate.isString() and candidate.asStr().len > 0)
                return privateWriteBorrowedName(context, candidate.asStr(), output);
        }
    }

    const is_named_function = object.jsFunction() != null or object.native != null or
        object.hostCallback() != null or object.errorCtor() != null;
    if (is_named_function)
        return privateWriteBorrowedName(context, privateCalculatedDisplayName(object), output);
    output.len = 0;
    return true;
}

export fn JSC__JSValue__getClassInfoName(
    encoded: EncodedValue,
    output: *[*:0]const u8,
    output_len: *usize,
) callconv(.c) bool {
    const boxed = privateBoxedFrom(encoded) orelse return false;
    if (boxed.private_kind != .value) return false;
    const name = privateStaticClassInfoName(boxed.value) orelse return false;
    output.* = name.ptr;
    output_len.* = name.len;
    return true;
}

export fn JSC__JSValue__getNameProperty(
    encoded: EncodedValue,
    global: JSContextRef,
    output: *PrivateZigString,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "Name target belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!internal.isObject() or internal.asObj().is_symbol or internal.asObj().is_bigint) {
        output.len = 0;
        return;
    }
    _ = privateNameProperty(context, &machine, internal.asObj(), output);
}

export fn JSC__JSValue__getClassName(
    encoded: EncodedValue,
    global: JSContextRef,
    output: *PrivateZigString,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "Class-name target belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!internal.isObject() or internal.asObj().is_symbol or internal.asObj().is_bigint) {
        output.len = 0;
        return;
    }
    const raw_name = privateStaticClassInfoName(internal) orelse {
        output.len = 0;
        return;
    };
    if (raw_name.len == 0 or std.mem.eql(u8, raw_name, "Function")) {
        _ = privateNameProperty(context, &machine, internal.asObj(), output);
        return;
    }
    _ = privateWriteBorrowedName(context, privateCalculatedClassName(&machine, internal.asObj(), raw_name), output);
}

export fn JSC__JSValue__getName(
    encoded: EncodedValue,
    global: JSContextRef,
    output: *PrivateBunString,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "Display-name target belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!internal.isObject() or internal.asObj().is_symbol or internal.asObj().is_bigint) {
        output.* = PrivateBunString.empty();
        return;
    }

    var name = privateCalculatedDisplayName(internal.asObj());
    if (name.len == 0) {
        if (interp.objectToStringTagKey(&machine)) |tag_key| {
            const tag = machine.getPropertyIfExists(internal, tag_key) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                return;
            };
            if (tag) |candidate| {
                if (candidate.isString()) name = candidate.asStr();
            }
        }
    }
    output.* = privateOwnedWTF8String(name) catch |err| {
        privatePublishBunStringError(context, err);
        return;
    };
}

fn privateInspectNativeFunction(
    machine: *interp.Interpreter,
    name: []const u8,
    length: usize,
    native: value.NativeFn,
) interp.EvalError!Value {
    const function = try gc_mod.allocObj(machine.arena);
    function.* = .{ .native = native, .proto = machine.functionProto() };
    try interp.installNativeProps(machine.arena, machine.root_shape, function, name, length);
    return Value.obj(function);
}

fn privateInspectStylizeNoColor(_: *anyopaque, _: Value, args: []const Value) value.HostError!Value {
    return if (args.len == 0) Value.undef() else args[0];
}

fn privateInspectStyleCodes(style_type: []const u8) ?struct { u8, u8 } {
    if (std.mem.eql(u8, style_type, "special")) return .{ 36, 39 };
    if (std.mem.eql(u8, style_type, "number") or std.mem.eql(u8, style_type, "bigint") or
        std.mem.eql(u8, style_type, "boolean")) return .{ 33, 39 };
    if (std.mem.eql(u8, style_type, "undefined")) return .{ 90, 39 };
    if (std.mem.eql(u8, style_type, "null")) return .{ 1, 22 };
    if (std.mem.eql(u8, style_type, "string") or std.mem.eql(u8, style_type, "symbol")) return .{ 32, 39 };
    if (std.mem.eql(u8, style_type, "date")) return .{ 35, 39 };
    if (std.mem.eql(u8, style_type, "regexp")) return .{ 31, 39 };
    if (std.mem.eql(u8, style_type, "module")) return .{ 4, 24 };
    return null;
}

fn privateInspectStylizeColor(ctx: *anyopaque, _: Value, args: []const Value) value.HostError!Value {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(ctx));
    const input = if (args.len == 0) Value.undef() else args[0];
    const text = try machine.toStringV(input);
    const style_type = if (args.len > 1) try machine.toStringV(args[1]) else "";
    const codes = privateInspectStyleCodes(style_type) orelse return Value.strAlloc(machine.arena, text);
    return Value.strAlloc(machine.arena, try std.fmt.allocPrint(
        machine.arena,
        "\x1b[{d}m{s}\x1b[{d}m",
        .{ codes[0], text, codes[1] },
    ));
}

fn privateInspectRecursive(ctx: *anyopaque, _: Value, args: []const Value) value.HostError!Value {
    const machine: *interp.Interpreter = @ptrCast(@alignCast(ctx));
    const input = if (args.len == 0) Value.undef() else args[0];
    var style: []const u8 = "special";
    const rendered = switch (input.kind()) {
        .undefined => blk: {
            style = "undefined";
            break :blk "undefined";
        },
        .null => blk: {
            style = "null";
            break :blk "null";
        },
        .boolean => blk: {
            style = "boolean";
            break :blk if (input.asBool()) "true" else "false";
        },
        .number => blk: {
            style = "number";
            break :blk try value.numberToString(machine.arena, input.asNum());
        },
        .string => blk: {
            style = "string";
            break :blk try std.fmt.allocPrint(machine.arena, "'{s}'", .{input.asStr()});
        },
        .object => blk: {
            const object = input.asObj();
            if (object.is_symbol) {
                style = "symbol";
                const description = object.symbolDescription() orelse "";
                break :blk try std.fmt.allocPrint(machine.arena, "Symbol({s})", .{description});
            }
            if (object.is_bigint) {
                style = "bigint";
                break :blk try std.fmt.allocPrint(machine.arena, "{s}n", .{try value.bigIntToString(object, machine.arena)});
            }
            break :blk "[object Object]";
        },
    };

    var colors = false;
    if (args.len > 1 and args[1].isObject()) {
        const candidate = try machine.getProperty(args[1], "colors");
        colors = candidate.toBoolean();
    }
    const rendered_value = try Value.strAlloc(machine.arena, rendered);
    if (!colors) return rendered_value;
    return privateInspectStylizeColor(ctx, Value.undef(), &.{ rendered_value, try Value.strAlloc(machine.arena, style) });
}

/// Exact Bun/Home custom-inspect call frame: `(depth, options, inspect)` with
/// the inspected value as `this`. The helper functions and options object are
/// ordinary realm-owned GC values, so the interpreter's active call frame roots
/// them across arbitrary user code and explicit collections.
export fn JSC__JSValue__callCustomInspectFunction(
    global: JSContextRef,
    encoded_function: EncodedValue,
    encoded_this: EncodedValue,
    depth: u32,
    max_depth: u32,
    colors: bool,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const function = privateValueFrom(global, encoded_function) orelse {
        const abrupt = machine.throwError("TypeError", "Custom inspect function belongs to another VM");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .empty;
    };
    const this_value = privateValueFrom(global, encoded_this) orelse {
        const abrupt = machine.throwError("TypeError", "Custom inspect receiver belongs to another VM");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .empty;
    };
    if (!function.isObject() or !function.asObj().isCallableObject()) {
        const abrupt = machine.throwError("TypeError", "Custom inspect value is not callable");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .empty;
    }

    const stylize = privateInspectNativeFunction(
        &machine,
        if (colors) "stylizeWithColor" else "stylizeWithNoColor",
        2,
        if (colors) privateInspectStylizeColor else privateInspectStylizeNoColor,
    ) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const inspect_roots_mark = machine.pushTempRoot(stylize) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer machine.restoreTempRoots(inspect_roots_mark);
    const inspect_function = privateInspectNativeFunction(&machine, "inspect", 2, privateInspectRecursive) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    _ = machine.pushTempRoot(inspect_function) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const options_value = machine.newObject() catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    _ = machine.pushTempRoot(options_value) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const options = options_value.asObj();
    options.setOwn(machine.arena, machine.root_shape, "stylize", stylize) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    options.setOwn(machine.arena, machine.root_shape, "depth", Value.num(@floatFromInt(max_depth))) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    options.setOwn(machine.arena, machine.root_shape, "colors", Value.boolVal(colors)) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };

    const result = machine.callValueWithThis(
        function,
        &.{ Value.num(@floatFromInt(depth)), options_value, inspect_function },
        this_value,
    ) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

fn privateJSONStringify(
    encoded: EncodedValue,
    global: JSContextRef,
    indent: ?u32,
    output: *PrivateBunString,
) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "JSON value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const spacing = if (indent) |width| Value.num(@floatFromInt(width)) else Value.undef();
    const rendered = builtins.jsonStringify(
        &machine,
        Value.undef(),
        &.{ internal, Value.undef(), spacing },
    ) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!rendered.isString()) {
        output.* = PrivateBunString.empty();
        return;
    }
    output.* = privateOwnedWTF8String(rendered.asStr()) catch |err| {
        privatePublishBunStringError(context, err);
        return;
    };
}

export fn JSC__JSValue__jsonStringify(
    encoded: EncodedValue,
    global: JSContextRef,
    indent: u32,
    output: *PrivateBunString,
) callconv(.c) void {
    privateJSONStringify(encoded, global, indent, output);
}

export fn JSC__JSValue__jsonStringifyFast(
    encoded: EncodedValue,
    global: JSContextRef,
    output: *PrivateBunString,
) callconv(.c) void {
    privateJSONStringify(encoded, global, null, output);
}

export fn JSC__JSValue__isJSXElement(
    encoded: EncodedValue,
    global: JSContextRef,
) callconv(.c) bool {
    const context = ctxForEvaluation(global) orelse return false;
    const group = privatePropertyBoundaryGroup(context) orelse return false;
    if (group.pending_exception != null) return false;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    defer context.popActiveInterpreter(&machine);
    const target = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "JSX element value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    // JSC's isObject excludes its Symbol/BigInt cells even though zig-js keeps
    // those GC-managed primitives in Object storage internally.
    if (!target.isObject() or target.asObj().is_symbol or target.asObj().is_bigint) return false;
    const type_value = machine.getProperty(target, "$$typeof") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    if (!type_value.isObject() or !type_value.asObj().is_symbol) return false;
    const legacy = interp.symbolForKey(&machine, "react.element") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    if (value.strictEquals(type_value, legacy)) return true;
    const transitional = interp.symbolForKey(&machine, "react.transitional.element") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    return value.strictEquals(type_value, transitional);
}

const PrivateProxyInternalField = enum(u32) {
    target = 0,
    handler = 1,
    _,
};

const PrivateNoSideEffectString = enum(usize) {
    symbol,
    true_value,
    false_value,
    null_value,
    undefined_value,
    object,
};

fn privateNoSideEffectStaticString(
    context: *Context,
    group: *CContextGroup,
    kind: PrivateNoSideEffectString,
) EncodedValue {
    const slot = &group.no_side_effect_strings[@intFromEnum(kind)];
    if (slot.*) |existing| return privateEncodedFromRef(@ptrCast(existing));
    const projected = switch (kind) {
        .symbol => Value.str("Symbol"),
        .true_value => Value.str("true"),
        .false_value => Value.str("false"),
        .null_value => Value.str("null"),
        .undefined_value => Value.str("undefined"),
        .object => Value.str("[object Object]"),
    };
    const created: *Boxed = @ptrCast(@alignCast(box(context, projected) orelse return .empty));
    slot.* = created;
    return privateEncodedFromRef(@ptrCast(created));
}

fn privateNoSideEffectOwnedString(context: *Context, bytes: []const u8) EncodedValue {
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    const projected = Value.strAlloc(context.arena(), bytes) catch return .empty;
    return privateEncodedFromValue(context, projected);
}

fn privateNoSideEffectValue(context: *Context, input: Value) !Value {
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);

    return switch (input.kind()) {
        .undefined => Value.str("undefined"),
        .null => Value.str("null"),
        .boolean => if (input.asBool()) Value.str("true") else Value.str("false"),
        .number => Value.strAlloc(context.arena(), try value.numberToString(context.arena(), input.asNum())),
        .string => input,
        .object => object: {
            const object = input.asObj();
            if (object.is_symbol) {
                const description = object.symbolDescription() orelse break :object Value.str("Symbol");
                break :object Value.strAlloc(context.arena(), try std.fmt.allocPrint(context.arena(), "Symbol({s})", .{description}));
            }
            if (object.is_bigint)
                break :object Value.strAlloc(context.arena(), try value.bigIntToString(object, context.arena()));
            break :object Value.str("[object Object]");
        },
    };
}

/// Pinned fatal-error projection: this deliberately bypasses every observable
/// JavaScript conversion hook and mutable intrinsic.
export fn Bun__noSideEffectsToString(
    vm_ref: ?*anyopaque,
    global: JSContextRef,
    encoded: EncodedValue,
) callconv(.c) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const group = privateGroupFromVM(vm_ref) orelse return .empty;
    if (context.c_api_group != vm_ref) return .empty;
    const input = privateValueFrom(global, encoded) orelse return .empty;
    // Preserve the pinned primitive singletons and string-handle identity.
    return switch (input.kind()) {
        .undefined => privateNoSideEffectStaticString(context, group, .undefined_value),
        .null => privateNoSideEffectStaticString(context, group, .null_value),
        .boolean => privateNoSideEffectStaticString(context, group, if (input.asBool()) .true_value else .false_value),
        .string => encoded,
        else => privateEncodedFromValue(context, privateNoSideEffectValue(context, input) catch return .empty),
    };
}

/// Pinned Bun unhandled-rejection classifier. JSC's implementation performs
/// the equivalent of `Object.prototype.hasOwnProperty.call(reason, "stack")`:
/// accessors count without being invoked, while Proxy [[GetOwnProperty]] traps
/// remain observable and may publish an abrupt completion.
export fn Bun__promises__isErrorLike(
    global: JSContextRef,
    encoded: EncodedValue,
) callconv(.c) bool {
    const context = ctxForEvaluation(global) orelse return false;
    const group = privatePropertyBoundaryGroup(context) orelse return false;
    if (group.pending_exception != null) return false;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    defer context.popActiveInterpreter(&machine);
    const reason = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "rejection reason belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    if (!reason.isObject() or reason.asObj().is_symbol or reason.asObj().is_bigint) return false;
    return machine.hasOwnPropertyResult(reason.asObj(), "stack") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
}

fn privateIsOrdinaryJSObject(input: Value) bool {
    return input.isObject() and !input.asObj().is_symbol and !input.asObj().is_bigint;
}

fn privateSetWarningProperty(
    machine: *interp.Interpreter,
    object: *Object,
    name: []const u8,
    property_value: Value,
    enumerable: bool,
) !void {
    try object.setOwn(machine.arena, machine.root_shape, name, property_value);
    try object.setAttr(machine.arena, name, .{ .writable = true, .enumerable = enumerable, .configurable = true });
}

/// Pinned Process::emitWarning normalization. Delivery is queued through the
/// selected realm so multiple warnings preserve FIFO order and listener throws
/// surface at the later microtask checkpoint, matching Bun's nextTick turn.
fn privateEmitProcessWarning(
    machine: *interp.Interpreter,
    warning: Value,
    warning_type_input: Value,
    code_input: Value,
    ctor_input: Value,
) !void {
    var warning_type = warning_type_input;
    var code = code_input;
    _ = ctor_input; // Pinned Bun currently leaves constructor-based stack trimming disabled.
    var detail = Value.undef();

    if (!warning_type.isNull() and privateIsOrdinaryJSObject(warning_type) and !warning_type.asObj().is_array) {
        _ = try machine.getProperty(warning_type, "ctor");
        code = try machine.getProperty(warning_type, "code");
        detail = try machine.getProperty(warning_type, "detail");
        if (!detail.isString()) detail = Value.undef();
        warning_type = try machine.getProperty(warning_type, "type");
        if (!warning_type.toBoolean()) warning_type = Value.str("Warning");
    } else if (warning_type.isCallable()) {
        code = Value.undef();
        warning_type = Value.str("Warning");
    }

    if (warning_type.isUndefined()) {
        warning_type = Value.str("Warning");
    } else if (!warning_type.isString()) {
        return machine.throwError("TypeError", "The \"type\" argument must be a string");
    }

    if (code.isCallable()) {
        code = Value.undef();
    } else if (!code.isUndefined() and !code.isString()) {
        return machine.throwError("TypeError", "The \"code\" argument must be a string");
    }
    const error_instance: *Object = if (warning.isString()) blk: {
        const message = if (warning.asStr().len == 0) "Warning" else warning.asStr();
        const created = try machine.makeError("Error", message);
        try privateSetWarningProperty(machine, created.asObj(), "name", warning_type, false);
        break :blk created.asObj();
    } else if (privateIsOrdinaryJSObject(warning) and warning.asObj().behavior.is_error)
        warning.asObj()
    else
        return machine.throwError("TypeError", "The \"warning\" argument must be a string or Error");

    if (!code.isUndefined()) try privateSetWarningProperty(machine, error_instance, "code", code, false);
    if (!detail.isUndefined()) try privateSetWarningProperty(machine, error_instance, "detail", detail, false);
    try interp.enqueueProcessWarning(machine, Value.obj(error_instance));
}

fn privateDecodeWarningArgument(
    context: *Context,
    machine: *interp.Interpreter,
    global: JSContextRef,
    encoded: EncodedValue,
    label: []const u8,
) !Value {
    return privateValueFrom(global, encoded) orelse
        return machine.throwError("TypeError", try std.fmt.allocPrint(context.arena(), "{s} belongs to another VM", .{label}));
}

export fn Bun__Process__emitWarning(
    global: JSContextRef,
    warning_encoded: EncodedValue,
    type_encoded: EncodedValue,
    code_encoded: EncodedValue,
    ctor_encoded: EncodedValue,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    const warning = privateDecodeWarningArgument(context, &machine, global, warning_encoded, "warning") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const warning_type = privateDecodeWarningArgument(context, &machine, global, type_encoded, "warning type") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const code = privateDecodeWarningArgument(context, &machine, global, code_encoded, "warning code") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const ctor = privateDecodeWarningArgument(context, &machine, global, ctor_encoded, "warning constructor") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    privateEmitProcessWarning(&machine, warning, warning_type, code, ctor) catch |err|
        privateSetPendingAbrupt(context, &machine, err);
}

const private_unhandled_rejection_warning_message =
    "Unhandled promise rejection. This error originated either by " ++
    "throwing inside of an async function without a catch block, " ++
    "or by rejecting a promise which was not handled with .catch(). " ++
    "To terminate the bun process on unhandled promise " ++
    "rejection, use the CLI flag `--unhandled-rejections=strict`.";

export fn Bun__promises__emitUnhandledRejectionWarning(
    global: JSContextRef,
    reason_encoded: EncodedValue,
    promise_encoded: EncodedValue,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    const reason = privateValueFrom(global, reason_encoded) orelse return;
    // The pinned implementation receives the promise for ABI symmetry but the
    // warning text and warning events do not expose it.
    _ = privateValueFrom(global, promise_encoded) orelse return;

    const warning = machine.makeError("Error", private_unhandled_rejection_warning_message) catch return;
    privateSetWarningProperty(&machine, warning.asObj(), "name", Value.str("UnhandledPromiseRejectionWarning"), false) catch return;

    var reason_stack: ?Value = null;
    const error_like = if (privateIsOrdinaryJSObject(reason))
        machine.hasOwnPropertyResult(reason.asObj(), "stack") catch blk: {
            machine.exception = Value.undef();
            break :blk false;
        }
    else
        false;
    if (error_like) {
        reason_stack = machine.getProperty(reason, "stack") catch blk: {
            machine.exception = Value.undef();
            break :blk null;
        };
        if (reason_stack) |stack|
            privateSetWarningProperty(&machine, warning.asObj(), "stack", stack, true) catch {};
    }
    if (reason_stack == null)
        reason_stack = privateNoSideEffectValue(context, reason) catch Value.undef();

    privateEmitProcessWarning(
        &machine,
        reason_stack orelse Value.undef(),
        Value.str("UnhandledPromiseRejectionWarning"),
        Value.undef(),
        Value.undef(),
    ) catch {
        machine.exception = Value.undef();
    };
    interp.enqueueProcessWarning(&machine, warning) catch {
        machine.exception = Value.undef();
    };
}

fn privateProcessEventCount(machine: *interp.Interpreter, event: []const u8) usize {
    return interp.processEventListenerCount(machine, event) catch 0;
}

export fn Bun__handleUnhandledRejection(
    global: JSContextRef,
    reason_encoded: EncodedValue,
    promise_encoded: EncodedValue,
) callconv(.c) c_int {
    const context = ctxForEvaluation(global) orelse return 0;
    const group = privatePropertyBoundaryGroup(context) orelse return 0;
    if (group.pending_exception != null) return 0;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 0;
    };
    defer context.popActiveInterpreter(&machine);

    const reason = privateDecodeWarningArgument(context, &machine, global, reason_encoded, "rejection reason") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 0;
    };
    const promise_value = privateDecodeWarningArgument(context, &machine, global, promise_encoded, "rejected promise") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 0;
    };
    if (privateProcessEventCount(&machine, "unhandledRejection") == 0) return 0;
    _ = interp.emitProcessEvent(&machine, "unhandledRejection", &.{ reason, promise_value }) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 1;
    };
    return 1;
}

export fn Bun__emitHandledPromiseEvent(
    global: JSContextRef,
    promise_encoded: EncodedValue,
) callconv(.c) bool {
    const context = ctxForEvaluation(global) orelse return false;
    const group = privatePropertyBoundaryGroup(context) orelse return false;
    if (group.pending_exception != null) return false;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    defer context.popActiveInterpreter(&machine);

    const promise_value = privateDecodeWarningArgument(context, &machine, global, promise_encoded, "handled promise") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    // Bun's default `.bun` rejection policy suppresses the optional
    // PromiseRejectionHandledWarning; the event itself remains observable.
    if (privateProcessEventCount(&machine, "rejectionHandled") == 0) return false;
    _ = interp.emitProcessEvent(&machine, "rejectionHandled", &.{promise_value}) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return true;
    };
    return true;
}

export fn Bun__handleUncaughtException(
    global: JSContextRef,
    error_encoded: EncodedValue,
    is_rejection: c_int,
) callconv(.c) c_int {
    const context = ctxForEvaluation(global) orelse return 0;
    const group = privatePropertyBoundaryGroup(context) orelse return 0;
    if (group.pending_exception != null) return 0;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 0;
    };
    defer context.popActiveInterpreter(&machine);

    const error_value = privateDecodeWarningArgument(context, &machine, global, error_encoded, "uncaught exception") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 0;
    };
    const handled = interp.handleProcessUncaughtException(&machine, error_value, is_rejection != 0) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return 1;
    };
    return @intFromBool(handled);
}

const private_unhandled_rejection_error_prefix =
    "This error originated either by throwing inside of an async function without a catch block, " ++
    "or by rejecting a promise which was not handled with .catch(). The promise rejected with the reason \"";

export fn Bun__wrapUnhandledRejectionErrorForUncaughtException(
    global: JSContextRef,
    reason_encoded: EncodedValue,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const reason = privateDecodeWarningArgument(context, &machine, global, reason_encoded, "rejection reason") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    const error_like = if (privateIsOrdinaryJSObject(reason))
        machine.hasOwnPropertyResult(reason.asObj(), "stack") catch blk: {
            machine.exception = Value.undef();
            break :blk false;
        }
    else
        false;
    if (error_like) return reason_encoded;

    const rendered = privateNoSideEffectValue(context, reason) catch Value.str("undefined");
    const rendered_bytes = if (rendered.isString()) rendered.asStr() else "undefined";
    const message = std.fmt.allocPrint(context.arena(), "{s}{s}\".", .{ private_unhandled_rejection_error_prefix, rendered_bytes }) catch {
        privateSetPendingAbrupt(context, &machine, error.OutOfMemory);
        return .empty;
    };
    const wrapped = machine.makeError("Error", message) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    privateSetWarningProperty(&machine, wrapped.asObj(), "name", Value.str("UnhandledPromiseRejection"), false) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    privateSetWarningProperty(&machine, wrapped.asObj(), "code", Value.str("ERR_UNHANDLED_REJECTION"), false) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, wrapped);
}

fn privateDispatchProcessCodeEvent(global: JSContextRef, event: []const u8, code: u8, once: bool) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    if (once) {
        const process_value = machine.env.get("process") orelse return;
        if (!process_value.isObject()) return;
        if ((process_value.asObj().getOwn("#processExitDispatched\x00runtime") orelse Value.boolVal(false)).toBoolean()) return;
        process_value.asObj().setOwn(machine.arena, machine.root_shape, "#processExitDispatched\x00runtime", Value.boolVal(true)) catch return;
        process_value.asObj().setOwn(machine.arena, machine.root_shape, "_exiting", Value.boolVal(true)) catch return;
    }
    const emitted = interp.emitProcessEvent(&machine, event, &.{Value.num(@floatFromInt(code))}) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (emitted and !once)
        machine.drainMicrotasks() catch |err| privateSetPendingAbrupt(context, &machine, err);
}

export fn Process__dispatchOnBeforeExit(global: JSContextRef, code: u8) callconv(.c) void {
    privateDispatchProcessCodeEvent(global, "beforeExit", code, false);
}

export fn Process__dispatchOnExit(global: JSContextRef, code: u8) callconv(.c) void {
    privateDispatchProcessCodeEvent(global, "exit", code, true);
}

fn privateEmitProcessIPCEvent(
    global: JSContextRef,
    event: []const u8,
    encoded_args: []const EncodedValue,
) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    // Bun checks hasEventListeners before decoding. Besides avoiding work, this
    // makes absent-listener dispatch a true no-op for empty or foreign handles,
    // and prevents `error` from taking EventEmitter's unhandled-error branch.
    if (privateProcessEventCount(&machine, event) == 0) return;
    var args: [2]Value = undefined;
    for (encoded_args, 0..) |encoded, i| {
        args[i] = privateDecodeWarningArgument(context, &machine, global, encoded, "IPC event value") catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return;
        };
    }
    _ = interp.emitProcessEvent(&machine, event, args[0..encoded_args.len]) catch |err|
        privateSetPendingAbrupt(context, &machine, err);
}

export fn Process__emitMessageEvent(
    global: JSContextRef,
    encoded_value: EncodedValue,
    handle: EncodedValue,
) callconv(.c) void {
    privateEmitProcessIPCEvent(global, "message", &.{ encoded_value, handle });
}

export fn Process__emitDisconnectEvent(global: JSContextRef) callconv(.c) void {
    privateEmitProcessIPCEvent(global, "disconnect", &.{});
}

export fn Process__emitErrorEvent(global: JSContextRef, encoded_value: EncodedValue) callconv(.c) void {
    privateEmitProcessIPCEvent(global, "error", &.{encoded_value});
}

const PrivateIterableCallback = *const fn (
    ?*anyopaque,
    JSContextRef,
    ?*anyopaque,
    EncodedValue,
) callconv(.c) void;

/// Drain a JavaScript iterable through the pinned native callback boundary.
/// Iterator acquisition and `next` are each cached once; a callback-published
/// exception closes the still-open iterator while preserving that first error.
export fn JSC__JSValue__forEach(
    encoded: EncodedValue,
    global: JSContextRef,
    callback_context: ?*anyopaque,
    callback: ?PrivateIterableCallback,
) callconv(.c) void {
    const emit = callback orelse return;
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    const iterable = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "iterable belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const iterator_key = machine.wellKnownSymbolKey("iterator") orelse {
        const err = machine.throwError("TypeError", "Symbol.iterator is unavailable");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const iterator_method = machine.getProperty(iterable, iterator_key) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!iterator_method.isCallable()) {
        const err = machine.throwError("TypeError", "value is not iterable");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    }
    const iterator = machine.callValueWithThis(iterator_method, &.{}, iterable) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!iterator.isObject() or iterator.asObj().is_symbol or iterator.asObj().is_bigint) {
        const err = machine.throwError("TypeError", "iterator is not an object");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    }
    const next = machine.getProperty(iterator, "next") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!next.isCallable()) {
        const err = machine.throwError("TypeError", "iterator next method is not callable");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    }
    while (true) {
        const result = machine.callValueWithThis(next, &.{}, iterator) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return;
        };
        if (!result.isObject() or result.asObj().is_symbol or result.asObj().is_bigint) {
            const err = machine.throwError("TypeError", "iterator result is not an object");
            privateSetPendingAbrupt(context, &machine, err);
            return;
        }
        const done = machine.getProperty(result, "done") catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return;
        };
        if (done.toBoolean()) return;
        const item = machine.getProperty(result, "value") catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return;
        };
        const item_encoded = privateEncodedFromValue(context, item);
        if (item_encoded == .empty) {
            privateSetPendingAbrupt(context, &machine, error.OutOfMemory);
            machine.iteratorClose(iterator) catch {};
            return;
        }
        emit(@ptrCast(group), global, callback_context, item_encoded);
        if (group.pending_exception != null) {
            machine.iteratorClose(iterator) catch {};
            return;
        }
    }
}

/// Pure projection of JSC::ProxyObject's two write-barrier fields. This is an
/// inspector primitive: it never performs an ordinary property read or invokes
/// a proxy trap. Revocation clears both fields to JavaScript null.
export fn Bun__ProxyObject__getInternalField(
    encoded: EncodedValue,
    field: PrivateProxyInternalField,
) callconv(.c) EncodedValue {
    const boxed = privateBoxedFrom(encoded) orelse return .empty;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return .empty;
    const proxy = boxed.value.asObj();
    if (proxy.proxy_revoked) return switch (field) {
        .target, .handler => .null,
        else => .empty,
    };
    const selected = switch (field) {
        .target => proxy.proxyTarget() orelse return .empty,
        .handler => proxy.proxyHandler() orelse return .empty,
        else => return .empty,
    };
    return privateEncodedFromValue(boxed.owner, Value.obj(selected));
}

const PrivateDeepPair = struct {
    left: *Object,
    right: *Object,
};

const PrivateDeepMapEntry = struct {
    key: Value,
    value_: Value,
};

fn privateDeepObject(input: Value) ?*Object {
    if (!input.isObject()) return null;
    const object = input.asObj();
    if (object.is_symbol or object.is_bigint or object.getterSetterCellData() != null) return null;
    return object;
}

fn privateDeepElementSnapshot(machine: *interp.Interpreter, object: *Object) ![]Value {
    object.lockElements();
    defer object.unlockElements();
    const result = try machine.arena.alloc(Value, object.elementsItems().len);
    @memcpy(result, object.elementsItems());
    return result;
}

fn privateDeepMapEntry(input: Value) ?PrivateDeepMapEntry {
    const object = privateDeepObject(input) orelse return null;
    if (object.elementsLen() < 2) return null;
    return .{
        .key = object.elementAt(0) orelse return null,
        .value_ = object.elementAt(1) orelse Value.undef(),
    };
}

fn privateDeepSetEntry(input: Value) ?Value {
    if (input.isObject() and input.asObj().behavior.is_set_deleted) return null;
    return input;
}

fn privateDeepArrayIndex(machine: *interp.Interpreter, object: *Object, index: usize) !?Value {
    if (index > std.math.maxInt(u32)) return null;
    return machine.getDirectIndex(object, @intCast(index));
}

fn privateDeepClassName(machine: *interp.Interpreter, object: *Object) []const u8 {
    var target = object;
    var guard: usize = 0;
    while (target.proxyTarget()) |next| {
        guard += 1;
        if (guard > 10_000) break;
        target = next;
    }
    return privateCalculatedClassName(machine, target, privateStaticClassInfoName(Value.obj(target)) orelse "Object");
}

fn privateDeepCompareEnumerable(
    machine: *interp.Interpreter,
    left: *Object,
    right: *Object,
    strict: bool,
    enable_asymmetric: bool,
    stack: *std.ArrayListUnmanaged(PrivateDeepPair),
    symbols_only: bool,
    skip_error_stack: bool,
) interp.EvalError!bool {
    const left_all = try builtins.ownEnumerablePropertyKeys(machine, left, true);
    const right_all = try builtins.ownEnumerablePropertyKeys(machine, right, true);
    var left_keys: std.ArrayListUnmanaged([]const u8) = .empty;
    var right_keys: std.ArrayListUnmanaged([]const u8) = .empty;
    for (left_all) |key| {
        if (symbols_only and !value.isRealSymbolKey(key)) continue;
        if (skip_error_stack and std.mem.eql(u8, key, "stack")) continue;
        try left_keys.append(machine.arena, key);
    }
    for (right_all) |key| {
        if (symbols_only and !value.isRealSymbolKey(key)) continue;
        if (skip_error_stack and std.mem.eql(u8, key, "stack")) continue;
        try right_keys.append(machine.arena, key);
    }
    if (strict and left_keys.items.len != right_keys.items.len) return false;

    for (left_keys.items) |key| {
        const left_value = try machine.getProperty(Value.obj(left), key);
        var present = false;
        for (right_keys.items) |right_key| {
            if (std.mem.eql(u8, key, right_key)) {
                present = true;
                break;
            }
        }
        if (!present) {
            if (!strict and left_value.isUndefined()) continue;
            return false;
        }
        const right_value = try machine.getProperty(Value.obj(right), key);
        if (!try privateDeepCompare(machine, left_value, right_value, strict, enable_asymmetric, stack, true)) return false;
    }
    for (right_keys.items) |key| {
        var present = false;
        for (left_keys.items) |left_key| {
            if (std.mem.eql(u8, key, left_key)) {
                present = true;
                break;
            }
        }
        if (present) continue;
        if (strict) return false;
        if (!(try machine.getProperty(Value.obj(right), key)).isUndefined()) return false;
    }
    return true;
}

fn privateDeepCompareMap(
    machine: *interp.Interpreter,
    left: *Object,
    right: *Object,
    strict: bool,
    enable_asymmetric: bool,
    stack: *std.ArrayListUnmanaged(PrivateDeepPair),
) interp.EvalError!bool {
    const left_raw = try privateDeepElementSnapshot(machine, left);
    const right_raw = try privateDeepElementSnapshot(machine, right);
    var left_entries: std.ArrayListUnmanaged(PrivateDeepMapEntry) = .empty;
    var right_entries: std.ArrayListUnmanaged(PrivateDeepMapEntry) = .empty;
    for (left_raw) |item| if (privateDeepMapEntry(item)) |entry| try left_entries.append(machine.arena, entry);
    for (right_raw) |item| if (privateDeepMapEntry(item)) |entry| try right_entries.append(machine.arena, entry);
    if (left_entries.items.len != right_entries.items.len) return false;
    for (left_entries.items) |left_entry| {
        var right_value = Value.undef();
        var found_direct = false;
        for (right_entries.items) |right_entry| {
            if (value.sameValueZero(left_entry.key, right_entry.key)) {
                right_value = right_entry.value_;
                found_direct = true;
                break;
            }
        }
        // Bun falls back to a linear structural-key search when Map#get yields
        // undefined, including when the direct key exists with an undefined
        // value. Preserve that observable candidate-selection order.
        if (!found_direct or right_value.isUndefined()) {
            var found_structural = false;
            for (right_entries.items) |right_entry| {
                if (try privateDeepCompare(machine, left_entry.key, right_entry.key, strict, enable_asymmetric, stack, false)) {
                    right_value = right_entry.value_;
                    found_structural = true;
                    break;
                }
            }
            if (!found_structural) return false;
        }
        if (!try privateDeepCompare(machine, left_entry.value_, right_value, strict, enable_asymmetric, stack, false)) return false;
    }
    return true;
}

fn privateDeepCompareSet(
    machine: *interp.Interpreter,
    left: *Object,
    right: *Object,
    strict: bool,
    enable_asymmetric: bool,
    stack: *std.ArrayListUnmanaged(PrivateDeepPair),
) interp.EvalError!bool {
    const left_raw = try privateDeepElementSnapshot(machine, left);
    const right_raw = try privateDeepElementSnapshot(machine, right);
    var left_entries: std.ArrayListUnmanaged(Value) = .empty;
    var right_entries: std.ArrayListUnmanaged(Value) = .empty;
    for (left_raw) |item| if (privateDeepSetEntry(item)) |entry| try left_entries.append(machine.arena, entry);
    for (right_raw) |item| if (privateDeepSetEntry(item)) |entry| try right_entries.append(machine.arena, entry);
    if (left_entries.items.len != right_entries.items.len) return false;
    for (left_entries.items) |left_entry| {
        var found = false;
        for (right_entries.items) |right_entry| {
            if (value.sameValueZero(left_entry, right_entry)) {
                found = true;
                break;
            }
        }
        if (found) continue;
        for (right_entries.items) |right_entry| {
            if (try privateDeepCompare(machine, left_entry, right_entry, strict, enable_asymmetric, stack, false)) {
                found = true;
                break;
            }
        }
        if (!found) return false;
    }
    return true;
}

fn privateDeepCompareTypedArray(
    machine: *interp.Interpreter,
    left: *const value.TypedArrayData,
    right: *const value.TypedArrayData,
    strict: bool,
) !bool {
    if (left.kind != right.kind) return false;
    // JSC reports a detached or out-of-bounds view's byteLength as zero and
    // accepts two zero-byte views before consulting the detached bit.
    const left_len = left.currentLength() orelse 0;
    const right_len = right.currentLength() orelse 0;
    if (left_len != right_len) return false;
    if (left_len == 0) return true;
    const left_buffer = left.buffer.arrayBuffer() orelse return false;
    const right_buffer = right.buffer.arrayBuffer() orelse return false;
    if (left_buffer.isDetached() or right_buffer.isDetached()) return false;
    if (!strict and (left.kind == .f16 or left.kind == .f32 or left.kind == .f64)) {
        for (0..left_len) |index| {
            const a = (try machine.taLoad(left, index)).asNum();
            const b = (try machine.taLoad(right, index)).asNum();
            if (a != b) return false;
        }
        return true;
    }
    const byte_len = left_len * left.kind.byteSize();
    const left_bytes = left.buffer.arrayBuffer().?.bytes()[left.byte_offset .. left.byte_offset + byte_len];
    const right_bytes = right.buffer.arrayBuffer().?.bytes()[right.byte_offset .. right.byte_offset + byte_len];
    return std.mem.eql(u8, left_bytes, right_bytes);
}

const PrivateAsymmetricKind = enum {
    anything,
    any,
    string_containing,
    string_matching,
    array_containing,
    object_containing,
    close_to,
    custom,
};

const PrivateAsymmetricPromise = enum { none, resolves, rejects };

const PrivateAsymmetricMatcher = struct {
    object: *Object,
    kind: PrivateAsymmetricKind,
    inverse: bool = false,
    promise_mode: PrivateAsymmetricPromise = .none,
};

const PrivateDeepVisited = struct {
    objects: std.ArrayListUnmanaged(*Object) = .empty,
    subsets: std.ArrayListUnmanaged(*Object) = .empty,
};

fn privateAsymmetricKind(name: []const u8) ?PrivateAsymmetricKind {
    const normalized = if (std.mem.startsWith(u8, name, "Expect")) name["Expect".len..] else name;
    if (std.ascii.eqlIgnoreCase(normalized, "Anything")) return .anything;
    if (std.ascii.eqlIgnoreCase(normalized, "Any")) return .any;
    if (std.ascii.eqlIgnoreCase(normalized, "StringContaining") or std.ascii.eqlIgnoreCase(normalized, "string_containing")) return .string_containing;
    if (std.ascii.eqlIgnoreCase(normalized, "StringMatching") or std.ascii.eqlIgnoreCase(normalized, "string_matching")) return .string_matching;
    if (std.ascii.eqlIgnoreCase(normalized, "ArrayContaining") or std.ascii.eqlIgnoreCase(normalized, "array_containing")) return .array_containing;
    if (std.ascii.eqlIgnoreCase(normalized, "ObjectContaining") or std.ascii.eqlIgnoreCase(normalized, "object_containing")) return .object_containing;
    if (std.ascii.eqlIgnoreCase(normalized, "CloseTo") or std.ascii.eqlIgnoreCase(normalized, "close_to")) return .close_to;
    if (std.ascii.eqlIgnoreCase(normalized, "Custom")) return .custom;
    return null;
}

fn privateMatcherData(object: *Object, names: []const []const u8) ?Value {
    for (names) |name|
        if (privateDirectDataPropertyInChain(object, name)) |found| return found;
    return null;
}

fn privateAsymmetricMatcher(
    machine: *interp.Interpreter,
    input: Value,
) interp.EvalError!?PrivateAsymmetricMatcher {
    const object = privateDeepObject(input) orelse return null;
    var kind: ?PrivateAsymmetricKind = null;
    if (privateMatcherData(object, &.{"__zig_js_asymmetric_matcher__"})) |explicit| {
        if (explicit.isString()) kind = privateAsymmetricKind(explicit.asStr());
    }

    if (kind == null) {
        const marker = privateMatcherData(object, &.{"$$typeof"}) orelse return null;
        const expected = try interp.symbolForKey(machine, "jest.asymmetricMatcher");
        if (!value.strictEquals(marker, expected)) return null;
        kind = privateAsymmetricKind(privateDeepClassName(machine, object));
        if (kind == null) {
            const method = privateMatcherData(object, &.{"asymmetricMatch"}) orelse return null;
            if (!method.isCallable()) return machine.throwError("TypeError", "asymmetricMatch is not callable");
            kind = .custom;
        }
    }

    var inverse = false;
    var promise_mode: PrivateAsymmetricPromise = .none;
    if (privateMatcherData(object, &.{ "inverse", "isNot" })) |inverse_value|
        inverse = inverse_value.toBoolean();
    if (privateMatcherData(object, &.{"flags"})) |flags|
        if (flags.isNumber()) {
            const bits: u32 = @bitCast(flags.toInt32());
            inverse = inverse or (bits & 4) != 0;
            if ((bits & 1) != 0) promise_mode = .resolves;
            if ((bits & 2) != 0) promise_mode = .rejects;
        };
    if (privateMatcherData(object, &.{ "promise", "promiseMode" })) |mode|
        if (mode.isString()) {
            if (std.mem.eql(u8, mode.asStr(), "resolves")) promise_mode = .resolves;
            if (std.mem.eql(u8, mode.asStr(), "rejects")) promise_mode = .rejects;
        };
    return .{ .object = object, .kind = kind.?, .inverse = inverse, .promise_mode = promise_mode };
}

fn privateAsymmetricInput(matcher: PrivateAsymmetricMatcher, other: Value) ?Value {
    if (matcher.promise_mode == .none) return other;
    const target = promise.promiseOf(other) orelse return null;
    target.lockState();
    defer target.unlockState();
    target.is_handled = true;
    return switch (target.state) {
        .fulfilled => if (matcher.promise_mode == .resolves) target.value else null,
        .rejected => if (matcher.promise_mode == .rejects) target.value else null,
        .pending => null,
    };
}

fn privateMatcherSample(object: *Object, names: []const []const u8) ?Value {
    return privateMatcherData(object, names) orelse privateMatcherData(object, &.{"sample"});
}

fn privateAsymmetricCompare(
    machine: *interp.Interpreter,
    matcher_value: Value,
    other_value: Value,
) interp.EvalError!?bool {
    const matcher = (try privateAsymmetricMatcher(machine, matcher_value)) orelse return null;
    const processed = privateAsymmetricInput(matcher, other_value);
    var allow_inverse = true;
    var raw = false;
    if (processed) |other| switch (matcher.kind) {
        .anything => raw = !other.isUndefined() and !other.isNull(),
        .any => any_match: {
            const constructor = privateMatcherSample(matcher.object, &.{"constructorValue"}) orelse Value.undef();
            if (constructor.isObject()) {
                const explicit_type = privateMatcherData(matcher.object, &.{"constructorType"});
                const constructor_name = if (explicit_type != null and explicit_type.?.isString())
                    explicit_type.?.asStr()
                else
                    privateCalculatedDisplayName(constructor.asObj());
                if ((machine.env.get("Symbol") != null and value.strictEquals(constructor, machine.env.get("Symbol").?)) or std.mem.eql(u8, constructor_name, "Symbol")) {
                    raw = other.isObject() and other.asObj().is_symbol;
                    break :any_match;
                }
                if ((machine.env.get("String") != null and value.strictEquals(constructor, machine.env.get("String").?)) or std.mem.eql(u8, constructor_name, "String")) {
                    raw = other.isString() or (other.isObject() and if (other.asObj().boxedPrimitive()) |boxed| boxed.isString() else false);
                    break :any_match;
                }
                if ((machine.env.get("BigInt") != null and value.strictEquals(constructor, machine.env.get("BigInt").?)) or std.mem.eql(u8, constructor_name, "BigInt")) {
                    raw = other.isObject() and other.asObj().is_bigint;
                    break :any_match;
                }
                if ((machine.env.get("Boolean") != null and value.strictEquals(constructor, machine.env.get("Boolean").?)) or std.mem.eql(u8, constructor_name, "Boolean")) {
                    raw = other.isBoolean() or (other.isObject() and if (other.asObj().boxedPrimitive()) |boxed| boxed.isBoolean() else false);
                    break :any_match;
                }
                if ((machine.env.get("Number") != null and value.strictEquals(constructor, machine.env.get("Number").?)) or std.mem.eql(u8, constructor_name, "Number")) {
                    raw = other.isNumber() or (other.isObject() and if (other.asObj().boxedPrimitive()) |boxed| boxed.isNumber() else false);
                    break :any_match;
                }
                if ((machine.env.get("Promise") != null and value.strictEquals(constructor, machine.env.get("Promise").?)) or std.mem.eql(u8, constructor_name, "Promise")) {
                    raw = promise.promiseOf(other) != null;
                    break :any_match;
                }
                if ((machine.env.get("Array") != null and value.strictEquals(constructor, machine.env.get("Array").?)) or std.mem.eql(u8, constructor_name, "Array")) {
                    raw = try builtins.isArrayValue(machine, other);
                    break :any_match;
                }
                if ((machine.env.get("Object") != null and value.strictEquals(constructor, machine.env.get("Object").?)) or std.mem.eql(u8, constructor_name, "Object")) {
                    raw = privateDeepObject(other) != null;
                    break :any_match;
                }
                raw = try machine.instanceOf(other, constructor);
            }
        },
        .string_containing => {
            const expected = privateMatcherSample(matcher.object, &.{"stringValue"}) orelse Value.undef();
            raw = other.isString() and expected.isString() and std.mem.indexOf(u8, other.asStr(), expected.asStr()) != null;
        },
        .string_matching => {
            const expected = privateMatcherSample(matcher.object, &.{"testValue"}) orelse Value.undef();
            if (other.isString() and expected.isString())
                raw = std.mem.indexOf(u8, other.asStr(), expected.asStr()) != null
            else if (other.isString() and expected.isObject() and expected.asObj().behavior.is_regex)
                raw = try machine.regexpTestBuiltin(expected.asObj(), other);
        },
        .array_containing => {
            const expected = privateMatcherSample(matcher.object, &.{"arrayValue"}) orelse Value.undef();
            if (expected.isObject() and other.isObject() and expected.asObj().is_array and other.asObj().is_array and
                expected.asObj().proxyHandler() == null and other.asObj().proxyHandler() == null)
            {
                raw = true;
                for (0..expected.asObj().arrayLength()) |expected_index| {
                    const key = try std.fmt.allocPrint(machine.arena, "{d}", .{expected_index});
                    const expected_item = try machine.getProperty(expected, key);
                    var found = false;
                    for (0..other.asObj().arrayLength()) |other_index| {
                        const other_key = try std.fmt.allocPrint(machine.arena, "{d}", .{other_index});
                        const other_item = try machine.getProperty(other, other_key);
                        var stack: std.ArrayListUnmanaged(PrivateDeepPair) = .empty;
                        if (try privateDeepCompare(machine, expected_item, other_item, false, true, &stack, true)) {
                            found = true;
                            break;
                        }
                    }
                    if (!found) {
                        raw = false;
                        break;
                    }
                }
            }
        },
        .object_containing => {
            const expected = privateMatcherSample(matcher.object, &.{"objectValue"}) orelse Value.undef();
            if (privateDeepObject(other)) |object| if (privateDeepObject(expected)) |subset| {
                var visited: PrivateDeepVisited = .{};
                raw = try privateDeepMatch(machine, object, subset, false, true, &visited);
            };
        },
        .close_to => {
            const expected = privateMatcherSample(matcher.object, &.{"numberValue"}) orelse Value.undef();
            const digits = privateMatcherSample(matcher.object, &.{ "digitsValue", "precision" }) orelse Value.num(2);
            if (!other.isNumber()) {
                allow_inverse = false;
            } else if (expected.isNumber() and digits.isNumber()) {
                const received_number = other.asNum();
                const expected_number = expected.asNum();
                raw = (std.math.isPositiveInf(received_number) and std.math.isPositiveInf(expected_number)) or
                    (std.math.isNegativeInf(received_number) and std.math.isNegativeInf(expected_number)) or
                    @abs(expected_number - received_number) < 0.5 * std.math.pow(f64, 10.0, -@as(f64, @floatFromInt(digits.toInt32())));
            }
        },
        .custom => {
            allow_inverse = false;
            const method = privateMatcherData(matcher.object, &.{"asymmetricMatch"}) orelse
                return machine.throwError("TypeError", "asymmetric matcher is missing asymmetricMatch");
            if (!method.isCallable()) return machine.throwError("TypeError", "asymmetricMatch is not callable");
            raw = (try machine.callValueWithThis(method, &.{other}, matcher_value)).toBoolean();
        },
    };
    return if (allow_inverse and matcher.inverse) !raw else raw;
}

fn privateDeepCompare(
    machine: *interp.Interpreter,
    left_value: Value,
    right_value: Value,
    strict: bool,
    enable_asymmetric: bool,
    stack: *std.ArrayListUnmanaged(PrivateDeepPair),
    add_to_stack: bool,
) interp.EvalError!bool {
    try machine.stackGuard();
    machine.depth += 1;
    defer machine.depth -= 1;
    if (enable_asymmetric) {
        if (try privateAsymmetricCompare(machine, right_value, left_value)) |matched| return matched;
        if (try privateAsymmetricCompare(machine, left_value, right_value)) |matched| return matched;
    }
    if (value.sameValue(left_value, right_value)) return true;
    const left = privateDeepObject(left_value) orelse return false;
    const right = privateDeepObject(right_value) orelse return false;

    for (stack.items) |pair| {
        if (pair.left == left) return pair.right == right;
        if (pair.right == right) return false;
    }
    if (add_to_stack) try stack.append(machine.arena, .{ .left = left, .right = right });
    defer {
        if (add_to_stack) _ = stack.pop();
    }

    if (privateObjectJSType(left) == .JSFunction or privateObjectJSType(right) == .JSFunction) return false;

    const left_is_array = try builtins.isArrayValue(machine, left_value);
    const right_is_array = try builtins.isArrayValue(machine, right_value);
    if (left_is_array != right_is_array) return false;
    if (left_is_array and left.proxyHandler() == null and right.proxyHandler() == null) {
        const left_len = left.arrayLength();
        const right_len = right.arrayLength();
        if (strict and left_len != right_len) return false;
        for (0..left_len) |index| {
            const a = try privateDeepArrayIndex(machine, left, index);
            const b = try privateDeepArrayIndex(machine, right, index);
            if (strict) {
                if (a == null and b == null) continue;
                if (a == null or b == null) return false;
            } else {
                if (a == null and b == null) continue;
                if ((a == null and b.?.isUndefined()) or (b == null and a.?.isUndefined())) continue;
                if (a == null or b == null) return false;
            }
            if (!try privateDeepCompare(machine, a.?, b.?, strict, enable_asymmetric, stack, true)) return false;
        }
        if (right_len > left_len) for (left_len..right_len) |index| {
            const item = try privateDeepArrayIndex(machine, right, index);
            if (item != null and !item.?.isUndefined()) return false;
        };
        return privateDeepCompareEnumerable(machine, left, right, strict, enable_asymmetric, stack, true, false);
    }

    if (left.is_set or right.is_set) {
        if (!left.is_set or !right.is_set or left.is_weak != right.is_weak) return false;
        if (!left.is_weak) return privateDeepCompareSet(machine, left, right, strict, enable_asymmetric, stack);
    }
    if (left.is_map or right.is_map) {
        if (!left.is_map or !right.is_map or left.is_weak != right.is_weak) return false;
        if (!left.is_weak) return privateDeepCompareMap(machine, left, right, strict, enable_asymmetric, stack);
    }

    const left_buffer = left.arrayBuffer();
    const right_buffer = right.arrayBuffer();
    if (left_buffer != null or right_buffer != null) {
        if (left_buffer == null or right_buffer == null) return false;
        const a = left_buffer.?;
        const b = right_buffer.?;
        const a_bytes = if (a.isDetached()) a.bytes()[0..0] else a.bytes();
        const b_bytes = if (b.isDetached()) b.bytes()[0..0] else b.bytes();
        if (a_bytes.len != b_bytes.len or a.is_shared != b.is_shared) return false;
        if (a_bytes.len == 0) return true;
        if (a.isDetached() or b.isDetached()) return false;
        return std.mem.eql(u8, a_bytes, b_bytes);
    }
    const left_typed = left.typedArray();
    const right_typed = right.typedArray();
    if (left_typed != null or right_typed != null) {
        if (left_typed == null or right_typed == null) return false;
        return privateDeepCompareTypedArray(machine, left_typed.?, right_typed.?, strict);
    }

    if (left.behavior.is_date or right.behavior.is_date)
        return left.behavior.is_date and right.behavior.is_date and left.dateMs() == right.dateMs();
    if (left.behavior.is_regex or right.behavior.is_regex)
        return left.behavior.is_regex and right.behavior.is_regex and
            std.mem.eql(u8, left.regexSource(), right.regexSource()) and
            std.mem.eql(u8, left.regexFlags(), right.regexFlags());
    if (left.behavior.is_error or right.behavior.is_error) {
        if (!left.behavior.is_error or !right.behavior.is_error) return false;
        if (!std.mem.eql(u8, left.errorName(), right.errorName())) return false;
        for ([_][]const u8{ "name", "message" }) |key| {
            if (!try privateDeepCompare(machine, try machine.getProperty(left_value, key), try machine.getProperty(right_value, key), strict, enable_asymmetric, stack, true)) return false;
        }
        if (strict and (try machine.hasPropertyResult(left, "cause")) != (try machine.hasPropertyResult(right, "cause"))) return false;
        if (!try privateDeepCompare(machine, try machine.getProperty(left_value, "cause"), try machine.getProperty(right_value, "cause"), strict, enable_asymmetric, stack, true)) return false;
        return privateDeepCompareEnumerable(machine, left, right, strict, enable_asymmetric, stack, false, true);
    }
    if (left.boxedPrimitive()) |boxed_left| {
        if (boxed_left.isString()) {
            const boxed_right = right.boxedPrimitive() orelse return false;
            return boxed_right.isString() and
                std.mem.eql(u8, privateDeepClassName(machine, left), privateDeepClassName(machine, right)) and
                std.mem.eql(u8, boxed_left.asStr(), boxed_right.asStr());
        }
    }

    if (strict and !std.mem.eql(u8, privateDeepClassName(machine, left), privateDeepClassName(machine, right))) return false;
    return privateDeepCompareEnumerable(machine, left, right, strict, enable_asymmetric, stack, false, false);
}

fn privateDeepSeen(items: []const *Object, needle: *Object) bool {
    for (items) |item| if (item == needle) return true;
    return false;
}

fn privateDeepReplace(machine: *interp.Interpreter, target: *Object, key: []const u8, replacement: Value) interp.EvalError!void {
    switch (try target.deleteAccessorOwn(machine.arena, key)) {
        .blocked => return machine.throwError("TypeError", "Cannot replace non-configurable asymmetric-matcher property"),
        else => {},
    }
    if (target.is_array) if (value.canonicalIndex(key)) |index| {
        try machine.putArrayDirectIndex(target, index, replacement);
        return;
    };
    try machine.setProp(target, key, replacement);
}

fn privateDeepMatch(
    machine: *interp.Interpreter,
    object: *Object,
    subset: *Object,
    replace_props_with_asymmetric: bool,
    is_matching_object_containing: bool,
    visited: *PrivateDeepVisited,
) interp.EvalError!bool {
    try machine.stackGuard();
    machine.depth += 1;
    defer machine.depth -= 1;
    if (object == subset) return true;

    const subset_keys = try builtins.ownEnumerablePropertyKeys(machine, subset, true);
    const object_value = Value.obj(object);
    const subset_value = Value.obj(subset);
    const object_is_array = try builtins.isArrayValue(machine, object_value);
    const subset_is_array = try builtins.isArrayValue(machine, subset_value);
    if (object_is_array and subset_is_array) {
        if (object.arrayLength() != subset.arrayLength()) return false;
        const object_keys = try builtins.ownEnumerablePropertyKeys(machine, object, true);
        if (object_keys.len != subset_keys.len) return false;
    }

    for (subset_keys) |key| {
        const object_property = (try machine.getPropertyIfExists(object_value, key)) orelse return false;
        const subset_property = try machine.getProperty(subset_value, key);

        if (try privateAsymmetricCompare(machine, subset_property, object_property)) |matched| {
            if (!matched) return false;
            if (replace_props_with_asymmetric) try privateDeepReplace(machine, object, key, subset_property);
            continue;
        }
        if (try privateAsymmetricCompare(machine, object_property, subset_property)) |matched| {
            if (!matched) return false;
            if (replace_props_with_asymmetric) try privateDeepReplace(machine, subset, key, object_property);
            continue;
        }

        const nested_object = privateDeepObject(object_property);
        const nested_subset = privateDeepObject(subset_property);
        if (nested_object != null and nested_subset != null) {
            if (is_matching_object_containing) {
                var stack: std.ArrayListUnmanaged(PrivateDeepPair) = .empty;
                if (!try privateDeepCompare(machine, object_property, subset_property, false, true, &stack, true)) return false;
            } else {
                const object_seen = privateDeepSeen(visited.objects.items, nested_object.?);
                const subset_seen = privateDeepSeen(visited.subsets.items, nested_subset.?);
                if (!object_seen) try visited.objects.append(machine.arena, nested_object.?);
                if (!subset_seen) try visited.subsets.append(machine.arena, nested_subset.?);
                if (object_seen or subset_seen) continue;
                if (!try privateDeepMatch(
                    machine,
                    nested_object.?,
                    nested_subset.?,
                    replace_props_with_asymmetric,
                    is_matching_object_containing,
                    visited,
                )) return false;
            }
        } else if (!value.sameValue(object_property, subset_property)) return false;
    }
    return true;
}

fn privateDeepEqualsBoundary(
    left_encoded: EncodedValue,
    right_encoded: EncodedValue,
    global: JSContextRef,
    strict: bool,
    enable_asymmetric: bool,
) bool {
    const context = ctxForEvaluation(global) orelse return false;
    const group = privatePropertyBoundaryGroup(context) orelse return false;
    if (group.pending_exception != null) return false;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    defer context.popActiveInterpreter(&machine);
    const left = privateValueFrom(global, left_encoded) orelse {
        const err = machine.throwError("TypeError", "Deep-equality value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    const right = privateValueFrom(global, right_encoded) orelse {
        const err = machine.throwError("TypeError", "Deep-equality value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    var stack: std.ArrayListUnmanaged(PrivateDeepPair) = .empty;
    return privateDeepCompare(&machine, left, right, strict, enable_asymmetric, &stack, true) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
}

export fn JSC__JSValue__deepEquals(
    left: EncodedValue,
    right: EncodedValue,
    global: JSContextRef,
) callconv(.c) bool {
    return privateDeepEqualsBoundary(left, right, global, false, false);
}

export fn JSC__JSValue__strictDeepEquals(
    left: EncodedValue,
    right: EncodedValue,
    global: JSContextRef,
) callconv(.c) bool {
    return privateDeepEqualsBoundary(left, right, global, true, false);
}

export fn JSC__JSValue__jestDeepEquals(
    left: EncodedValue,
    right: EncodedValue,
    global: JSContextRef,
) callconv(.c) bool {
    return privateDeepEqualsBoundary(left, right, global, false, true);
}

export fn JSC__JSValue__jestStrictDeepEquals(
    left: EncodedValue,
    right: EncodedValue,
    global: JSContextRef,
) callconv(.c) bool {
    return privateDeepEqualsBoundary(left, right, global, true, true);
}

export fn JSC__JSValue__jestDeepMatch(
    object_encoded: EncodedValue,
    subset_encoded: EncodedValue,
    global: JSContextRef,
    replace_props_with_asymmetric: bool,
) callconv(.c) bool {
    const context = ctxForEvaluation(global) orelse return false;
    const group = privatePropertyBoundaryGroup(context) orelse return false;
    if (group.pending_exception != null) return false;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    defer context.popActiveInterpreter(&machine);
    const object_value = privateValueFrom(global, object_encoded) orelse {
        const err = machine.throwError("TypeError", "Deep-match value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    const subset_value = privateValueFrom(global, subset_encoded) orelse {
        const err = machine.throwError("TypeError", "Deep-match subset belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
    const object = privateDeepObject(object_value) orelse return false;
    const subset = privateDeepObject(subset_value) orelse return false;
    var visited: PrivateDeepVisited = .{};
    return privateDeepMatch(&machine, object, subset, replace_props_with_asymmetric, false, &visited) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return false;
    };
}

export fn JSC__JSString__eql(
    left_cell: ?*anyopaque,
    global: JSContextRef,
    right_cell: ?*anyopaque,
) callconv(.c) bool {
    const context = ctxForHandleInspection(global) orelse return false;
    const left_box = privateStringBoxFromCell(left_cell) orelse return false;
    const right_box = privateStringBoxFromCell(right_cell) orelse return false;
    const left = valueFromContext(context, @ptrCast(left_box)) orelse return false;
    const right = valueFromContext(context, @ptrCast(right_box)) orelse return false;
    return std.mem.eql(u8, left.asStr(), right.asStr());
}

export fn JSC__JSString__is8Bit(cell: ?*anyopaque) callconv(.c) bool {
    const boxed = privateStringBoxFromCell(cell) orelse return false;
    return interp.Interpreter.jsStringIs8Bit(boxed.value.asStr());
}

export fn JSC__JSString__length(cell: ?*anyopaque) callconv(.c) usize {
    const boxed = privateStringBoxFromCell(cell) orelse return 0;
    return interp.Interpreter.utf16LenOfString(boxed.value.asStr());
}

export fn JSC__JSString__toObject(cell: ?*anyopaque, global: JSContextRef) callconv(.c) JSObjectRef {
    const context = ctxForHandleInspection(global) orelse return null;
    const boxed = privateStringBoxFromCell(cell) orelse return null;
    const handle: JSValueRef = @ptrCast(boxed);
    if (valueFromContext(context, handle) == null) return null;
    return JSValueToObject(global, handle, null);
}

export fn JSC__JSCell__getObject(cell: ?*anyopaque) callconv(.c) JSObjectRef {
    const boxed = privateBoxFromCell(cell) orelse return null;
    if (boxed.private_kind != .value) return null;
    if (!boxed.value.isObject()) return null;
    const object = boxed.value.asObj();
    if (object.is_symbol or object.is_bigint) return null;
    return @ptrCast(boxed);
}

export fn JSC__JSCell__toObject(cell: ?*anyopaque, global: JSContextRef) callconv(.c) JSObjectRef {
    const context = ctxForHandleInspection(global) orelse return null;
    const boxed = privateBoxFromCell(cell) orelse return null;
    if (boxed.private_kind != .value) return null;
    const handle: JSValueRef = @ptrCast(boxed);
    if (valueFromContext(context, handle) == null) return null;
    return JSValueToObject(global, handle, null);
}

export fn JSC__JSValue__createEmptyObject(global: JSContextRef, initial_capacity: usize) callconv(.c) EncodedValue {
    _ = initial_capacity;
    return privateEncodedFromRef(JSObjectMake(global, null, null));
}

export fn JSC__JSValue__createEmptyObjectWithNullPrototype(global: JSContextRef) callconv(.c) EncodedValue {
    const object = JSObjectMake(global, null, null) orelse return .empty;
    const null_value = JSValueMakeNull(global) orelse return .empty;
    JSObjectSetPrototype(global, object, null_value);
    return privateEncodedFromRef(object);
}

/// `JSC::constructEmptyObject(globalObject, objectPrototype, min(capacity,
/// JSFinalObject::maxInlineCapacity))` followed by the consumer initializer
/// (bindings.cpp:2477): Bun's struct-marshalling path populates the fresh POJO
/// inside the callback. zig-js shapes grow on demand, so the capacity clamp is
/// a performance hint with no observable effect. The callback receives the
/// stable canonical cell handle — the same address the returned EncodedJSValue
/// exposes at the private cell boundary — and runs exactly once, synchronously,
/// before the object is handed back.
export fn JSC__JSObject__create(global: JSContextRef, initial_capacity: usize, ctx: ?*anyopaque, initializer: ?*const fn (?*anyopaque, ?*anyopaque, JSContextRef) callconv(.c) void) callconv(.c) EncodedValue {
    _ = initial_capacity;
    const object = JSObjectMake(global, null, null) orelse return .empty;
    if (initializer) |init| init(ctx, @ptrCast(object), global);
    return privateEncodedFromRef(object);
}

/// `URLSearchParams::create(str, nullptr)` wrapped via `toJSNewlyCreated`
/// (URLSearchParams.cpp:34): decode the ZigString query and construct a
/// realm-prototype `URLSearchParams` instance — the exact
/// `new URLSearchParams(string)` engine path, so the result is
/// `instanceof URLSearchParams` with fully working methods.
export fn URLSearchParams__create(global: JSContextRef, input: ?*const PrivateZigString) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const init = privateZigStringValue(context, input orelse return .empty) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    if (!init.isString()) return .empty;
    const created = interp.urlSearchParamsCreateFromString(&machine, init.asStr()) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodedFromValue(context, created);
}

/// `WebCoreCast<JSURLSearchParams, URLSearchParams>` (URLSearchParams.cpp:41).
/// zig-js has no separate native object — the instance IS the JS object
/// carrying the engine's `\x00usp` pairs slot (native-created or
/// JS-constructed alike, in any realm of the group) — so the returned pointer
/// is the canonical cell handle, the same convention as `JSC__JSObject__create`.
export fn URLSearchParams__fromJS(encoded: EncodedValue) callconv(.c) ?*anyopaque {
    const boxed = privateBoxedFrom(encoded) orelse return null;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return null;
    if (boxed.value.asObj().getOwn("\x00usp") == null) return null;
    return @ptrCast(boxed);
}

/// `urlSearchParams->toString()` handed out as a `ZigString`
/// (URLSearchParams.cpp:49): serialize the instance's pairs exactly like the
/// JS `toString` method and invoke the callback once with a stable borrowed
/// ZigString view (latin-1 when the serialization is 8-bit). The owner realm
/// is recovered from the handle — Bun's signature carries no global object.
export fn URLSearchParams__toString(params: ?*anyopaque, ctx: ?*anyopaque, callback: ?*const fn (?*anyopaque, *const PrivateZigString) callconv(.c) void) callconv(.c) void {
    const cb = callback orelse return;
    const boxed = privateBoxFromCell(params) orelse return;
    if (boxed.private_kind != .value or !boxed.value.isObject()) return;
    if (boxed.value.asObj().getOwn("\x00usp") == null) return;
    const context = boxed.owner;
    const opaque_group = context.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch return;
    defer context.popActiveInterpreter(&machine);
    const bytes = interp.urlSearchParamsSerialize(&machine, boxed.value) catch return;
    const view = privateBorrowedZigStringView(group, bytes) catch return;
    cb(ctx, &view);
}

// ===== URL native record boundary (#308) =====
// Bun's `WTF::URL*` is a context-free heap object: `URL__fromString` carries no
// global object, so the zig-js mapping is a native parsed-URL record owning its
// component bytes in one c_allocator backing allocation — never a JS object.
// The engine's allocator-first `urlParse`/`urlSerialize` do the WHATWG work on
// a per-call arena; the record copies the results out and outlives the arena.
const private_url_magic: usize = 0x5a4a_5552_4c30_3031; // "ZJURL01"
const private_url_flag_host: u8 = 1;
const private_url_flag_query: u8 = 2;
const private_url_flag_fragment: u8 = 4;
const private_url_flag_opaque_path: u8 = 8;

const PrivateUrlSlice = extern struct { off: usize, len: usize };
const PrivateUrl = extern struct {
    magic: usize,
    backing: ?[*]u8,
    backing_len: usize,
    href: PrivateUrlSlice,
    scheme: PrivateUrlSlice,
    username: PrivateUrlSlice,
    password: PrivateUrlSlice,
    host: PrivateUrlSlice,
    port: PrivateUrlSlice,
    path: PrivateUrlSlice,
    query: PrivateUrlSlice,
    fragment: PrivateUrlSlice,
    flags: u8,
};

fn privateUrlView(url: *const PrivateUrl, s: PrivateUrlSlice) []const u8 {
    const backing = url.backing orelse return "";
    return backing[s.off .. s.off + s.len];
}

fn privateUrlFromOpaque(raw: ?*anyopaque) ?*PrivateUrl {
    const pointer = raw orelse return null;
    if (@intFromPtr(pointer) % @alignOf(PrivateUrl) != 0) return null;
    const url: *PrivateUrl = @ptrCast(@alignCast(pointer));
    if (url.magic != private_url_magic) return null;
    return url;
}

fn privateBunStringWTF8Alloc(allocator: std.mem.Allocator, string: *const PrivateBunString) PrivateBunStringError![]const u8 {
    switch (string.tag) {
        .dead => return error.InvalidString,
        .empty => return allocator.alloc(u8, 0),
        .wtf_string_impl => {
            const impl = string.value.wtf_string_impl orelse return error.InvalidString;
            if (impl.m_length == 0) return allocator.alloc(u8, 0);
            if (impl.m_hash_and_flags & private_wtf_flag_8_bit_buffer != 0)
                return privateLatin1ToWTF8(allocator, impl.m_ptr[0..impl.m_length]);
            const units: [*]align(1) const u16 = @ptrCast(impl.m_ptr);
            return privateUTF16ToWTF8(allocator, units[0..impl.m_length]);
        },
        .zig_string, .static_zig_string => {
            const zig_string = string.value.zig_string;
            if (zig_string.len == 0) return allocator.alloc(u8, 0);
            const untagged = zig_string.tagged_ptr & ((@as(usize, 1) << 53) - 1);
            if (untagged == 0) return error.InvalidString;
            if (zig_string.tagged_ptr & (@as(usize, 1) << 63) != 0) {
                const units: [*]align(1) const u16 = @ptrFromInt(untagged);
                return privateUTF16ToWTF8(allocator, units[0..zig_string.len]);
            }
            const source: [*]const u8 = @ptrFromInt(untagged);
            if (zig_string.tagged_ptr & (@as(usize, 1) << 61) != 0)
                return privateUTF8PrefixAsWTF8(allocator, source[0..zig_string.len], null);
            return privateLatin1ToWTF8(allocator, source[0..zig_string.len]);
        },
    }
}

fn privateUrlAppend(parts: *std.ArrayListUnmanaged(u8), arena: std.mem.Allocator, s: []const u8) error{OutOfMemory}!PrivateUrlSlice {
    const off = parts.items.len;
    try parts.appendSlice(arena, s);
    return .{ .off = off, .len = s.len };
}

/// Shared `WTF::URL(str)` construction (BunString.cpp:677): parse through the
/// engine's allocator-first `urlParse` with no base, null when invalid. The
/// returned record owns its bytes; `URL__deinit` frees it.
fn privateUrlCreateFromWTF8(arena: std.mem.Allocator, input_bytes: []const u8) ?*PrivateUrl {
    const parts = (interp.urlParse(arena, input_bytes, null) catch return null) orelse return null;
    if (parts.scheme.len == 0) return null; // WTF validity: absolute URL needs a scheme
    const href = interp.urlSerialize(arena, parts, false) catch return null;

    var concat: std.ArrayListUnmanaged(u8) = .empty;
    const href_s = privateUrlAppend(&concat, arena, href) catch return null;
    const scheme_s = privateUrlAppend(&concat, arena, parts.scheme) catch return null;
    const username_s = privateUrlAppend(&concat, arena, parts.username) catch return null;
    const password_s = privateUrlAppend(&concat, arena, parts.password) catch return null;
    const host_s = privateUrlAppend(&concat, arena, parts.host orelse "") catch return null;
    const port_s = privateUrlAppend(&concat, arena, parts.port) catch return null;
    const path_s = privateUrlAppend(&concat, arena, parts.path) catch return null;
    const query_s = privateUrlAppend(&concat, arena, parts.query orelse "") catch return null;
    const fragment_s = privateUrlAppend(&concat, arena, parts.fragment orelse "") catch return null;

    const backing = private_string_allocator.dupe(u8, concat.items) catch return null;
    const url = private_string_allocator.create(PrivateUrl) catch {
        private_string_allocator.free(backing);
        return null;
    };
    var flags: u8 = 0;
    if (parts.host != null) flags |= private_url_flag_host;
    if (parts.query != null) flags |= private_url_flag_query;
    if (parts.fragment != null) flags |= private_url_flag_fragment;
    if (parts.opaque_path) flags |= private_url_flag_opaque_path;
    url.* = .{
        .magic = private_url_magic,
        .backing = backing.ptr,
        .backing_len = backing.len,
        .href = href_s,
        .scheme = scheme_s,
        .username = username_s,
        .password = password_s,
        .host = host_s,
        .port = port_s,
        .path = path_s,
        .query = query_s,
        .fragment = fragment_s,
        .flags = flags,
    };
    return url;
}

/// Shared `WTF::URL(base, relative).string()` serialization: parse with an
/// optional already-parsed base and return the full href, null when invalid.
fn privateUrlHrefWTF8(arena: std.mem.Allocator, input_bytes: []const u8, base: ?interp.UrlParts) ?[]const u8 {
    const parts = (interp.urlParse(arena, input_bytes, base) catch return null) orelse return null;
    if (parts.scheme.len == 0) return null;
    return interp.urlSerialize(arena, parts, false) catch return null;
}

/// `WTF::URL(str)` + `new WTF::URL` (BunString.cpp:677): parse through the
/// engine's allocator-first `urlParse` with no base, null when invalid. The
/// returned record owns its bytes; `URL__deinit` frees it.
export fn URL__fromString(input: ?*const PrivateBunString) callconv(.c) ?*anyopaque {
    const string = input orelse return null;
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const arena = arena_state.allocator();
    const input_bytes = privateBunStringWTF8Alloc(arena, string) catch return null;
    return privateUrlCreateFromWTF8(arena, input_bytes);
}

/// `delete url` (BunString.cpp:692). Null tolerated; the magic is cleared so a
/// double deinit or stale pointer is observably inert rather than corrupting.
export fn URL__deinit(raw: ?*anyopaque) callconv(.c) void {
    const url = privateUrlFromOpaque(raw) orelse return;
    url.magic = 0;
    if (url.backing) |backing| private_string_allocator.free(backing[0..url.backing_len]);
    url.backing = null;
    private_string_allocator.destroy(url);
}

fn privateUrlOwnedString(bytes: []const u8) PrivateBunString {
    return privateOwnedWTF8String(bytes) catch return PrivateBunString.dead();
}

/// `url->string()` (BunString.cpp:697): the full serialization, fragment
/// included, exactly as parsed. Bun dereferences the pointer unconditionally;
/// zig-js returns Dead for a null/stale record instead.
export fn URL__href(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(privateUrlView(url, url.href));
}

/// `url->protocol()` (BunString.cpp:687): the scheme without the colon.
export fn URL__protocol(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(privateUrlView(url, url.scheme));
}

/// `url->user()` (BunString.cpp:702).
export fn URL__username(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(privateUrlView(url, url.username));
}

/// `url->password()` (BunString.cpp:707).
export fn URL__password(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(privateUrlView(url, url.password));
}

/// `url->query()` (BunString.cpp:712): the query WITH a leading `?` when a
/// query component is present (even an empty one), the empty string otherwise.
export fn URL__search(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    if (url.flags & private_url_flag_query == 0) return privateUrlOwnedString("");
    const query = privateUrlView(url, url.query);
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const prefixed = std.mem.concat(arena_state.allocator(), u8, &.{ "?", query }) catch return PrivateBunString.dead();
    return privateUrlOwnedString(prefixed);
}

/// `url->host()` (BunString.cpp:724): host WITHOUT the port — deliberately not
/// the JS `host` getter.
export fn URL__host(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(privateUrlView(url, url.host));
}

/// `url->hostAndPort()` (BunString.cpp:736): host WITH the port — deliberately
/// not the JS `hostname` getter.
export fn URL__hostname(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    const host = privateUrlView(url, url.host);
    const port = privateUrlView(url, url.port);
    if (port.len == 0) return privateUrlOwnedString(host);
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const joined = std.mem.concat(arena_state.allocator(), u8, &.{ host, ":", port }) catch return PrivateBunString.dead();
    return privateUrlOwnedString(joined);
}

/// `url->port()` (BunString.cpp:741): `maxInt(u32)` when the URL has no port;
/// the parser guarantees any present port is within the u16 range.
export fn URL__port(raw: ?*anyopaque) callconv(.c) u32 {
    const url = privateUrlFromOpaque(raw) orelse return std.math.maxInt(u32);
    const port = privateUrlView(url, url.port);
    if (port.len == 0) return std.math.maxInt(u32);
    return std.fmt.parseInt(u32, port, 10) catch std.math.maxInt(u32);
}

/// `url->path()` (BunString.cpp:752).
export fn URL__pathname(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(privateUrlView(url, url.path));
}

/// `url->fragmentIdentifierWithLeadingNumberSign()` (BunString.cpp:661): the
/// fragment WITH a leading `#`, empty when the fragment is absent or empty.
export fn URL__hash(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    if (url.flags & private_url_flag_fragment == 0) return privateUrlOwnedString("");
    const fragment = privateUrlView(url, url.fragment);
    if (fragment.len == 0) return privateUrlOwnedString("");
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const prefixed = std.mem.concat(arena_state.allocator(), u8, &.{ "#", fragment }) catch return PrivateBunString.dead();
    return privateUrlOwnedString(prefixed);
}

/// `url->fragmentIdentifier()` (BunString.cpp:669): the fragment WITHOUT `#`.
export fn URL__fragmentIdentifier(raw: ?*anyopaque) callconv(.c) PrivateBunString {
    const url = privateUrlFromOpaque(raw) orelse return PrivateBunString.dead();
    if (url.flags & private_url_flag_fragment == 0) return privateUrlOwnedString("");
    return privateUrlOwnedString(privateUrlView(url, url.fragment));
}

/// `value.toWTFString` + `new WTF::URL` (BunString.cpp:596): coerce the JS
/// value through ToString — a throwing coercion publishes the pending
/// exception and yields null (Bun's `RETURN_IF_EXCEPTION → nullptr`) — then
/// parse with no base. Empty or invalid input yields null without an
/// exception; success returns the owned native record (`URL__deinit` frees).
export fn URL__fromJS(encoded: EncodedValue, global: JSContextRef) callconv(.c) ?*anyopaque {
    const context = ctxForEvaluation(global) orelse return null;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return null;
    };
    defer context.popActiveInterpreter(&machine);

    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "URL value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return null;
    };
    const text = machine.toStringV(internal) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return null;
    };
    if (text.len == 0) return null;
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    return privateUrlCreateFromWTF8(arena_state.allocator(), text);
}

/// `value.toWTFString` + `WTF::URL(str).string()` (BunString.cpp:613): the
/// full serialization of the coerced value, Dead when the coercion throws
/// (exception published), when empty, or when invalid.
export fn URL__getHrefFromJS(encoded: EncodedValue, global: JSContextRef) callconv(.c) PrivateBunString {
    const context = ctxForEvaluation(global) orelse return PrivateBunString.dead();
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return PrivateBunString.dead();
    };
    defer context.popActiveInterpreter(&machine);

    const internal = privateValueFrom(global, encoded) orelse {
        const err = machine.throwError("TypeError", "URL value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return PrivateBunString.dead();
    };
    const text = machine.toStringV(internal) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return PrivateBunString.dead();
    };
    if (text.len == 0) return PrivateBunString.dead();
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const href = privateUrlHrefWTF8(arena_state.allocator(), text, null) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(href);
}

/// `WTF::URL(str).string()` (BunString.cpp:630): parse and re-serialize with
/// no base, Dead for empty/invalid input. Context-free.
export fn URL__getHref(input: ?*const PrivateBunString) callconv(.c) PrivateBunString {
    const string = input orelse return PrivateBunString.dead();
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const arena = arena_state.allocator();
    const input_bytes = privateBunStringWTF8Alloc(arena, string) catch return PrivateBunString.dead();
    const href = privateUrlHrefWTF8(arena, input_bytes, null) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(href);
}

/// `WTF::URL(WTF::URL(base), relative).string()` (BunString.cpp:650): resolve
/// the relative reference against the parsed base, Dead when either side is
/// invalid. Context-free.
export fn URL__getHrefJoin(base: ?*const PrivateBunString, relative: ?*const PrivateBunString) callconv(.c) PrivateBunString {
    const base_string = base orelse return PrivateBunString.dead();
    const relative_string = relative orelse return PrivateBunString.dead();
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const arena = arena_state.allocator();
    const base_bytes = privateBunStringWTF8Alloc(arena, base_string) catch return PrivateBunString.dead();
    const relative_bytes = privateBunStringWTF8Alloc(arena, relative_string) catch return PrivateBunString.dead();
    const base_parts = (interp.urlParse(arena, base_bytes, null) catch return PrivateBunString.dead()) orelse return PrivateBunString.dead();
    if (base_parts.scheme.len == 0) return PrivateBunString.dead();
    const href = privateUrlHrefWTF8(arena, relative_bytes, base_parts) orelse return PrivateBunString.dead();
    return privateUrlOwnedString(href);
