/// `URL::fileURLWithFileSystemPath(path).stringWithoutFragmentIdentifier()`
/// (BunString.cpp:564): `file://` plus each `/`-separated segment percent-
/// encoded with the WHATWG path encode set. Slashes are preserved and dot
/// segments are NOT resolved — WTF sets the path post-parse.
export fn URL__getFileURLString(file_path: ?*const PrivateBunString) callconv(.c) PrivateBunString {
    const string = file_path orelse return PrivateBunString.dead();
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const arena = arena_state.allocator();
    const path = privateBunStringWTF8Alloc(arena, string) catch return PrivateBunString.dead();
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(arena, "file://") catch return PrivateBunString.dead();
    var segments = std.mem.splitScalar(u8, path, '/');
    var first = true;
    while (segments.next()) |segment| {
        if (!first) out.append(arena, '/') catch return PrivateBunString.dead();
        first = false;
        interp.urlPercentEncode(arena, &out, segment, .path) catch return PrivateBunString.dead();
    }
    return privateUrlOwnedString(out.items);
}

/// `WTF::URL(str).fileSystemPath()` (BunString.cpp:640): the percent-decoded
/// path of the parsed input (`%XX` only — `+` stays literal, this is a path
/// not a query), Dead when the input is empty or invalid.
export fn URL__pathFromFileURL(input: ?*const PrivateBunString) callconv(.c) PrivateBunString {
    const string = input orelse return PrivateBunString.dead();
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const arena = arena_state.allocator();
    const input_bytes = privateBunStringWTF8Alloc(arena, string) catch return PrivateBunString.dead();
    const parts = (interp.urlParse(arena, input_bytes, null) catch return PrivateBunString.dead()) orelse return PrivateBunString.dead();
    if (parts.scheme.len == 0) return PrivateBunString.dead();
    const decoded = interp.urlPercentDecode(arena, parts.path) catch return PrivateBunString.dead();
    return privateUrlOwnedString(decoded);
}

/// `WTF::URL(StringView(latin1)).pathStart()` (BunString.cpp:569): the byte
/// offset where the path begins in the canonical serialization — the origin
/// length for tuple-origin URLs. The latin-1 slice is widened to WTF-8 before
/// parsing (WTF 8-bit string semantics); empty/invalid input yields 0, and a
/// null slice yields 0 (Bun dereferences unconditionally). Context-free.
export fn URL__originLength(latin1_slice: ?[*]const u8, len: usize) callconv(.c) u32 {
    const slice = latin1_slice orelse return 0;
    var arena_state = std.heap.ArenaAllocator.init(private_string_allocator);
    defer arena_state.deinit();
    const arena = arena_state.allocator();
    const input_bytes = privateLatin1ToWTF8(arena, slice[0..len]) catch return 0;
    const parts = (interp.urlParse(arena, input_bytes, null) catch return 0) orelse return 0;
    if (parts.scheme.len == 0) return 0;
    // Mirror urlSerialize's prefix emission exactly: `scheme:` plus, when a
    // host component is present, `//` + userinfo (`user[:pw]@`, only when
    // non-empty) + host + (`:port` when set); the `/.` sentinel precedes a
    // non-opaque path that begins with `//`.
    var start: usize = parts.scheme.len + 1;
    if (parts.host) |host| {
        start += 2 + host.len;
        if (parts.username.len > 0 or parts.password.len > 0)
            start += parts.username.len + (if (parts.password.len > 0) 1 + parts.password.len else 0) + 1;
        if (parts.port.len > 0) start += 1 + parts.port.len;
    } else if (!parts.opaque_path and std.mem.startsWith(u8, parts.path, "//")) {
        start += 2;
    }
    return @intCast(@min(start, std.math.maxInt(u32)));
}

/// The URL-interface slot predicate behind `WebCoreCast<JSDOMURL, DOMURL>`
/// (bindings.cpp:2132): URL-builtin objects carry hidden component slots
/// written only by `urlStore`, invisible to script.
fn privateDomUrlFromValue(internal: Value) ?*Object {
    if (!internal.isObject()) return null;
    const object = internal.asObj();
    const scheme = object.getOwn("\x00Us") orelse return null;
    if (!scheme.isString()) return null;
    const host_flag = object.getOwn("\x00Uhh") orelse return null;
    if (!host_flag.isBoolean()) return null;
    return object;
}

fn privateDomUrlObjectFromOpaque(raw: ?*anyopaque) ?*Object {
    const pointer = raw orelse return null;
    if (@intFromPtr(pointer) % @alignOf(Object) != 0) return null;
    return privateDomUrlFromValue(Value.obj(@ptrCast(@alignCast(pointer))));
}

fn privateCreateDomUrlValue(context: *Context, machine: *interp.Interpreter, input: []const u8) EncodedValue {
    const result = interp.urlCreateDomUrlObject(machine, input) catch |err| {
        privateSetPendingAbrupt(context, machine, err);
        return .empty;
    };
    return privateEncodeResult(context, machine, result);
}

/// `DOMURL::create(str, String())` + `toJSNewlyCreated` (BunString.cpp:580):
/// the realm's URL-interface object for the BunString input — same shape as
/// `new URL(str)` minus the new-target check. `DOMURL::create` is
/// `ExceptionOr` (webcore/DOMURL.h:45): invalid input publishes the TypeError
/// and returns an empty handle (Bun's `RETURN_IF_EXCEPTION → {}`).
export fn BunString__toJSDOMURL(global: JSContextRef, input: ?*const PrivateBunString) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const string = input orelse return .empty;
    const bytes = privateBunStringPropertyKey(context, string) orelse return .empty;
    return privateCreateDomUrlValue(context, &machine, bytes);
}

/// `ZigString.toURL()` (Home ZigString.zig:148; not vendored in the upstream
