fn privateWriteDateISOString(timestamp: f64, out: *[28]u8) c_int {
    var buffer: [28]u8 = undefined;
    const len = interp.Interpreter.writeDateISOString(timestamp, &buffer) orelse return -1;
    @memcpy(out[0..len], buffer[0..len]);
    return @intCast(len);
}

export fn JSC__JSValue__toISOString(
    global: JSContextRef,
    encoded: EncodedValue,
    out: *[28]u8,
) callconv(.c) c_int {
    const internal = privateValueFrom(global, encoded) orelse return -1;
    if (!internal.isObject() or !internal.asObj().behavior.is_date) return -1;
    return privateWriteDateISOString(internal.asObj().dateMs(), out);
}

/// Bun's pinned Zig declaration accidentally says `(global, f64) JSValue`,
/// while its wrapper and C++ body both use this 28-byte writer contract.
export fn JSC__JSValue__DateNowISOString(global: JSContextRef, out: *[28]u8) callconv(.c) c_int {
    _ = ctxForHandleInspection(global) orelse return -1;
    return privateWriteDateISOString(interp.currentTimeMilliseconds(), out);
}

export fn JSC__JSGlobalObject__vm(global: JSContextRef) callconv(.c) ?*anyopaque {
    const context = ctxForHandleInspection(global) orelse return null;
    return context.c_api_group;
}

/// Bun's pinned bridge returns the `VirtualMachine` registered in the realm's
/// WebCore client data. zig-js's context group is both the JSC VM and the
/// embedding VM, so this publishes the exact same ownership identity as
/// `JSC__JSGlobalObject__vm` without allocating or touching pending state.
export fn JSC__JSGlobalObject__bunVM(global: JSContextRef) callconv(.c) ?*anyopaque {
    const context = ctxForHandleInspection(global) orelse return null;
    return context.c_api_group;
}

export fn JSGlobalObject__hasException(global: JSContextRef) callconv(.c) bool {
    const context = ctxForHandleInspection(global) orelse return false;
    const opaque_group = context.c_api_group orelse return false;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    return group.pending_exception != null;
}

export fn JSGlobalObject__clearException(global: JSContextRef) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const opaque_group = context.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    group.pending_exception = null;
    group.primary.private_pending_exception_root = null;
}

fn privateGroupFromVM(vm_ref: ?*anyopaque) ?*CContextGroup {
    return @ptrCast(@alignCast(vm_ref orelse return null));
}

fn privateMaterializeTermination(group: *CContextGroup) ?*Boxed {
    if (group.pending_exception) |pending| return pending;
    if (!group.termination_requested.load(.acquire)) return null;
    if (group.termination_exception) |termination| {
        group.pending_exception = termination;
        group.primary.private_pending_exception_root = termination.value;
        return termination;
    }

    const context = group.primary;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch return null;
    defer context.popActiveInterpreter(&machine);
    const thrown = machine.makeError("TerminationError", "JavaScript execution terminated") catch return null;
    const encoded = privateEncodedFromValue(context, thrown);
    if (encoded == .empty) return null;
    const exception = privateExceptionBox(context, thrown, encoded) orelse return null;
    group.termination_exception = exception;
    group.pending_exception = exception;
    group.primary.private_pending_exception_root = thrown;
    return exception;
}

const PrivateTopExceptionScope = extern struct {
    group: ?*CContextGroup,
};

fn privateTopExceptionScope(ptr: ?*anyopaque) ?*PrivateTopExceptionScope {
    const raw = ptr orelse return null;
    if (@intFromPtr(raw) % @alignOf(PrivateTopExceptionScope) != 0) return null;
    return @ptrCast(@alignCast(raw));
}

export fn TopExceptionScope__construct(
    ptr: ?*anyopaque,
    global: JSContextRef,
    function_name: [*:0]const u8,
    file_name: [*:0]const u8,
    line: c_uint,
    size: usize,
    alignment: usize,
) callconv(.c) void {
    _ = function_name;
    _ = file_name;
    _ = line;
    if (size < @sizeOf(PrivateTopExceptionScope) or alignment < @alignOf(PrivateTopExceptionScope)) return;
    const scope = privateTopExceptionScope(ptr) orelse return;
    const context = ctxForHandleInspection(global) orelse {
        scope.* = .{ .group = null };
        return;
    };
    scope.* = .{ .group = privatePropertyBoundaryGroup(context) };
}

export fn TopExceptionScope__pureException(ptr: ?*anyopaque) callconv(.c) ?*anyopaque {
    const scope = privateTopExceptionScope(ptr) orelse return null;
    const group = scope.group orelse return null;
    return @ptrCast(group.pending_exception orelse return null);
}

export fn TopExceptionScope__exceptionIncludingTraps(ptr: ?*anyopaque) callconv(.c) ?*anyopaque {
    const scope = privateTopExceptionScope(ptr) orelse return null;
    const group = scope.group orelse return null;
    return @ptrCast(privateMaterializeTermination(group) orelse return null);
}

export fn TopExceptionScope__clearException(ptr: ?*anyopaque) callconv(.c) void {
    const scope = privateTopExceptionScope(ptr) orelse return;
    const group = scope.group orelse return;
    group.pending_exception = null;
    group.primary.private_pending_exception_root = null;
}

export fn TopExceptionScope__assertNoException(ptr: ?*anyopaque) callconv(.c) void {
    const scope = privateTopExceptionScope(ptr) orelse return;
    const group = scope.group orelse return;
    if (group.pending_exception != null) @panic("TopExceptionScope expected no pending exception");
}

export fn TopExceptionScope__destruct(ptr: ?*anyopaque) callconv(.c) void {
    const scope = privateTopExceptionScope(ptr) orelse return;
    scope.* = .{ .group = null };
}

export fn JSGlobalObject__clearExceptionExceptTermination(global: JSContextRef) callconv(.c) bool {
    const context = ctxForHandleInspection(global) orelse return false;
    const group = privatePropertyBoundaryGroup(context) orelse return false;
    if (group.pending_exception) |pending| {
        if (group.termination_exception == pending) return false;
        group.pending_exception = null;
        group.primary.private_pending_exception_root = null;
    }
    return true;
}

/// `WTF::setTimeZoneOverride` + `vm.dateCache.resetIfNecessarySlow()`
/// (ZigGlobalObject.cpp:3117): a process-wide default zone consumed by
/// Intl.DateTimeFormat (and `Date#toLocaleString`, which routes through it)
/// and `Temporal.Now` when no explicit zone is given. zig-js keeps no date
/// cache, so the pinned reset is vacuous. Empty input clears the override
/// (WTF's reset); unknown names return false with the override unchanged.
/// Note: zig-js `Date` local-time methods are UTC-coincident by engine design,
/// so the override flows to the Intl/Temporal default-zone consumers.
export fn JSGlobalObject__setTimeZone(global: JSContextRef, time_zone: ?*const PrivateZigString) callconv(.c) bool {
    const context = ctxForHandleInspection(global) orelse return false;
    const string_ref = time_zone orelse return false;
    const decoded = privateZigStringValue(context, string_ref) catch {
        // Conversion failures (dead strings, OOM) surface only as the pinned
        // false return; clear any transient boundary exception they published.
        if (context.c_api_group) |opaque_group| {
            const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
            group.pending_exception = null;
            group.primary.private_pending_exception_root = null;
        }
        return false;
    };
    const bytes = decoded.asStr();
    if (bytes.len == 0) return interp.setTimeZoneOverride(gpa, null);
    var buf: [128]u8 = undefined;
    const canonical = interp.validCanonicalTimeZoneName(bytes, &buf) orelse return false;
    return interp.setTimeZoneOverride(gpa, canonical);
}

export fn JSGlobalObject__requestTermination(global: JSContextRef) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    group.termination_requested.store(true, .release);
}

export fn JSGlobalObject__clearTerminationException(global: JSContextRef) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    group.termination_requested.store(false, .release);
    if (group.pending_exception) |pending| {
        if (group.termination_exception == pending) {
            group.pending_exception = null;
            group.primary.private_pending_exception_root = null;
        }
    }
}

fn privateCreateNativeError(
    global: JSContextRef,
    name: []const u8,
    message: []const u8,
) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);
    const result = machine.makeError(name, message) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

export fn JSGlobalObject__createOutOfMemoryError(global: JSContextRef) callconv(.c) EncodedValue {
    return privateCreateNativeError(global, "OutOfMemoryError", "Out of memory");
}

export fn JSGlobalObject__throwOutOfMemoryError(global: JSContextRef) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const result = privateCreateNativeError(global, "OutOfMemoryError", "Out of memory");
    if (result == .empty) return;
    const thrown = privateValueFrom(global, result) orelse return;
    privateSetPendingValue(context, thrown);
}

export fn JSGlobalObject__throwStackOverflow(global: JSContextRef) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const result = privateCreateNativeError(global, "RangeError", "Maximum call stack size exceeded");
    if (result == .empty) return;
    const thrown = privateValueFrom(global, result) orelse return;
    privateSetPendingValue(context, thrown);
}

export fn JSC__JSValue__isTerminationException(encoded: EncodedValue) callconv(.c) bool {
    const boxed = privateBoxedFrom(encoded) orelse return false;
    const opaque_group = boxed.owner.c_api_group orelse return false;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    const termination = group.termination_exception orelse return false;
    return termination == boxed or termination.exception_encoded == encoded;
}

export fn JSC__VM__clearHasTerminationRequest(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    group.termination_requested.store(false, .release);
}

export fn JSC__VM__hasTerminationRequest(vm_ref: ?*anyopaque) callconv(.c) bool {
    const group = privateGroupFromVM(vm_ref) orelse return false;
    return group.termination_requested.load(.acquire);
}

export fn JSC__VM__notifyNeedTermination(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    group.termination_requested.store(true, .release);
}

export fn JSC__VM__executionForbidden(vm_ref: ?*anyopaque) callconv(.c) bool {
    const group = privateGroupFromVM(vm_ref) orelse return false;
    return group.execution_forbidden.load(.acquire);
}

fn privateContextIsEntered(context: *Context) bool {
    context.lockActiveInterpreters();
    defer context.unlockActiveInterpreters();
    return context.active_interpreters.items.len != 0;
}

export fn JSC__VM__isEntered(vm_ref: ?*anyopaque) callconv(.c) bool {
    const group = privateGroupFromVM(vm_ref) orelse return false;
    if (privateContextIsEntered(group.primary)) return true;
    for (group.contexts.items) |context| {
        if (context.c_api_ref_count.load(.acquire) != 0 and privateContextIsEntered(context)) return true;
    }
    return false;
}

export fn JSC__VM__setExecutionForbidden(vm_ref: ?*anyopaque, forbidden: bool) callconv(.c) void {
    _ = forbidden; // Pinned JSC binding ignores the argument and only sets true.
    const group = privateGroupFromVM(vm_ref) orelse return;
    group.execution_forbidden.store(true, .release);
}

fn privateGroupApiLock(group: *CContextGroup) void {
    const me: u64 = @intCast(std.Thread.getCurrentId());
    if (group.api_lock_owner.load(.acquire) == me) {
        group.api_lock_depth += 1;
        return;
    }
    var spins: usize = 0;
    while (!group.api_lock.tryLock()) : (spins += 1) {
        if ((spins & 0xff) == 0) std.Thread.yield() catch {} else std.atomic.spinLoopHint();
    }
    group.api_lock_owner.store(me, .release);
    group.api_lock_depth = 1;
}

fn privateGroupApiUnlock(group: *CContextGroup) void {
    const me: u64 = @intCast(std.Thread.getCurrentId());
    // Only the owning thread may release (JSC asserts on foreign release);
    // tolerate it here like every other private boundary null/misuse guard.
    if (group.api_lock_owner.load(.acquire) != me) return;
    group.api_lock_depth -= 1;
    if (group.api_lock_depth == 0) {
        group.api_lock_owner.store(0, .release);
        group.api_lock.unlock();
    }
}

/// `vm->apiLock().lock()` (bindings.cpp:4906). Home's RAII `VM.Lock` pairs
/// this with `JSC__VM__releaseAPILock`.
export fn JSC__VM__getAPILock(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    privateGroupApiLock(group);
}

/// `vm->apiLock().unlock()` (bindings.cpp:4912).
export fn JSC__VM__releaseAPILock(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    privateGroupApiUnlock(group);
}

/// `JSLockHolder locker(vm); callback(ctx);` (bindings.cpp:4896) — the
/// deprecated callback form of the API lock.
export fn JSC__VM__holdAPILock(
    vm_ref: ?*anyopaque,
    ctx: ?*anyopaque,
    callback: ?*const fn (ctx: ?*anyopaque) callconv(.c) void,
) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    const run = callback orelse return;
    privateGroupApiLock(group);
    defer privateGroupApiUnlock(group);
    run(ctx);
}

fn privateMonotonicNowNs() u64 {
    return @intCast(@max(std.Io.Timestamp.now(agent.engineIo(), .awake).nanoseconds, 0));
}

/// Host watchdog behind `JSC::Watchdog`: naps until the armed deadline, then
/// raises the group's termination request and cooperatively interrupts running
/// evaluation via `Context.requestTermination` — the thread-safe,
/// allocation-free entry point context.zig documents for exactly this purpose.
/// Per that contract the request is terminal for the context; zig-js does not
/// resume evaluation after a time-limit termination the way JSC allows after
/// `clearHasTerminationRequest`.
fn privateExecutionWatchdog(group: *CContextGroup) void {
    const io = agent.engineIo();
    while (!group.watchdog_stop.load(.acquire)) {
        const deadline = group.execution_deadline_ns.load(.acquire);
        if (deadline == 0 or group.watchdog_fired_ns.load(.acquire) == deadline) {
            std.Io.sleep(io, .fromNanoseconds(500_000), .awake) catch {};
            continue;
        }
        const now = privateMonotonicNowNs();
        if (now < deadline) {
            const remaining = @min(deadline - now, 1_000_000);
            std.Io.sleep(io, .fromNanoseconds(@intCast(remaining)), .awake) catch {};
            continue;
        }
        group.watchdog_fired_ns.store(deadline, .release);
        group.termination_requested.store(true, .release);
        group.primary.requestTermination();
    }
}

/// `vm->ensureWatchdog().setTimeLimit(Seconds{limit})` (bindings.cpp:4875).
/// Mapping: `+inf` is `Watchdog::noTimeLimit`; non-positive limits fire at the
/// next watchdog tick; NaN stays armed but never fires (JSC comparison
/// semantics); finite limits saturate instead of overflowing the u64 deadline.
export fn JSC__VM__setExecutionTimeLimit(vm_ref: ?*anyopaque, timeout: f64) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    const now = privateMonotonicNowNs();
    const deadline: u64 = if (std.math.isNan(timeout))
        std.math.maxInt(u64)
    else if (std.math.isPositiveInf(timeout))
        0
    else if (timeout <= 0)
        now
    else blk: {
        const ns = timeout * @as(f64, @floatFromInt(std.time.ns_per_s));
        const headroom: f64 = @floatFromInt(std.math.maxInt(u64) - now);
        if (ns >= headroom) break :blk std.math.maxInt(u64);
        break :blk now + @as(u64, @intFromFloat(@ceil(ns)));
    };
    group.execution_deadline_ns.store(deadline, .release);
    if (deadline != 0 and group.watchdog_thread == null) {
        group.watchdog_thread = std.Thread.spawn(.{}, privateExecutionWatchdog, .{group}) catch null;
    }
}

/// `if (vm->watchdog()) watchdog->setTimeLimit(noTimeLimit)` (bindings.cpp:4869).
/// Disarming never clears an already-requested termination, matching JSC.
export fn JSC__VM__clearExecutionTimeLimit(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    group.execution_deadline_ns.store(0, .release);
    group.watchdog_fired_ns.store(0, .release);
}

/// `vm->watchdog() && vm->watchdog()->hasTimeLimit()` (bindings.cpp:2830). The
/// limit stays reported after it fires, exactly like `Watchdog::hasTimeLimit`.
export fn JSC__VM__hasExecutionTimeLimit(vm_ref: ?*anyopaque) callconv(.c) bool {
    const group = privateGroupFromVM(vm_ref) orelse return false;
    return group.execution_deadline_ns.load(.acquire) != 0;
}

/// `(*arg0).notifyNeedWatchdogCheck()` (bindings.cpp:4992): sets the VM's
/// `VMTraps::NeedWatchdogCheck` bit. The running evaluation consumes the trap
/// at its next step checkpoint, re-checking the armed execution time limit on
/// the executing thread and terminating once it has elapsed — the synchronous
/// half of the watchdog, intentionally redundant with the host watchdog
/// thread exactly like JSC's trap bit and `Watchdog` timer. With no armed
/// limit the consumed trap is a no-op.
export fn JSC__VM__notifyNeedWatchdogCheck(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    group.need_watchdog_check.store(true, .release);
}

/// `(*arg0).notifyNeedDebuggerBreak()` (bindings.cpp:4997): sets the VM's
/// `VMTraps::NeedDebuggerBreak` bit. Every realm of this VM with an enabled
/// debugger session pauses with reason "pause" at its next statement
/// boundary — the same path as CDP `Debugger.pause`, with owner selection
/// still going through `chooseInspectorPauseOwner`. Without an attached
/// debugger the notify is inert, matching a JSC trap with no debugger.
export fn JSC__VM__notifyNeedDebuggerBreak(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    privateNotifyDebuggerBreak(group.primary);
    for (group.contexts.items) |context| privateNotifyDebuggerBreak(context);
}

fn privateNotifyDebuggerBreak(context: *Context) void {
    const state = inspectorState(context) orelse return;
    if (inspectorHasDebugger(state)) state.pause_requested.store(true, .release);
}

fn privateSaturatingAddAtomic(value_: *std.atomic.Value(usize), amount: usize) void {
    var current = value_.load(.monotonic);
    while (true) {
        const next = std.math.add(usize, current, amount) catch std.math.maxInt(usize);
        if (value_.cmpxchgWeak(current, next, .acq_rel, .monotonic)) |observed| {
            current = observed;
        } else return;
    }
}

fn privateSaturatingAdd(left: usize, right: usize) usize {
    return std.math.add(usize, left, right) catch std.math.maxInt(usize);
}

fn privateVMExternalMemory(group: *CContextGroup) usize {
    var total = @atomicLoad(usize, &group.primary.gc_array_buffer_bytes_live, .acquire);
    for (group.contexts.items) |context| {
        total = privateSaturatingAdd(
            total,
            @atomicLoad(usize, &context.gc_array_buffer_bytes_live, .acquire),
        );
    }
    return total;
}

fn privateDrainMicrotasks(context: *Context) void {
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    machine.drainMicrotasks() catch |err| privateSetPendingAbrupt(context, &machine, err);
}

fn privateVMDrainMicrotasks(group: *CContextGroup) void {
    if (group.pending_exception != null) return;
    privateDrainMicrotasks(group.primary);
    if (group.pending_exception != null) return;
    for (group.contexts.items) |context| {
        if (context.c_api_ref_count.load(.acquire) != 0) {
            privateDrainMicrotasks(context);
            if (group.pending_exception != null) return;
        }
    }
}

export fn JSC__JSGlobalObject__queueMicrotaskCallback(
    global: JSContextRef,
    callback_context: ?*anyopaque,
    callback: ?PrivateMicrotaskCallback,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const function = callback orelse return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    promise.enqueueNativeCallback(&machine, callback_context, function) catch |err|
        privateSetPendingAbrupt(context, &machine, err);
}

fn privateMicrotaskJobValue(global: JSContextRef, encoded: EncodedValue) ?Value {
    if (encoded == .empty) return Value.undef();
    return privateValueFrom(global, encoded);
}

fn privateQueueProcessNextTick(
    global: JSContextRef,
    encoded_callback: EncodedValue,
    encoded_args: []const EncodedValue,
) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    const callback = privateDecodeWarningArgument(context, &machine, global, encoded_callback, "nextTick callback") catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!callback.isCallable()) {
        const err = machine.throwError("TypeError", "The \"callback\" argument must be a function");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    }
    const process_value = machine.env.get("process") orelse return;
    if ((process_value.asObj().getOwn("_exiting") orelse Value.boolVal(false)).toBoolean()) return;

    var args: [2]Value = undefined;
    for (encoded_args, 0..) |encoded, i| {
        args[i] = privateDecodeWarningArgument(context, &machine, global, encoded, "nextTick argument") catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return;
        };
    }
    promise.enqueueNextTick(&machine, callback, args[0..encoded_args.len]) catch |err|
        privateSetPendingAbrupt(context, &machine, err);
}

export fn Bun__Process__queueNextTick1(
    global: JSContextRef,
    callback: EncodedValue,
    arg1: EncodedValue,
) callconv(.c) void {
    privateQueueProcessNextTick(global, callback, &.{arg1});
}

export fn Bun__Process__queueNextTick2(
    global: JSContextRef,
