export fn JSC__JSGlobalObject__queueMicrotaskJob(
    global: JSContextRef,
    encoded_job: EncodedValue,
    encoded_first: EncodedValue,
    encoded_second: EncodedValue,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    const job = privateMicrotaskJobValue(global, encoded_job) orelse {
        const err = machine.throwError("TypeError", "Microtask job belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const first = privateMicrotaskJobValue(global, encoded_first) orelse {
        const err = machine.throwError("TypeError", "Microtask argument belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const second = privateMicrotaskJobValue(global, encoded_second) orelse {
        const err = machine.throwError("TypeError", "Microtask argument belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (!job.isCallable()) {
        const err = machine.throwError("TypeError", "Microtask job must be callable");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    }
    promise.enqueueJob(&machine, job, first, second) catch |err|
        privateSetPendingAbrupt(context, &machine, err);
}

export fn JSC__JSGlobalObject__drainMicrotasks(global: JSContextRef) callconv(.c) u8 {
    const context = ctxForEvaluation(global) orelse return 0;
    const group = privatePropertyBoundaryGroup(context) orelse return 0;
    if (privateMaterializeTermination(group)) |exception|
        if (group.termination_exception == exception) return 1;
    if (group.pending_exception != null) return 0;
    privateDrainMicrotasks(context);
    if (privateMaterializeTermination(group)) |exception|
        if (group.termination_exception == exception) return 1;
    return 0;
}

export fn JSC__VM__drainMicrotasks(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    if (group.pending_exception != null) return;
    privateVMDrainMicrotasks(group);
}

export fn JSC__JSGlobalObject__handleRejectedPromises(global: JSContextRef) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    while (promise.takeUnhandledRejection(&machine)) |notification| {
        const reason = notification.reason;
        if (privateProcessEventCount(&machine, "unhandledRejection") != 0) {
            _ = interp.emitProcessEvent(&machine, "unhandledRejection", &.{ reason, notification.promise }) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                machine.exception = Value.undef();
                continue;
            };
            continue;
        }
        const handler = context.global_object.getOwn("onunhandledrejection") orelse Value.undef();
        if (handler.isCallable()) {
            _ = machine.callValueWithThis(handler, &.{reason}, Value.obj(context.global_object)) catch |err| {
                privateSetPendingAbrupt(context, &machine, err);
                machine.exception = Value.undef();
                continue;
            };
        } else if (group.pending_exception == null) {
            // With no installed event hook, preserve the first rejection as the
            // host-visible uncaught completion instead of silently dropping it.
            privateSetPendingValue(context, reason);
        }
    }
    while (promise.takeHandledRejection(&machine)) |handled| {
        if (privateProcessEventCount(&machine, "rejectionHandled") == 0) continue;
        _ = interp.emitProcessEvent(&machine, "rejectionHandled", &.{handled}) catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            machine.exception = Value.undef();
            continue;
        };
    }
}

/// Serialize through the engine's context-independent structured-clone frame.
/// The two pinned flags only change behavior for special host objects in JSC;
/// zig-js's currently supported ordinary graph has the same wire bytes. A
/// SharedArrayBuffer is different: its frame retains a process-local token, so
/// persistence/cross-process requests reject it instead of publishing bytes
/// that cannot satisfy the flag's lifetime contract.
export fn Bun__serializeJSValue(
    global: JSContextRef,
    encoded: EncodedValue,
    flags: u8,
) callconv(.c) PrivateSerializedScriptExternal {
    return privateSerializeJSValue(global, encoded, flags, gpa);
}

fn privateSerializeJSValue(
    global: JSContextRef,
    encoded: EncodedValue,
    flags: u8,
    allocator: std.mem.Allocator,
) PrivateSerializedScriptExternal {
    const context = ctxForEvaluation(global) orelse return .{};
    const group = privatePropertyBoundaryGroup(context) orelse return .{};
    if (group.pending_exception != null) return .{};
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .{};
    };
    defer context.popActiveInterpreter(&machine);

    if (flags & ~@as(u8, 0x03) != 0) {
        const abrupt = machine.throwError("TypeError", "Invalid structured serialization flags");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .{};
    }
    const input = privateValueFrom(global, encoded) orelse {
        const abrupt = machine.throwError("TypeError", "Serialized value belongs to another VM");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .{};
    };
    const bytes = structured_clone.serialize(&machine, allocator, input) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .{};
    };
    if (flags & 0x03 != 0 and structured_clone.hasSharedReferences(bytes)) {
        structured_clone.releaseSerialized(bytes);
        allocator.free(bytes);
        const detail = if (flags & 0x02 != 0)
            "SharedArrayBuffer cannot be serialized for storage"
        else
            "SharedArrayBuffer requires a portable cross-process backing handle";
        const abrupt = machine.throwDOMException("DataCloneError", detail);
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .{};
    }

    const handle = registerPrivateSerializedScript(.{ .bytes = bytes, .allocator = allocator }) catch {
        structured_clone.releaseSerialized(bytes);
        allocator.free(bytes);
        privateSetPendingAbrupt(context, &machine, error.OutOfMemory);
        return .{};
    };
    return .{ .bytes = bytes.ptr, .size = bytes.len, .handle = handle };
}

export fn Bun__SerializedScriptSlice__free(raw: ?*anyopaque) callconv(.c) void {
    // Monotonic opaque tokens are never dereferenced or reused, so null,
    // duplicate, and arbitrarily stale caller input cannot free newer data.
    const owned = takePrivateSerializedScript(raw) orelse return;
    structured_clone.releaseSerialized(owned.bytes);
    owned.allocator.free(owned.bytes);
}

export fn Bun__JSValue__deserialize(
    global: JSContextRef,
    data: [*c]const u8,
    size: usize,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    if (data == null and size != 0) {
        const abrupt = machine.throwError("TypeError", "Invalid serialized byte span");
        privateSetPendingAbrupt(context, &machine, abrupt);
        return .empty;
    }
    const bytes: []const u8 = if (size == 0) "" else data[0..size];
    const result = structured_clone.deserialize(&machine, bytes) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    return privateEncodeResult(context, &machine, result);
}

fn privateModuleLoaderPromiseFromBunString(
    global: JSContextRef,
    module_name: ?*const PrivateBunString,
) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    const name = module_name orelse {
        privatePublishBunStringError(context, error.InvalidString);
        return .empty;
    };
    const decoded = privateBunStringValue(context, name, null) catch |err| {
        privatePublishBunStringError(context, err);
        return .empty;
    };
    const promise_value = context.loadAndEvaluateModule(decoded.asStr(), "") catch {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return .empty;
    };
    const encoded = privateEncodedFromValue(context, promise_value);
    if (encoded == .empty)
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
    return encoded;
}

/// Bun's pinned wrapper around `loadAndEvaluateModule`: the opaque return cell
/// is the same rooted Boxed Promise handle used by the rest of this private ABI.
export fn JSC__JSModuleLoader__loadAndEvaluateModule(
    global: JSContextRef,
    module_name: ?*const PrivateBunString,
) callconv(.c) ?*anyopaque {
    return privatePromiseCellFromEncoded(privateModuleLoaderPromiseFromBunString(global, module_name));
}

export fn JSModuleLoader__import(
    global: JSContextRef,
    module_name: ?*const PrivateBunString,
