    return privatePromiseCellFromEncoded(privateModuleLoaderPromiseFromBunString(global, module_name));
}

fn privateModuleLoaderEvaluateError(
    context: *Context,
    exception_out: ?*EncodedValue,
    kind: []const u8,
    message: []const u8,
) EncodedValue {
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    const reason = machine.makeError(kind, message) catch {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return .empty;
    };
    const encoded = privateEncodedFromValue(context, reason);
    if (encoded == .empty) {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return .empty;
    }
    if (exception_out) |out| out.* = encoded else privateSetPendingValue(context, reason);
    return .undefined;
}

fn privateEncodeModuleLoaderValue(context: *Context, result: Value) EncodedValue {
    const encoded = privateEncodedFromValue(context, result);
    if (encoded == .empty)
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
    return encoded;
}

/// Match the pinned JSC tri-state result: an already-fulfilled import returns
/// its namespace, an already-rejected import writes the reason and returns
/// undefined, and a top-level-await import returns its still-pending Promise.
export fn JSC__JSModuleLoader__evaluate(
    global: JSContextRef,
    source_ptr: [*c]const u8,
    source_len: usize,
    origin_ptr: [*c]const u8,
    origin_len: usize,
    referrer_ptr: [*c]const u8,
    referrer_len: usize,
    this_value: EncodedValue,
    exception_out: ?*EncodedValue,
) callconv(.c) EncodedValue {
    _ = this_value; // The pinned implementation receives but does not inspect it.
    const context = ctxForEvaluation(global) orelse return .empty;
    const group = privatePropertyBoundaryGroup(context) orelse return .empty;
    if (group.pending_exception != null) return .empty;
    if ((source_ptr == null and source_len != 0) or
        (origin_ptr == null and origin_len != 0) or
        (referrer_ptr == null and referrer_len != 0))
        return privateModuleLoaderEvaluateError(context, exception_out, "TypeError", "Invalid module source span");

    const source = if (source_len == 0) "" else source_ptr[0..source_len];
    const origin = if (origin_len == 0) "" else origin_ptr[0..origin_len];
    const referrer = if (referrer_len == 0) "" else referrer_ptr[0..referrer_len];
    const path = context.provideModuleLoaderSource(origin, source) catch
        return privateModuleLoaderEvaluateError(context, exception_out, "OutOfMemoryError", "Cannot retain module source");
    const promise_value = context.loadAndEvaluateModule(path, referrer) catch
        return privateModuleLoaderEvaluateError(context, exception_out, "OutOfMemoryError", "Cannot evaluate module");
    const internal_promise = promise.promiseOf(promise_value) orelse
        return privateModuleLoaderEvaluateError(context, exception_out, "TypeError", "Module loader returned a non-Promise");
    internal_promise.lockState();
    const state = internal_promise.state;
    const result = internal_promise.value;
    // This boundary synchronously consumes a rejected import into its explicit
    // exception out-channel, so it is not an unhandled host rejection.
    if (state == .rejected) internal_promise.is_handled = true;
    internal_promise.unlockState();
    return switch (state) {
        .fulfilled => privateEncodeModuleLoaderValue(context, result),
        .rejected => rejected: {
            const encoded = privateEncodeModuleLoaderValue(context, result);
            if (encoded == .empty) break :rejected .empty;
            if (exception_out) |out| out.* = encoded else privateSetPendingValue(context, result);
            break :rejected .undefined;
        },
        .pending => privateEncodeModuleLoaderValue(context, promise_value),
    };
}

export fn JSC__JSGlobalObject__deleteModuleRegistryEntry(
    global: JSContextRef,
    key: *const PrivateZigString,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const group = privatePropertyBoundaryGroup(context) orelse return;
    if (group.pending_exception != null) return;
    const decoded = privateZigStringPropertyKey(context, key) orelse return;
    _ = context.deleteModuleRegistryEntry(decoded);
}

export fn JSC__VM__deleteAllCode(vm_ref: ?*anyopaque, global: JSContextRef) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    const context = ctxForEvaluation(global) orelse return;
    if (context.c_api_group != vm_ref) return;
    privateVMDrainMicrotasks(group);
    context.clearModuleRegistry();
    group.primary.jit_owner.clear();
    group.primary.requestGarbageCollection();
}

fn privateStrongRefRemove(ref: *PrivateStrongRef) void {
    const primary = ref.group.primary;
    primary.realmLock();
    defer primary.realmUnlock();
    if (!ref.alive) return;
    ref.alive = false;
    ref.encoded = .empty;
    ref.root.value = Value.undef();
    for (primary.private_strong_roots.items, 0..) |root, index| {
        if (root == &ref.root) {
            _ = primary.private_strong_roots.swapRemove(index);
            return;
        }
    }
}

export fn Bun__StrongRef__new(global: JSContextRef, encoded: EncodedValue) callconv(.c) ?*PrivateStrongRef {
    const context = ctxForHandleInspection(global) orelse return null;
    const opaque_group = context.c_api_group orelse return null;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    const internal = privateValueFrom(global, encoded) orelse return null;
    if (!group.retain()) return null;
    errdefer if (group.release()) group.destroy();

    const ref = group.primary.arena().create(PrivateStrongRef) catch return null;
    ref.* = .{
        .encoded = encoded,
        .root = .{ .value = internal },
        .group = group,
    };
    group.primary.realmLock();
    defer group.primary.realmUnlock();
    group.primary.private_strong_roots.append(group.primary.gpa, &ref.root) catch return null;
    return ref;
}

export fn Bun__StrongRef__set(ref: ?*PrivateStrongRef, global: JSContextRef, encoded: EncodedValue) callconv(.c) void {
    const strong = ref orelse return;
    const context = ctxForHandleInspection(global) orelse return;
    if (context.c_api_group != @as(?*anyopaque, @ptrCast(strong.group))) return;
    const internal = privateValueFrom(global, encoded) orelse return;
    const primary = strong.group.primary;
    primary.realmLock();
    defer primary.realmUnlock();
    if (!strong.alive) return;
    // Publish the traced value and consumer-visible encoding as one operation
    // with respect to the collector's root snapshot.
    strong.root.value = internal;
    strong.encoded = encoded;
}

export fn Bun__StrongRef__clear(ref: ?*PrivateStrongRef) callconv(.c) void {
    const strong = ref orelse return;
    const primary = strong.group.primary;
    primary.assertOwnerThread();
    primary.realmLock();
    defer primary.realmUnlock();
    if (!strong.alive) return;
    strong.root.value = Value.undef();
    strong.encoded = .empty;
}

export fn Bun__StrongRef__delete(ref: ?*PrivateStrongRef) callconv(.c) void {
    const strong = ref orelse return;
    const group = strong.group;
    group.primary.assertOwnerThread();
    privateStrongRefRemove(strong);
    if (group.release()) group.destroy();
}

fn privateWeakRefRemove(ref: *PrivateWeakRef) void {
    const primary = ref.group.primary;
    primary.realmLock();
    defer primary.realmUnlock();
    if (!ref.alive) return;
    ref.alive = false;
    ref.root.notify_on_collect.store(false, .release);
    _ = ref.root.target.swap(null, .acq_rel);
    for (primary.private_weak_roots.items, 0..) |root, index| {
        if (root == &ref.root) {
            _ = primary.private_weak_roots.swapRemove(index);
            return;
        }
    }
}

export fn Bun__WeakRef__new(
    global: JSContextRef,
    encoded: EncodedValue,
    ref_type: PrivateWeakRefType,
    callback_context: ?*anyopaque,
) callconv(.c) ?*PrivateWeakRef {
    const context = ctxForHandleInspection(global) orelse return null;
    const opaque_group = context.c_api_group orelse return null;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    const internal = privateValueFrom(global, encoded) orelse return null;
    if (!internal.isObject() or internal.asObj().is_symbol or internal.asObj().is_bigint) return null;
    switch (ref_type) {
        .fetch_response, .postgresql_query_client => {},
        else => return null,
    }
    if (!group.retain()) return null;
    errdefer if (group.release()) group.destroy();

    const ref = group.primary.arena().create(PrivateWeakRef) catch return null;
    const finalize_fn: ?Context.PrivateWeakFinalizeFn = switch (ref_type) {
        .fetch_response => Bun__FetchResponse_finalize,
        .postgresql_query_client => null,
        else => unreachable,
    };
    ref.* = .{
        .root = .{
            .target = .init(@ptrCast(internal.asObj())),
            .notify_on_collect = .init(finalize_fn != null and callback_context != null),
            .finalize_fn = finalize_fn,
            .finalize_context = callback_context,
        },
        .group = group,
        .ref_type = ref_type,
        .callback_context = callback_context,
    };
    group.primary.realmLock();
    defer group.primary.realmUnlock();
    group.primary.private_weak_roots.append(group.primary.gpa, &ref.root) catch return null;
    // Permit zig-gc's weak passes even when no JavaScript WeakRef/WeakMap has
    // been constructed in this realm.
    group.primary.gc_weak_work.store(true, .release);
    return ref;
}

export fn Bun__WeakRef__get(ref: ?*PrivateWeakRef) callconv(.c) EncodedValue {
    const weak = ref orelse return .empty;
    if (!weak.alive) return .empty;
    const target = weak.root.target.load(.acquire) orelse return .empty;
    return privateEncodedFromValue(weak.group.primary, Value.obj(@ptrCast(@alignCast(target))));
}

export fn Bun__WeakRef__clear(ref: ?*PrivateWeakRef) callconv(.c) void {
    const weak = ref orelse return;
    if (!weak.alive) return;
    weak.root.notify_on_collect.store(false, .release);
    _ = weak.root.target.swap(null, .acq_rel);
}

export fn Bun__WeakRef__delete(ref: ?*PrivateWeakRef) callconv(.c) void {
    const weak = ref orelse return;
    const group = weak.group;
    group.primary.assertOwnerThread();
    privateWeakRefRemove(weak);
    if (group.release()) group.destroy();
}

fn privateRemoveStrongRootLocked(context: *Context, target: *Context.PrivateStrongRoot) void {
    for (context.private_strong_roots.items, 0..) |root, index| {
        if (root == target) {
            _ = context.private_strong_roots.swapRemove(index);
            return;
        }
    }
}

fn privateMarkedArgumentBufferCleanup(buffer: *PrivateMarkedArgumentBuffer) void {
    if (buffer.magic != private_marked_argument_buffer_magic) return;
    if (buffer.group) |group| {
        const primary = group.primary;
        primary.realmLock();
        for (buffer.roots.items) |root| privateRemoveStrongRootLocked(primary, root);
        primary.realmUnlock();
        for (buffer.roots.items) |root| primary.gpa.destroy(root);
    }
    buffer.values.deinit(gpa);
    buffer.roots.deinit(gpa);
    buffer.* = .{ .magic = 0 };
}

export fn MarkedArgumentBuffer__run(
    callback_context: ?*anyopaque,
    callback: ?PrivateMarkedArgumentCallback,
) callconv(.c) void {
    const function = callback orelse return;
    var buffer: PrivateMarkedArgumentBuffer = .{};
    defer privateMarkedArgumentBufferCleanup(&buffer);
    function(callback_context, &buffer);
}

export fn MarkedArgumentBuffer__append(raw: ?*anyopaque, encoded: EncodedValue) callconv(.c) void {
    const pointer = raw orelse return;
    if (@intFromPtr(pointer) % @alignOf(PrivateMarkedArgumentBuffer) != 0) return;
    const buffer: *PrivateMarkedArgumentBuffer = @ptrCast(@alignCast(pointer));
    if (buffer.magic != private_marked_argument_buffer_magic) return;

    if (!encoded.isCell()) {
        _ = encoded.toInternalPrimitive(Value) catch return;
        buffer.values.append(gpa, encoded) catch return;
        return;
    }
    const boxed = privateBoxedFrom(encoded) orelse return;
    if (boxed.private_kind != .value) return;
    const erased_group = boxed.owner.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(erased_group));
    if (buffer.group) |existing| {
        if (existing != group) return;
    }

    buffer.values.ensureUnusedCapacity(gpa, 1) catch return;
    buffer.roots.ensureUnusedCapacity(gpa, 1) catch return;
    const root = group.primary.gpa.create(Context.PrivateStrongRoot) catch return;
    root.* = .{ .value = boxed.value };
    const primary = group.primary;
    primary.realmLock();
    primary.private_strong_roots.ensureUnusedCapacity(primary.gpa, 1) catch {
        primary.realmUnlock();
        primary.gpa.destroy(root);
        return;
    };
    primary.private_strong_roots.appendAssumeCapacity(root);
    buffer.roots.appendAssumeCapacity(root);
    buffer.values.appendAssumeCapacity(encoded);
    buffer.group = group;
    primary.realmUnlock();
}

fn privateCommonJSExtensionContext(global: JSContextRef) ?*Context {
    const context = ctxForHandleInspection(global) orelse return null;
    const erased_group = context.c_api_group orelse return null;
    const group: *CContextGroup = @ptrCast(@alignCast(erased_group));
    if (group.pending_exception != null) return null;
    return context;
}

export fn JSCommonJSExtensions__appendFunction(global: JSContextRef, encoded: EncodedValue) callconv(.c) u32 {
    const context = privateCommonJSExtensionContext(global) orelse return std.math.maxInt(u32);
    const internal = privateValueFrom(global, encoded) orelse return std.math.maxInt(u32);
    if (context.private_commonjs_functions.items.len > std.math.maxInt(u32)) return std.math.maxInt(u32);
    const root = context.gpa.create(Context.PrivateStrongRoot) catch {
        privatePublishBunStringError(context, error.OutOfMemory);
        return std.math.maxInt(u32);
    };
    root.* = .{ .value = internal };

    context.realmLock();
    context.private_commonjs_functions.ensureUnusedCapacity(context.gpa, 1) catch {
        context.realmUnlock();
        context.gpa.destroy(root);
        privatePublishBunStringError(context, error.OutOfMemory);
        return std.math.maxInt(u32);
    };
    context.private_strong_roots.ensureUnusedCapacity(context.gpa, 1) catch {
        context.realmUnlock();
        context.gpa.destroy(root);
        privatePublishBunStringError(context, error.OutOfMemory);
        return std.math.maxInt(u32);
    };
    const index: u32 = @intCast(context.private_commonjs_functions.items.len);
    context.private_commonjs_functions.appendAssumeCapacity(root);
    context.private_strong_roots.appendAssumeCapacity(root);
    context.realmUnlock();
    return index;
}

export fn JSCommonJSExtensions__setFunction(global: JSContextRef, index: u32, encoded: EncodedValue) callconv(.c) void {
    const context = privateCommonJSExtensionContext(global) orelse return;
    const internal = privateValueFrom(global, encoded) orelse return;
    context.realmLock();
    defer context.realmUnlock();
    if (index >= context.private_commonjs_functions.items.len) return;
    context.private_commonjs_functions.items[index].value = internal;
}

export fn JSCommonJSExtensions__swapRemove(global: JSContextRef, index: u32) callconv(.c) u32 {
    const context = privateCommonJSExtensionContext(global) orelse return index;
    context.realmLock();
    if (index >= context.private_commonjs_functions.items.len) {
        context.realmUnlock();
        return index;
    }
    const removed = context.private_commonjs_functions.items[index];
    const last_index: u32 = @intCast(context.private_commonjs_functions.items.len - 1);
    _ = context.private_commonjs_functions.swapRemove(index);
    privateRemoveStrongRootLocked(context, removed);
    context.realmUnlock();
    context.gpa.destroy(removed);
    return if (index < last_index) last_index else index;
}

fn privateRunFullCollection(group: *CContextGroup) usize {
    group.async_gc_requested.store(false, .release);
    group.primary.collectGarbage();
    if (group.collection_epoch != std.math.maxInt(u64)) group.collection_epoch += 1;
    const accounting = group.primary.runtimeHeapAccounting();
    return accounting.last_full_collection_bytes;
}

export fn JSC__VM__blockBytesAllocated(vm_ref: ?*anyopaque) callconv(.c) usize {
    const group = privateGroupFromVM(vm_ref) orelse return 0;
    const heap_bytes = group.primary.runtimeHeapAccounting().live_bytes;
    return privateSaturatingAdd(heap_bytes, group.reported_extra_memory.load(.acquire));
}

export fn JSC__VM__collectAsync(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    group.async_gc_requested.store(true, .release);
    group.primary.requestGarbageCollection();
}

export fn JSC__VM__externalMemorySize(vm_ref: ?*anyopaque) callconv(.c) usize {
    const group = privateGroupFromVM(vm_ref) orelse return 0;
    return privateVMExternalMemory(group);
}

export fn JSC__VM__heapSize(vm_ref: ?*anyopaque) callconv(.c) usize {
    const group = privateGroupFromVM(vm_ref) orelse return 0;
    return group.primary.runtimeHeapAccounting().live_bytes;
}

export fn JSC__VM__performOpportunisticallyScheduledTasks(vm_ref: ?*anyopaque, until: f64) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    if (std.math.isNan(until) or until <= 0) return;
    if (group.async_gc_requested.load(.acquire)) _ = privateRunFullCollection(group);
    privateVMDrainMicrotasks(group);
}

export fn JSC__VM__releaseWeakRefs(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    _ = privateRunFullCollection(group);
}

export fn JSC__VM__reportExtraMemory(vm_ref: ?*anyopaque, bytes: usize) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    privateSaturatingAddAtomic(&group.reported_extra_memory, bytes);
}

export fn JSC__VM__runGC(vm_ref: ?*anyopaque, sync: bool) callconv(.c) usize {
    _ = sync; // Both pinned paths complete one full collection before returning.
    const group = privateGroupFromVM(vm_ref) orelse return 0;
    return privateRunFullCollection(group);
}

export fn JSC__VM__shrinkFootprint(vm_ref: ?*anyopaque) callconv(.c) void {
    const group = privateGroupFromVM(vm_ref) orelse return;
    _ = privateRunFullCollection(group);
}

export fn JSGlobalObject__tryTakeException(global: JSContextRef) callconv(.c) EncodedValue {
    const context = ctxForHandleInspection(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    const exception = group.pending_exception orelse return .empty;
    group.pending_exception = null;
    group.primary.private_pending_exception_root = null;
    return EncodedValue.fromCellAddress(@intFromPtr(exception)) catch .empty;
}

export fn JSC__VM__throwError(
    vm_ref: ?*anyopaque,
    global: JSContextRef,
    encoded: EncodedValue,
) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const opaque_group = context.c_api_group orelse return;
    if (vm_ref != opaque_group) return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null or encoded == .empty) return;

    if (encoded.asCellAddress()) |_| {
        const boxed = privateBoxedFrom(encoded) orelse return;
        if (boxed.private_kind == .exception) {
            group.pending_exception = boxed;
            group.primary.private_pending_exception_root = boxed.value;
            return;
        }
    } else |_| {}

    const thrown = privateValueFrom(global, encoded) orelse return;
    group.pending_exception = privateExceptionBox(context, thrown, encoded);
    if (group.pending_exception != null)
        group.primary.private_pending_exception_root = thrown;
}

export fn JSC__Exception__asJSValue(exception: ?*anyopaque) callconv(.c) EncodedValue {
    const boxed = privateBoxFromCell(exception) orelse return .empty;
    if (boxed.private_kind != .exception) return .empty;
    return boxed.exception_encoded;
}

fn privateDerefBunString(string: PrivateBunString) void {
    if (string.tag == .wtf_string_impl) Bun__WTFStringImpl__deref(string.value.wtf_string_impl);
}

fn privateRuntimeTypeForValue(input: Value) PrivateJSRuntimeType {
    return switch (input.kind()) {
        .undefined => .undefined,
        .null => .null,
        .boolean => .boolean,
        .number => if (std.math.isFinite(input.asNum()) and @trunc(input.asNum()) == input.asNum()) .any_int else .number,
        .string => .string,
        .object => object: {
            const object = input.asObj();
            if (object.is_symbol) break :object .symbol;
            if (object.is_bigint) break :object .bigint;
            if (object.isCallableObject()) break :object .function;
            break :object .object;
        },
    };
}

fn privateErrorCodeForName(name: []const u8) PrivateJSErrorCode {
    if (std.mem.eql(u8, name, "EvalError")) return .eval_error;
    if (std.mem.eql(u8, name, "RangeError")) return .range_error;
    if (std.mem.eql(u8, name, "ReferenceError")) return .reference_error;
    if (std.mem.eql(u8, name, "SyntaxError")) return .syntax_error;
    if (std.mem.eql(u8, name, "TypeError")) return .type_error;
    if (std.mem.eql(u8, name, "URIError")) return .uri_error;
    if (std.mem.eql(u8, name, "AggregateError")) return .aggregate_error;
    if (std.mem.eql(u8, name, "OutOfMemoryError")) return .out_of_memory_error;
    if (std.mem.eql(u8, name, "StackOverflow")) return .stack_overflow;
    return .error_;
}

fn privateDirectString(object: *Object, name: []const u8) ?[]const u8 {
    const property = object.getOwn(name) orelse return null;
    return if (property.isString()) property.asStr() else null;
}

fn privateDirectInt(object: *Object, name: []const u8) ?i32 {
    const property = object.getOwn(name) orelse return null;
    if (!property.isNumber() or !std.math.isFinite(property.asNum())) return null;
    const truncated = @trunc(property.asNum());
    if (truncated < std.math.minInt(i32) or truncated > std.math.maxInt(i32)) return null;
    return @intFromFloat(truncated);
}

fn privateSetProjectedString(output: *PrivateBunString, bytes: []const u8) bool {
    output.* = privateOwnedWTF8String(bytes) catch return false;
    return true;
}

fn privateProjectExceptionValue(
    context: *Context,
    input: Value,
    exception_cell: ?*anyopaque,
    output: *PrivateZigException,
) bool {
    output.type = .user_error;
    output.runtime_type = .nothing;
    output.errno = 0;
    output.syscall = .empty();
    output.system_code = .empty();
    output.path = .empty();
    output.name = .empty();
    output.message = .empty();
    output.exception = exception_cell;
    output.remapped = false;
    output.fd = -1;
    output.browser_url = .empty();

    if (input.isObject()) {
        const object = input.asObj();
        const name = privateDirectString(object, "name") orelse if (object.behavior.is_error) object.errorName() else "Error";
        const message = privateDirectString(object, "message") orelse if (object.behavior.is_error)
            (privateDirectString(object, "\x00dommsg") orelse "")
        else
            "";
        output.type = privateErrorCodeForName(name);
        if (!privateSetProjectedString(&output.name, name)) return false;
        if (!privateSetProjectedString(&output.message, message)) return false;

        if (object.getOwn("cause")) |cause| output.runtime_type = privateRuntimeTypeForValue(cause);
        if (privateDirectString(object, "syscall")) |text|
            if (!privateSetProjectedString(&output.syscall, text)) return false;
        if (object.getOwn("code")) |code| {
            const text = if (code.isString()) code.asStr() else if (code.isNumber())
                code.toString(context.arena()) catch return false
            else
                "";
            if (!privateSetProjectedString(&output.system_code, text)) return false;
        }
        if (privateDirectString(object, "path")) |text|
            if (!privateSetProjectedString(&output.path, text)) return false;
        output.errno = privateDirectInt(object, "errno") orelse 0;
        output.fd = privateDirectInt(object, "fd") orelse -1;
        return true;
    }

    output.type = .error_;
    const message = input.toString(context.arena()) catch return false;
    if (!privateSetProjectedString(&output.name, "Error")) return false;
    if (!privateSetProjectedString(&output.message, message)) return false;
    return true;
}

fn privateExceptionInput(global: JSContextRef, encoded: EncodedValue) ?struct { context: *Context, value: Value, cell: ?*anyopaque } {
    const context = ctxForHandleInspection(global) orelse return null;
    if (encoded.asCellAddress()) |address| {
        const boxed = privateBoxedFrom(encoded) orelse return null;
        if (boxed.owner.c_api_group != context.c_api_group) return null;
        return .{
            .context = boxed.owner,
            .value = boxed.value,
            .cell = if (boxed.private_kind == .exception) @ptrFromInt(address) else null,
        };
    } else |_| {}
    const input = privateValueFrom(global, encoded) orelse return null;
    return .{ .context = context, .value = input, .cell = null };
}

fn privatePopulateRetainedStack(input: Value, output: *PrivateZigStackTrace) void {
    output.frames_len = 0;
    output.referenced_source_provider = null;
    if (output.frames_cap == 0 or output.frames_ptr == null or !input.isObject() or !input.asObj().behavior.is_error) return;

    const retained = input.asObj().errorStackFrames();
    const count = @min(retained.len, @as(usize, output.frames_cap));
    for (retained[0..count], output.frames_ptr[0..count]) |source, *destination| {
        const function_name = privateOwnedWTF8String(source.function_name) catch break;
        const source_url = privateOwnedWTF8String(source.source_url) catch {
            privateDerefBunString(function_name);
            break;
        };
        destination.* = .{
            .function_name = function_name,
            .source_url = source_url,
            .position = .{
                .line = source.line_zero_based,
                .column = source.column_zero_based,
                .line_start_byte = source.line_start_byte,
            },
            .code_type = @enumFromInt(@intFromEnum(source.code_type)),
            .is_async = source.is_async,
            .remapped = false,
            .jsc_stack_frame_index = source.jsc_stack_frame_index,
        };
        output.frames_len += 1;
    }
}

/// Project the Error's creation-time structured stack into Bun/Home's exact
/// `ZigStackTrace` storage. Like upstream's `OnlyPosition` path, the caller owns
/// the frame buffer and receives no source-line payload/provider reference.
export fn JSC__Exception__getStackTrace(
    exception: ?*anyopaque,
    global: JSContextRef,
    trace: ?*PrivateZigStackTrace,
) callconv(.c) void {
    const output = trace orelse return;
    output.frames_len = 0;
    output.source_lines_len = 0;
    output.referenced_source_provider = null;

    const context = ctxForHandleInspection(global) orelse return;
    const boxed = privateBoxFromCell(exception) orelse return;
    if (boxed.private_kind != .exception or boxed.owner.c_api_group != context.c_api_group) return;
    privatePopulateRetainedStack(boxed.value, output);
}

/// Full Home/Bun exception projection. Caller-provided stack buffers are
/// preserved while scalar/string fields and retained frames are populated.
export fn JSC__JSValue__toZigException(
    encoded: EncodedValue,
    global: JSContextRef,
    output: ?*PrivateZigException,
) callconv(.c) void {
    const destination = output orelse return;
    const input = privateExceptionInput(global, encoded) orelse return;
    if (!privateProjectExceptionValue(input.context, input.value, input.cell, destination)) return;
    privatePopulateRetainedStack(input.value, &destination.stack);
}

fn privateDebugScriptForFrame(context: *Context, frame: value.ErrorStackFrame) ?Context.DebugScript {
    context.lockDebugRegistry();
    defer context.unlockDebugRegistry();
    if (frame.script_id != 0) {
        for (context.debug_scripts.items) |script| if (script.id == frame.script_id) return script;
    }
    var index = context.debug_scripts.items.len;
    while (index > 0) {
        index -= 1;
        const script = context.debug_scripts.items[index];
        if (std.mem.eql(u8, script.url, frame.source_url)) return script;
    }
    return null;
}

fn privateLineBounds(source: []const u8, offset: usize) struct { start: usize, end: usize } {
    var start = @min(offset, source.len);
    while (start > 0 and source[start - 1] != '\n') start -= 1;
    var end = @min(offset, source.len);
    while (end < source.len and source[end] != '\n') end += 1;
    if (end > start and source[end - 1] == '\r') end -= 1;
    return .{ .start = start, .end = end };
}

/// Second-phase source collection corresponding to upstream
/// `PopulateStackTraceFlags::OnlySourceLines`. Source lines are owned BunStrings,
/// so no SourceProvider reference is needed and consumer deinit remains exact.
export fn ZigException__collectSourceLines(
    encoded: EncodedValue,
    global: JSContextRef,
    output: ?*PrivateZigException,
) callconv(.c) void {
    const destination = output orelse return;
    const storage_cap = @min(destination.stack.source_lines_len, destination.stack.source_lines_to_collect);
    destination.stack.source_lines_len = 0;
    destination.stack.referenced_source_provider = null;
    if (storage_cap == 0 or destination.stack.source_lines_ptr == null or destination.stack.source_lines_numbers == null or destination.stack.frames_len == 0) return;

    const input = privateExceptionInput(global, encoded) orelse return;
    if (!input.value.isObject() or !input.value.asObj().behavior.is_error) return;
    const retained = input.value.asObj().errorStackFrames();
    const retained_index = destination.stack.frames_ptr[0].jsc_stack_frame_index;
    if (retained_index < 0 or retained_index >= retained.len) return;
    const frame = retained[@intCast(retained_index)];
    const script = privateDebugScriptForFrame(input.context, frame) orelse return;
    if (frame.line_start_byte < 0) return;

    var bounds = privateLineBounds(script.source, @intCast(frame.line_start_byte));
    var line = frame.line_zero_based;
    var written: u8 = 0;
    while (written < storage_cap) : (written += 1) {
        const owned = privateOwnedWTF8String(script.source[bounds.start..bounds.end]) catch break;
        destination.stack.source_lines_ptr[written] = owned;
        destination.stack.source_lines_numbers[written] = line;
        destination.stack.source_lines_len += 1;
        if (bounds.start == 0) break;
        var previous_end = bounds.start - 1;
        if (previous_end > 0 and script.source[previous_end - 1] == '\r') previous_end -= 1;
        bounds = privateLineBounds(script.source, previous_end -| 1);
        line -= 1;
    }
}

/// By-value conversion used when the caller has only an exception cell and no
/// frame/source buffers. Owned strings and the stable cell pointer are returned;
/// the zero-capacity trace makes the absence of caller storage explicit.
export fn ZigException__fromException(exception: ?*anyopaque) callconv(.c) PrivateZigException {
    var output = PrivateZigException{};
    const boxed = privateBoxFromCell(exception) orelse return output;
    if (boxed.private_kind != .exception) return output;
    _ = privateProjectExceptionValue(boxed.owner, boxed.value, exception, &output);
    return output;
}

export fn JSC__JSValue__isException(encoded: EncodedValue, vm_ref: ?*anyopaque) callconv(.c) bool {
    _ = vm_ref;
    return privateIsExceptionCell(encoded);
}

export fn JSC__JSValue__toError_(encoded: EncodedValue) callconv(.c) EncodedValue {
    const boxed = privateBoxedFrom(encoded) orelse return .empty;
    if (boxed.private_kind == .exception) return boxed.exception_encoded;
    if (!boxed.value.isObject() or !boxed.value.asObj().behavior.is_error) return .empty;
    return encoded;
}

export fn JSC__JSValue__isAnyError(encoded: EncodedValue) callconv(.c) bool {
    const boxed = privateBoxedFrom(encoded) orelse return false;
    return boxed.private_kind == .exception or
        (boxed.value.isObject() and boxed.value.asObj().behavior.is_error);
}

export fn JSC__JSValue__asInternalPromise(encoded: EncodedValue) callconv(.c) ?*anyopaque {
    return privatePromiseCellFromEncoded(encoded);
}

export fn JSC__JSValue__asPromise(encoded: EncodedValue) callconv(.c) ?*anyopaque {
    return privatePromiseCellFromEncoded(encoded);
}

export fn JSC__JSValue__createInternalPromise(global: JSContextRef) callconv(.c) EncodedValue {
    return privateCreateNativePromise(global, null, .undefined);
}

export fn JSC__JSPromise__create(global: JSContextRef) callconv(.c) ?*anyopaque {
    return privatePromiseCellFromEncoded(privateCreateNativePromise(global, null, .undefined));
}

export fn JSC__JSPromise__resolvedPromise(
    global: JSContextRef,
    encoded: EncodedValue,
) callconv(.c) ?*anyopaque {
    return privatePromiseCellFromEncoded(privateCreateNativePromise(global, .fulfilled, encoded));
}

export fn JSC__JSPromise__resolvedPromiseValue(
    global: JSContextRef,
    encoded: EncodedValue,
) callconv(.c) EncodedValue {
    return privateCreateNativePromise(global, .fulfilled, encoded);
}

export fn JSC__JSPromise__rejectedPromise(
    global: JSContextRef,
    encoded: EncodedValue,
) callconv(.c) ?*anyopaque {
    return privatePromiseCellFromEncoded(privateCreateNativePromise(global, .rejected, encoded));
}

/// This deprecated value-returning constructor deliberately performs the same
/// direct rejected-state initialization as Bun's pinned implementation. zig-js
/// does not yet expose a host rejection tracker, so there is no notification to
/// suppress here; adding one must preserve this entry point's distinction.
export fn JSC__JSPromise__rejectedPromiseValue(
    global: JSContextRef,
    encoded: EncodedValue,
) callconv(.c) EncodedValue {
    return privateCreateNativePromise(global, .rejected, encoded);
}

/// Register the pinned Home/Bun fulfillment and rejection callbacks on a
/// native Promise. The selected JSHostFn runs from the Promise microtask queue
/// with `(settlement_value, context_value)` as its two ordinary arguments.
export fn JSC__JSValue___then(
    encoded_promise: EncodedValue,
    global: JSContextRef,
    encoded_context: EncodedValue,
    resolve: ?*const PrivateJSHostFn,
    reject: ?*const PrivateJSHostFn,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const opaque_group = context.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return;

    const promise_box = privateBoxedFrom(encoded_promise) orelse return;
    if (promise_box.private_kind != .value or promise_box.owner.c_api_group != opaque_group) return;
    const native_promise = promise.promiseOf(promise_box.value) orelse return;
    const retained_context = privateValueFrom(global, encoded_context) orelse return;
    const resolve_callback = resolve orelse return;
    const reject_callback = reject orelse return;

    const empty_name = PrivateBunString.empty();
    const resolve_encoded = JSFunction__createFromZig(
        global,
        empty_name,
        resolve_callback,
        2,
        .public,
        .none,
        null,
    );
    if (resolve_encoded == .empty) return;
    const reject_encoded = JSFunction__createFromZig(
        global,
        empty_name,
        reject_callback,
        2,
        .public,
        .none,
        null,
    );
    if (reject_encoded == .empty) return;
    const resolve_value = privateValueFrom(global, resolve_encoded) orelse return;
    const reject_value = privateValueFrom(global, reject_encoded) orelse return;

    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);
    promise.performThenDetached(
        &machine,
        native_promise,
        resolve_value,
        reject_value,
        retained_context,
    ) catch |err| privateSetPendingAbrupt(context, &machine, err);
}

/// Reconstruct the pending async-await chain rooted at `promise_cell` and
/// install it as the structured trace for an otherwise stackless Error. This is
/// deliberately side-effect-free: malformed inputs, settled chains, existing
/// traces, materialized stack info, and allocation failure are all no-ops.
export fn Bun__attachAsyncStackFromPromise(
    global: JSContextRef,
    encoded_error: EncodedValue,
    promise_cell: ?*anyopaque,
) callconv(.c) void {
    const context = ctxForHandleInspection(global) orelse return;
    const error_value = privateValueFrom(global, encoded_error) orelse return;
    if (!error_value.isObject()) return;
    const error_object = error_value.asObj();
    if (!error_object.behavior.is_error or error_object.hasMaterializedErrorInfo() or error_object.getOwn("stack") != null or
        error_object.errorStackFrames().len != 0) return;

    var machine = context.interpreter();
    const limit = machine.selectedStackTraceLimit();
    if (limit == 0) return;
    var current = privatePromiseFromCell(global, promise_cell) orelse return;
    var frames: std.ArrayListUnmanaged(value.ErrorStackFrame) = .empty;
    frame_walk: while (frames.items.len < limit) {
        var activation: ?*vm.Generator = null;
        var forward_hops: usize = 0;
        while (forward_hops < 32) : (forward_hops += 1) {
            const link = promise.asyncStackLink(current);
            if (link.state != .pending) break :frame_walk;
            if (link.activation) |raw_activation| {
                activation = @ptrCast(@alignCast(raw_activation));
                break;
            }
            current = link.forward_to orelse break :frame_walk;
        }
        const suspended = activation orelse break;
        if (suspended.done) break;
        var frame = suspended.async_suspension_frame orelse break;
        frame.function_name = context.arena().dupe(u8, frame.function_name) catch return;
        frame.source_url = context.arena().dupe(u8, frame.source_url) catch return;
        frame.is_async = true;
        frame.jsc_stack_frame_index = @intCast(frames.items.len);
        frames.append(context.arena(), frame) catch return;
        const parent = suspended.async_parent_promise orelse break;
        if (parent == current) break;
        current = parent;
    }
    if (frames.items.len == 0) return;
    const owned = frames.toOwnedSlice(context.arena()) catch return;
    error_object.setErrorStackFrames(context.arena(), owned) catch return;
}

export fn JSC__JSPromise__wrap(
    global: JSContextRef,
    callback_context: *anyopaque,
    callback: PrivatePromiseWrapCallback,
) callconv(.c) EncodedValue {
    const context = ctxForEvaluation(global) orelse return .empty;
    const opaque_group = context.c_api_group orelse return .empty;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return .empty;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return .empty;
    };
    defer context.popActiveInterpreter(&machine);

    const callback_result = callback(callback_context, global);
    if (privateTakePendingExceptionValue(context)) |thrown|
        return privateEncodeNativePromise(context, &machine, .rejected, thrown);

    const internal = privateValueFrom(global, callback_result) orelse {
        const invalid = machine.makeError("TypeError", "Promise callback returned a value from another VM") catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return .empty;
        };
        return privateEncodeNativePromise(context, &machine, .rejected, invalid);
    };
    if (promise.promiseOf(internal) != null) return callback_result;
    if (internal.isObject() and internal.asObj().behavior.is_error)
        return privateEncodeNativePromise(context, &machine, .rejected, internal);
    return privateEncodeNativePromise(context, &machine, .fulfilled, internal);
}

export fn JSC__AnyPromise__wrap(
    global: JSContextRef,
    encoded_promise: EncodedValue,
    callback_context: *anyopaque,
    callback: PrivatePromiseWrapCallback,
) callconv(.c) void {
    const context = ctxForEvaluation(global) orelse return;
    const opaque_group = context.c_api_group orelse return;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return;
    const gc_saved = gc_mod.setActiveHeap(context.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(context.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = context.interpreter();
    context.pushActiveInterpreter(&machine) catch |err| {
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    defer context.popActiveInterpreter(&machine);

    const target_value = privateValueFrom(global, encoded_promise) orelse {
        const err = machine.throwError("TypeError", "AnyPromise target belongs to another VM");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    const target = promise.promiseOf(target_value) orelse {
        const err = machine.throwError("TypeError", "AnyPromise target is not a native Promise");
        privateSetPendingAbrupt(context, &machine, err);
        return;
    };

    const callback_result = callback(callback_context, global);
    if (privateTakePendingExceptionValue(context)) |thrown| {
        promise.reject(&machine, target, thrown) catch |err|
            privateSetPendingAbrupt(context, &machine, err);
        return;
    }
    const internal = privateValueFrom(global, callback_result) orelse {
        const invalid = machine.makeError("TypeError", "Promise callback returned a value from another VM") catch |err| {
            privateSetPendingAbrupt(context, &machine, err);
            return;
        };
        promise.reject(&machine, target, invalid) catch |err|
            privateSetPendingAbrupt(context, &machine, err);
        return;
    };
    if (internal.isObject() and internal.asObj().behavior.is_error) {
        promise.reject(&machine, target, internal) catch |err|
            privateSetPendingAbrupt(context, &machine, err);
        return;
    }
    promise.resolve(&machine, target, internal) catch |err|
        privateSetPendingAbrupt(context, &machine, err);
}

