    if (context.c_api_group != @as(?*anyopaque, @ptrCast(signal.group))) return .empty;
    if (!interp.abortSignalAborted(signal.object)) return .empty;
    if (signal.common_reason != .none) {
        output.* = @intFromEnum(signal.common_reason);
        return .undefined;
