}

export fn JSC__JSValue__asArrayBuffer(
    encoded: EncodedValue,
    global: JSContextRef,
    out: ?*PrivateBunArrayBuffer,
) callconv(.c) bool {
    const output = out orelse return false;
    const context = ctxForHandleInspection(global) orelse return false;
    const opaque_group = context.c_api_group orelse return false;
    const group: *CContextGroup = @ptrCast(@alignCast(opaque_group));
    if (group.pending_exception != null) return false;
    const internal = privateValueFrom(global, encoded) orelse return false;
    if (!internal.isObject()) return false;
    const object = internal.asObj();

    var result = PrivateBunArrayBuffer{ .encoded_value = encoded };
    if (object.typedArray()) |typed| {
        const backing = typed.buffer.arrayBuffer() orelse return false;
        result.cell_type = private_jstype.selectedTag(privateObjectJSType(object));
        result.shared = backing.is_shared;
        result.resizable = backing.max_byte_length != null;
        const length = typed.currentLength() orelse {
            output.* = result;
            return true;
        };
        const byte_length = std.math.mul(usize, length, typed.kind.byteSize()) catch return false;
        const bytes = backing.bytes();
        if (typed.byte_offset > bytes.len or byte_length > bytes.len - typed.byte_offset) return false;
        result.ptr = bytes.ptr + typed.byte_offset;
        result.len = length;
        result.byte_len = byte_length;
    } else if (object.dataView()) |view| {
        const backing = view.buffer.arrayBuffer() orelse return false;
        result.cell_type = private_jstype.selectedTag(.DataView);
        result.shared = backing.is_shared;
        result.resizable = backing.max_byte_length != null;
        const byte_length = view.currentByteLength() orelse {
            output.* = result;
            return true;
        };
        const bytes = backing.bytes();
        if (view.byte_offset > bytes.len or byte_length > bytes.len - view.byte_offset) return false;
        result.ptr = bytes.ptr + view.byte_offset;
        result.len = byte_length;
        result.byte_len = byte_length;
    } else if (object.arrayBuffer()) |buffer| {
        result.cell_type = private_jstype.selectedTag(.ArrayBuffer);
        result.shared = buffer.is_shared;
        result.resizable = buffer.max_byte_length != null;
        if (!buffer.isDetached()) {
            const bytes = buffer.bytes();
            result.ptr = bytes.ptr;
            result.len = bytes.len;
            result.byte_len = bytes.len;
        }
    } else return false;

    output.* = result;
    return true;
}

fn privateArrayBufferBacking(input: Value) ?*value.ArrayBufferData {
    if (!input.isObject()) return null;
    const object = input.asObj();
    if (object.arrayBuffer()) |buffer| return buffer;
    if (object.typedArray()) |typed| return typed.buffer.arrayBuffer();
    if (object.dataView()) |view| return view.buffer.arrayBuffer();
    return null;
}

fn privateDiscardNativeArrayBufferHandle(handle: *value.NativeArrayBufferHandle) void {
    _ = handle.releaseExternal();
    handle.releaseWrapper();
    handle.releaseTracking();
}

fn privateEnsureNativeArrayBufferHandle(
    context: *Context,
    backing: *value.ArrayBufferData,
) ?*value.NativeArrayBufferHandle {
    backing.lockBuffer();
    defer backing.unlockBuffer();
    if (backing.native_handle.load(.acquire)) |existing| {
        if (existing.tryRetainExternal()) return existing;
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return null;
    }

    const current = backing.bytes();
    const candidate = if (backing.shared) |storage|
        value.NativeArrayBufferHandle.createShared(storage)
    else if (backing.external_owner != null)
        value.NativeArrayBufferHandle.createExternal(current, backing.max_byte_length)
    else
        value.NativeArrayBufferHandle.createOwned(current, backing.max_byte_length) catch {
            privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
            return null;
        };
    const handle = candidate catch {
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return null;
    };
    context.trackNativeArrayBufferHandle(handle) catch {
        privateDiscardNativeArrayBufferHandle(handle);
        privateSetPendingValue(context, context.reserved_thread_oom_error orelse Value.staticStr("OutOfMemory"));
        return null;
    };

    if (backing.external_owner) |owner| {
        const lease = owner.take() orelse {
            // The context tracking reference deliberately keeps this failed
            // candidate valid until teardown; it was never published.
            _ = handle.releaseExternal();
            handle.releaseWrapper();
            privateSetPendingValue(context, Value.staticStr("TypeError"));
            return null;
        };
        handle.armExternal(lease);
        backing.external_owner = null;
    }

    // Publish the independent backing before retiring the wrapper's previous
    // storage. Readers then switch directly from the old bytes to the handle.
    backing.native_handle.store(handle, .release);
    if (backing.shared == null) {
        const old = backing.local_data;
        backing.swapLocalData(&.{});
        if (backing.gc_owned and backing.external_owner == null and old.len > 0) {
            // External storage was transferred rather than allocated by gpa.
            const handle_bytes = handle.snapshotBytes();
            if (old.ptr != handle_bytes.ptr) {
                context.gpa.rawFree(old, .@"8", @returnAddress());
                _ = @atomicRmw(usize, &context.gc_array_buffer_bytes_live, .Sub, old.len, .monotonic);
            }
        }
    }
    return handle;
}

/// Production generated-binding seam for the pinned
/// IDLArrayBufferRef -> RefPtr<ArrayBuffer> -> leakRef() conversion. The
/// returned pointer carries the transferred native +1.
export fn JSC__IDLArrayBufferRef__convertToExtern(
    encoded: EncodedValue,
    global: JSContextRef,
) callconv(.c) ?*value.NativeArrayBufferHandle {
    const context = ctxForHandleInspection(global) orelse return null;
    const group = privatePropertyBoundaryGroup(context) orelse return null;
    if (group.pending_exception != null) return null;
    const input = privateValueFrom(global, encoded) orelse return null;
    const backing = privateArrayBufferBacking(input) orelse return null;
    // The pinned IDL converter is explicitly unshared and rejects detached
    // ArrayBuffers/views before ExternTraits transfers the RefPtr.
    // A Memory.grow replaces and detaches the JS wrapper's current backing.
    // The generated native handle currently models stable ordinary/shared
    // backings, so rejecting Memory buffers avoids publishing a handle whose
    // pointer could be retired by a later grow.
    if (backing.is_shared or backing.is_wasm_memory or backing.isDetached()) return null;
    return privateEnsureNativeArrayBufferHandle(context, backing);
}

export fn JSC__ArrayBuffer__ref(handle: ?*value.NativeArrayBufferHandle) callconv(.c) void {
    if (handle) |entry| _ = entry.tryRetainExternal();
}

export fn JSC__ArrayBuffer__deref(handle: ?*value.NativeArrayBufferHandle) callconv(.c) void {
    if (handle) |entry| _ = entry.releaseExternal();
}

export fn JSC__ArrayBuffer__asBunArrayBuffer(
    handle: ?*value.NativeArrayBufferHandle,
    out: ?*PrivateBunArrayBuffer,
) callconv(.c) void {
    const output = out orelse return;
    const entry = handle orelse {
        output.* = .{};
        return;
    };
    const bytes = entry.snapshotBytes();
    output.* = .{
        .ptr = if (bytes.len == 0) null else bytes.ptr,
        .len = bytes.len,
        .byte_len = bytes.len,
        .encoded_value = .empty,
        .cell_type = private_jstype.selectedTag(.ArrayBuffer),
        .shared = entry.isShared(),
        .resizable = entry.isResizable(),
    };
}

fn makeExternalArrayBuffer(
    c: *Context,
    bytes: ?*anyopaque,
    byte_length: usize,
    deallocator: JSTypedArrayBytesDeallocator,
    deallocator_context: ?*anyopaque,
    exception: ExceptionRef,
) ?ExternalArrayBuffer {
    if (byte_length > 0 and bytes == null) {
        releaseExternalInput(bytes, deallocator, deallocator_context);
        setException(c, exception, "TypeError: non-empty external buffer requires non-null bytes");
        return null;
    }
    const owner = c.createExternalBufferOwner(bytes, deallocator, deallocator_context) catch {
        releaseExternalInput(bytes, deallocator, deallocator_context);
        setException(c, exception, "OutOfMemory");
        return null;
    };
    var owner_transferred = false;
    defer {
        if (!owner_transferred) _ = owner.release();
    }
    const data: []u8 = if (byte_length == 0)
        &.{}
    else
        @as([*]u8, @ptrCast(bytes.?))[0..byte_length];

    const gc_saved = gc_mod.setActiveHeap(c.gc);
    defer _ = gc_mod.setActiveHeap(gc_saved);
    const sa_saved = strcell.setActiveArena(c.arena());
    defer _ = strcell.setActiveArena(sa_saved);
    var machine = c.interpreter();
    c.pushActiveInterpreter(&machine) catch {
        setException(c, exception, "OutOfMemory");
        return null;
    };
    defer c.popActiveInterpreter(&machine);
    const object = machine.makeExternalArrayBuffer(data, owner) catch |err| {
        if (err == error.Throw) {
            if (exception != null) exception[0] = box(c, machine.exception);
        } else {
            setException(c, exception, @errorName(err));
        }
        return null;
    };
    owner_transferred = true;
    return .{ .object = object, .owner = owner };
}

export fn JSObjectMakeTypedArray(ctx: JSContextRef, array_type: JSTypedArrayType, length: usize, exception: ExceptionRef) callconv(.c) JSObjectRef {
    const c = ctxFrom(ctx) orelse return null;
    const kind = typedArrayKind(array_type) orelse return null;
    const args = [_]Value{Value.num(@floatFromInt(length))};
    return makeTypedArrayObject(c, kind, &args, exception);
}

export fn JSObjectMakeTypedArrayWithBytesNoCopy(
    ctx: JSContextRef,
    array_type: JSTypedArrayType,
    bytes: ?*anyopaque,
    byte_length: usize,
    bytes_deallocator: JSTypedArrayBytesDeallocator,
    deallocator_context: ?*anyopaque,
    exception: ExceptionRef,
) callconv(.c) JSObjectRef {
    const c = ctxFrom(ctx) orelse {
        releaseExternalInput(bytes, bytes_deallocator, deallocator_context);
        return null;
    };
    const kind = typedArrayKind(array_type) orelse {
        releaseExternalInput(bytes, bytes_deallocator, deallocator_context);
        return null;
    };
    const element_size = kind.byteSize();
    if (byte_length % element_size != 0) {
        releaseExternalInput(bytes, bytes_deallocator, deallocator_context);
        setException(c, exception, "RangeError: external byte length is not a multiple of the element size");
        return null;
    }
    const external = makeExternalArrayBuffer(c, bytes, byte_length, bytes_deallocator, deallocator_context, exception) orelse return null;
    const args = [_]Value{Value.obj(external.object)};
    return makeTypedArrayObject(c, kind, &args, exception) orelse {
        _ = external.owner.release();
        return null;
    };
}

export fn JSObjectMakeArrayBufferWithBytesNoCopy(
    ctx: JSContextRef,
    bytes: ?*anyopaque,
    byte_length: usize,
    bytes_deallocator: JSTypedArrayBytesDeallocator,
