test "private property path traversal preserves pinned string and array semantics" {
    const context = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;
    const Probe = struct {
        fn encoded(context_: *Context, source: []const u8) !EncodedValue {
            return privateEncodedFromValue(context_, try context_.evaluate(source));
        }

        fn call(context_: *Context, global: JSContextRef, target_source: []const u8, path_source: []const u8) !EncodedValue {
            return JSC__JSValue__getIfPropertyExistsFromPath(
                try encoded(context_, target_source),
                global,
                try encoded(context_, path_source),
            );
        }

        fn expect(context_: *Context, global: JSContextRef, target_source: []const u8, path_source: []const u8, expected_source: []const u8) !void {
            const actual = try call(context_, global, target_source, path_source);
            try std.testing.expect(actual != .empty);
            const actual_value = privateValueFrom(global, actual) orelse return error.ValueInitFailed;
            try std.testing.expect(value.strictEquals(actual_value, try context_.evaluate(expected_source)));
        }
    };

    try Probe.expect(internal, context, "({ a: { b: 41 } })", "'a.b'", "41");
    try Probe.expect(internal, context, "({ a: { b: 42 } })", "'a[b]'", "42");
    try Probe.expect(internal, context, "({ 'A😀': { '𐐀': 43 } })", "'A😀.𐐀'", "43");
    try Probe.expect(internal, context, "({ '': 44 })", "''", "44");
    try Probe.expect(internal, context, "({ '': { '': 45 } })", "'.'", "45");
    try Probe.expect(internal, context, "({ '': { a: 46 } })", "'.a'", "46");
    try Probe.expect(internal, context, "({ a: { '': { b: 47 } } })", "'a..b'", "47");
    try Probe.expect(internal, context, "({ a: { '': 48 } })", "'a.'", "48");
    try Probe.expect(internal, context, "({ a: 49 })", "'a[]'", "49");
    try std.testing.expectEqual(EncodedValue.empty, try Probe.call(internal, context, "({ '': 1 })", "'[]'"));
    try std.testing.expectEqual(EncodedValue.undefined, try Probe.call(internal, context, "({ a: undefined })", "'a'"));
    try std.testing.expectEqual(EncodedValue.empty, try Probe.call(internal, context, "({ a: 1 })", "'missing'"));

    try Probe.expect(internal, context, "({ a: { '0': { b: 50 } } })", "['a', 0, 'b']", "50");
    try Probe.expect(internal, context, "({ '0': 51 })", "[-0]", "51");
    try Probe.expect(internal, context, "({ '1e+21': 52 })", "[1e21]", "52");
    try Probe.expect(internal, context, "'abc'", "['length']", "3");
    try Probe.expect(internal, context, "({ a: { inherited: 53 } })", "(() => { const p = ['a', ,]; Object.setPrototypeOf(p, { 1: 'inherited' }); return p; })()", "53");
    try std.testing.expectEqual(EncodedValue.empty, try Probe.call(internal, context, "({ a: 1 })", "['a', , 'ignored']"));
    try std.testing.expectEqual(EncodedValue.empty, try Probe.call(internal, context, "({ a: 1 })", "['a', true]"));

    const observable_target = try Probe.encoded(internal, "globalThis.__path_gets_224 = 0; globalThis.__path_has_224 = 0; " ++
        "new Proxy({ a: { b: 54 } }, { get(t, k, r) { __path_gets_224++; return Reflect.get(t, k, r); }, has() { __path_has_224++; return true; } })");
    const observable_result = JSC__JSValue__getIfPropertyExistsFromPath(observable_target, context, try Probe.encoded(internal, "'a.b'"));
    try std.testing.expect(value.strictEquals(privateValueFrom(context, observable_result) orelse return error.ValueInitFailed, try internal.evaluate("54")));
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__path_gets_224")).asNum());
    try std.testing.expectEqual(@as(f64, 0), (try internal.evaluate("__path_has_224")).asNum());

    const observable_path = try Probe.encoded(internal, "globalThis.__path_length_gets_224 = 0; globalThis.__path_index_gets_224 = 0; " ++
        "new Proxy(['a', 0, 'b'], { get(t, k, r) { if (k === 'length') __path_length_gets_224++; else if (String(+k) === k) __path_index_gets_224++; return Reflect.get(t, k, r); } })");
    const array_result = JSC__JSValue__getIfPropertyExistsFromPath(try Probe.encoded(internal, "({ a: { '0': { b: 55 } } })"), context, observable_path);
    try std.testing.expect(value.strictEquals(privateValueFrom(context, array_result) orelse return error.ValueInitFailed, try internal.evaluate("55")));
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__path_length_gets_224")).asNum());
    try std.testing.expectEqual(@as(f64, 3), (try internal.evaluate("__path_index_gets_224")).asNum());

    try std.testing.expectEqual(EncodedValue.empty, try Probe.call(internal, context, "({ get a() { throw 2241; } })", "'a'"));
    var pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(2241), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));
    try std.testing.expectEqual(EncodedValue.empty, try Probe.call(internal, context, "null", "'a'"));
    pending = JSGlobalObject__tryTakeException(context);
    const null_error = privateValueFrom(context, JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress()))) orelse return error.MissingException;
    try std.testing.expect(null_error.isObject() and null_error.asObj().behavior.is_error);
    try std.testing.expectEqual(EncodedValue.empty, try Probe.call(internal, context, "({ a: 1 })", "(() => { const r = Proxy.revocable([], {}); r.revoke(); return r.proxy; })()"));
    pending = JSGlobalObject__tryTakeException(context);
    const revoked_error = privateValueFrom(context, JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress()))) orelse return error.MissingException;
    try std.testing.expect(revoked_error.isObject() and revoked_error.asObj().behavior.is_error);

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_target = privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("({ a: 1 })"));
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__getIfPropertyExistsFromPath(foreign_target, context, try Probe.encoded(internal, "'a'")));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);

    const blocked_target = try Probe.encoded(internal, "({ a: 56 })");
    const blocked_path = try Probe.encoded(internal, "'a'");
    JSC__VM__throwError(JSC__JSGlobalObject__vm(context), context, EncodedValue.fromInt32(224));
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__getIfPropertyExistsFromPath(blocked_target, context, blocked_path));
    pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(224), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));
}

test "private value-key property query and BunString upsert preserve direct and observable semantics" {
    const context = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;
    const Probe = struct {
        fn encoded(context_: *Context, source: []const u8) !EncodedValue {
            return privateEncodedFromValue(context_, try context_.evaluate(source));
        }

        fn bunString(bytes: []const u8) PrivateBunString {
            return .{
                .tag = .static_zig_string,
                .value = .{ .zig_string = .{ .tagged_ptr = @intFromPtr(bytes.ptr), .len = bytes.len } },
            };
        }

        fn expect(context_: *Context, source: []const u8) !void {
            const result = try context_.evaluate(source);
            try std.testing.expect(result.toBoolean());
        }
    };

    const target = try Probe.encoded(internal, "globalThis.__property_ops_370 = Object.create({ set direct(v) { globalThis.__property_setter_370 = v; }, inherited: 4 }); Object.defineProperty(__property_ops_370, 'ownAccessor', { configurable: true, get() { return 99; } }); __property_ops_370");
    var direct = Probe.bunString("direct");
    JSC__JSValue__putBunString(target, context, &direct, EncodedValue.fromInt32(1));
    try Probe.expect(internal, "Object.hasOwn(__property_ops_370, 'direct') && __property_ops_370.direct === 1 && globalThis.__property_setter_370 === undefined");
    var own_accessor = Probe.bunString("ownAccessor");
    JSC__JSValue__putBunString(target, context, &own_accessor, EncodedValue.fromInt32(2));
    try Probe.expect(internal, "__property_ops_370.ownAccessor === 2 && Object.getOwnPropertyDescriptor(__property_ops_370, 'ownAccessor').get === undefined");

    var items = Probe.bunString("items");
    try std.testing.expectEqual(EncodedValue.undefined, JSC__JSValue__upsertBunStringArray(target, context, &items, EncodedValue.fromInt32(1)));
    try Probe.expect(internal, "__property_ops_370.items === 1");
    try std.testing.expectEqual(EncodedValue.undefined, JSC__JSValue__upsertBunStringArray(target, context, &items, EncodedValue.fromInt32(2)));
    try std.testing.expectEqual(EncodedValue.undefined, JSC__JSValue__upsertBunStringArray(target, context, &items, EncodedValue.fromInt32(3)));
    try Probe.expect(internal, "Array.isArray(__property_ops_370.items) && __property_ops_370.items.join(',') === '1,2,3'");

    var inherited = Probe.bunString("inherited");
    try std.testing.expectEqual(EncodedValue.undefined, JSC__JSValue__upsertBunStringArray(target, context, &inherited, EncodedValue.fromInt32(5)));
    try Probe.expect(internal, "Object.hasOwn(__property_ops_370, 'inherited') && __property_ops_370.inherited.join(',') === '4,5'");

    try std.testing.expect(JSC__JSValue__hasOwnPropertyValue(target, context, try Probe.encoded(internal, "'items'")));
    try std.testing.expect(!JSC__JSValue__hasOwnPropertyValue(target, context, try Probe.encoded(internal, "'missing'")));
    const symbol_target = try Probe.encoded(internal, "globalThis.__property_symbol_370 = Symbol('own'); globalThis.__property_symbol_target_370 = { [__property_symbol_370]: 1 }; __property_symbol_target_370");
    try std.testing.expect(JSC__JSValue__hasOwnPropertyValue(symbol_target, context, try Probe.encoded(internal, "__property_symbol_370")));

    const coercing_key = try Probe.encoded(internal, "globalThis.__property_key_calls_370 = 0; ({ [Symbol.toPrimitive]() { __property_key_calls_370++; return 'items'; } })");
    try std.testing.expect(JSC__JSValue__hasOwnPropertyValue(target, context, coercing_key));
    try Probe.expect(internal, "__property_key_calls_370 === 1");

    const proxy = try Probe.encoded(internal, "globalThis.__property_descriptor_calls_370 = 0; new Proxy({ own: 1 }, { getOwnPropertyDescriptor(t, k) { __property_descriptor_calls_370++; return Reflect.getOwnPropertyDescriptor(t, k); } })");
    try std.testing.expect(JSC__JSValue__hasOwnPropertyValue(proxy, context, try Probe.encoded(internal, "'own'")));
    try Probe.expect(internal, "__property_descriptor_calls_370 === 1");

    const throwing_key = try Probe.encoded(internal, "({ [Symbol.toPrimitive]() { throw 3701; } })");
    try std.testing.expect(!JSC__JSValue__hasOwnPropertyValue(target, context, throwing_key));
    const pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(3701), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_value = privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("({ foreign: true })"));
    JSC__JSValue__putBunString(target, context, &direct, foreign_value);
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);
    try std.testing.expect(!JSC__JSValue__hasOwnPropertyValue(target, context, foreign_value));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);
}

test "private property iterator preserves snapshots observability and VM inquiry" {
    const context = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;
    const Probe = struct {
        fn encoded(context_: *Context, source: []const u8) !EncodedValue {
            return privateEncodedFromValue(context_, try context_.evaluate(source));
        }

        fn cell(encoded_value: EncodedValue) !*anyopaque {
            return @ptrFromInt(try encoded_value.asCellAddress());
        }

        fn text(context_: *Context, string: *const PrivateBunString) ![]const u8 {
            const result = try privateBunStringValue(context_, string, null);
            if (!result.isString()) return error.ValueInitFailed;
            return result.asStr();
        }

        fn indexOf(context_: *Context, iterator: *PrivateJSPropertyIterator, expected: []const u8) !usize {
            for (0..iterator.entries.len) |index| {
                var name = PrivateBunString.dead();
                Bun__JSPropertyIterator__getName(iterator, &name, index);
                if (std.mem.eql(u8, try text(context_, &name), expected)) return index;
            }
            return error.MissingProperty;
        }
    };

    const target = try Probe.encoded(
        internal,
        "globalThis.__property_iterator_gets_368 = 0; " ++
            "globalThis.__property_iterator_proto_368 = { shadow: 30, inherited: 40, " ++
            "get throwing() { throw 3681; }, [Symbol('protoSymbol')]: 50 }; " ++
            "globalThis.__property_iterator_target_368 = Object.create(__property_iterator_proto_368); " ++
            "__property_iterator_target_368[2] = 2; __property_iterator_target_368[0] = 0; " ++
            "__property_iterator_target_368.alpha = 10; " ++
            "Object.defineProperty(__property_iterator_target_368, 'getter', { enumerable: true, get() { __property_iterator_gets_368++; return 20; } }); " ++
            "__property_iterator_target_368['unicode😀key'] = 60; " ++
            "__property_iterator_target_368[Symbol('ownSymbol')] = 70; " ++
            "Object.defineProperty(__property_iterator_target_368, 'shadow', { value: 99, enumerable: false }); " ++
            "__property_iterator_target_368",
    );
    const target_cell = try Probe.cell(target);

    var own_count: usize = 999;
    const own = Bun__JSPropertyIterator__create(context, target, &own_count, true, false) orelse
        return error.IteratorCreateFailed;
    defer Bun__JSPropertyIterator__deinit(own);
    try std.testing.expectEqual(@as(usize, 6), own_count);
    try std.testing.expectEqual(@as(usize, 12), Bun__JSPropertyIterator__getLongestPropertyName(own, context, target_cell));
    const expected_own = [_][]const u8{ "0", "2", "alpha", "getter", "unicode😀key", "ownSymbol" };
    for (expected_own, 0..) |expected, index| {
        var name = PrivateBunString.dead();
        Bun__JSPropertyIterator__getName(own, &name, index);
        try std.testing.expectEqual(PrivateBunStringTag.zig_string, name.tag);
        try std.testing.expectEqualStrings(expected, try Probe.text(internal, &name));
    }

    var non_index_count: usize = 999;
    const non_index = Bun__JSPropertyIterator__create(context, target, &non_index_count, true, true) orelse
        return error.IteratorCreateFailed;
    defer Bun__JSPropertyIterator__deinit(non_index);
    try std.testing.expectEqual(@as(usize, 4), non_index_count);
    try std.testing.expectEqualStrings("alpha", try Probe.text(internal, &non_index.entries[0].name));

    var full_count: usize = 999;
    const full = Bun__JSPropertyIterator__create(context, target, &full_count, false, true) orelse
        return error.IteratorCreateFailed;
    defer Bun__JSPropertyIterator__deinit(full);
    // The non-index flag is ignored for inherited enumeration, matching the
    // pinned C++ branch. A non-enumerable own `shadow` also does not enter the
    // PropertyNameArrayBuilder, so the enumerable prototype name is retained.
    try std.testing.expectEqual(@as(usize, 10), full_count);
    try std.testing.expectEqualStrings("0", try Probe.text(internal, &full.entries[0].name));
    const inherited_index = try Probe.indexOf(internal, full, "inherited");
    const shadow_index = try Probe.indexOf(internal, full, "shadow");
    const throwing_index = try Probe.indexOf(internal, full, "throwing");
    _ = try Probe.indexOf(internal, full, "protoSymbol");

    var output = PrivateBunString.dead();
    const inherited = Bun__JSPropertyIterator__getNameAndValueNonObservable(full, context, target_cell, &output, inherited_index);
    try std.testing.expectEqual(EncodedValue.fromInt32(40), inherited);
    try std.testing.expectEqualStrings("inherited", try Probe.text(internal, &output));
    const sibling = JSGlobalContextCreateInGroup(JSContextGetGroup(context), null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    output = PrivateBunString.dead();
    try std.testing.expectEqual(
        EncodedValue.fromInt32(40),
        Bun__JSPropertyIterator__getNameAndValueNonObservable(full, sibling, target_cell, &output, inherited_index),
    );
    output = PrivateBunString.dead();
    const shadow = Bun__JSPropertyIterator__getNameAndValueNonObservable(full, context, target_cell, &output, shadow_index);
    // Lookup starts at the receiver, so the non-enumerable own slot wins even
    // though the enumerable prototype slot supplied the snapshotted name.
    try std.testing.expectEqual(EncodedValue.fromInt32(99), shadow);

    const getter_index = try Probe.indexOf(internal, own, "getter");
    output = PrivateBunString.empty();
    try std.testing.expectEqual(EncodedValue.empty, Bun__JSPropertyIterator__getNameAndValueNonObservable(own, context, target_cell, &output, getter_index));
    try std.testing.expectEqual(PrivateBunStringTag.dead, output.tag);
    try std.testing.expectEqual(@as(f64, 0), (try internal.evaluate("__property_iterator_gets_368")).asNum());
    try std.testing.expectEqual(EncodedValue.fromInt32(20), Bun__JSPropertyIterator__getNameAndValue(own, context, target_cell, &output, getter_index));
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__property_iterator_gets_368")).asNum());

    // Names are an owned snapshot, while values are looked up live.
    _ = try internal.evaluate("delete __property_iterator_target_368.alpha; __property_iterator_target_368.afterSnapshot = 80");
    const alpha_index = try Probe.indexOf(internal, own, "alpha");
    output = PrivateBunString.empty();
    try std.testing.expectEqual(EncodedValue.empty, Bun__JSPropertyIterator__getNameAndValue(own, context, target_cell, &output, alpha_index));
    try std.testing.expectEqual(PrivateBunStringTag.dead, output.tag);
    try std.testing.expectError(error.MissingProperty, Probe.indexOf(internal, own, "afterSnapshot"));

    output = PrivateBunString.empty();
    try std.testing.expectEqual(EncodedValue.empty, Bun__JSPropertyIterator__getNameAndValue(full, context, target_cell, &output, throwing_index));
    var pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(3681), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));

    const proxy = try Probe.encoded(
        internal,
        "globalThis.__property_iterator_proxy_own_368 = 0; globalThis.__property_iterator_proxy_desc_368 = 0; globalThis.__property_iterator_proxy_get_368 = 0; " ++
            "new Proxy({ pure: 81 }, { ownKeys(t) { __property_iterator_proxy_own_368++; return Reflect.ownKeys(t); }, " ++
            "getOwnPropertyDescriptor(t, k) { __property_iterator_proxy_desc_368++; return Reflect.getOwnPropertyDescriptor(t, k); }, " ++
            "get(t, k, r) { __property_iterator_proxy_get_368++; return Reflect.get(t, k, r); } })",
    );
    var proxy_count: usize = 0;
    const proxy_iterator = Bun__JSPropertyIterator__create(context, proxy, &proxy_count, true, true) orelse
        return error.IteratorCreateFailed;
    defer Bun__JSPropertyIterator__deinit(proxy_iterator);
    try std.testing.expectEqual(@as(usize, 1), proxy_count);
    const own_calls = (try internal.evaluate("__property_iterator_proxy_own_368")).asNum();
    const desc_calls = (try internal.evaluate("__property_iterator_proxy_desc_368")).asNum();
    output = PrivateBunString.empty();
    try std.testing.expectEqual(EncodedValue.empty, Bun__JSPropertyIterator__getNameAndValueNonObservable(proxy_iterator, context, try Probe.cell(proxy), &output, 0));
    try std.testing.expectEqual(own_calls, (try internal.evaluate("__property_iterator_proxy_own_368")).asNum());
    try std.testing.expectEqual(desc_calls, (try internal.evaluate("__property_iterator_proxy_desc_368")).asNum());
    try std.testing.expectEqual(@as(f64, 0), (try internal.evaluate("__property_iterator_proxy_get_368")).asNum());
    try std.testing.expectEqual(EncodedValue.fromInt32(81), Bun__JSPropertyIterator__getNameAndValue(proxy_iterator, context, try Probe.cell(proxy), &output, 0));
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__property_iterator_proxy_get_368")).asNum());

    const typed = try Probe.encoded(
        internal,
        "(() => { const proto = Object.create(Uint8Array.prototype); proto['-1'] = 91; " ++
            "return Object.setPrototypeOf(new Uint8Array([1]), proto); })()",
    );
    var typed_count: usize = 0;
    const typed_iterator = Bun__JSPropertyIterator__create(context, typed, &typed_count, false, false) orelse
        return error.IteratorCreateFailed;
    defer Bun__JSPropertyIterator__deinit(typed_iterator);
    const negative_index = try Probe.indexOf(internal, typed_iterator, "-1");
    output = PrivateBunString.empty();
    try std.testing.expectEqual(EncodedValue.empty, Bun__JSPropertyIterator__getNameAndValueNonObservable(
        typed_iterator,
        context,
        try Probe.cell(typed),
        &output,
        negative_index,
    ));

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_object = privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("({ inherited: 1 })"));
    output = PrivateBunString.empty();
    try std.testing.expectEqual(EncodedValue.empty, Bun__JSPropertyIterator__getNameAndValue(full, context, try Probe.cell(foreign_object), &output, inherited_index));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);

    var invalid_name = PrivateBunString.empty();
    Bun__JSPropertyIterator__getName(own, &invalid_name, own_count);
    try std.testing.expectEqual(PrivateBunStringTag.dead, invalid_name.tag);

    // The native iterator owns a VM reference just like JSC's Ref<VM>: its
    // borrowed names remain valid after the last public global is released,
    // and deinit performs the eventual group teardown.
    const retained_context = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    const retained_internal = ctxForEvaluation(retained_context) orelse return error.ContextCreateFailed;
    const retained_target = privateEncodedFromValue(retained_internal, try retained_internal.evaluate("({ retained: 368 })"));
    var retained_count: usize = 0;
    const retained_iterator = Bun__JSPropertyIterator__create(retained_context, retained_target, &retained_count, true, true) orelse
        return error.IteratorCreateFailed;
    try std.testing.expectEqual(@as(usize, 1), retained_count);
    JSGlobalContextRelease(retained_context);
    var retained_name = PrivateBunString.dead();
    Bun__JSPropertyIterator__getName(retained_iterator, &retained_name, 0);
    try std.testing.expectEqual(PrivateBunStringTag.zig_string, retained_name.tag);
    Bun__JSPropertyIterator__deinit(retained_iterator);
}

test "private class and display names preserve metadata and observable tag rules" {
    const group_ref = JSContextGroupCreate() orelse return error.GroupCreateFailed;
    defer JSContextGroupRelease(group_ref);
    const context = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const sibling = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;
    const Probe = struct {
        fn encoded(context_: *Context, source: []const u8) !EncodedValue {
            return privateEncodedFromValue(context_, try context_.evaluate(source));
        }

        fn zigName(context_: *Context, global: JSContextRef, value_encoded: EncodedValue, class_name: bool) ![]const u8 {
            var output = PrivateZigString{ .tagged_ptr = 0x225, .len = 225 };
            if (class_name)
                JSC__JSValue__getClassName(value_encoded, global, &output)
            else
                JSC__JSValue__getNameProperty(value_encoded, global, &output);
            const result = try privateZigStringValue(context_, &output);
            return result.asStr();
        }

        fn bunName(context_: *Context, global: JSContextRef, value_encoded: EncodedValue) ![]const u8 {
            var output = PrivateBunString.dead();
            JSC__JSValue__getName(value_encoded, global, &output);
            defer if (output.tag == .wtf_string_impl) Bun__WTFStringImpl__deref(output.value.wtf_string_impl);
            const result = try privateBunStringValue(context_, &output, null);
            return context_.arena().dupe(u8, result.asStr());
        }
    };

    const class_info_cases = [_]struct { []const u8, []const u8 }{
        .{ "'value'", "String" },
        .{ "Symbol('value')", "Symbol" },
        .{ "1n", "BigInt" },
        .{ "({})", "Object" },
        .{ "[]", "Array" },
        .{ "new Uint16Array(1)", "Uint16Array" },
        .{ "new DataView(new ArrayBuffer(1))", "DataView" },
        .{ "new Map()", "Map" },
        .{ "new WeakSet()", "WeakSet" },
        .{ "new Date(0)", "Date" },
        .{ "/x/", "RegExp" },
        .{ "Promise.resolve(1)", "Promise" },
        .{ "(function named() {})", "Function" },
    };
    for (class_info_cases) |case| {
        var pointer: [*:0]const u8 = "untouched";
        var length: usize = 225;
        try std.testing.expect(JSC__JSValue__getClassInfoName(try Probe.encoded(internal, case[0]), &pointer, &length));
        try std.testing.expectEqualStrings(case[1], pointer[0..length]);
    }
    var untouched_pointer: [*:0]const u8 = "untouched";
    var untouched_length: usize = 225;
    try std.testing.expect(!JSC__JSValue__getClassInfoName(EncodedValue.fromInt32(1), &untouched_pointer, &untouched_length));
    try std.testing.expectEqualStrings("untouched", std.mem.span(untouched_pointer));
    try std.testing.expectEqual(@as(usize, 225), untouched_length);

    try std.testing.expectEqualStrings("Tagged", try Probe.zigName(internal, context, try Probe.encoded(internal, "({ [Symbol.toStringTag]: 'Tagged' })"), false));
    try std.testing.expectEqualStrings("named", try Probe.zigName(internal, context, try Probe.encoded(internal, "(function named() {})"), false));
    try std.testing.expectEqualStrings("max", try Probe.zigName(internal, context, try Probe.encoded(internal, "Math.max"), false));
    try std.testing.expectEqualStrings("fallback", try Probe.zigName(internal, context, try Probe.encoded(internal, "(() => { function fallback() {} fallback[Symbol.toStringTag] = 1; return fallback; })()"), false));
    try std.testing.expectEqualStrings("", try Probe.zigName(internal, context, try Probe.encoded(internal, "({ name: 'spoofed' })"), false));

    const tagged_getter = try Probe.encoded(internal, "globalThis.__name_tag_gets_225 = 0; ({ get [Symbol.toStringTag]() { __name_tag_gets_225++; return 'GetterTag'; } })");
    try std.testing.expectEqualStrings("GetterTag", try Probe.zigName(internal, context, tagged_getter, false));
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__name_tag_gets_225")).asNum());

    try std.testing.expectEqualStrings("Array", try Probe.zigName(internal, context, try Probe.encoded(internal, "[]"), true));
    try std.testing.expectEqualStrings("Widget", try Probe.zigName(internal, context, try Probe.encoded(internal, "new (class Widget {})"), true));
    try std.testing.expectEqualStrings("named", try Probe.zigName(internal, context, try Probe.encoded(internal, "(function named() {})"), true));
    try std.testing.expectEqualStrings("DirectTag", try Probe.zigName(internal, context, try Probe.encoded(internal, "({ [Symbol.toStringTag]: 'DirectTag' })"), true));
    const pure_tag = try Probe.encoded(internal, "globalThis.__class_tag_gets_225 = 0; Object.defineProperty({}, Symbol.toStringTag, { get() { __class_tag_gets_225++; return 'Wrong'; } })");
    try std.testing.expectEqualStrings("Object", try Probe.zigName(internal, context, pure_tag, true));
    try std.testing.expectEqual(@as(f64, 0), (try internal.evaluate("__class_tag_gets_225")).asNum());

    try std.testing.expectEqualStrings("Shown", try Probe.bunName(internal, context, try Probe.encoded(internal, "(() => { function original() {} original.displayName = 'Shown'; return original; })()")));
    try std.testing.expectEqualStrings("名字😀", try Probe.bunName(internal, context, try Probe.encoded(internal, "({ [Symbol.toStringTag]: '名字😀' })")));
    try std.testing.expectEqualStrings("", try Probe.bunName(internal, context, try Probe.encoded(internal, "({ name: 'spoofed' })")));

    const shared_function = try Probe.encoded(internal, "(function sharedName() {})");
    try std.testing.expectEqualStrings("sharedName", try Probe.zigName(internal, sibling, shared_function, false));
    try std.testing.expectEqualStrings("sharedName", try Probe.bunName(internal, sibling, shared_function));

    var abrupt_output = PrivateZigString{ .tagged_ptr = 0x225, .len = 225 };
    JSC__JSValue__getNameProperty(try Probe.encoded(internal, "({ get [Symbol.toStringTag]() { throw 2251; } })"), context, &abrupt_output);
    try std.testing.expectEqual(@as(usize, 0x225), abrupt_output.tagged_ptr);
    try std.testing.expectEqual(@as(usize, 225), abrupt_output.len);
    var pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(2251), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));

    var abrupt_bun = PrivateBunString.dead();
    JSC__JSValue__getName(try Probe.encoded(internal, "({ get [Symbol.toStringTag]() { throw 2252; } })"), context, &abrupt_bun);
    try std.testing.expectEqual(PrivateBunStringTag.dead, abrupt_bun.tag);
    pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(2252), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    var foreign_output = PrivateZigString{ .tagged_ptr = 0x225, .len = 225 };
    JSC__JSValue__getClassName(privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("({})")), context, &foreign_output);
    try std.testing.expectEqual(@as(usize, 0x225), foreign_output.tagged_ptr);
    try std.testing.expectEqual(@as(usize, 225), foreign_output.len);
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);

    const blocked = try Probe.encoded(internal, "(function blocked() {})");
    var blocked_output = PrivateZigString{ .tagged_ptr = 0x225, .len = 225 };
    JSC__VM__throwError(JSC__JSGlobalObject__vm(context), context, EncodedValue.fromInt32(225));
    JSC__JSValue__getNameProperty(blocked, context, &blocked_output);
    try std.testing.expectEqual(@as(usize, 0x225), blocked_output.tagged_ptr);
    try std.testing.expectEqual(@as(usize, 225), blocked_output.len);
    pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(225), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));
}

test "private record construction preserves cardinality ownership and direct insertion" {
    const group_ref = JSContextGroupCreate() orelse return error.GroupCreateFailed;
    defer JSContextGroupRelease(group_ref);
    const context = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const sibling = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;
    const sibling_internal = ctxForEvaluation(sibling) orelse return error.ContextCreateFailed;
    const utf8_tag = @as(usize, 1) << 61;
    const utf16_tag = @as(usize, 1) << 63;

    const empty_encoded = JSC__JSValue__fromEntries(sibling, null, null, 0, false);
    const empty = privateValueFrom(sibling, empty_encoded) orelse return error.ValueInitFailed;
    var sibling_machine = sibling_internal.interpreter();
    try std.testing.expect(empty.isObject());
    try std.testing.expect(empty.asObj().protoAtomic() == sibling_machine.objectProto());
    try std.testing.expectEqual(@as(usize, 0), (try empty.asObj().ownKeys(sibling_internal.arena())).len);

    var later_key_bytes = [_]u8{ 'l', 'a', 't', 'e', 'r' };
    const numeric_key_bytes = "2";
    var unicode_key_units = [_]u16{ 0x540d, 0x5b57, 0xd83d, 0xde00 };
    const first_value_bytes = "first";
    var latin1_value_bytes = [_]u8{ 'c', 'a', 'f', 0xe9 };
    var last_value_bytes = [_]u8{ 'l', 'a', 's', 't' };
    const utf8_value_bytes = "值😀";
    var keys = [_]PrivateZigString{
        .{ .tagged_ptr = @intFromPtr(later_key_bytes[0..].ptr), .len = later_key_bytes.len },
        .{ .tagged_ptr = @intFromPtr(numeric_key_bytes.ptr), .len = numeric_key_bytes.len },
        .{ .tagged_ptr = @intFromPtr(later_key_bytes[0..].ptr), .len = later_key_bytes.len },
        .{ .tagged_ptr = @intFromPtr(unicode_key_units[0..].ptr) | utf16_tag, .len = unicode_key_units.len },
    };
    var entries = [_]PrivateZigString{
        .{ .tagged_ptr = @intFromPtr(first_value_bytes.ptr), .len = first_value_bytes.len },
        .{ .tagged_ptr = @intFromPtr(latin1_value_bytes[0..].ptr), .len = latin1_value_bytes.len },
        .{ .tagged_ptr = @intFromPtr(last_value_bytes[0..].ptr), .len = last_value_bytes.len },
        .{ .tagged_ptr = @intFromPtr(utf8_value_bytes.ptr) | utf8_tag, .len = utf8_value_bytes.len },
    };
    const entries_encoded = JSC__JSValue__fromEntries(sibling, keys[0..].ptr, entries[0..].ptr, keys.len, false);
    const entries_value = privateValueFrom(sibling, entries_encoded) orelse return error.ValueInitFailed;
    @memset(&later_key_bytes, 'x');
    @memset(&latin1_value_bytes, 'x');
    @memset(&last_value_bytes, 'x');
    @memset(&unicode_key_units, 0x78);
    try sibling_internal.global_object.setOwn(sibling_internal.arena(), sibling_internal.root_shape, "__record_entries_227", entries_value);
    try std.testing.expect((try sibling_internal.evaluate(
        "Object.getPrototypeOf(__record_entries_227) === Object.prototype && " ++
            "Object.keys(__record_entries_227).join(',') === '2,later,名字😀' && " ++
            "__record_entries_227.later === 'last' && __record_entries_227[2] === 'café' && " ++
            "__record_entries_227['名字😀'] === '值😀'",
    )).asBool());

    var clone_key_bytes = [_]u8{ 'o', 'w', 'n', 'e', 'd' };
    var clone_value_units = [_]u16{ 's', 'a', 'f', 'e', 0xd83d, 0xde00 };
    var clone_keys = [_]PrivateZigString{.{ .tagged_ptr = @intFromPtr(clone_key_bytes[0..].ptr), .len = clone_key_bytes.len }};
    var clone_values = [_]PrivateZigString{.{ .tagged_ptr = @intFromPtr(clone_value_units[0..].ptr) | utf16_tag, .len = clone_value_units.len }};
    const cloned_encoded = JSC__JSValue__fromEntries(context, clone_keys[0..].ptr, clone_values[0..].ptr, 1, true);
    const cloned = privateValueFrom(context, cloned_encoded) orelse return error.ValueInitFailed;
    @memset(&clone_key_bytes, 'x');
    @memset(&clone_value_units, 0x78);
    try std.testing.expectEqualStrings("safe😀", cloned.asObj().getOwn("owned").?.asStr());

    const target = try internal.evaluate(
        "globalThis.__record_hits_227 = 0; " ++
            "globalThis.__record_target_227 = Object.create({ set many(value) { __record_hits_227++; } }); " ++
            "Object.defineProperty(__record_target_227, 'replace', { get() { return 'old'; }, configurable: true }); " ++
            "__record_target_227",
    );
    const target_encoded = privateEncodedFromValue(internal, target);
    const zero_key_bytes = "zero";
    const one_key_bytes = "one";
    const many_key_bytes = "many";
    const replace_key_bytes = "replace";
    const zero_key = PrivateZigString{ .tagged_ptr = @intFromPtr(zero_key_bytes.ptr), .len = zero_key_bytes.len };
    const one_key = PrivateZigString{ .tagged_ptr = @intFromPtr(one_key_bytes.ptr), .len = one_key_bytes.len };
    const many_key = PrivateZigString{ .tagged_ptr = @intFromPtr(many_key_bytes.ptr), .len = many_key_bytes.len };
    const replace_key = PrivateZigString{ .tagged_ptr = @intFromPtr(replace_key_bytes.ptr), .len = replace_key_bytes.len };
    var one_values = [_]PrivateZigString{.{ .tagged_ptr = @intFromPtr(utf8_value_bytes.ptr) | utf8_tag, .len = utf8_value_bytes.len }};
    const alpha_bytes = "alpha";
    var many_values = [_]PrivateZigString{
        .{ .tagged_ptr = @intFromPtr(alpha_bytes.ptr), .len = alpha_bytes.len },
        .{ .tagged_ptr = @intFromPtr(clone_value_units[0..].ptr) | utf16_tag, .len = 4 },
    };
    // Restore the four UTF-16 code units used by the many-value call after the
    // ownership test deliberately overwrote the original caller buffer.
    clone_value_units[0] = 'b';
    clone_value_units[1] = 'e';
    clone_value_units[2] = 't';
    clone_value_units[3] = 'a';
    JSC__JSValue__putRecord(target_encoded, context, &zero_key, null, 0);
    JSC__JSValue__putRecord(target_encoded, context, &one_key, one_values[0..].ptr, 1);
    JSC__JSValue__putRecord(target_encoded, context, &many_key, many_values[0..].ptr, many_values.len);
    JSC__JSValue__putRecord(target_encoded, context, &replace_key, one_values[0..].ptr, 1);
    try std.testing.expect((try internal.evaluate(
        "__record_hits_227 === 0 && Array.isArray(__record_target_227.zero) && __record_target_227.zero.length === 0 && " ++
            "__record_target_227.one === '值😀' && Array.isArray(__record_target_227.many) && " ++
            "__record_target_227.many.join(',') === 'alpha,beta' && __record_target_227.replace === '值😀' && " ++
            "['zero','one','many','replace'].every(key => { const d = Object.getOwnPropertyDescriptor(__record_target_227, key); return d.writable && d.enumerable && d.configurable; })",
    )).asBool());

    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__fromEntries(context, null, null, 1, false));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__fromEntries(context, keys[0..].ptr, entries[0..].ptr, @as(usize, std.math.maxInt(u32)) + 1, false));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);
    JSC__JSValue__putRecord(target_encoded, context, null, null, 0);
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_target = privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("({})"));
    JSC__JSValue__putRecord(foreign_target, context, &one_key, one_values[0..].ptr, 1);
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);

    const blocked_key_bytes = "blocked";
    const blocked_key = PrivateZigString{ .tagged_ptr = @intFromPtr(blocked_key_bytes.ptr), .len = blocked_key_bytes.len };
    JSC__VM__throwError(JSC__JSGlobalObject__vm(context), context, EncodedValue.fromInt32(227));
    JSC__JSValue__putRecord(target_encoded, context, &blocked_key, one_values[0..].ptr, 1);
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__fromEntries(context, clone_keys[0..].ptr, clone_values[0..].ptr, 1, true));
    const pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(227), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));
    try std.testing.expect(target.asObj().getOwn("blocked") == null);
}

test "private JSON stringification preserves normal and undefined-space semantics" {
    const group_ref = JSContextGroupCreate() orelse return error.GroupCreateFailed;
    defer JSContextGroupRelease(group_ref);
    const context = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const sibling = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;
    const Probe = struct {
        fn encoded(context_: *Context, source: []const u8) !EncodedValue {
            return privateEncodedFromValue(context_, try context_.evaluate(source));
        }

        fn run(context_: *Context, global: JSContextRef, value_encoded: EncodedValue, indent: ?u32) ![]const u8 {
            var output = PrivateBunString.dead();
            if (indent) |width|
