    try std.testing.expectEqual(target, projected_target);
    try std.testing.expectEqual(handler, projected_handler);
    try std.testing.expectEqual(@as(f64, 0), (try internal.evaluate("__proxy_traps_233")).asNum());
    try std.testing.expect(value.strictEquals(privateValueFrom(sibling, projected_target) orelse return error.ValueInitFailed, try internal.evaluate("__proxy_target_233")));

    const revoked = privateEncodedFromValue(internal, try internal.evaluate("(() => { const pair = Proxy.revocable({}, {}); pair.revoke(); return pair.proxy; })()"));
    try std.testing.expectEqual(EncodedValue.null, Bun__ProxyObject__getInternalField(revoked, .target));
    try std.testing.expectEqual(EncodedValue.null, Bun__ProxyObject__getInternalField(revoked, .handler));
    try std.testing.expectEqual(EncodedValue.empty, Bun__ProxyObject__getInternalField(EncodedValue.fromInt32(233), .target));
    try std.testing.expectEqual(EncodedValue.empty, Bun__ProxyObject__getInternalField(target, .target));
    try std.testing.expectEqual(EncodedValue.empty, Bun__ProxyObject__getInternalField(proxy, @enumFromInt(233)));

    JSC__VM__throwError(JSC__JSGlobalObject__vm(context), context, EncodedValue.fromInt32(233));
    try std.testing.expectEqual(target, Bun__ProxyObject__getInternalField(proxy, .target));
    const pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(233), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_proxy = privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("globalThis.__foreign_target_233 = {}; new Proxy(__foreign_target_233, {})"));
    const foreign_target = Bun__ProxyObject__getInternalField(foreign_proxy, .target);
    try std.testing.expect(value.strictEquals(privateValueFrom(foreign, foreign_target) orelse return error.ValueInitFailed, try foreign_internal.evaluate("__foreign_target_233")));
    try std.testing.expect(privateValueFrom(context, foreign_target) == null);
}

test "private deep equality preserves pinned structural semantics and boundaries" {
    const group_ref = JSContextGroupCreate() orelse return error.GroupCreateFailed;
    defer JSContextGroupRelease(group_ref);
    const context = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const sibling = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;

    const Probe = struct {
        fn encoded(context_: *Context, source: []const u8) !EncodedValue {
            return privateEncodedFromValue(context_, try context_.evaluate(source));
        }

        fn expectPair(
            context_: *Context,
            global: JSContextRef,
            left_source: []const u8,
            right_source: []const u8,
            loose_expected: bool,
            strict_expected: bool,
        ) !void {
            const left = try encoded(context_, left_source);
            const right = try encoded(context_, right_source);
            try std.testing.expectEqual(loose_expected, JSC__JSValue__deepEquals(left, right, global));
            try std.testing.expectEqual(strict_expected, JSC__JSValue__strictDeepEquals(left, right, global));
        }
    };

    // SameValue is the primitive fast path in both modes.
    try Probe.expectPair(internal, context, "NaN", "NaN", true, true);
    try Probe.expectPair(internal, context, "+0", "-0", false, false);
    try Probe.expectPair(internal, context, "({ a: 1, b: { c: 2 } })", "({ b: { c: 2 }, a: 1 })", true, true);
    try Probe.expectPair(internal, context, "({ missing: undefined })", "({})", true, false);
    try Probe.expectPair(internal, context, "new (class Widget { constructor() { this.x = 1; } })", "({ x: 1 })", true, false);
    try Probe.expectPair(internal, context, "Object.create(null)", "({})", true, true);
    try Probe.expectPair(internal, context, "new String('zig-js')", "new String('zig-js')", true, true);
    try Probe.expectPair(internal, context, "new (class Wrapped extends String {})('zig-js')", "new String('zig-js')", false, false);
    try Probe.expectPair(internal, context, "(function named() {})", "(function named() {})", false, false);

    // Arrays use direct, non-accessor indexed storage, distinguish holes only
    // in strict mode, ignore enumerable string extras, and compare Symbols.
    try Probe.expectPair(internal, context, "[, 1]", "[undefined, 1]", true, false);
    try Probe.expectPair(internal, context, "[1]", "[1, undefined]", true, false);
    try Probe.expectPair(internal, context, "(() => { const a = [1]; a.extra = 1; return a; })()", "(() => { const a = [1]; a.extra = 2; return a; })()", true, true);
    try Probe.expectPair(
        internal,
        context,
        "(() => { const a = [1]; a[Symbol.for('deep')] = { x: 1 }; return a; })()",
        "(() => { const a = [1]; a[Symbol.for('deep')] = { x: 2 }; return a; })()",
        false,
        false,
    );
    try Probe.expectPair(
        internal,
        context,
        "(() => { const a = []; Object.defineProperty(a, '0', { get() { throw 2300; }, enumerable: true }); return a; })()",
        "[,]",
        true,
        true,
    );
    try Probe.expectPair(internal, context, "new Proxy([1], {})", "({ 0: 1 })", false, false);
    try Probe.expectPair(internal, context, "new Proxy([1], {})", "[1]", true, true);

    // Active pair tracking terminates equal cycles and rejects incompatible
    // cyclic correspondence without imposing global alias-identity rules.
    try Probe.expectPair(internal, context, "(() => { const a = { n: 1 }; a.self = a; return a; })()", "(() => { const a = { n: 1 }; a.self = a; return a; })()", true, true);
    try Probe.expectPair(
        internal,
        context,
        "(() => { const a = {}; a.self = a; return a; })()",
        "(() => { const a = {}; const b = {}; a.self = b; b.self = b; return a; })()",
        false,
        false,
    );

    try Probe.expectPair(internal, context, "new Date(230)", "new Date(230)", true, true);
    try Probe.expectPair(internal, context, "new Date(NaN)", "new Date(NaN)", false, false);
    try Probe.expectPair(internal, context, "/deep/giu", "/deep/giu", true, true);
    try Probe.expectPair(internal, context, "/deep/g", "/deep/i", false, false);
    try Probe.expectPair(internal, context, "new Error('boom', { cause: { code: 230 } })", "new Error('boom', { cause: { code: 230 } })", true, true);
    try Probe.expectPair(internal, context, "new Error('boom')", "new Error('boom', { cause: undefined })", true, false);
    try Probe.expectPair(internal, context, "(() => { const e = new TypeError('boom'); e.name = 'Same'; return e; })()", "(() => { const e = new Error('boom'); e.name = 'Same'; return e; })()", false, false);

    try Probe.expectPair(
        internal,
        context,
        "new Set([{ x: 1 }, { y: 2 }])",
        "new Set([{ y: 2 }, { x: 1 }])",
        true,
        true,
    );
    try Probe.expectPair(
        internal,
        context,
        "new Map([[{ x: 1 }, { value: 2 }], ['direct', 3]])",
        "new Map([['direct', 3], [{ x: 1 }, { value: 2 }]])",
        true,
        true,
    );
    try Probe.expectPair(internal, context, "new Uint8Array([1, 2, 3]).buffer", "new Uint8Array([1, 2, 3]).buffer", true, true);
    try Probe.expectPair(internal, context, "new Uint8Array([1, 2, 3]).buffer", "new Uint8Array([1, 2, 4]).buffer", false, false);
    try Probe.expectPair(internal, context, "new Float64Array([+0])", "new Float64Array([-0])", true, false);
    try Probe.expectPair(internal, context, "new Float32Array([NaN])", "new Float32Array([NaN])", false, true);
    try Probe.expectPair(internal, context, "new Uint16Array([1, 2])", "new Uint8Array([1, 2])", false, false);
    // The pinned switch has no DataView case; distinct views therefore use the
    // ordinary class/property path and do not compare backing bytes.
    try Probe.expectPair(internal, context, "new DataView(new Uint8Array([1]).buffer)", "new DataView(new Uint8Array([2]).buffer)", true, true);

    const proxy = try Probe.encoded(
        internal,
        "globalThis.__deep_own_230 = 0; globalThis.__deep_desc_230 = 0; globalThis.__deep_get_230 = 0; " ++
            "new Proxy({ value: { ok: true } }, { " ++
            "ownKeys(target) { __deep_own_230++; return Reflect.ownKeys(target); }, " ++
            "getOwnPropertyDescriptor(target, key) { __deep_desc_230++; return Reflect.getOwnPropertyDescriptor(target, key); }, " ++
            "get(target, key, receiver) { __deep_get_230++; return Reflect.get(target, key, receiver); } })",
    );
    const plain = try Probe.encoded(internal, "({ value: { ok: true } })");
    try std.testing.expect(JSC__JSValue__deepEquals(proxy, plain, context));
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__deep_own_230")).asNum());
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__deep_desc_230")).asNum());
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__deep_get_230")).asNum());

    const throwing = try Probe.encoded(internal, "({ get value() { throw 2301; } })");
    try std.testing.expect(!JSC__JSValue__deepEquals(throwing, plain, context));
    var pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(2301), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));

    const shared_left = try Probe.encoded(internal, "(() => { const a = { sibling: true }; a.self = a; return a; })()");
    const shared_right = try Probe.encoded(internal, "(() => { const a = { sibling: true }; a.self = a; return a; })()");
    try std.testing.expect(JSC__JSValue__strictDeepEquals(shared_left, shared_right, sibling));

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_value = privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("({ foreign: true })"));
    try std.testing.expect(!JSC__JSValue__deepEquals(foreign_value, plain, context));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);

    const blocked_left = try Probe.encoded(internal, "globalThis.__deep_blocked_230 = 0; ({ get value() { __deep_blocked_230++; return 1; } })");
    JSC__VM__throwError(JSC__JSGlobalObject__vm(context), context, EncodedValue.fromInt32(230));
    try std.testing.expect(!JSC__JSValue__deepEquals(blocked_left, plain, context));
    pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(230), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));
    try std.testing.expectEqual(@as(f64, 0), (try internal.evaluate("__deep_blocked_230")).asNum());

    const deep_left = try Probe.encoded(internal, "(() => { let root = {}, cursor = root; for (let i = 0; i < 20000; i++) cursor = cursor.next = {}; return root; })()");
    const deep_right = try Probe.encoded(internal, "(() => { let root = {}, cursor = root; for (let i = 0; i < 20000; i++) cursor = cursor.next = {}; return root; })()");
    try std.testing.expect(!JSC__JSValue__deepEquals(deep_left, deep_right, context));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);
}

test "private Jest deep matching preserves asymmetric and subset semantics" {
    const group_ref = JSContextGroupCreate() orelse return error.GroupCreateFailed;
    defer JSContextGroupRelease(group_ref);
    const context = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const sibling = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;

    const Probe = struct {
        fn encoded(context_: *Context, source: []const u8) !EncodedValue {
            return privateEncodedFromValue(context_, try context_.evaluate(source));
        }

        fn expectJest(context_: *Context, global: JSContextRef, value_source: []const u8, matcher_source: []const u8, expected: bool) !void {
            const actual = try encoded(context_, value_source);
            const matcher = try encoded(context_, matcher_source);
            try std.testing.expectEqual(expected, JSC__JSValue__jestDeepEquals(actual, matcher, global));
            try std.testing.expectEqual(expected, JSC__JSValue__jestStrictDeepEquals(actual, matcher, global));
            try std.testing.expectEqual(expected, JSC__JSValue__jestDeepEquals(matcher, actual, global));
        }
    };

    const anything = "({ __zig_js_asymmetric_matcher__: 'anything' })";
    try Probe.expectJest(internal, context, "0", anything, true);
    try Probe.expectJest(internal, context, "null", anything, false);
    try Probe.expectJest(internal, context, "null", "({ __zig_js_asymmetric_matcher__: 'anything', inverse: true })", true);
    // Non-Jest equality never inspects or dispatches the matcher protocol.
    try std.testing.expect(!JSC__JSValue__deepEquals(try Probe.encoded(internal, "0"), try Probe.encoded(internal, anything), context));

    for ([_]struct { []const u8, []const u8, bool }{
        .{ "new Number(1)", "Number", true },
        .{ "new Boolean(false)", "Boolean", true },
        .{ "'value'", "String", true },
        .{ "1n", "BigInt", true },
        .{ "Symbol('value')", "Symbol", true },
        .{ "Promise.resolve(1)", "Promise", true },
        .{ "new Proxy([], {})", "Array", true },
        .{ "(function(){})", "Object", true },
        .{ "1", "String", false },
    }) |case| {
        const matcher_source = try std.fmt.allocPrint(internal.arena(), "({{ __zig_js_asymmetric_matcher__: 'any', constructorValue: {s} }})", .{case[1]});
        try Probe.expectJest(internal, context, case[0], matcher_source, case[2]);
    }
    try Probe.expectJest(
        internal,
        context,
        "new (class Child {})",
        "(() => { class Child {} return { __zig_js_asymmetric_matcher__: 'any', constructorValue: Child }; })()",
        false,
    );
    const shared_class_pair = try Probe.encoded(internal, "(() => { class Shared {}; return [new Shared(), { __zig_js_asymmetric_matcher__: 'any', constructorValue: Shared }]; })()");
    const shared_class_object = privateValueFrom(context, shared_class_pair) orelse return error.ValueInitFailed;
    const shared_class_value = shared_class_object.asObj().elementAt(0) orelse return error.ValueInitFailed;
    const shared_class_matcher = shared_class_object.asObj().elementAt(1) orelse return error.ValueInitFailed;
    try std.testing.expect(JSC__JSValue__jestDeepEquals(privateEncodedFromValue(internal, shared_class_value), privateEncodedFromValue(internal, shared_class_matcher), context));

    try Probe.expectJest(internal, context, "'a needle here'", "({ __zig_js_asymmetric_matcher__: 'string_containing', sample: 'needle' })", true);
    try Probe.expectJest(internal, context, "'abc-230'", "({ __zig_js_asymmetric_matcher__: 'string_matching', sample: /[a-z]+-\\d+/ })", true);
    try Probe.expectJest(
        internal,
        context,
        "[{ id: 1 }, 'extra', { id: 2 }]",
        "({ __zig_js_asymmetric_matcher__: 'array_containing', sample: [{ id: 2 }, { __zig_js_asymmetric_matcher__: 'anything' }] })",
        true,
    );
    try Probe.expectJest(
        internal,
        context,
        "({ nested: { exact: true, extra: true } })",
        "({ __zig_js_asymmetric_matcher__: 'object_containing', sample: { nested: { exact: true } } })",
        false,
    );
    try Probe.expectJest(
        internal,
        context,
        "({ nested: { exact: true, extra: true } })",
        "({ __zig_js_asymmetric_matcher__: 'object_containing', sample: { nested: { __zig_js_asymmetric_matcher__: 'object_containing', sample: { exact: true } } } })",
        true,
    );
    try Probe.expectJest(internal, context, "2.006", "({ __zig_js_asymmetric_matcher__: 'close_to', sample: 2, precision: 2 })", false);
    try Probe.expectJest(internal, context, "2.004", "({ __zig_js_asymmetric_matcher__: 'close_to', sample: 2, precision: 2 })", true);
    try Probe.expectJest(internal, context, "Infinity", "({ __zig_js_asymmetric_matcher__: 'close_to', sample: Infinity })", true);
    try Probe.expectJest(internal, context, "'2'", "({ __zig_js_asymmetric_matcher__: 'close_to', sample: 2, inverse: true })", false);

    const standard_custom = "({ $$typeof: Symbol.for('jest.asymmetricMatcher'), asymmetricMatch(value) { return value === 231; } })";
    try Probe.expectJest(internal, context, "231", standard_custom, true);
    try Probe.expectJest(internal, context, "230", standard_custom, false);
    try Probe.expectJest(internal, context, "Promise.resolve(231)", "({ __zig_js_asymmetric_matcher__: 'custom', promise: 'resolves', asymmetricMatch(value) { return value === 231; } })", true);
    try Probe.expectJest(internal, context, "Promise.reject(231)", "({ __zig_js_asymmetric_matcher__: 'custom', promise: 'rejects', asymmetricMatch(value) { return value === 231; } })", true);
    try Probe.expectJest(internal, context, "Promise.resolve(231)", "({ __zig_js_asymmetric_matcher__: 'anything', promise: 'rejects' })", false);

    try std.testing.expect(JSC__JSValue__jestDeepMatch(
        try Probe.encoded(internal, "({ own: 1, nested: { a: 2, b: 3 }, [Symbol.for('subset')]: 4 })"),
        try Probe.encoded(internal, "({ nested: { a: 2 }, [Symbol.for('subset')]: 4 })"),
        context,
        false,
    ));
    try std.testing.expect(JSC__JSValue__jestDeepMatch(
        try Probe.encoded(internal, "Object.create({ inherited: { value: 231 } })"),
        try Probe.encoded(internal, "({ inherited: { value: 231 } })"),
        context,
        false,
    ));
    try std.testing.expect(!JSC__JSValue__jestDeepMatch(
        try Probe.encoded(internal, "[1, 2]"),
        try Probe.encoded(internal, "[1]"),
        context,
        false,
    ));
    try std.testing.expect(JSC__JSValue__jestDeepMatch(
        try Probe.encoded(internal, "(() => { const a = { value: 1 }; a.self = a; return a; })()"),
        try Probe.encoded(internal, "(() => { const a = { value: 1 }; a.self = a; return a; })()"),
        context,
        false,
    ));

    const replace_target = try Probe.encoded(internal, "globalThis.__jest_replace_target_231 = { value: 231 }; __jest_replace_target_231");
    const replace_subset = try Probe.encoded(internal, "globalThis.__jest_replace_matcher_231 = { __zig_js_asymmetric_matcher__: 'anything' }; ({ value: __jest_replace_matcher_231 })");
    try std.testing.expect(JSC__JSValue__jestDeepMatch(replace_target, replace_subset, context, true));
    try std.testing.expect((try internal.evaluate("__jest_replace_target_231.value === __jest_replace_matcher_231")).asBool());
    const accessor_target = try Probe.encoded(
        internal,
        "globalThis.__jest_accessor_gets_231 = 0; globalThis.__jest_accessor_target_231 = {}; " ++
            "Object.defineProperty(__jest_accessor_target_231, 'value', { enumerable: true, configurable: true, get() { __jest_accessor_gets_231++; return 231; } }); __jest_accessor_target_231",
    );
    try std.testing.expect(JSC__JSValue__jestDeepMatch(accessor_target, replace_subset, context, true));
    try std.testing.expect((try internal.evaluate("__jest_accessor_gets_231 === 1 && Object.getOwnPropertyDescriptor(__jest_accessor_target_231, 'value').value === __jest_replace_matcher_231")).asBool());
    const reverse_target = try Probe.encoded(internal, "globalThis.__jest_reverse_matcher_231 = { __zig_js_asymmetric_matcher__: 'anything' }; ({ value: __jest_reverse_matcher_231 })");
    const reverse_subset = try Probe.encoded(internal, "globalThis.__jest_reverse_subset_231 = { value: 231 }; __jest_reverse_subset_231");
    try std.testing.expect(JSC__JSValue__jestDeepMatch(reverse_target, reverse_subset, context, true));
    try std.testing.expect((try internal.evaluate("__jest_reverse_subset_231.value === __jest_reverse_matcher_231")).asBool());

    const observable_target = try Probe.encoded(
        internal,
        "globalThis.__jest_gets_231 = 0; globalThis.__jest_target_231 = new Proxy({ value: 231 }, { get(target, key, receiver) { __jest_gets_231++; return Reflect.get(target, key, receiver); } }); __jest_target_231",
    );
    try std.testing.expect(JSC__JSValue__jestDeepMatch(observable_target, try Probe.encoded(internal, "({ value: 231 })"), context, false));
    try std.testing.expectEqual(@as(f64, 1), (try internal.evaluate("__jest_gets_231")).asNum());
    const throwing_matcher = try Probe.encoded(internal, "({ __zig_js_asymmetric_matcher__: 'custom', asymmetricMatch() { throw 2311; } })");
    try std.testing.expect(!JSC__JSValue__jestDeepEquals(EncodedValue.fromInt32(231), throwing_matcher, context));
    var pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(2311), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));

    const sibling_target = try Probe.encoded(internal, "({ sibling: 231 })");
    const sibling_subset = try Probe.encoded(internal, "({ sibling: { __zig_js_asymmetric_matcher__: 'any', constructorValue: Number } })");
    try std.testing.expect(JSC__JSValue__jestDeepMatch(sibling_target, sibling_subset, sibling, false));

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_matcher = privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("({ __zig_js_asymmetric_matcher__: 'anything' })"));
    try std.testing.expect(!JSC__JSValue__jestDeepEquals(EncodedValue.fromInt32(231), foreign_matcher, context));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);

    const blocked_matcher = try Probe.encoded(internal, "globalThis.__jest_blocked_231 = 0; ({ __zig_js_asymmetric_matcher__: 'custom', asymmetricMatch() { __jest_blocked_231++; return true; } })");
    JSC__VM__throwError(JSC__JSGlobalObject__vm(context), context, EncodedValue.fromInt32(231));
    try std.testing.expect(!JSC__JSValue__jestDeepEquals(EncodedValue.fromInt32(231), blocked_matcher, context));
    pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(231), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));
    try std.testing.expectEqual(@as(f64, 0), (try internal.evaluate("__jest_blocked_231")).asNum());
}

test "private VM entry-state query tracks nested and sibling interpreters" {
    const group_ref = JSContextGroupCreate() orelse return error.GroupCreateFailed;
    defer JSContextGroupRelease(group_ref);
    const first = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(first);
    const sibling = JSGlobalContextCreateInGroup(group_ref, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    const first_context = ctxForEvaluation(first) orelse return error.ContextCreateFailed;
    const sibling_context = ctxForEvaluation(sibling) orelse return error.ContextCreateFailed;
    const vm_ref = JSC__JSGlobalObject__vm(first);

    try std.testing.expect(!JSC__VM__isEntered(null));
    try std.testing.expect(!JSC__VM__isEntered(vm_ref));
    var first_machine = first_context.interpreter();
    var nested_machine = first_context.interpreter();
    var sibling_machine = sibling_context.interpreter();
    try first_context.pushActiveInterpreter(&first_machine);
    try std.testing.expect(JSC__VM__isEntered(vm_ref));
    try first_context.pushActiveInterpreter(&nested_machine);
    first_context.popActiveInterpreter(&first_machine);
    try std.testing.expect(JSC__VM__isEntered(vm_ref));
    first_context.popActiveInterpreter(&nested_machine);
    try std.testing.expect(!JSC__VM__isEntered(vm_ref));
    try sibling_context.pushActiveInterpreter(&sibling_machine);
    try std.testing.expect(JSC__VM__isEntered(vm_ref));
    sibling_context.popActiveInterpreter(&sibling_machine);

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    try std.testing.expect(!JSC__VM__isEntered(JSC__JSGlobalObject__vm(foreign)));
    JSC__VM__throwError(vm_ref, first, EncodedValue.fromInt32(221));
    try std.testing.expect(!JSC__VM__isEntered(vm_ref));
    const preserved = JSGlobalObject__tryTakeException(first);
    try std.testing.expectEqual(EncodedValue.fromInt32(221), JSC__Exception__asJSValue(@ptrFromInt(try preserved.asCellAddress())));
}

test "private rooted native value containers retain and release exact cells" {
    const Factory = struct {
        fn create() !*CContextGroup {
            const primary = try Context.createWith(std.testing.allocator, .{ .enable_gc = true });
            errdefer primary.destroy();
            const group = try gpa.create(CContextGroup);
            group.* = .{
                .owner_thread = std.Thread.getCurrentId(),
                .primary = primary,
                .atom_strings = strcell.InternTable.init(gpa),
            };
            primary.c_api_group = @ptrCast(group);
            primary.watchdog_check_flag = &group.need_watchdog_check;
            primary.watchdog_deadline_ns = &group.execution_deadline_ns;
            primary.initCApiRef();
            return group;
        }
    };
    const CallbackState = struct {
        global: JSContextRef,
        encoded: EncodedValue,
        foreign: EncodedValue,
        failed: bool = false,

        fn run(raw: ?*anyopaque, opaque_buffer: ?*anyopaque) callconv(.c) void {
            const state: *@This() = @ptrCast(@alignCast(raw.?));
            MarkedArgumentBuffer__append(opaque_buffer, EncodedValue.fromInt32(7));
            MarkedArgumentBuffer__append(opaque_buffer, state.encoded);
            MarkedArgumentBuffer__append(opaque_buffer, state.foreign);
            const buffer: *PrivateMarkedArgumentBuffer = @ptrCast(@alignCast(opaque_buffer.?));
            if (buffer.values.items.len != 2 or buffer.roots.items.len != 1 or
                buffer.group == null or buffer.group.?.primary.private_strong_roots.items.len != 1)
            {
                state.failed = true;
                return;
            }
            _ = JSC__VM__runGC(@ptrCast(buffer.group.?), true);
            if (!value.strictEquals(buffer.roots.items[0].value, privateValueFrom(state.global, state.encoded) orelse {
                state.failed = true;
                return;
            })) state.failed = true;
        }
    };

    const group = try Factory.create();
    defer if (group.release()) group.destroy();
    const foreign_group = try Factory.create();
    defer if (foreign_group.release()) foreign_group.destroy();
    const global: JSContextRef = @ptrCast(group.primary);
    const foreign_global: JSContextRef = @ptrCast(foreign_group.primary);

    const target = try group.primary.evaluate("({ issue: 212 })");
    const foreign_target = try foreign_group.primary.evaluate("({ foreign: true })");
    var state = CallbackState{
        .global = global,
        .encoded = privateEncodedFromValue(group.primary, target),
        .foreign = privateEncodedFromValue(foreign_group.primary, foreign_target),
    };
    MarkedArgumentBuffer__run(&state, CallbackState.run);
    try std.testing.expect(!state.failed);
    try std.testing.expectEqual(@as(usize, 0), group.primary.private_strong_roots.items.len);
    MarkedArgumentBuffer__run(null, null);
    MarkedArgumentBuffer__append(null, state.encoded);

    const first = privateEncodedFromValue(group.primary, try group.primary.evaluate("() => 'first'"));
    const second = privateEncodedFromValue(group.primary, try group.primary.evaluate("() => 'second'"));
    const last = privateEncodedFromValue(group.primary, try group.primary.evaluate("() => 'last'"));
    try std.testing.expectEqual(@as(u32, 0), JSCommonJSExtensions__appendFunction(global, first));
    try std.testing.expectEqual(@as(u32, 1), JSCommonJSExtensions__appendFunction(global, second));
    try std.testing.expectEqual(@as(u32, 2), JSCommonJSExtensions__appendFunction(global, last));
    try std.testing.expectEqual(@as(usize, 3), group.primary.private_commonjs_functions.items.len);
    try std.testing.expectEqual(@as(usize, 3), group.primary.private_strong_roots.items.len);

    JSCommonJSExtensions__setFunction(global, 1, second);
    try std.testing.expect(value.strictEquals(
        group.primary.private_commonjs_functions.items[1].value,
        privateValueFrom(global, second).?,
    ));
    JSCommonJSExtensions__setFunction(global, 99, first);
    JSCommonJSExtensions__setFunction(global, 1, state.foreign);
    try std.testing.expectEqual(@as(u32, 2), JSCommonJSExtensions__swapRemove(global, 0));
    try std.testing.expect(value.strictEquals(
        group.primary.private_commonjs_functions.items[0].value,
        privateValueFrom(global, last).?,
    ));
    try std.testing.expectEqual(@as(u32, 1), JSCommonJSExtensions__swapRemove(global, 1));
    try std.testing.expectEqual(@as(u32, 0), JSCommonJSExtensions__swapRemove(global, 0));
    try std.testing.expectEqual(@as(usize, 0), group.primary.private_commonjs_functions.items.len);
    try std.testing.expectEqual(@as(usize, 0), group.primary.private_strong_roots.items.len);

    try std.testing.expectEqual(@as(u32, 0), JSCommonJSExtensions__appendFunction(foreign_global, state.foreign));
    try std.testing.expectEqual(@as(usize, 1), foreign_group.primary.private_commonjs_functions.items.len);
    try std.testing.expectEqual(@as(usize, 0), group.primary.private_commonjs_functions.items.len);
    try std.testing.expectEqual(std.math.maxInt(u32), JSCommonJSExtensions__appendFunction(global, state.foreign));
    _ = JSCommonJSExtensions__swapRemove(foreign_global, 0);

    JSC__VM__throwError(JSC__JSGlobalObject__vm(global), global, EncodedValue.fromInt32(212));
    try std.testing.expectEqual(std.math.maxInt(u32), JSCommonJSExtensions__appendFunction(global, first));
    const preserved = JSGlobalObject__tryTakeException(global);
    const preserved_pointer: *anyopaque = @ptrFromInt(try preserved.asCellAddress());
    try std.testing.expectEqual(EncodedValue.fromInt32(212), JSC__Exception__asJSValue(preserved_pointer));
}

test "C-API: JSGarbageCollect honors JSValueProtect/Unprotect (GC on)" {
    // A GC-enabled context driven through the C-API (the default
    // JSGlobalContextCreate stays arena-backed; here we opt in directly).
    const ctx_obj = try Context.createWith(std.testing.allocator, .{ .enable_gc = true });
    defer ctx_obj.destroy();
    const ctx: JSContextRef = @ptrCast(ctx_obj);

    // Protect a JSValueRef to an object — protected handles are traced as GC
    // roots until matching JSValueUnprotect calls remove them.
    const mk = JSStringCreateWithUTF8CString("({ tag: 123 })") orelse return error.StringInitFailed;
    defer JSStringRelease(mk);
    const held = JSEvaluateScript(ctx, mk, null, null, 0, null) orelse return error.EvalFailed;
    try std.testing.expect(ZJSValueProtect(ctx, held));
    try std.testing.expect(ZJSValueProtect(ctx, held));

    // Produce a pile of unreferenced garbage.
    const junk = JSStringCreateWithUTF8CString("for (let i = 0; i < 500; i++) { ({ a: i, b: [i] }); } 0") orelse return error.StringInitFailed;
    defer JSStringRelease(junk);
    _ = JSEvaluateScript(ctx, junk, null, null, 0, null);

    const before = ctx_obj.gc.?.live_cells;
    JSGarbageCollect(ctx); // real precise collection
    const after = ctx_obj.gc.?.live_cells;
    try std.testing.expect(after < before); // garbage reclaimed

    // The held reference survived collection while protected and is still usable.
    const key = JSStringCreateWithUTF8CString("tag") orelse return error.StringInitFailed;
    defer JSStringRelease(key);
    const tag = JSObjectGetProperty(ctx, held, key, null) orelse return error.PropFailed;
    try std.testing.expectEqual(@as(f64, 123), JSValueToNumber(ctx, tag, null));

    const with_protection = ctx_obj.gc.?.live_cells;
    try std.testing.expect(ZJSValueUnprotect(ctx, held));
    JSGarbageCollect(ctx);
    try std.testing.expectEqual(with_protection, ctx_obj.gc.?.live_cells);
    try std.testing.expect(ZJSValueUnprotect(ctx, held));
    JSGarbageCollect(ctx);
    try std.testing.expect(ctx_obj.gc.?.live_cells < with_protection);
    try std.testing.expect(!ZJSValueUnprotect(ctx, held));
}

test "private counted JSValue protection discovers its VM and releases on balance" {
    const global = ZJSGlobalContextCreateGarbageCollected(false) orelse
        return error.ContextCreateFailed;
    defer JSGlobalContextRelease(global);
    const context = ctxForEvaluation(global) orelse return error.ContextCreateFailed;

    const held = try context.evaluate("({ marker: 367 })");
    const encoded = privateEncodedFromValue(context, held);
    try std.testing.expect(encoded != .empty);
    try std.testing.expectEqual(@as(usize, 0), context.c_api_handles.items.len);

    Bun__JSValue__protect(.empty);
    Bun__JSValue__protect(.deleted);
    Bun__JSValue__protect(.undefined);
    Bun__JSValue__protect(.null);
    Bun__JSValue__protect(.false);
    Bun__JSValue__protect(.true);
    Bun__JSValue__protect(EncodedValue.fromInt32(367));
    Bun__JSValue__protect(EncodedValue.fromDouble(36.7));
    Bun__JSValue__unprotect(.empty);
    try std.testing.expectEqual(@as(usize, 0), context.c_api_handles.items.len);

    Bun__JSValue__protect(encoded);
    Bun__JSValue__protect(encoded);
    try std.testing.expectEqual(@as(usize, 1), context.c_api_handles.items.len);
    try std.testing.expectEqual(@as(usize, 2), context.c_api_handles.items[0].count);
    try std.testing.expectEqual(
        @intFromPtr(privateBoxedFrom(encoded).?),
        @intFromPtr(context.c_api_handles.items[0].ref),
    );

    JSGarbageCollect(global);
    const marker_key = JSStringCreateWithUTF8CString("marker") orelse return error.StringInitFailed;
    defer JSStringRelease(marker_key);
    const survivor_ref = privateRefFromEncoded(global, encoded) orelse return error.ValueMissing;
    const marker = JSObjectGetProperty(global, survivor_ref, marker_key, null) orelse
        return error.PropertyMissing;
    try std.testing.expectEqual(@as(f64, 367), JSValueToNumber(global, marker, null));
    const protected_cells = context.gc.?.live_cells;

    Bun__JSValue__unprotect(encoded);
    try std.testing.expectEqual(@as(usize, 1), context.c_api_handles.items.len);
    try std.testing.expectEqual(@as(usize, 1), context.c_api_handles.items[0].count);
    JSGarbageCollect(global);
    try std.testing.expect(privateValueFrom(global, encoded) != null);

    Bun__JSValue__unprotect(encoded);
    try std.testing.expectEqual(@as(usize, 0), context.c_api_handles.items.len);
    JSGarbageCollect(global);
    try std.testing.expect(context.gc.?.live_cells < protected_cells);
    Bun__JSValue__unprotect(encoded);
    try std.testing.expectEqual(@as(usize, 0), context.c_api_handles.items.len);
}

test "C-API: JIT-enabled compaction fails closed in native callback then moves protected handle quiescently" {
    const State = struct {
        var calls: usize = 0;
        var status: ZJSGCCompactionStatus = .compacted;
        var moved_cells: usize = 1;
        var moved_bytes: usize = 1;

        fn compact(
            ctx: JSContextRef,
            _: JSObjectRef,
            _: JSObjectRef,
            _: usize,
            _: [*c]const JSValueRef,
            _: ExceptionRef,
        ) callconv(.c) JSValueRef {
            calls += 1;
            status = ZJSContextCompactGarbage(ctx, &moved_cells, &moved_bytes);
            return JSValueMakeBoolean(ctx, status == .unsupported and moved_cells == 0 and moved_bytes == 0);
        }
    };
    State.calls = 0;
    State.status = .compacted;
    State.moved_cells = 1;
    State.moved_bytes = 1;

    var invalid_cells: usize = 1;
    var invalid_bytes: usize = 1;
    try std.testing.expectEqual(
        ZJSGCCompactionStatus.unsupported,
        ZJSContextCompactGarbage(null, &invalid_cells, &invalid_bytes),
    );
    try std.testing.expectEqual(@as(usize, 0), invalid_cells);
    try std.testing.expectEqual(@as(usize, 0), invalid_bytes);
    try std.testing.expectEqual(ZJSGCCompactionStatus.out_of_memory, cCompactionStatus(.out_of_memory));

    const ctx = ZJSGlobalContextCreateGarbageCollected(true) orelse return error.JSCInitFailed;
    defer JSGlobalContextRelease(ctx);
    const context = ctxFrom(ctx) orelse return error.JSCInitFailed;
    const global = JSContextGetGlobalObject(ctx) orelse return error.GlobalObjectFailed;
    const callback_name = JSStringCreateWithUTF8CString("hostCompact") orelse return error.StringInitFailed;
    defer JSStringRelease(callback_name);
    const callback = JSObjectMakeFunctionWithCallback(ctx, callback_name, State.compact) orelse return error.FunctionCreateFailed;
    var exception: JSValueRef = null;
    JSObjectSetProperty(ctx, global, callback_name, callback, 0, &exception);
    try std.testing.expect(exception == null);

    const setup = JSStringCreateWithUTF8CString(
        \\globalThis.compactDiscard = [];
        \\for (let i = 0; i < 4096; i++)
        \\  compactDiscard.push({ dead: i, child: { value: i + 1 } });
        \\globalThis.compactSurvivor = { tag: 355, nested: { live: true } };
        \\compactDiscard = null;
        \\hostCompact();
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(setup);
    const callback_result = JSEvaluateScript(ctx, setup, null, null, 1, &exception) orelse return error.EvalFailed;
    try std.testing.expect(exception == null);
    try std.testing.expect(JSValueToBoolean(ctx, callback_result));
    try std.testing.expectEqual(@as(usize, 1), State.calls);
    try std.testing.expectEqual(ZJSGCCompactionStatus.unsupported, State.status);
    try std.testing.expectEqual(@as(usize, 0), State.moved_cells);
    try std.testing.expectEqual(@as(usize, 0), State.moved_bytes);
    try std.testing.expect(!context.gc_relocation_active.load(.acquire));

    const survivor_name = JSStringCreateWithUTF8CString("compactSurvivor") orelse return error.StringInitFailed;
    defer JSStringRelease(survivor_name);
    const survivor = JSObjectGetProperty(ctx, global, survivor_name, &exception) orelse return error.PropFailed;
    try std.testing.expect(exception == null);
    try std.testing.expect(ZJSValueProtect(ctx, survivor));
    defer std.debug.assert(ZJSValueUnprotect(ctx, survivor));
    const old_payload = valueFromContext(context, survivor).?.asObj();

    var moved_cells: usize = 0;
    var moved_bytes: usize = 0;
    try std.testing.expectEqual(
        ZJSGCCompactionStatus.compacted,
        ZJSContextCompactGarbage(ctx, &moved_cells, &moved_bytes),
    );
    try std.testing.expect(moved_cells > 0);
    try std.testing.expect(moved_bytes > 0);
    const new_payload = valueFromContext(context, survivor).?.asObj();
    try std.testing.expect(old_payload != new_payload);
    try std.testing.expectEqual(
        ZJSGCCompactionStatus.no_candidates,
        ZJSContextCompactGarbage(ctx, &moved_cells, &moved_bytes),
    );
    try std.testing.expectEqual(@as(usize, 0), moved_cells);
    try std.testing.expectEqual(@as(usize, 0), moved_bytes);
    const tag_name = JSStringCreateWithUTF8CString("tag") orelse return error.StringInitFailed;
    defer JSStringRelease(tag_name);
    const tag = JSObjectGetProperty(ctx, survivor, tag_name, &exception) orelse return error.PropFailed;
    try std.testing.expect(exception == null);
    try std.testing.expectEqual(@as(f64, 355), JSValueToNumber(ctx, tag, &exception));
    try std.testing.expect(exception == null);

    const oom_setup = JSStringCreateWithUTF8CString(
        \\globalThis.compactOomDiscard = [];
        \\for (let i = 0; i < 4096; i++)
        \\  compactOomDiscard.push({ dead: i, child: { value: i + 1 } });
        \\globalThis.compactOomTail = { still: 'live' };
        \\compactOomDiscard = null;
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(oom_setup);
    _ = JSEvaluateScript(ctx, oom_setup, null, null, 1, &exception) orelse return error.EvalFailed;
    try std.testing.expect(exception == null);
    // Grow all reusable mark scratch with its owning allocator before swapping
    // only the relocation-plan allocator to the deterministic failure source.
    context.collectGarbage();
    var no_scratch: [1]u8 = undefined;
    var fixed = std.heap.FixedBufferAllocator.init(&no_scratch);
    const saved_aux = context.gc.?.aux;
    context.gc.?.aux = fixed.allocator();
    moved_cells = 1;
    moved_bytes = 1;
    const oom_status = ZJSContextCompactGarbage(ctx, &moved_cells, &moved_bytes);
    context.gc.?.aux = saved_aux;
    try std.testing.expectEqual(ZJSGCCompactionStatus.out_of_memory, oom_status);
    try std.testing.expectEqual(@as(usize, 0), moved_cells);
    try std.testing.expectEqual(@as(usize, 0), moved_bytes);
    const tag_after_oom = JSObjectGetProperty(ctx, survivor, tag_name, &exception) orelse return error.PropFailed;
    try std.testing.expect(exception == null);
    try std.testing.expectEqual(@as(f64, 355), JSValueToNumber(ctx, tag_after_oom, &exception));
}

test "C-API: callback schedules protected compaction at the next baseline JIT checkpoint" {
    if (!jit.supported or builtin.cpu.arch != .aarch64) return error.SkipZigTest;

    const State = struct {
        var calls: usize = 0;
        var protected: JSValueRef = null;
        var old_payload: usize = 0;
        var direct_status: ZJSGCCompactionStatus = .compacted;
        var request_accepted: bool = false;

        fn schedule(
            ctx: JSContextRef,
            _: JSObjectRef,
            _: JSObjectRef,
            argument_count: usize,
            arguments: [*c]const JSValueRef,
            _: ExceptionRef,
        ) callconv(.c) JSValueRef {
            calls += 1;
            if (argument_count != 1 or arguments == null or arguments[0] == null)
                return JSValueMakeBoolean(ctx, false);
            const context = ctxFrom(ctx) orelse return JSValueMakeBoolean(ctx, false);
            protected = arguments[0];
            if (!ZJSValueProtect(ctx, protected)) return JSValueMakeBoolean(ctx, false);
            old_payload = @intFromPtr((valueFromContext(context, protected) orelse return JSValueMakeBoolean(ctx, false)).asObj());
            direct_status = ZJSContextCompactGarbage(ctx, null, null);
            request_accepted = ZJSContextRequestGarbageCompaction(ctx);
            return JSValueMakeBoolean(ctx, direct_status == .unsupported and request_accepted);
        }
    };
    State.calls = 0;
    State.protected = null;
    State.old_payload = 0;
    State.direct_status = .compacted;
    State.request_accepted = false;

    try std.testing.expect(!ZJSContextRequestGarbageCompaction(null));
    {
        const arena_ctx = JSGlobalContextCreate(null) orelse return error.JSCInitFailed;
        defer JSGlobalContextRelease(arena_ctx);
        try std.testing.expect(!ZJSContextRequestGarbageCompaction(arena_ctx));
    }

    const ctx = ZJSGlobalContextCreateGarbageCollected(true) orelse return error.JSCInitFailed;
    defer JSGlobalContextRelease(ctx);
    const context = ctxFrom(ctx) orelse return error.JSCInitFailed;
    const global = JSContextGetGlobalObject(ctx) orelse return error.GlobalObjectFailed;
    const callback_name = JSStringCreateWithUTF8CString("hostScheduleCompaction") orelse return error.StringInitFailed;
    defer JSStringRelease(callback_name);
    const callback = JSObjectMakeFunctionWithCallback(ctx, callback_name, State.schedule) orelse return error.FunctionCreateFailed;
    var exception: JSValueRef = null;
    JSObjectSetProperty(ctx, global, callback_name, callback, 0, &exception);
    try std.testing.expect(exception == null);

    const warm_source = JSStringCreateWithUTF8CString(
        \\function cScheduledSum(n) {
        \\  var total = 0;
        \\  var i = 0;
        \\  while (i < n) { total = total + i; i = i + 1; }
        \\  return total;
        \\}
        \\cScheduledSum(4096);
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(warm_source);
    const warm_result = JSEvaluateScript(ctx, warm_source, null, null, 1, &exception) orelse return error.EvalFailed;
    try std.testing.expect(exception == null);
    try std.testing.expectEqual(@as(f64, 8_386_560), JSValueToNumber(ctx, warm_result, &exception));
    const sum_name = JSStringCreateWithUTF8CString("cScheduledSum") orelse return error.StringInitFailed;
    defer JSStringRelease(sum_name);
    const sum_value = JSObjectGetProperty(ctx, global, sum_name, &exception) orelse return error.PropFailed;
    const sum_function: *interp.Function = @ptrCast(@alignCast((valueFromContext(context, sum_value) orelse return error.ValueFailed).asObj().jsFunction().?));
    try std.testing.expectEqual(jit.TierState.ready, sum_function.chunk.?.tier.loadState());

    const discard_source = JSStringCreateWithUTF8CString(
        \\globalThis.cScheduledDiscard = [];
        \\for (let i = 0; i < 4096; i++)
        \\  cScheduledDiscard.push({ dead: i, child: { value: i + 1 } });
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(discard_source);
    _ = JSEvaluateScript(ctx, discard_source, null, null, 1, &exception) orelse return error.EvalFailed;
    try std.testing.expect(exception == null);

    const precise_compactions_before = context.gc_moving_safepoint_compactions.load(.monotonic);
    const setup = JSStringCreateWithUTF8CString(
        \\cScheduledDiscard = null;
        \\globalThis.cScheduledSurvivor = { marker: 360 };
        \\hostScheduleCompaction(cScheduledSurvivor);
        \\cScheduledSum(20000);
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(setup);
    const result = JSEvaluateScript(ctx, setup, null, null, 1, &exception) orelse return error.EvalFailed;
    defer if (State.protected != null) std.debug.assert(ZJSValueUnprotect(ctx, State.protected));
    try std.testing.expect(exception == null);
    try std.testing.expectEqual(@as(f64, 199_990_000), JSValueToNumber(ctx, result, &exception));
    try std.testing.expect(exception == null);
    try std.testing.expectEqual(@as(usize, 1), State.calls);
    try std.testing.expectEqual(ZJSGCCompactionStatus.unsupported, State.direct_status);
    try std.testing.expect(State.request_accepted);
    try std.testing.expect(!context.gc_compaction_requested.load(.acquire));
    try std.testing.expectEqual(
        precise_compactions_before + 1,
        context.gc_moving_safepoint_compactions.load(.monotonic),
    );
    const protected = State.protected orelse return error.ProtectFailed;
    const current = valueFromContext(context, protected) orelse return error.ValueFailed;
    try std.testing.expect(State.old_payload != @intFromPtr(current.asObj()));
    const marker_name = JSStringCreateWithUTF8CString("marker") orelse return error.StringInitFailed;
    defer JSStringRelease(marker_name);
    const marker = JSObjectGetProperty(ctx, protected, marker_name, &exception) orelse return error.PropFailed;
    try std.testing.expect(exception == null);
    try std.testing.expectEqual(@as(f64, 360), JSValueToNumber(ctx, marker, &exception));
}

test "C-API: no-GIL parked peer defers scheduled compaction until post-join" {
    if (builtin.single_threaded or !jit.supported or builtin.cpu.arch != .aarch64)
        return error.SkipZigTest;

    const State = struct {
        var protected: JSValueRef = null;
        var old_payload: usize = 0;
        var compactions_before: u64 = 0;
        var schedule_calls: usize = 0;
        var confirm_calls: usize = 0;
        var direct_status: ZJSGCCompactionStatus = .compacted;
        var confirm_status: ZJSGCCompactionStatus = .compacted;

        fn schedule(
            ctx: JSContextRef,
            _: JSObjectRef,
            _: JSObjectRef,
            argument_count: usize,
            arguments: [*c]const JSValueRef,
            _: ExceptionRef,
        ) callconv(.c) JSValueRef {
            schedule_calls += 1;
            if (argument_count != 1 or arguments == null or arguments[0] == null)
                return JSValueMakeBoolean(ctx, false);
            const context = ctxFrom(ctx) orelse return JSValueMakeBoolean(ctx, false);
            protected = arguments[0];
            if (!ZJSValueProtect(ctx, protected)) return JSValueMakeBoolean(ctx, false);
            old_payload = @intFromPtr((valueFromContext(context, protected) orelse return JSValueMakeBoolean(ctx, false)).asObj());
            compactions_before = context.gc_moving_safepoint_compactions.load(.monotonic);
            direct_status = ZJSContextCompactGarbage(ctx, null, null);
            return JSValueMakeBoolean(
                ctx,
                direct_status == .unsupported and ZJSContextRequestGarbageCompaction(ctx),
            );
        }

        fn confirm(
            ctx: JSContextRef,
            _: JSObjectRef,
            _: JSObjectRef,
            _: usize,
            _: [*c]const JSValueRef,
            _: ExceptionRef,
        ) callconv(.c) JSValueRef {
            confirm_calls += 1;
            const context = ctxFrom(ctx) orelse return JSValueMakeBoolean(ctx, false);
            const pending = context.gc_compaction_requested.load(.acquire);
            const unchanged = context.gc_moving_safepoint_compactions.load(.monotonic) == compactions_before;
            const closed = !context.gc_relocation_active.load(.acquire);
            confirm_status = ZJSContextCompactGarbage(ctx, null, null);
            return JSValueMakeBoolean(ctx, pending and unchanged and closed and confirm_status == .unsupported);
        }
    };
    State.protected = null;
    State.old_payload = 0;
    State.compactions_before = 0;
    State.schedule_calls = 0;
    State.confirm_calls = 0;
    State.direct_status = .compacted;
    State.confirm_status = .compacted;

    const ctx = ZJSGlobalContextCreateThreaded(false) orelse return error.JSCInitFailed;
    defer JSGlobalContextRelease(ctx);
    const context = ctxFrom(ctx) orelse return error.JSCInitFailed;
    const global = JSContextGetGlobalObject(ctx) orelse return error.GlobalObjectFailed;
    var exception: JSValueRef = null;

    const schedule_name = JSStringCreateWithUTF8CString("hostScheduleNoGilCompaction") orelse return error.StringInitFailed;
    defer JSStringRelease(schedule_name);
    const schedule_callback = JSObjectMakeFunctionWithCallback(ctx, schedule_name, State.schedule) orelse return error.FunctionCreateFailed;
    JSObjectSetProperty(ctx, global, schedule_name, schedule_callback, 0, &exception);
    try std.testing.expect(exception == null);

    const confirm_name = JSStringCreateWithUTF8CString("hostConfirmNoGilCompaction") orelse return error.StringInitFailed;
    defer JSStringRelease(confirm_name);
    const confirm_callback = JSObjectMakeFunctionWithCallback(ctx, confirm_name, State.confirm) orelse return error.FunctionCreateFailed;
    JSObjectSetProperty(ctx, global, confirm_name, confirm_callback, 0, &exception);
    try std.testing.expect(exception == null);

    const warm_source = JSStringCreateWithUTF8CString(
        \\function noGilScheduledSum(n) {
        \\  var total = 0;
        \\  var i = 0;
        \\  while (i < n) { total = total + i; i = i + 1; }
        \\  return total;
        \\}
        \\noGilScheduledSum(4096);
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(warm_source);
    const warm_result = JSEvaluateScript(ctx, warm_source, null, null, 1, &exception) orelse return error.EvalFailed;
    try std.testing.expect(exception == null);
    try std.testing.expectEqual(@as(f64, 8_386_560), JSValueToNumber(ctx, warm_result, &exception));

    const source = JSStringCreateWithUTF8CString(
        \\globalThis.noGilCompactGate = { parked: 0, wake: 0 };
        \\globalThis.noGilCompactDiscard = [];
        \\for (let i = 0; i < 4096; i++)
        \\  noGilCompactDiscard.push({ dead: i, child: { value: i + 1 } });
        \\globalThis.noGilCompactSurvivor = { marker: 361 };
        \\globalThis.noGilCompactWorker = new Thread((gate) => {
        \\  Atomics.store(gate, "parked", 1);
        \\  Atomics.notify(gate, "parked");
        \\  Atomics.wait(gate, "wake", 0);
        \\  return "joined";
        \\}, noGilCompactGate);
        \\while (Atomics.load(noGilCompactGate, "parked") === 0) {}
        \\noGilCompactDiscard = null;
        \\if (!hostScheduleNoGilCompaction(noGilCompactSurvivor)) throw new Error("schedule");
        \\if (noGilScheduledSum(20000) !== 199990000) throw new Error("native result");
        \\if (!hostConfirmNoGilCompaction()) throw new Error("premature movement");
        \\Atomics.store(noGilCompactGate, "wake", 1);
        \\Atomics.notify(noGilCompactGate, "wake");
        \\noGilCompactWorker.join()
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(source);
    const result = JSEvaluateScript(ctx, source, null, null, 1, &exception) orelse return error.EvalFailed;
    defer if (State.protected != null) std.debug.assert(ZJSValueUnprotect(ctx, State.protected));
    try std.testing.expect(exception == null);
    try std.testing.expectEqualStrings("joined", valueFromContext(context, result).?.asStr());
    try std.testing.expectEqual(@as(usize, 1), State.schedule_calls);
    try std.testing.expectEqual(@as(usize, 1), State.confirm_calls);
    try std.testing.expectEqual(ZJSGCCompactionStatus.unsupported, State.direct_status);
    try std.testing.expectEqual(ZJSGCCompactionStatus.unsupported, State.confirm_status);
    try std.testing.expect(context.gc_compaction_requested.load(.acquire));
    try std.testing.expectEqual(
        State.compactions_before,
        context.gc_moving_safepoint_compactions.load(.monotonic),
    );
    try std.testing.expect(!context.gc_relocation_active.load(.acquire));

    var moved_cells: usize = 0;
    var moved_bytes: usize = 0;
    try std.testing.expectEqual(
        ZJSGCCompactionStatus.compacted,
        ZJSContextCompactGarbage(ctx, &moved_cells, &moved_bytes),
    );
    try std.testing.expect(moved_cells > 0 and moved_bytes > 0);
    try std.testing.expect(!context.gc_compaction_requested.load(.acquire));
    const protected = State.protected orelse return error.ProtectFailed;
    const current = valueFromContext(context, protected) orelse return error.ValueFailed;
    try std.testing.expect(State.old_payload != @intFromPtr(current.asObj()));
    const marker_name = JSStringCreateWithUTF8CString("marker") orelse return error.StringInitFailed;
    defer JSStringRelease(marker_name);
    const marker = JSObjectGetProperty(ctx, protected, marker_name, &exception) orelse return error.PropFailed;
    try std.testing.expect(exception == null);
    try std.testing.expectEqual(@as(f64, 361), JSValueToNumber(ctx, marker, &exception));
    try std.testing.expectEqual(
        ZJSGCCompactionStatus.no_candidates,
        ZJSContextCompactGarbage(ctx, &moved_cells, &moved_bytes),
    );
}

test "C-API: protected handles trace managed StringCells" {
    const ctx_obj = try Context.createWith(std.testing.allocator, .{ .enable_gc = true });
    defer ctx_obj.destroy();
    const ctx: JSContextRef = @ptrCast(ctx_obj);
    JSGarbageCollect(ctx);

    const source = JSStringCreateWithUTF8CString("managed-325") orelse return error.StringInitFailed;
    defer JSStringRelease(source);
    const held = JSValueMakeString(ctx, source) orelse return error.StringInitFailed;
    try std.testing.expect(ZJSValueProtect(ctx, held));
    JSGarbageCollect(ctx);
    const protected_bytes = ctx_obj.gc_string_bytes_live;

    const copy = JSValueToStringCopy(ctx, held, null) orelse return error.StringInitFailed;
    defer JSStringRelease(copy);
    const max = JSStringGetMaximumUTF8CStringSize(copy);
    const bytes = try std.testing.allocator.alloc(u8, max);
    defer std.testing.allocator.free(bytes);
    const written = JSStringGetUTF8CString(copy, bytes.ptr, bytes.len);
    try std.testing.expectEqualStrings("managed-325", bytes[0 .. written - 1]);

    try std.testing.expect(ZJSValueUnprotect(ctx, held));
    JSGarbageCollect(ctx);
    try std.testing.expect(ctx_obj.gc_string_bytes_live < protected_bytes);
}

test "C-API: JSValueProtect reserves handle capacity chunks" {
    const ctx_obj = try Context.createWith(std.testing.allocator, .{ .enable_gc = true, .enable_threads = true });
    defer ctx_obj.destroy();
    const ctx: JSContextRef = @ptrCast(ctx_obj);

    const first = JSValueToObject(ctx, JSValueMakeNumber(ctx, 1), null) orelse return error.ObjectCreateFailed;
    try std.testing.expect(ZJSValueProtect(ctx, first));
    try std.testing.expectEqual(@as(usize, 1), ctx_obj.c_api_handles.items.len);
    try std.testing.expect(ctx_obj.c_api_handles.capacity >= Context.c_api_handle_reserve_granularity);
    const first_capacity = ctx_obj.c_api_handles.capacity;

    try std.testing.expect(ZJSValueProtect(ctx, first));
    try std.testing.expectEqual(@as(usize, 1), ctx_obj.c_api_handles.items.len);
    try std.testing.expectEqual(@as(usize, 2), ctx_obj.c_api_handles.items[0].count);
    try std.testing.expectEqual(first_capacity, ctx_obj.c_api_handles.capacity);

    ctx_obj.c_api_handles.items[0].count = std.math.maxInt(usize);
    try std.testing.expect(!ZJSValueProtect(ctx, first));
    try std.testing.expectEqual(std.math.maxInt(usize), ctx_obj.c_api_handles.items[0].count);
    ctx_obj.c_api_handles.items[0].count = 2;

    while (ctx_obj.c_api_handles.items.len < first_capacity) {
        const v = JSValueToObject(ctx, JSValueMakeNumber(ctx, @floatFromInt(ctx_obj.c_api_handles.items.len)), null) orelse return error.ObjectCreateFailed;
        try std.testing.expect(ZJSValueProtect(ctx, v));
    }
    try std.testing.expectEqual(first_capacity, ctx_obj.c_api_handles.items.len);
    try std.testing.expectEqual(first_capacity, ctx_obj.c_api_handles.capacity);

    const overflow = JSValueToObject(ctx, JSValueMakeNumber(ctx, 99), null) orelse return error.ObjectCreateFailed;
    try std.testing.expect(ZJSValueProtect(ctx, overflow));
    try std.testing.expectEqual(first_capacity + 1, ctx_obj.c_api_handles.items.len);
    try std.testing.expect(ctx_obj.c_api_handles.capacity > first_capacity);

    try std.testing.expect(!ZJSValueProtect(ctx, null));
    try std.testing.expect(!ZJSValueUnprotect(ctx, null));
}

test "C-API: JSValueProtect roots survive mid-script parallel GC" {
    if (builtin.single_threaded) return error.SkipZigTest;

    const ctx_obj = try Context.createWithTestingOptions(std.testing.allocator, .{
        .enable_threads = true,
        .enable_gc = true,
        .parallel_gc = true,
        .parallel_js = true,
        .parallel_midscript_gc = true,
    });
    defer ctx_obj.destroy();
    const ctx: JSContextRef = @ptrCast(ctx_obj);

    const mk = JSStringCreateWithUTF8CString("({ tag: 456, nested: { marker: 789 } })") orelse return error.StringInitFailed;
    defer JSStringRelease(mk);
    const held = JSEvaluateScript(ctx, mk, null, null, 0, null) orelse return error.EvalFailed;
    try std.testing.expect(ZJSValueProtect(ctx, held));

    const src = JSStringCreateWithUTF8CString(
        \\(() => {
        \\  const N = 3;
        \\  const gate = { ready: 0, go: 0 };
        \\  const threads = [];
        \\  for (let t = 0; t < N; t++) {
        \\    threads.push(new Thread((gate, id) => {
        \\      Atomics.add(gate, 'ready', 1);
        \\      Atomics.notify(gate, 'ready');
        \\      while (Atomics.load(gate, 'go') === 0)
        \\        Atomics.wait(gate, 'go', 0, 1);
        \\      const keep = [];
        \\      for (let round = 0; round < 6; round++) {
        \\        for (let i = 0; i < 500; i++)
        \\          ({ id, round, i, payload: 'c-api-midgc-worker-' + id + '-' + round + '-' + i });
        \\        keep.push({ id, round, marker: id * 100 + round });
        \\        let spin = 0;
        \\        for (let j = 0; j < 5000; j++) spin = (spin + j + round) & 0x3fffffff;
        \\        if (spin < 0) keep.push({ impossible: true });
        \\      }
        \\      return keep.length;
        \\    }, gate, t));
        \\  }
        \\  while (Atomics.load(gate, 'ready') < N)
        \\    Atomics.wait(gate, 'ready', Atomics.load(gate, 'ready'), 1);
        \\  Atomics.store(gate, 'go', 1);
        \\  Atomics.notify(gate, 'go', Infinity);
        \\  const keep = [];
        \\  for (let round = 0; round < 12; round++) {
        \\    for (let i = 0; i < 900; i++)
        \\      keep.push({ round, i, nested: { value: round + i }, text: 'c-api-midgc-main-' + round + '-' + i });
        \\    let spin = 0;
        \\    for (let j = 0; j < 8000; j++) spin = (spin + j + round) & 0x3fffffff;
        \\    if (spin < 0) keep.push({ impossible: true });
        \\  }
        \\  let joined = 0;
        \\  for (const t of threads) joined += t.join();
        \\  return keep.length + joined;
        \\})();
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(src);

    const before_collections = ctx_obj.gc_par_collections.load(.monotonic);
    var attempt: usize = 0;
    while (attempt < 10 and ctx_obj.gc_par_collections.load(.monotonic) == before_collections) : (attempt += 1) {
        const result = JSEvaluateScript(ctx, src, null, null, 0, null) orelse return error.EvalFailed;
        try std.testing.expectEqual(@as(f64, 10818), JSValueToNumber(ctx, result, null));
    }
    try std.testing.expect(ctx_obj.gc_par_collections.load(.monotonic) > before_collections);

    const key = JSStringCreateWithUTF8CString("tag") orelse return error.StringInitFailed;
    defer JSStringRelease(key);
    const tag = JSObjectGetProperty(ctx, held, key, null) orelse return error.PropFailed;
    try std.testing.expectEqual(@as(f64, 456), JSValueToNumber(ctx, tag, null));

    const nested_key = JSStringCreateWithUTF8CString("nested") orelse return error.StringInitFailed;
    defer JSStringRelease(nested_key);
    const marker_key = JSStringCreateWithUTF8CString("marker") orelse return error.StringInitFailed;
    defer JSStringRelease(marker_key);
    const nested = JSObjectGetProperty(ctx, held, nested_key, null) orelse return error.PropFailed;
    const marker = JSObjectGetProperty(ctx, nested, marker_key, null) orelse return error.PropFailed;
    try std.testing.expectEqual(@as(f64, 789), JSValueToNumber(ctx, marker, null));

    JSGarbageCollect(ctx);
    const with_protection = ctx_obj.gc.?.live_cells;
    try std.testing.expect(ZJSValueUnprotect(ctx, held));
    JSGarbageCollect(ctx);
    try std.testing.expect(ctx_obj.gc.?.live_cells < with_protection);
}

test "private async Error stacks follow pending Promise await chains" {
    const group = JSContextGroupCreate() orelse return error.GroupCreateFailed;
    defer JSContextGroupRelease(group);
    const context = JSGlobalContextCreateInGroup(group, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const sibling = JSGlobalContextCreateInGroup(group, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;
    const sibling_internal = ctxForEvaluation(sibling) orelse return error.ContextCreateFailed;

    const source = JSStringCreateWithUTF8CString(
        \\globalThis.__resolve_254 = undefined;
        \\globalThis.__gate_254 = new Promise(resolve => { __resolve_254 = resolve; });
        \\async function inner254() {
        \\  await __gate_254;
        \\}
        \\async function outer254() {
        \\  await inner254();
        \\}
        \\globalThis.__outer_254 = outer254();
        \\__gate_254;
    ) orelse return error.StringInitFailed;
    defer JSStringRelease(source);
    const source_url = JSStringCreateWithUTF8CString("async-stack-254.js") orelse return error.StringInitFailed;
    defer JSStringRelease(source_url);
    var exception: JSValueRef = null;
    const gate_ref = JSEvaluateScript(context, source, null, source_url, 40, &exception) orelse return error.EvalFailed;
    try std.testing.expect(exception == null);
    const gate = privateEncodedFromRef(gate_ref);
    const gate_cell = JSC__JSValue__asPromise(gate) orelse return error.PromiseCreateFailed;

    const makeStacklessError = struct {
        fn make(c: *Context, text: []const u8) !EncodedValue {
            const error_value = try c.evaluate(text);
            try error_value.asObj().setErrorStackFrames(c.arena(), &.{});
            return privateEncodedFromValue(c, error_value);
        }
    }.make;

    const encoded_error = try makeStacklessError(internal, "globalThis.__async_error_254 = new Error('native-254')");
    _ = JSC__VM__runGC(JSC__JSGlobalObject__vm(context), true);
    Bun__attachAsyncStackFromPromise(context, encoded_error, gate_cell);
    const error_object = (privateValueFrom(context, encoded_error) orelse return error.ValueInitFailed).asObj();
    const frames = error_object.errorStackFrames();
    try std.testing.expectEqual(@as(usize, 2), frames.len);
    try std.testing.expectEqualStrings("inner254", frames[0].function_name);
    try std.testing.expectEqualStrings("outer254", frames[1].function_name);
    for (frames, 0..) |frame, index| {
        try std.testing.expect(frame.is_async);
        try std.testing.expectEqualStrings("async-stack-254.js", frame.source_url);
        try std.testing.expect(frame.line_zero_based >= 39);
        try std.testing.expect(frame.column_zero_based >= 0);
        try std.testing.expect(frame.line_start_byte >= 0);
        try std.testing.expectEqual(@as(i32, @intCast(index)), frame.jsc_stack_frame_index);
    }

    const sibling_error = try makeStacklessError(sibling_internal, "globalThis.__sibling_async_error_254 = new Error('sibling-254')");
    Bun__attachAsyncStackFromPromise(sibling, sibling_error, gate_cell);
    try std.testing.expectEqual(@as(usize, 2), (privateValueFrom(sibling, sibling_error) orelse return error.ValueInitFailed).asObj().errorStackFrames().len);

    const existing = privateEncodedFromValue(internal, try internal.evaluate("new Error('existing-254')"));
    const existing_count = (privateValueFrom(context, existing) orelse return error.ValueInitFailed).asObj().errorStackFrames().len;
    Bun__attachAsyncStackFromPromise(context, existing, gate_cell);
    try std.testing.expectEqual(existing_count, (privateValueFrom(context, existing) orelse return error.ValueInitFailed).asObj().errorStackFrames().len);

    const materialized = try makeStacklessError(internal, "globalThis.__materialized_254 = new Error('materialized-254')");
    _ = try internal.evaluate("void __materialized_254.stack");
    Bun__attachAsyncStackFromPromise(context, materialized, gate_cell);
    try std.testing.expectEqual(@as(usize, 0), (privateValueFrom(context, materialized) orelse return error.ValueInitFailed).asObj().errorStackFrames().len);
    const assigned_stack = try makeStacklessError(internal, "globalThis.__assigned_stack_254 = new Error('assigned-254')");
    _ = try internal.evaluate("__assigned_stack_254.stack = 'custom-254'");
    Bun__attachAsyncStackFromPromise(context, assigned_stack, gate_cell);
    try std.testing.expectEqual(@as(usize, 0), (privateValueFrom(context, assigned_stack) orelse return error.ValueInitFailed).asObj().errorStackFrames().len);

    _ = try internal.evaluate("Error.stackTraceLimit = 0");
    const zero_limit = try makeStacklessError(internal, "new Error('zero-limit-254')");
    Bun__attachAsyncStackFromPromise(context, zero_limit, gate_cell);
    try std.testing.expectEqual(@as(usize, 0), (privateValueFrom(context, zero_limit) orelse return error.ValueInitFailed).asObj().errorStackFrames().len);
    _ = try internal.evaluate("Error.stackTraceLimit = 1");
    const one_limit = try makeStacklessError(internal, "new Error('one-limit-254')");
    Bun__attachAsyncStackFromPromise(context, one_limit, gate_cell);
    try std.testing.expectEqual(@as(usize, 1), (privateValueFrom(context, one_limit) orelse return error.ValueInitFailed).asObj().errorStackFrames().len);
    _ = try internal.evaluate("Error.stackTraceLimit = 10");

    const pending_error = try makeStacklessError(internal, "new Error('pending-254')");
    JSC__VM__throwError(JSC__JSGlobalObject__vm(context), context, EncodedValue.fromInt32(254));
    Bun__attachAsyncStackFromPromise(context, pending_error, gate_cell);
    try std.testing.expectEqual(@as(usize, 2), (privateValueFrom(context, pending_error) orelse return error.ValueInitFailed).asObj().errorStackFrames().len);
    const preserved = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(254), JSC__Exception__asJSValue(@ptrFromInt(try preserved.asCellAddress())));

    Bun__attachAsyncStackFromPromise(context, .undefined, gate_cell);
    Bun__attachAsyncStackFromPromise(context, encoded_error, null);
    const settled = privateEncodedFromValue(internal, try internal.evaluate("Promise.resolve(254)"));
    const settled_error = try makeStacklessError(internal, "new Error('settled-254')");
    Bun__attachAsyncStackFromPromise(context, settled_error, JSC__JSValue__asPromise(settled));
    try std.testing.expectEqual(@as(usize, 0), (privateValueFrom(context, settled_error) orelse return error.ValueInitFailed).asObj().errorStackFrames().len);

    const forwarded_gate = privateEncodedFromValue(internal, try internal.evaluate(
        \\globalThis.__forwarded_gate_254 = new Promise(resolve => { globalThis.__forwarded_resolve_254 = resolve; });
        \\async function returnsPromise254() { return __forwarded_gate_254; }
        \\async function awaitsForwarded254() { await returnsPromise254(); }
        \\globalThis.__forwarded_outer_254 = awaitsForwarded254();
        \\__forwarded_gate_254;
    ));
    const forwarded_error = try makeStacklessError(internal, "new Error('forwarded-254')");
    Bun__attachAsyncStackFromPromise(context, forwarded_error, JSC__JSValue__asPromise(forwarded_gate));
    const forwarded_frames = (privateValueFrom(context, forwarded_error) orelse return error.ValueInitFailed).asObj().errorStackFrames();
    try std.testing.expectEqual(@as(usize, 1), forwarded_frames.len);
    try std.testing.expectEqualStrings("awaitsForwarded254", forwarded_frames[0].function_name);

    const within_hop_gate = privateEncodedFromValue(internal, try internal.evaluate(
        \\globalThis.__within_hop_gate_254 = new Promise(resolve => { globalThis.__within_hop_resolve_254 = resolve; });
        \\let __within_hop_tail_254 = __within_hop_gate_254;
        \\for (let i = 0; i < 30; i++) __within_hop_tail_254 = __within_hop_tail_254.then();
        \\async function withinHopGuard254() { await __within_hop_tail_254; }
        \\globalThis.__within_hop_outer_254 = withinHopGuard254();
        \\__within_hop_gate_254;
    ));
    const within_hop_error = try makeStacklessError(internal, "new Error('within-hop-254')");
    Bun__attachAsyncStackFromPromise(context, within_hop_error, JSC__JSValue__asPromise(within_hop_gate));
    const within_hop_frames = (privateValueFrom(context, within_hop_error) orelse return error.ValueInitFailed).asObj().errorStackFrames();
    try std.testing.expectEqual(@as(usize, 1), within_hop_frames.len);
    try std.testing.expectEqualStrings("withinHopGuard254", within_hop_frames[0].function_name);

    const beyond_hop_gate = privateEncodedFromValue(internal, try internal.evaluate(
        \\globalThis.__beyond_hop_gate_254 = new Promise(resolve => { globalThis.__beyond_hop_resolve_254 = resolve; });
        \\let __beyond_hop_tail_254 = __beyond_hop_gate_254;
        \\for (let i = 0; i < 32; i++) __beyond_hop_tail_254 = __beyond_hop_tail_254.then();
        \\async function beyondHopGuard254() { await __beyond_hop_tail_254; }
        \\globalThis.__beyond_hop_outer_254 = beyondHopGuard254();
