test "private structured serialization owns bytes and preserves clone semantics" {
    const Probe = struct {
        fn expose(global: JSContextRef, name: [*:0]const u8, result: EncodedValue) !void {
            const key = JSStringCreateWithUTF8CString(name) orelse return error.StringCreateFailed;
            defer JSStringRelease(key);
            const ref = privateRefFromEncoded(global, result) orelse return error.ValueCreateFailed;
            var exception: JSValueRef = null;
            JSObjectSetProperty(global, JSContextGetGlobalObject(global), key, ref, 0, &exception);
            if (exception != null) return error.PropertySetFailed;
        }

        fn expectRejected(external: PrivateSerializedScriptExternal, global: JSContextRef) !void {
            try std.testing.expect(external.bytes == null and external.size == 0 and external.handle == null);
            try std.testing.expect(JSGlobalObject__hasException(global));
            JSGlobalObject__clearException(global);
        }
    };

    const context = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;

    const source = try internal.evaluate(
        \\globalThis.__serial_source_323 = { number: 323, typed: new Uint8Array([3, 2, 3]) };
        \\__serial_source_323.self = __serial_source_323;
        \\__serial_source_323.aliases = [__serial_source_323.typed, __serial_source_323.typed];
        \\__serial_source_323;
    );
    const source_encoded = privateEncodedFromValue(internal, source);
    const external = Bun__serializeJSValue(context, source_encoded, 0);
    try std.testing.expect(external.bytes != null and external.size != 0 and external.handle != null);
    const stable = try std.testing.allocator.dupe(u8, external.bytes.?[0..external.size]);
    defer std.testing.allocator.free(stable);
    JSGarbageCollect(context);
    try std.testing.expectEqualSlices(u8, stable, external.bytes.?[0..external.size]);

    const restored = Bun__JSValue__deserialize(context, external.bytes.?, external.size);
    try std.testing.expect(restored != .empty and !JSGlobalObject__hasException(context));
    try Probe.expose(context, "__serial_restored_323", restored);
    try std.testing.expect((try internal.evaluate(
        \\__serial_restored_323 !== __serial_source_323 &&
        \\__serial_restored_323.self === __serial_restored_323 &&
        \\__serial_restored_323.aliases[0] === __serial_restored_323.typed &&
        \\__serial_restored_323.aliases[1] === __serial_restored_323.typed &&
        \\__serial_restored_323.number === 323 &&
        \\Array.from(__serial_restored_323.typed).join(',') === '3,2,3'
    )).asBool());
    Bun__SerializedScriptSlice__free(external.handle);
    Bun__SerializedScriptSlice__free(external.handle);
    Bun__SerializedScriptSlice__free(null);

    for ([_]u8{ 1, 2, 3 }) |flags| {
        const flagged = Bun__serializeJSValue(context, EncodedValue.fromInt32(323), flags);
        try std.testing.expect(flagged.bytes != null and flagged.handle != null);
        const primitive = Bun__JSValue__deserialize(context, flagged.bytes.?, flagged.size);
        try std.testing.expectEqual(EncodedValue.fromInt32(323), primitive);
        Bun__SerializedScriptSlice__free(flagged.handle);
    }

    const sab = privateEncodedFromValue(internal, try internal.evaluate(
        \\globalThis.__serial_sab_323 = new SharedArrayBuffer(4);
        \\new Uint8Array(__serial_sab_323)[0] = 23;
        \\__serial_sab_323;
    ));
    const sab_external = Bun__serializeJSValue(context, sab, 0);
    try std.testing.expect(sab_external.bytes != null and sab_external.handle != null);
    const sab_restored = Bun__JSValue__deserialize(context, sab_external.bytes.?, sab_external.size);
    try Probe.expose(context, "__serial_sab_restored_323", sab_restored);
    try std.testing.expect((try internal.evaluate(
        \\__serial_sab_restored_323 !== __serial_sab_323 &&
        \\new Uint8Array(__serial_sab_restored_323)[0] === 23 &&
        \\(new Uint8Array(__serial_sab_restored_323)[1] = 32,
        \\ new Uint8Array(__serial_sab_323)[1] === 32)
    )).asBool());
    Bun__SerializedScriptSlice__free(sab_external.handle);
    for ([_]u8{ 1, 2, 3 }) |flags|
        try Probe.expectRejected(Bun__serializeJSValue(context, sab, flags), context);

    try Probe.expectRejected(Bun__serializeJSValue(context, source_encoded, 4), context);
    const uncloneable = privateEncodedFromValue(internal, try internal.evaluate("(() => 323)"));
    try Probe.expectRejected(Bun__serializeJSValue(context, uncloneable, 0), context);

    const malformed = [_]u8{ 0x5a, 0x4a, 0x53, 0x43 };
    try std.testing.expectEqual(EncodedValue.empty, Bun__JSValue__deserialize(context, &malformed, malformed.len));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);
    try std.testing.expectEqual(EncodedValue.empty, Bun__JSValue__deserialize(context, null, 1));
    try std.testing.expect(JSGlobalObject__hasException(context));
    JSGlobalObject__clearException(context);

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_value = privateEncodedFromValue(foreign_internal, try foreign_internal.evaluate("({ foreign: 323 })"));
    try Probe.expectRejected(Bun__serializeJSValue(context, foreign_value, 0), context);

    var no_memory: [0]u8 = .{};
    var failing = std.heap.FixedBufferAllocator.init(&no_memory);
    try Probe.expectRejected(
        privateSerializeJSValue(context, EncodedValue.fromInt32(323), 0, failing.allocator()),
        context,
    );
}

test "private custom inspect invokes exact receiver options and helper" {
    const Probe = struct {
        fn encoded(context: *Context, source: []const u8) !EncodedValue {
            return privateEncodedFromValue(context, try context.evaluate(source));
        }

        fn expose(global: JSContextRef, name: [*:0]const u8, result: EncodedValue) !void {
            const key = JSStringCreateWithUTF8CString(name) orelse return error.StringCreateFailed;
            defer JSStringRelease(key);
            const ref = privateRefFromEncoded(global, result) orelse return error.ValueCreateFailed;
            var exception: JSValueRef = null;
            JSObjectSetProperty(global, JSContextGetGlobalObject(global), key, ref, 0, &exception);
            if (exception != null) return error.PropertySetFailed;
        }

        fn clearExpected(global: JSContextRef) !void {
            try std.testing.expect(JSGlobalObject__hasException(global));
            JSGlobalObject__clearException(global);
        }
    };

    const context = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(context);
    const internal = ctxForEvaluation(context) orelse return error.ContextCreateFailed;
    const receiver = try Probe.encoded(internal, "({ marker: 322, value: 323 })");
    const function = try Probe.encoded(
        internal,
        "(function (depth, options, inspect) { gc(); return {" ++
            "receiver: this.marker, depth, maxDepth: options.depth, colors: options.colors," ++
            "keys: Object.keys(options).join(','), helperType: typeof inspect," ++
            "helperName: inspect.name, recursive: inspect(this.value, options)," ++
            "plain: options.stylize('plain', 'number')}; })",
    );
    const result = JSC__JSValue__callCustomInspectFunction(context, function, receiver, 7, 11, false);
    try std.testing.expect(result != .empty and !JSGlobalObject__hasException(context));
    try Probe.expose(context, "__inspect_result_322", result);
    try std.testing.expect((try internal.evaluate(
        "__inspect_result_322.receiver === 322 && __inspect_result_322.depth === 7 &&" ++
            "__inspect_result_322.maxDepth === 11 && __inspect_result_322.colors === false &&" ++
            "__inspect_result_322.keys === 'stylize,depth,colors' &&" ++
            "__inspect_result_322.helperType === 'function' && __inspect_result_322.helperName === 'inspect' &&" ++
            "__inspect_result_322.recursive === '323' && __inspect_result_322.plain === 'plain'",
    )).asBool());

    const color_function = try Probe.encoded(internal, "(function (_, options) { return options.stylize('323', 'number'); })");
    const colored = JSC__JSValue__callCustomInspectFunction(context, color_function, receiver, 0, std.math.maxInt(u32), true);
    try std.testing.expectEqualStrings(
        "\x1b[33m323\x1b[39m",
        (privateValueFrom(context, colored) orelse return error.ValueCreateFailed).asStr(),
    );

    const throwing = try Probe.encoded(internal, "(function () { throw 322; })");
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__callCustomInspectFunction(context, throwing, receiver, 0, 0, false));
    var pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(322), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__callCustomInspectFunction(context, receiver, receiver, 0, 0, false));
    try Probe.clearExpected(context);

    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    const foreign_internal = ctxForEvaluation(foreign) orelse return error.ContextCreateFailed;
    const foreign_function = try Probe.encoded(foreign_internal, "(function () { return 1; })");
    const foreign_receiver = try Probe.encoded(foreign_internal, "({})");
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__callCustomInspectFunction(context, foreign_function, receiver, 0, 0, false));
    try Probe.clearExpected(context);
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__callCustomInspectFunction(context, function, foreign_receiver, 0, 0, false));
    try Probe.clearExpected(context);

    JSC__VM__throwError(JSC__JSGlobalObject__vm(context), context, EncodedValue.fromInt32(3220));
    try std.testing.expectEqual(EncodedValue.empty, JSC__JSValue__callCustomInspectFunction(context, function, receiver, 0, 0, false));
    pending = JSGlobalObject__tryTakeException(context);
    try std.testing.expectEqual(EncodedValue.fromInt32(3220), JSC__Exception__asJSValue(@ptrFromInt(try pending.asCellAddress())));
}

test "private AbortSignal boundary shares identity callbacks reasons and roots" {
    const CallbackState = struct {
        id: u8,
        sequence: *[8]u8,
        used: *usize,
        calls: usize = 0,
        reason: EncodedValue = .empty,
        required: [2]?*PrivateAbortSignal = .{ null, null },
        late: ?*@This() = null,
        signal: ?*PrivateAbortSignal = null,
        failed: bool = false,

        fn callback(raw: ?*anyopaque, reason: EncodedValue) callconv(.c) void {
            const state: *@This() = @ptrCast(@alignCast(raw orelse return));
            if (state.used.* >= state.sequence.len) {
                state.failed = true;
                return;
            }
            for (state.required) |required| if (required) |signal_| {
                if (!WebCore__AbortSignal__aborted(signal_)) state.failed = true;
            };
            state.sequence[state.used.*] = state.id;
            state.used.* += 1;
            state.calls += 1;
            state.reason = reason;
            if (state.late) |late| {
                state.late = null;
                if (WebCore__AbortSignal__addListener(state.signal, late, callback) == null)
                    state.failed = true;
            }
        }
    };

    const group = JSContextGroupCreate() orelse return error.GroupCreateFailed;
    defer JSContextGroupRelease(group);
    const global = JSGlobalContextCreateInGroup(group, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(global);
    const sibling = JSGlobalContextCreateInGroup(group, null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(sibling);
    const context = ctxForEvaluation(global) orelse return error.ContextCreateFailed;
    const internal_group: *CContextGroup = @ptrCast(@alignCast(context.c_api_group.?));

    const encoded = privateEncodedFromValue(context, try context.evaluate(
        "globalThis.__abort_controller_329 = new AbortController(); __abort_controller_329.signal",
    ));
    const signal = WebCore__AbortSignal__fromJS(encoded) orelse return error.ValueCreateFailed;
    try std.testing.expectEqual(signal, WebCore__AbortSignal__fromJS(encoded));
    try std.testing.expectEqual(encoded, WebCore__AbortSignal__toJS(signal, sibling));
    try std.testing.expect(!WebCore__AbortSignal__aborted(signal));
    try std.testing.expectEqual(EncodedValue.null, WebCore__AbortSignal__abortReason(signal));
    var common: u8 = 99;
    try std.testing.expectEqual(EncodedValue.empty, WebCore__AbortSignal__reasonIfAborted(signal, global, &common));
    try std.testing.expectEqual(@as(u8, 0), common);

    var sequence: [8]u8 = @splat(0);
    var used: usize = 0;
    var late = CallbackState{ .id = 3, .sequence = &sequence, .used = &used };
    var first = CallbackState{ .id = 1, .sequence = &sequence, .used = &used, .late = &late, .signal = signal };
    var second = CallbackState{ .id = 2, .sequence = &sequence, .used = &used };
    try std.testing.expectEqual(signal, WebCore__AbortSignal__addListener(signal, &first, CallbackState.callback));
    try std.testing.expectEqual(signal, WebCore__AbortSignal__addListener(signal, &second, CallbackState.callback));
    WebCore__AbortSignal__signal(signal, global, .timeout);
    try std.testing.expect(WebCore__AbortSignal__aborted(signal));
    try std.testing.expectEqualSlices(u8, &.{ 1, 3, 2 }, sequence[0..used]);
    try std.testing.expect(!first.failed and !late.failed and !second.failed);
    try std.testing.expectEqual(@as(usize, 1), first.calls);
    try std.testing.expectEqual(@as(usize, 1), late.calls);
    try std.testing.expectEqual(@as(usize, 1), second.calls);
    try std.testing.expect(first.reason != .empty and first.reason == late.reason and first.reason == second.reason);
    try std.testing.expectEqual(EncodedValue.undefined, WebCore__AbortSignal__reasonIfAborted(signal, sibling, &common));
    try std.testing.expectEqual(@as(u8, 1), common);
    try std.testing.expectEqual(first.reason, WebCore__AbortSignal__abortReason(signal));
    WebCore__AbortSignal__signal(signal, global, .user_abort);
    try std.testing.expectEqual(@as(usize, 3), used);

    const arbitrary_encoded = privateEncodedFromValue(context, try context.evaluate(
        "globalThis.__arbitrary_controller_329 = new AbortController(); __arbitrary_controller_329.signal",
    ));
    const arbitrary = WebCore__AbortSignal__fromJS(arbitrary_encoded) orelse return error.ValueCreateFailed;
    var arbitrary_state = CallbackState{ .id = 4, .sequence = &sequence, .used = &used };
    _ = WebCore__AbortSignal__addListener(arbitrary, &arbitrary_state, CallbackState.callback);
    _ = try context.evaluate("__arbitrary_controller_329.abort({ marker: 329 })");
    common = 99;
    const arbitrary_reason = WebCore__AbortSignal__reasonIfAborted(arbitrary, global, &common);
    try std.testing.expectEqual(@as(u8, 0), common);
    try std.testing.expect(arbitrary_reason != .empty and arbitrary_reason == arbitrary_state.reason);
    try std.testing.expect((privateValueFrom(global, arbitrary_reason) orelse return error.ValueCreateFailed).isObject());

    const dependent_encoded = privateEncodedFromValue(context, try context.evaluate(
        "globalThis.__source_controller_329 = new AbortController(); " ++
            "globalThis.__dependent_signal_329 = AbortSignal.any([__source_controller_329.signal]); __dependent_signal_329",
    ));
    const source_encoded = privateEncodedFromValue(context, try context.evaluate("__source_controller_329.signal"));
    const source = WebCore__AbortSignal__fromJS(source_encoded) orelse return error.ValueCreateFailed;
    const dependent = WebCore__AbortSignal__fromJS(dependent_encoded) orelse return error.ValueCreateFailed;
    var dependent_state = CallbackState{
        .id = 5,
        .sequence = &sequence,
        .used = &used,
        .required = .{ source, dependent },
    };
    _ = WebCore__AbortSignal__addListener(dependent, &dependent_state, CallbackState.callback);
    _ = try context.evaluate("__source_controller_329.abort(329)");
    try std.testing.expectEqual(@as(usize, 1), dependent_state.calls);
    try std.testing.expect(!dependent_state.failed);

    const clean_encoded = WebCore__AbortSignal__create(global);
    const clean = WebCore__AbortSignal__fromJS(clean_encoded) orelse return error.ValueCreateFailed;
    var removed = CallbackState{ .id = 6, .sequence = &sequence, .used = &used };
    var kept = CallbackState{ .id = 7, .sequence = &sequence, .used = &used };
    _ = WebCore__AbortSignal__addListener(clean, &removed, CallbackState.callback);
    _ = WebCore__AbortSignal__addListener(clean, &removed, CallbackState.callback);
    _ = WebCore__AbortSignal__addListener(clean, &kept, CallbackState.callback);
    WebCore__AbortSignal__cleanNativeBindings(clean, &removed);
    WebCore__AbortSignal__signal(clean, global, .connection_closed);
    try std.testing.expectEqual(@as(usize, 0), removed.calls);
    try std.testing.expectEqual(@as(usize, 1), kept.calls);

    const roots_before = internal_group.primary.private_strong_roots.items.len;
    const owned = WebCore__AbortSignal__new(global) orelse return error.ValueCreateFailed;
    try std.testing.expectEqual(roots_before + 1, internal_group.primary.private_strong_roots.items.len);
    WebCore__AbortSignal__incrementPendingActivity(owned);
    WebCore__AbortSignal__unref(owned);
    try std.testing.expectEqual(roots_before + 1, internal_group.primary.private_strong_roots.items.len);
    WebCore__AbortSignal__decrementPendingActivity(owned);
    try std.testing.expectEqual(roots_before, internal_group.primary.private_strong_roots.items.len);
    try std.testing.expectEqual(owned, WebCore__AbortSignal__ref(owned));
    try std.testing.expectEqual(roots_before + 1, internal_group.primary.private_strong_roots.items.len);
    WebCore__AbortSignal__unref(owned);
    try std.testing.expectEqual(roots_before, internal_group.primary.private_strong_roots.items.len);

    const fake = privateEncodedFromValue(context, try context.evaluate(
        "Object.defineProperty({}, String.fromCharCode(0) + 'ASsig', { value: true })",
    ));
    try std.testing.expectEqual(@as(?*PrivateAbortSignal, null), WebCore__AbortSignal__fromJS(fake));
    const foreign = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(foreign);
    try std.testing.expectEqual(EncodedValue.empty, WebCore__AbortSignal__toJS(signal, foreign));
}

test "AbortSignal timeout owns observable signals and invalidates borrowed Bun handles" {
    const global = JSGlobalContextCreate(null) orelse return error.ContextCreateFailed;
    defer JSGlobalContextRelease(global);
    const context = ctxForEvaluation(global) orelse return error.ContextCreateFailed;
    const roots_before = context.private_strong_roots.items.len;

    try std.testing.expect((try context.evaluate(
        \\(() => {
        \\  let rejected = 0;
        \\  for (const delay of [-1, NaN, Infinity, 9007199254740992]) {
        \\    try { AbortSignal.timeout(delay); } catch (error) {
        \\      if (error.name === "TypeError") rejected++;
        \\    }
        \\  }
        \\  let missing = false;
        \\  try { AbortSignal.timeout(); } catch (error) { missing = error.name === "TypeError"; }
        \\  const maximum = AbortSignal.timeout(9007199254740991) instanceof AbortSignal;
        \\  return rejected === 4 && missing && maximum;
        \\})()
    )).asBool());
    try std.testing.expect(!(try context.evaluate(
        "(() => { const signal = AbortSignal.timeout(0); return signal.aborted; })()",
    )).asBool());
    _ = try context.evaluate(
        "globalThis.__timeout_order_330 = []; " ++
            "AbortSignal.timeout(0).addEventListener('abort', () => __timeout_order_330.push('abort')); " ++
            "Promise.resolve().then(() => __timeout_order_330.push('promise'))",
    );
    try std.testing.expectEqualStrings(
        "promise,abort",
        (try context.evaluate("__timeout_order_330.join(',')")).asStr(),
    );

    const encoded = privateEncodedFromValue(context, try context.evaluate(
        "globalThis.__timeout_signal_330 = AbortSignal.timeout(60000); __timeout_signal_330",
    ));
    const signal = WebCore__AbortSignal__fromJS(encoded) orelse return error.ValueCreateFailed;
    const timeout = WebCore__AbortSignal__getTimeout(signal) orelse return error.ValueCreateFailed;
    try std.testing.expectEqual(Context.BunTimerState.active, timeout.event_loop_timer.state);
    try std.testing.expectEqual(Context.BunTimerTag.abort_signal_timeout, timeout.event_loop_timer.tag);
    try std.testing.expectEqual(@as(?*anyopaque, @ptrCast(signal)), timeout.signal);
    try std.testing.expectEqual(@as(u32, 1 << 30), timeout.flags);
    try std.testing.expect(timeout.generation != 0);

    _ = try context.evaluate(
        "globalThis.__timeout_listener_330 = () => {}; __timeout_signal_330.addEventListener('abort', __timeout_listener_330)",
    );
    try std.testing.expectEqual(roots_before + 1, context.private_strong_roots.items.len);
    _ = try context.evaluate("__timeout_signal_330.removeEventListener('abort', __timeout_listener_330)");
    try std.testing.expectEqual(roots_before, context.private_strong_roots.items.len);

    var native_callback_calls: usize = 0;
    const NativeCallback = struct {
        fn run(raw: ?*anyopaque, _: EncodedValue) callconv(.c) void {
            const calls: *usize = @ptrCast(@alignCast(raw orelse return));
            calls.* += 1;
        }
    };
    _ = WebCore__AbortSignal__addListener(signal, &native_callback_calls, NativeCallback.run) orelse
        return error.ValueCreateFailed;
    try std.testing.expectEqual(roots_before + 1, context.private_strong_roots.items.len);
    WebCore__AbortSignal__cleanNativeBindings(signal, &native_callback_calls);
    try std.testing.expectEqual(roots_before, context.private_strong_roots.items.len);

    _ = try context.evaluate("__timeout_signal_330.addEventListener('abort', __timeout_listener_330)");
    try std.testing.expectEqual(roots_before + 1, context.private_strong_roots.items.len);
    context.advanceAbortSignalTimeoutGeneration();
    try std.testing.expect(!(try context.evaluate("__timeout_signal_330.aborted")).asBool());
    try std.testing.expectEqual(@as(?*Context.AbortSignalTimeout, null), WebCore__AbortSignal__getTimeout(signal));
    try std.testing.expectEqual(roots_before, context.private_strong_roots.items.len);
    try std.testing.expectEqual(@as(usize, 0), native_callback_calls);

    _ = try context.evaluate(
        "globalThis.__natural_timeout_330 = AbortSignal.timeout(0); __natural_timeout_330",
    );
    try std.testing.expect((try context.evaluate(
        "__natural_timeout_330.aborted && __natural_timeout_330.reason.name === 'TimeoutError'",
    )).asBool());
}
